window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-016.json"] = [{"name":"紫辉尾蜂鸟","english_name":"Tyrian Metaltail","scientific_name":"Metallura tyrianthina","overview":"紫辉尾蜂鸟（英文名：Tyrian Metaltail，学名：Metallura tyrianthina），是雨燕目蜂鸟科辉尾蜂鸟属的珍稀鸟类。分布于南美洲北部，从委内瑞拉至玻利维亚北部，常见于安第斯山脉温带森林及其边缘地带。具有独特的金属光泽绿色上羽，棕色下羽和亮绿色喉部。雌雄差异明显，雄鸟尾羽呈青铜色光泽，而雌鸟下羽具白色与绿色斑点。","appearance":"紫辉尾蜂鸟体长约9至10厘米，体重2.7至5.1克。雄鸟上身呈瓶绿色，下身灰色，带有苍白的羽毛边缘，喉部闪耀着翡翠绿，尾羽略叉开，闪烁青铜色。雌鸟上身同样是瓶绿色，下身更偏白色，带有绿色斑点；喉部与上胸为橙赭色，点缀以橄榄绿色斑点；尾羽外侧有白色尖端。幼鸟与成年雌鸟相似。不同亚种间存在显著差异，例如M. t. districta雄鸟尾羽为紫色，雌鸟下羽无斑点；M. t. chloropogon雄鸟几乎全黑，雌鸟喉部与上胸仅有少量斑点。","call":"紫辉尾蜂鸟的歌声罕见，由一系列微弱、高音、含糊不清的音符组成，通常听到的是追逐时交替的颤音和重复的吱吱声，以及短暂的‘tsit’或‘pit’音符。","habits":"栖息于多种湿润开阔景观的内部，包括次生林、云雾林、苔藓树线灌丛和小精灵森林。在海拔1,500至4,200米之间活动，偏好2,500至3,300米的地带。季节性地进行显著的垂直迁移。以花蜜和小型昆虫为食，常在花丛中悬停或攀附采食。","breeding":"繁殖季节因南北分布而异，雌鸟独自筑巢、孵化和育雏，巢为开放杯状，由苔藓、地衣、肝叶和其他植物材料构成，放置于岩石缝隙或悬挂在土石岸边的根部。每窝产两枚白色蛋。","identification":"与其他辉尾蜂鸟属物种相比，紫辉尾蜂鸟的金属光泽色彩更为独特，尤其是雄鸟的青铜色尾羽和雌鸟的斑点下羽。","protection":"IUCN：LC（无危）","distribution":"分布于南美，从委内瑞拉北部至玻利维亚北部，包括哥伦比亚、厄瓜多尔、秘鲁等地。","other":"该物种在Las Cajas国家休闲区（厄瓜多尔）和其分布范围内多个保护区中均有发现，显示出对人类引起的环境变化相对不敏感。"},{"name":"佩里辉尾蜂鸟","english_name":"Perija Metaltail","scientific_name":"Metallura iracunda","overview":"佩里辉尾蜂鸟（英文名：Perija Metaltail，学名：Metallura iracunda），是雨燕目蜂鸟科辉尾蜂鸟属的小型鸟类，分布于南美洲哥伦比亚北部和委内瑞拉西北部的Perijá山脉。蜂鸟科以其小巧体型著称，是世界上最小的鸟类，能够悬停及向后飞行。此物种为EN濒危等级。","appearance":"佩里辉尾蜂鸟长约10至11厘米，重约3.6至4.1克。拥有短而直的黑色喙。成年雄鸟上体近似黑色带金边，下体为深青铜绿色并带有金色光泽，拥有一条略呈叉状的闪闪发亮的红宝石色尾羽。雌鸟上体几乎全黑，喉部和上胸部为橙黄色，饰有橄榄绿斑点，下胸和腹部为丰富米黄色，点缀着绿色斑点。其尾羽末端呈淡褐色。雏鸟外观与成年雌鸟相似。","habits":"栖息于Perijá山脉的开阔灌木地带、喀斯特森林边缘、竹林、草地以及砂岩露头，海拔高度介于2400至3200米之间，偶尔低至1850米。通常保持在高海拔范围内，与紫辉尾蜂鸟的分布有所重叠。","breeding":"关于佩里辉尾蜂鸟的繁殖行为、求偶、筑巢、产卵等信息目前未知。","identification":"与更常见的紫辉尾蜂鸟相比，佩里辉尾蜂鸟体型更大，尾羽更长，颜色为铜色而非蓝色；雄鸟颜色更深，雌鸟喉部有斑点。","protection":"IUCN：NT（近危）","distribution":"主要分布于哥伦比亚北部的Perijá山脉和相邻的委内瑞拉西北部，具体包括Cerro Pintado、Cerro Tetari、Cerro Tres Tetas、Cerro Viruela等地。","other":"佩里辉尾蜂鸟的生存环境面临走私、毒品种植、非法采矿等多种威胁，导致栖息地破坏和减少。"},{"name":"翠绿辉尾蜂鸟","english_name":"Viridian Metaltail","scientific_name":"Metallura williami","overview":"翠绿辉尾蜂鸟（英文名：Viridian Metaltail，学名：Metallura williami），是雨燕目蜂鸟科辉尾蜂鸟属的小型鸟类。以体形细小、翅膀扇动速度快著称，分布于南美从哥伦比亚中部至厄瓜多尔南部的高海拔地区。","appearance":"雄鸟体长约11至12厘米，重4.1至5.3克，具中等长度的直黑喙，全身呈瓶绿色，喉部闪烁着与体羽相同但更鲜艳的绿色光泽斑块；尾羽上方为闪亮的蓝紫色，下方为丝滑的蓝紫色，略呈叉状。雌鸟上下体色相似，但喉部光泽斑块不完整，腹部点缀着白色或淡褐色斑点。幼鸟外观与雌鸟类似。","call":"发出一系列3至5个下降的尖锐音符，常随后跟几个混乱的干燥嗡嗡颤音‘trsee-seee-seee-sew..trrk-tsetswe-trrk’，以及重复的干燥或沙哑音符。","habits":"栖息于安第斯山脉高海拔的草甸，散布着灌木丛，以及湿润山地森林和矮林的边缘地带。在哥伦比亚，分布可达海拔4,000米，而厄瓜多尔则通常在2,700至3,600米之间，最低记录为2,100米。推测其为留鸟，但雄鸟可能在非繁殖季节向更高海拔移动。","breeding":"繁殖季节尚未确切界定，但估计在2月至8月之间。巢由苔藓制成，内衬柔软的植物绒毛和小羽毛，常建于岩石缝隙或其他隐蔽位置。雌鸟负责孵化两枚白色卵。","identification":"与Tyrian辉尾蜂鸟的区别在于翠绿辉尾蜂鸟的尾羽上端不会显示那么多的赤褐色，尽管颜色会随地理位置变化，可能是绿色或蓝色。与紫喉辉尾蜂鸟和涅比辉尾蜂鸟在地理上共存，但通过海拔高度隔离。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，从中哥伦比亚到南厄瓜多尔，包括哥伦比亚中部至厄瓜多尔南部的繁殖区域。","other":"存在四个亚种，曾有分类将其两个亚种视为独立物种，但目前仍被视为亚种。"},{"name":"紫喉辉尾蜂鸟","english_name":"Violet-throated Metaltail","scientific_name":"Metallura baroni","overview":"紫喉辉尾蜂鸟（英文名：Violet-throated Metaltail，学名：Metallura baroni），是雨燕目蜂鸟科辉尾蜂鸟属的鸟类。特有种蜂鸟，仅分布于厄瓜多尔中南部安第斯山脉的高海拔地区。其最显著的特征是紫色的喉咙和蓝绿色的尾巴，体型较小，长约10至11厘米，重量介于3.9至5克之间。","appearance":"雄性紫喉辉尾蜂鸟具有中等长度的黑色直喙，上部和下部羽毛呈深橄榄绿，喉咙处有醒目的紫罗兰色斑块；尾巴上方为闪烁的天蓝色，下方则闪耀着黄绿色光泽。雌鸟下腹部被灰色或米色鳞状斑点覆盖，喉咙斑块不如雄鸟完整，尾羽外侧有白色尖端。幼鸟外观与雌鸟相似。","call":"鸣声为一系列下降的3到5个尖锐音符，随后是几个杂乱的音节，类似‘trsee-seee-seee-sew..trr-tsee-tse-tsew..trr-tsee-tse-tsew’，可能是求偶歌曲或追逐叫声。","habits":"栖息于湿润的精灵森林边缘、Polylepis树林以及相邻的高山区草地。常见于Cajas国家公园及周边地区，海拔高度在3000至3900米间，偶尔低至1900米。以花蜜为食，常在各种开花植物中觅食，雄鸟建立领地。","breeding":"繁殖期可能在11月至2月，巢穴类似无跟拖鞋，由苔藓、小枝和羊毛构成，每次产两枚白色蛋，孵化和育雏周期未知。","identification":"与普遍的紫辉尾蜂鸟相比，紫喉辉尾蜂鸟缺乏锈色尾巴，且喉咙颜色为纯紫色而非绿色或淡黄色。","protection":"IUCN：VU（易危）","distribution":"主要分布于厄瓜多尔中南部的Cajas国家公园及其周边Río Mazán保护区。","other":"自1981年起，Río Mazán保护区免于砍伐，成为紫喉辉尾蜂鸟数量最多的地区之一，目前该物种的保护重点在于确保Cajas国家公园的有效保护，并调查库恩卡附近高山区的可能分布。"},{"name":"涅比辉尾蜂鸟","english_name":"Neblina Metaltail","scientific_name":"Metallura odomae","overview":"涅比辉尾蜂鸟（英文名：Neblina Metaltail，学名：Metallura odomae），是雨燕目蜂鸟科辉尾蜂鸟属的鸟类。仅分布于南美洲厄瓜多尔南部和秘鲁北部偏远地区。其名字来源于西班牙语'neblina'，意为'雾'，反映了它们栖息于云雾缭绕的森林边缘的独特生境。","appearance":"雄鸟呈现绿色体羽，拥有玫瑰色喉部，眼后有一白色斑点；尾巴在下方呈绿色，上方可能因光线不同而显青铜或蓝绿色。雌鸟相似，但腹部有白色斑驳，且较小的不完整喉斑。雄鸟拥有深红至玫瑰红色的喉部，而雌鸟整体较暗淡，下体羽端或鳞状覆盖着白色或淡黄色。","call":"其叫声被描述为响亮的'seet-seet-seet-ti-tttt...'和'急促、金属质感的叽叽声'。","habits":"它们生活在高山矮林边缘和灌木丛生的草甸附近，活跃于各种高度，雄鸟会围绕花朵守卫领地。它们全年留在同一栖息地，即使在极端天气条件下也是如此。","breeding":"关于繁殖生态知之甚少，仅有的一次巢穴发现是在八月，由雌鸟筑巢。巢为杯状，主要由苔藓构成，外部装饰有地衣，位于岩石表面的小洞中。","identification":"与火喉辉尾蜂鸟最为相似，但两者的分布区并不重叠；雄鸟的火喉辉尾蜂鸟喉部颜色更偏橙红，而非玫瑰红，整体体羽更为青铜绿。雌性涅比辉尾蜂鸟下体较为绿色，斑纹较少。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，主要集中在厄瓜多尔南部和秘鲁北部，特别是在Podocarpus国家公园以北至秘鲁Piura和Cajamarca部门的北部地区。","other":"涅比辉尾蜂鸟于1980年首次被描述，物种单一，无亚种分化。"},{"name":"铜辉尾蜂鸟","english_name":"Coppery Metaltail","scientific_name":"Metallura theresiae","overview":"铜辉尾蜂鸟（英文名：Coppery Metaltail，学名：Metallura theresiae），是雨燕目蜂鸟科辉尾蜂鸟属的鸟类。独特的蜂鸟，以其鲜艳的铜色羽毛而闻名。体型小巧，生活在秘鲁北部和中部安第斯山脉的林线森林与灌木丛中，海拔通常高于3000米。这种蜂鸟具有短而细的喙，略显上翘，这是其属Metallura的特征之一。目前，铜辉尾蜂鸟的种群被认为是稳定的。","appearance":"铜辉尾蜂鸟的上体呈现深红铜色，下体则是青铜绿色，略显绿色调。雄鸟的喉部有一条狭窄而闪耀的绿色颈环，尾羽上表面为深蓝色，下表面则为青铜绿色。雌鸟与雄鸟相似，但颜色较暗淡，颈环也不如雄鸟明显。幼鸟没有成年鸟的颈环。","call":"铜辉尾蜂鸟发出一系列脆弱的zeee叫声，有时会与ttrrrt音符交替出现，还有一种急促、尖锐的颤音，类似于紫辉尾蜂鸟，但音调更低沉，更不强调，带有一些嗡嗡声。","habits":"铜辉尾蜂鸟居住在安第斯山脉的高海拔地区，栖息于小树和灌木丛边缘。它们以花蜜为主食，也会捕食小型节肢动物。雄鸟会保卫自己的觅食领地。","breeding":"铜辉尾蜂鸟的繁殖生态细节尚未充分了解，但其繁殖季节可能包括8月和9月。具体的筑巢和繁殖行为仍需进一步研究。","identification":"铜辉尾蜂鸟与其他辉尾蜂鸟属物种的区别在于其独特的暗红色铜色调羽毛，以及绿喉和白色眼后斑点。与之相近的涅比辉尾蜂鸟和Fire-throated Metaltail色彩更绿，颈环更红，且地理分布不重叠。","protection":"IUCN：LC（无危）","distribution":"铜辉尾蜂鸟分布于秘鲁北部和中部的安第斯山脉，包括东部斜坡从马兰翁河以东至瓦努科省，以及亚马逊省的科利利亚纳山脊。","other":"人类密度在其栖息地中较低，但烧荒以创造牧场对铜辉尾蜂鸟构成威胁。"},{"name":"火喉辉尾蜂鸟","english_name":"Fiery-throated Metaltail","scientific_name":"Metallura eupogon","overview":"火喉辉尾蜂鸟（英文名：Fiery-throated Metaltail，学名：Metallura eupogon），是雨燕目蜂鸟科辉尾蜂鸟属的小型鸟类，主要分布于秘鲁安第斯山脉东部的高海拔森林地带。雄鸟通体呈深绿色，带有金色青铜光泽，拥有闪亮的玫瑰色喉斑。雌鸟较暗淡，喉部斑点不明显，有时仅见零星红色斑点。","appearance":"雄鸟的羽毛颜色鲜艳，略带金铜色光泽，尾羽上方为蓝绿色，下方为黄绿色，但在野外观察时往往呈现全黑色。雌鸟相比雄鸟色彩较为暗淡，喉部斑点模糊。尾羽双侧颜色各异，上部蓝绿，下部黄绿，但现场观察时可能显得整体深色。喙部适中，直而黑，眼后有一小白斑。","call":"追击叫声为一连串下降的3至6个尖锐音符，随后是一系列重复的、嘈杂的、混乱的短语，类似于“trt-tsee-seee-seee-sew..trr-tsee-tsew..trr-tsee-tsew..”。","habits":"栖息于矮林边缘、小树林旁的开阔地和山地草原。其活动范围主要在海拔2,900至4,000米之间，常见于3,500米以上的高度。饮食习惯尚不清楚，但推测以花蜜为主，同时也会捕捉小型节肢动物。","breeding":"繁殖季节可能包括六月和七月，但具体繁殖生态资料不足。","identification":"与涅比辉尾蜂鸟相似，但二者并无地理重叠。雄鸟可通过其独特的玫瑰色喉斑加以识别。","protection":"IUCN：LC（无危）","distribution":"火喉辉尾蜂鸟的分布范围限于秘鲁中部安第斯山脉东坡，从Huánuco省的Huallaga河以南至Cuzco省的Apurímac河。","other":"曾经，紫喉辉尾蜂鸟和涅比辉尾蜂鸟被视作火喉辉尾蜂鸟的亚种。"},{"name":"鳞辉尾蜂鸟","english_name":"Scaled Metaltail","scientific_name":"Metallura aeneocauda","overview":"鳞辉尾蜂鸟（英文名：Scaled Metaltail，学名：Metallura aeneocauda），是雨燕目蜂鸟科辉尾蜂鸟属的鸟类。体型较小，深绿色，具短直喙。在秘鲁东南部至玻利维亚西北部的安第斯山脉东坡发现，栖息于云雾林边缘、苔藓矮树林及岩石草甸地带。两个亚种，其中M. a. malagae曾被视作独立物种。","appearance":"长度约12至13厘米，体重5.2至5.4克。雄鸟上体呈瓶绿，尾羽略带叉状，上侧天空蓝带青铜绿光泽，下侧闪烁绿色。喉部亮绿色，下体绿色，边缘褐色形成鳞片状外观。雌鸟相似，但喉部小，下体更斑驳。亚种malagae尾上侧红铜色，下侧红色，喙较长。","call":"追逐叫声为下降的3至6个尖锐音符，随后是重复的、嗡嗡杂乱的短语“trt-tsee-seee-seee-sew..trr-tsee-tsew..trr-tsee-tsew..”。","habits":"可能定居，偶尔分散到高草原和较低山地森林。以多种开花植物和灌木的花蜜为食，常攀附花朵。雄鸟保卫领地，同时广泛捕食昆虫。","breeding":"繁殖季节包含五月和六月，但具体繁殖生态尚未详尽记录。","identification":"雄鸟与Tyrian辉尾蜂鸟相比，喉部和胸部更带青铜色，尾部更绿；雌鸟比后者暗淡，喉部和胸部无橙黄色调。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁东南部至玻利维亚西北部的安第斯山脉东坡，高度介于2,500至3,600米之间，常见于3,000米以上。"},{"name":"黑辉尾蜂鸟","english_name":"Black Metaltail","scientific_name":"Metallura phoebe","overview":"黑辉尾蜂鸟（英文名：Black Metaltail，学名：Metallura phoebe），是雨燕目蜂鸟科辉尾蜂鸟属的鸟类。仅分布于秘鲁的高安第斯山脉。其羽毛以黑色为主，隐约透露出红色和绿色的光泽。雄鸟拥有闪烁的蓝绿色喉部斑点，而雌鸟和幼鸟则较小或无此特征。","appearance":"成年黑辉尾蜂鸟长约13至14厘米，体重约5.6至5.9克。它们比其他辉尾蜂鸟属物种大且颜色更暗。雄鸟具有中等长度的直黑喙，全身黑色并带有玫瑰灰色光泽，喉部有闪光的绿松石色斑点，尾巴在良好光照下呈现铜色，眼后有一小块白色斑点。雌鸟类似，但喉部斑点较小或不完整。幼鸟与雌鸟相似，但缺乏喉部斑点。","call":"通常发出尖锐的、哨声似的叫声，或一系列下降的短促高音，有时为短暂的干燥颤音。","habits":"栖息于半干旱的高山灌木丛和短林地带，如Polylepis森林、植被覆盖的峡谷以及草木繁茂的斜坡。在海拔1500米至4500米之间活动，偏好2700米以上高度。可能在特定季节进行高度迁移。主要以多种灌木、草本植物和藤本植物的花蜜为食，如Mutisia、Melastomataceae、Bomarea、Cajophora、Loasa、Salpichroa、Ludwigia和各种菊科植物，偶尔也会在开花的Tristerix槲寄生和Eucalyptes树冠中觅食。雄鸟会建立并保卫喂食领地。","breeding":"繁殖期可能从7月持续到12月，再到次年1月。巢由苔藓构成，悬挂在根部或悬垂在溪流上方的细枝上。一窝产两枚白色蛋，由雌鸟独自孵化。首次繁殖发生在第二年。","identification":"与同属其他物种相比，黑辉尾蜂鸟体型较大且颜色更深，雄鸟的绿松石色喉部斑点是识别关键。","protection":"IUCN：LC（无危）","distribution":"分布于秘鲁西部安第斯山脉，从南部Cajamarca省向南几乎延伸至智利边境；在秘鲁北部跨越R Marañón河东侧，以及中部秘鲁的Huánuco、Pasco、Junín等地的山谷。","other":"在人类活动压力较大的海拔3250至3800米区域，其栖息地遭受严重破坏，但在Huascarán国家公园和Calipuy国家保护区仍保持常见。"},{"name":"棕顶尖嘴蜂鸟","english_name":"Rufous-capped Thornbill","scientific_name":"Chalcostigma ruficeps","overview":"棕顶尖嘴蜂鸟（英文名：Rufous-capped Thornbill，学名：Chalcostigma ruficeps），是雨燕目蜂鸟科尖嘴蜂鸟属的鸟类。巢呈小杯形，由植物纤维、蛛网、地衣和苔藓构成，常附着于树枝、大叶片或岩石突出部。分布于南美安第斯山脉东坡，从厄瓜多尔东南部至玻利维亚中西部，海拔1,400至3,500米，常见于2,500米左右。","appearance":"体长约10.5厘米，重量3.3至3.9克。雄鸟拥有短而直的黑色喙，上体瓶绿色，下体锈色杂绿，尤其是侧翼；冠部红赭色；喉部狭窄，翡翠绿色，边缘黄绿色渐变为金黄色。雌鸟喉部和胸部橙赭色，点缀橄榄绿色，腹部略淡；尾羽端部较浅。幼鸟类似雌鸟。","call":"叫声包括短暂的干燥双响‘trr-trr’，以及升降音调的啾啾声‘t-tr-tr-tsee-tseee-tititrrr’。","habits":"栖息于湿润次生林、河岸灌丛、湿润山地森林边缘及云雾林。海拔范围1,400至3,500米，常见于2,500米。可能进行季节性高程移动。以Melastomataceae家族的花蜜为食，偶尔刺穿花朵基部或利用花刺鸟留下的裂缝。","breeding":"繁殖季为12月至翌年3月在玻利维亚，可能7月至10月在秘鲁。雌鸟独力孵化两个白色卵。","identification":"相较于紫辉尾蜂鸟，棕顶尖嘴蜂鸟尾较长；相较于彩须尖嘴蜂鸟，体型较小，栖息于较低海拔。","protection":"IUCN：LC（无危）","distribution":"分布于厄瓜多尔东南部至玻利维亚中西部的安第斯山脉东坡，偶见于哥伦比亚中部安第斯山脉。","other":"曾在哥伦比亚中部安第斯山脉的Pan de Azúcar有单次记录，其状态尚不确定。"},{"name":"绿尖嘴蜂鸟","english_name":"Olivaceous Thornbill","scientific_name":"Chalcostigma olivaceum","overview":"绿尖嘴蜂鸟（英文名：Olivaceous Thornbill，学名：Chalcostigma olivaceum），是雨燕目蜂鸟科尖嘴蜂鸟属的鸟类。主要分布在南美洲，从秘鲁中西部至玻利维亚中西部。其独特之处在于常在地面寻找食物，主要栖息于湿润的高海拔草甸。","appearance":"绿尖嘴蜂鸟全身呈灰褐色或青铜绿色，雄鸟拥有独特的窄长喉部羽毛，颜色由喉咙处的闪烁绿色渐变为蓝紫色。雌鸟和幼鸟的这种特征则显著减小或缺失。尾羽较短，尾叉明显，喙短而黑。","call":"目前仅有一次记录描述了其叫声为‘tzit’的叫声，具体鸣唱特点尚待进一步研究。","habits":"绿尖嘴蜂鸟偏好生活在湿度较高的高海拔草原，如湿润的Puna草原，偶尔也会出现在山地灌木丛中。它们不仅以花蜜为食，还会捕捉小型昆虫，甚至在草地上行走以寻找食物。雄鸟会保卫自己的觅食领地。","breeding":"繁殖季节可能包含一月份，但具体时间跨度未知。雌鸟单独孵化两枚卵，筑巢地点可能位于Polylepis或Gynoxys树林中。关于其繁殖行为的详细信息尚不明确。","identification":"与蓝背尖嘴蜂鸟相比，绿尖嘴蜂鸟体型更大，尾羽呈钢蓝色，雄鸟背部为蓝紫色。亚种C. o. pallens相较于指名亚种体型更小，整体颜色更淡。","protection":"IUCN：LC（无危）","distribution":"绿尖嘴蜂鸟的分布范围从秘鲁中部向东南延伸至玻利维亚西部。在秘鲁，它出现在安卡什和胡宁省之间安第斯山脉的西侧；而在玻利维亚，则可见于拉帕兹省。海拔高度在秘鲁为3500至4700米，在玻利维亚为3100至4500米。","other":"绿尖嘴蜂鸟的生物学特性研究较少，其生态习性和繁殖行为仍需进一步探索。"},{"name":"蓝背尖嘴蜂鸟","english_name":"Blue-mantled Thornbill","scientific_name":"Chalcostigma stanleyi","overview":"蓝背尖嘴蜂鸟（英文名：Blue-mantled Thornbill，学名：Chalcostigma stanleyi），是雨燕目蜂鸟科尖嘴蜂鸟属的鸟类。珍稀的蜂鸟科鸟类，分布于南美洲的厄瓜多尔至玻利维亚中西部。这种蜂鸟体型小巧，长约12至13厘米，雄鸟体重约6.2克，雌鸟约4.5克，其显著特征为深色的外表，背部带有金属蓝光泽，是安第斯山脉高海拔地区的特有种。","appearance":"蓝背尖嘴蜂鸟拥有短而直的黑色喙，全身呈深灰褐色，上尾覆羽呈现蓝绿色调，头部和颈背有青铜绿光泽，背部反射出紫蓝色。雄鸟的喉部有一条狭窄的绿宝石色斑块，向下渐变为粉红至紫罗兰色，有时尖端为紫蓝色；尾巴叉状，钢蓝色。雌鸟相似，但喉部斑块不具“胡须”状延伸，外侧尾羽有较淡的尖端。幼鸟类似雌鸟。","call":"其主要叫声为下降的吱吱声，随后是一个更柔和的上升音符，接着是一串下滑的“tseetsitsitsitsitr-whee-tsew”音调，伴有各种变体。","habits":"生活在较为湿润的高山草甸和jalca植被覆盖的陡峭岩石斜坡上，尤其偏好Polylepis林地和灌木丛。通常在海拔3000米至4200米之间，偶尔低至2200米。以小花如Berberis、Gauteria、Ribes和红色小Gentiana的花蜜为食，同时也会捕食小型昆虫。在恶劣天气期间会暂时迁移到较低海拔。","breeding":"繁殖期一般在雨季，雌鸟单独孵化两个白色卵。关于其繁殖生态学的其他信息尚待研究。","identification":"在高海拔地区，蓝背尖嘴蜂鸟与同属的其他物种区别明显，其独特的背部金属光泽和喉部颜色变化是辨识的关键。","protection":"IUCN：LC（无危）","distribution":"分布于南美安第斯山脉，从厄瓜多尔至玻利维亚中部西部，包括秘鲁的部分地区。"},{"name":"铜尾尖嘴蜂鸟","english_name":"Bronze-tailed Thornbill","scientific_name":"Chalcostigma heteropogon","overview":"铜尾尖嘴蜂鸟（英文名：Bronze-tailed Thornbill，学名：Chalcostigma heteropogon），是雨燕目蜂鸟科尖嘴蜂鸟属的鸟类。色彩鲜明的小型蜂鸟。其分布局限于南美洲西半球，常见于委内瑞拉西部和哥伦比亚东部的安第斯山脉。该鸟体型中等，尾羽较长，雄雌皆呈橄榄绿色，尾部和臀部闪烁着铜红色光泽。","appearance":"成年铜尾尖嘴蜂鸟体长约13至14厘米，体重介于5.9至6.3克。雄鸟具有一条长而闪耀的绿松石色喉咙斑，末端延伸为粉色，形似胡须；雌鸟的喉咙颜色较淡，带暗色标记，且无粉色延长部分。幼鸟外观类似雌鸟，但拥有赤褐色的冠羽。","call":"该鸟的叫声特征尚不明确，已知的叫声包括重复的低沉短促‘tzk’声。","habits":"栖息于陡峭岩石斜坡上的半干旱至湿润的帕拉莫草原和矮林边缘地带，以花蜜为食，偏好Bartisia santolinaefolia、Rubus gachetensis等植物的花朵。同时，它也会在Espeletia花丛中捕食小型昆虫，或者在离地面1至3米处捕食飞虫。","breeding":"繁殖季节大致从9月持续到次年1月，但可能更长。雌鸟独自孵化两枚白色蛋，关于繁殖生态的其他细节尚未被充分研究。","identification":"与其他蜂鸟相比，铜尾尖嘴蜂鸟的铜色尾羽和独特的粉色‘胡须’是其显著的辨识特征。","protection":"IUCN：LC（无危）。尽管其分布范围有限，且种群数量不明并被认为正在减少，但该物种在一些保护区得到保护。","distribution":"分布于南美洲，具体包括委内瑞拉西部的塔马山地和哥伦比亚东部安第斯山脉，南至库印纳马卡省。在海拔3,000至3,900米的高度范围内活动。","other":"关于其分类学，目前存在将其所属的Chalcostigma属合并入Oxypogon属的提议。"},{"name":"彩须尖嘴蜂鸟","english_name":"Rainbow-bearded Thornbill","scientific_name":"Chalcostigma herrani","overview":"彩须尖嘴蜂鸟（英文名：Rainbow-bearded Thornbill，学名：Chalcostigma herrani），是雨燕目蜂鸟科尖嘴蜂鸟属的鸟类。这一特征在光线适宜时呈现出耀眼的金属光泽。分布于南美洲的安第斯山脉高海拔地区，自哥伦比亚中部至秘鲁北部，偏好生长在亚高山森林边缘、灌木丛和岩石斜坡下的矮树丛中。","appearance":"彩须尖嘴蜂鸟体型介于10至12厘米之间，雄鸟体重约为6.2克，雌鸟稍轻，约5.6克。它们拥有短而尖锐的喙，全身主要呈深青铜色，雄鸟的头部顶部为红褐色或橙红色，尾羽呈蓝黑色，叉状尾端有明显的白色斑点。最显著的特征是雄鸟个体下巴至喉咙部位有一条长而窄的彩虹色羽毛，颜色由绿松石色过渡至黄色，末端为鲜红色。雌鸟个体的这一特征较为淡化或缺失，腹部至尾下覆羽呈淡黄赭色。","call":"彩须尖嘴蜂鸟的鸣叫声记录较少，可能的歌声被描述为一系列低沉的‘cheet-dee-dee-cheet’声。","habits":"彩须尖嘴蜂鸟栖息于高海拔的亚高山环境，包括灌木丛和矮树丛。它们通常单独觅食，偏好在花朵上停留吸取花蜜，同时也会捕捉昆虫。飞行时，它们会追逐竞争对手，即使是体型较大的鸟类，如花刺鸟，也不放过。","breeding":"彩须尖嘴蜂鸟的繁殖季节至少包括7月至9月，但具体繁殖行为描述有限。已知的一次观察中，巢穴内有三个卵，这与大多数蜂鸟通常产两枚卵的情况不同。","identification":"与同属的棕顶尖嘴蜂鸟相比，彩须尖嘴蜂鸟体型较大，尾部有白色斑点，且雄鸟具有独特的彩虹色喉咙羽毛。雌鸟个体的这一特征则较为简化或不存在。","protection":"IUCN：LC（无危）","distribution":"彩须尖嘴蜂鸟的分布范围覆盖了哥伦比亚的卡乌卡省至秘鲁北部的皮乌拉和卡哈马卡省，以及厄瓜多尔的安第斯山脉两侧。"},{"name":"反嘴蜂鸟","english_name":"Mountain Avocetbill","scientific_name":"Opisthoprora euryptera","overview":"反嘴蜂鸟（英文名：Mountain Avocetbill，学名：Opisthoprora euryptera），是雨燕目蜂鸟科反嘴蜂鸟属的鸟类。稀有的安第斯山脉森林中的蜂鸟，主要分布在哥伦比亚、厄瓜多尔和秘鲁北部的高海拔森林和茂密的路边植被中。其最显著的特征是拥有一个短小、上翘的黑色喙，铜色的冠羽，绿色的上体，以及灰暗带条纹的下体，飞羽呈黑色。反嘴蜂鸟通常单独在低矮密集的植被中觅食，以小型管状花朵为食。","appearance":"反嘴蜂鸟体型小而健壮，全身以绿色为主，上体为青铜绿色，下体为白色并带有深绿色条纹，腹部略带淡黄色，尾部呈叉状，外侧尾羽末端有窄的白色。喙短而黑，尖端明显上翘，类似反嘴鹬的喙型。两性相似，无明显的性别差异。","call":"鸣叫声为一系列下降的细薄哨音，类似于啄木鸟的声音，具体表现为'wsee wsee wsee wsee'。","habits":"栖息于高海拔的云雾林中，偏好森林边缘和空地，常见于路边灌丛。以花蜜为食，通过悬停或攀附花朵的方式摄取，偶尔会刺穿花底以吸取花蜜。也会捕食小型昆虫。活动范围在地面以上3米以内。","breeding":"繁殖生态学尚未详细描述，但相信其繁殖行为与其他蜂鸟类似，可能是多配偶制。具体繁殖周期、筑巢、交配、产卵等信息有待进一步研究。","identification":"与其他安第斯山脉的蜂鸟相比，如紫背刺嘴蜂鸟(Metallura)等，反嘴蜂鸟可通过其独特的上翘喙型和条纹而非斑点的下体特征加以区分。","protection":"IUCN：LC（无危）","distribution":"南美洲，分布于哥伦比亚中央安第斯山脉、厄瓜多尔东坡以及秘鲁北部的东部山坡。","other":"该物种为独有属Opisthoprora下的唯一成员，与hillstars(Oreotrochilus)和trainbearers(Lesbia)关系密切。"},{"name":"灰嘴彗星蜂鸟","english_name":"Grey-bellied Comet","scientific_name":"Taphrolesbia griseiventris","appearance":"灰嘴彗星蜂鸟体型较大，尾部长而深叉。成年鸟的上体呈现金属绿至铜橙色，下体统一灰色，雄鸟具有明显的蓝色喉斑。雌鸟的尾部较短，叉度较小，缺乏蓝色喉斑，下体颜色略浅。幼鸟的喉部和胸部为棕褐色，带有淡绿色斑点。","habits":"栖息于干燥的高山灌木丛，尤其是陡峭峡谷附近的环境。以多种花朵为食，有时会直接刺穿大花朵基部以吸取花蜜。极度领土性，支配着所在区域的其他蜂鸟。","identification":"与铜尾彗星蜂鸟相比，灰嘴彗星蜂鸟体型更大，尾部更深叉，雄鸟喉斑蓝色，雌鸟尾部无白色边缘。","protection":"IUCN：EN（濒危）","distribution":"南美：秘鲁西北部，分布于Marañon河谷和秘鲁高安第斯山脉的特有种鸟区域，海拔2,750至3,170米。"},{"name":"长尾蜂鸟","english_name":"Long-tailed Sylph","scientific_name":"Aglaiocercus kingii","overview":"长尾蜂鸟（英文名：Long-tailed Sylph，学名：Aglaiocercus kingii），是雨燕目蜂鸟科长尾蜂鸟属的鸟类。拥有极长尾巴的引人注目的蜂鸟。主要分布在南美洲，从委内瑞拉到玻利维亚中西部的安第斯山脉东坡，海拔高度介于1200米至2500米之间。","appearance":"雄鸟长16至19厘米（含12厘米的尾羽），重5至6克；雌鸟较短小，长9.7至11.7厘米，重约4.5至4.7克。雄鸟上体闪烁着青铜金属绿色，头部呈现亮丽的翡翠绿，喉部蓝色或紫色斑点，尾羽上方蓝绿紫交织，下方蓝黑色。雌鸟上体金属绿色，下体带有肉桂色，喉部白色或淡黄色，散落着绿色斑点，尾部短窄，外侧尾羽深蓝，末端白色。幼鸟类似雌鸟，但腹部稍带淡黄色，绿色斑点较为模糊，背部有隐蔽的白色斑块。","call":"其假定的歌声为一连串的嗡嗡音节“bzzt...bzzt...bzzt...”，每秒约一音节。叫声包括重复的短促、沙哑的‘dzzrt’和更拉长、音调较高的‘bzzeeew’，以及细长高音的上升颤音。","habits":"栖息于多种生境，包括山前地带、灌木丛、开阔地、花园，偶尔出现在湿润森林边缘和次生林地，但很少深入森林内部。在安第斯山脉，季节性地迁移到海拔2500至2700米的高度，甚至可达3000米。以花蜜和昆虫为食，通过巡游觅食、领地防御和刺穿花朵基部等方式获取花蜜，同时在高处猎捕昆虫。","breeding":"繁殖期从2月持续到10月，但可能全年繁殖。雄鸟建造带有侧面入口的圆顶巢，由苔藓和植物纤维构成，巢置于树枝上，隐藏于叶下。雌鸟孵化两个白色蛋，孵化期15至17天，小鸟离巢时间为21至24天。","identification":"雄鸟与列车鸟相似，但注意其不同的栖息环境。雌鸟与雄鸟差异显著，尤其是下体的肉桂色调和白色的喉部条纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的委内瑞拉至玻利维亚中西部，包括哥伦比亚、厄瓜多尔、秘鲁等地。在安第斯山脉东西两侧均有记录。","other":"长尾蜂鸟在多个国家的国家公园中常见，例如委内瑞拉的Sierra Nevada国家公园和哥伦比亚的Chingaza国家公园。"},{"name":"南美长尾蜂鸟","english_name":"Venezuelan Sylph","scientific_name":"Aglaiocercus berlepschi","overview":"南美长尾蜂鸟（英文名：Venezuelan Sylph，学名：Aglaiocercus berlepschi），是雨燕目蜂鸟科长尾蜂鸟属的珍稀鸟类。这种蜂鸟仅见于委内瑞拉东北部的两个小山系中，以其极长的蓝色尾羽和独特的外形著称，是当地特有种。","appearance":"雄性南美长尾蜂鸟总长可达22厘米（8.7英寸），包括14至15厘米（5.5至5.9英寸）的外侧尾羽，体重约5.5克（0.19盎司）。其头部覆盖着深绿色的光泽羽毛，背部呈闪亮绿色，喉咙部分有着闪耀的蓝色羽毛，下体呈青铜绿色，带有白色大腿。尾巴内部的羽毛较短，呈蓝绿色，而外部的羽毛非常长，基部为深紫色，末端转为蓝色。雌鸟体型较小，长9.5至11厘米（3.7至4.3英寸），体重约为4.5克（0.16盎司）。雌鸟的头顶有蓝色光泽，上体类似雄鸟，但下体为白色，带有绿色斑点，尾巴较短，略呈叉状，蓝绿色，外侧羽毛尖端为白色。幼鸟外观类似于成年雌鸟，但头部羽毛边缘呈淡褐色。","call":"南美长尾蜂鸟的叫声包括一系列连续的嗡嗡声'bzzt...bzzt...bzzt...'，以及高音上升的啾啾声'tititi-teetsee..see..seee'，可能是在追逐时发出的叫声。","habits":"南美长尾蜂鸟栖息于海拔1,450至1,800米（4,800至5,900英尺）的沿海山脉斜坡上的亚热带森林和灌木丛中。它是一种留鸟，以花蜜为食，尤其偏好Inga属的开花植物。它采用陷阱线觅食策略，围绕一圈开花植物巡逻，也会保卫特定的觅食领地。它还会从栖息处捕捉昆虫。通常单独或成对觅食，偶尔会与其他同类一同在开花树上进食。","breeding":"繁殖季节从8月持续到次年1月。雌鸟会在附生植物中建造穹顶状的巢穴，并孵化蛋，关于繁殖生态学的其他信息未知。","identification":"雄性南美长尾蜂鸟与更广泛分布的长尾蜂鸟非常相似，但其分布范围极为有限，通过地理位置和尾羽颜色可区分。","protection":"IUCN：VU（易危）","distribution":"南美长尾蜂鸟的分布局限于委内瑞拉东北部的Turimiquire地区，具体在苏克雷州、莫纳加斯州和安索阿特吉州交汇的山区。","other":"南美长尾蜂鸟面临的主要威胁是其栖息地内的快速和广泛森林砍伐。尽管其部分栖息地位于El Guácharo国家公园和Macizo Montañoso del Turimiquire保护区，但森林破坏仍然严重，需要采取紧急措施保护剩余的森林和调查其基本生态需求。"},{"name":"紫长尾蜂鸟","english_name":"Violet-tailed Sylph","scientific_name":"Aglaiocercus coelestis","overview":"紫长尾蜂鸟（英文名：Violet-tailed Sylph，学名：Aglaiocercus coelestis），是雨燕目蜂鸟科长尾蜂鸟属的鸟类。该物种拥有极为醒目的长尾。雄鸟主要呈翡翠绿色，喉部蓝绿，尾羽呈现紫色与蓝色的金属光泽。雌鸟外观差异较大，橙腹白胸。分布于南美安第斯山脉的丘陵与亚热带地带，约在海拔900至2000米之间，主要在厄瓜多尔西部和哥伦比亚境内。","appearance":"雄鸟体长18至21厘米（含10至15厘米的尾羽），雌鸟9.5至9.7厘米；体重4.6至5.2克。雄鸟具有黑色短直喙，头部和背部绿光闪耀，臀部变为蓝紫色，下体绿色，尾羽深叉状，大部分呈金属紫，末端蓝。雌鸟头部蓝光闪烁，眼后有白色斑点，喉部白色带绿斑，胸部白色带，其余下体肉桂色，尾短不叉，蓝绿色，外侧尾羽尖端白色。幼鸟上体暗绿，下体淡黄绿，头部羽毛边缘黄色。","call":"其假定的歌声为一系列连续的短音，'psit..psit..psit..'，每秒约2个音节。叫声包括重复的短促嗡嗡声'bzzt'或'bz-zzrt'，高音拉长的'bzeee'，以及高音起伏的鸣叫'seee..seee..seee..seee..tr-tr-tititi-teetsee..see..see'，可能为追逐叫声。","habits":"栖息于云雾林、森林边缘、半开放地形带灌木和树丛的区域，海拔1000至2000米，偶尔低至300米。觅食范围从近地面到树冠，沿森林边缘、小径和内部。雄雌鸟沿分散花朵群落觅食，雄鸟偶尔捍卫食物领域。","breeding":"繁殖期从10月至次年2月。巢为侧面入口的穹顶型，由苔藓和蜘蛛网构成，建在苔藓或寄生植物丛中。一窝产两枚白色蛋，孵化期15至17天，仅由雌鸟承担；雏鸟淡色，背部长有稀疏灰色绒毛；离巢时间为26至30天。雄雌鸟在非繁殖季节也会建造巢穴用于夜间栖息。","identification":"雄鸟的长叉尾和金属紫蓝色光泽，雌鸟的橙腹白胸，是其显著的识别特征。与同属其他种类如长尾蜂鸟和南美长尾蜂鸟在体型、色彩和尾羽形状上有明显区别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲哥伦比亚和厄瓜多尔的云雾林及周边地区，主要在安第斯山脉的丘陵与亚热带地带。","other":"在某些国家公园内，如哥伦比亚的Los Farallones国家公园附近，紫长尾蜂鸟是常见的云雾林边缘居民，局部密度至少为3至4对/平方公里；在La Planada保护区，密度随季节变化，干季至少为5至7对/平方公里，湿季至少为2对/平方公里。"},{"name":"紫蓝妆脸蜂鸟","english_name":"Hyacinth Visorbearer","scientific_name":"Augastes scutatus","overview":"紫蓝妆脸蜂鸟（英文名：Hyacinth Visorbearer，学名：Augastes scutatus），是雨燕目蜂鸟科妆脸蜂鸟属的鸟类。为巴西特有种。其别名为紫蓝妆脸蜂鸟，分布于巴西东南部的山地地区。雄鸟拥有绿色上部和蓝色下部，胸部带有醒目的白色带纹；雌鸟腹部呈现蓝灰相间的斑驳状，面部略显灰白。分布于巴西的Serra do Espinhaço山脉的岩石地带。","appearance":"雄性紫蓝妆脸蜂鸟体长8.1至9.9厘米，体重3至4克；雌鸟稍小，体长8至9.7厘米，体重2.7至3.8克。雄鸟拥有比雌鸟更长的翅膀、跗跖、尾巴和喙。雄鸟喙短而直，呈黑色，头顶及上部青铜绿色，前额和喉部金绿光泽，边缘黑色，颈部两侧蓝紫色，胸部有白色至淡粉色的宽带，腹部深蓝色；尾羽虹彩青铜绿色。雌鸟喉部绿色无黑边，腹部蓝灰色相间，尾羽外侧灰尖。幼鸟似雌鸟，缺乏闪烁的喉部羽毛，可能在喙基有红色，腹部灰色。雄鸟幼鸟下部有少许蓝色羽毛。","call":"雄鸟会发出一系列高音的‘tjic’、‘whi’、‘zuzu’等音符，通常在领地内的两到三个选定位置鸣唱；雌鸟不唱歌，但会发出‘tilp-tilp’声离开或返回巢穴，以及‘ti-ti-chip-chip’或‘chip-chip-chip’声，面对威胁时会发出刺耳的‘trrrzz-trrrzz-trrrzz-trrrzz...’声。","habits":"紫蓝妆脸蜂鸟栖息于巴西东南部的山地地区，偏好岩石地带和灌木植被环境，海拔高度介于900至2000米之间。以多种开花植物的花蜜为食，包括陆生凤梨科、仙人掌、菊科等，同时也会捕捉空中的昆虫。雄鸟保卫领地，尤其是花朵密集的区域；雌鸟则倾向于在花朵稀疏的区域活动。","breeding":"繁殖季节可能全年皆有。筑巢材料包括菊科种子、仙人掌纤维和其他纤维，外壁粘贴干叶或苔藓碎片，内部铺软质材料。巢建于离地面0.6至2.05米高的垂直枝叉处。产卵数为2枚，白色，由雌鸟单独孵化15至16天，雏鸟离巢时间为19至25天。","identification":"与同属的妆脸蜂鸟相比，紫蓝妆脸蜂鸟具有不同的色彩模式和地理分布。两个亚种A. s. ilseae和A. s. soaresi分别在颜色和体型上有所差异。","protection":"IUCN：LC（无危）；CITES: II级；该物种虽有局部常见，但其栖息地受到采矿威胁。","distribution":"分布局限于巴西的Minas Gerais州，包括中央巴西高地和高原地区，以及Serra do Espinhaço山脉的campos rupestres。出现在Serra do Cipó国家公园、Rio Preto州立公园、Pico do Itambé州立公园等地。","other":"该物种在当地被视为相对安全，因为其栖息地不适合农业开发，但部分已知栖息地因露天采矿而退化。"},{"name":"妆脸蜂鸟","english_name":"Hooded Visorbearer","scientific_name":"Augastes lumachella","overview":"妆脸蜂鸟（英文名：Hooded Visorbearer，学名：Augastes lumachella），是雨燕目蜂鸟科妆脸蜂鸟属的鸟类。小型、色彩绚丽的蜂鸟，分布于巴西东北部的Chapada Diamantina区域高海拔地带，主要栖息于岩石、灌木和仙人掌生长的高原上。其最显著的特征是雄鸟的黑色额部和脸颊环绕着绿色的喙周，以及喉部的小金色斑点。","appearance":"体型小巧，长度约8.3至10厘米，体重4至4.8克。雄鸟头部特征明显，黑色额头和脸颊包围着金色绿色的喙周，喉咙基部有金色至火红色光泽，胸部有白色带纹，尾羽铜红。雌鸟头部灰色，侧面棕色，绿色较暗淡，缺乏雄鸟额头的金色光泽。幼鸟与成年雌鸟相似，头部侧面灰褐色。","call":"鸣唱声音鼻音浓重且干燥，连续重复短语，起始于滑音似的鼻音，随后是1至2个模糊音节，间歇性地穿插快速序列。","habits":"栖息于高海拔岩石区，以花蜜为主食，常访问仙人掌、陆生凤梨、Stachytarpheta crassifolia等植物的花蜜，也会在空中捕食昆虫。活动范围低至地面1米以下，全年留居于特定区域，但在特定月份有小规模局部移动。","breeding":"繁殖期为1月至5月，巢由软质菊科种子和仙人掌绒毛构成，装饰有苔藓，用蛛网粘合，建于离地0.6至0.8米高的干燥垂直枝叉上。每窝产卵两枚，孵化期15至16天，由雌鸟单独孵化，雏鸟离巢期20至24天。","identification":"雄鸟的头部图案和尾羽颜色使它在其自然范围内具有独特的辨识度。与雌鸟相比，雄鸟的金色喉部和黑色边框非常显眼。","protection":"IUCN：NT（近危）。受到栖息地丧失的威胁，尤其是无序采矿和自然区域转变为牧场及人类居住地。气候变化预计会导致其栖息范围大幅缩减。","distribution":"分布于巴西东北部的Chapada Diamantina区域，位于Bahia州，海拔900至2000米之间，主要栖息在岩石、仙人掌和低矮灌木覆盖的高原上。","other":"尽管其数量尚未量化，但据信正在减少。对于观鸟爱好者而言，妆脸蜂鸟是Chapada Diamantina地区极具吸引力的鸟类之一。"},{"name":"楔嘴蜂鸟","english_name":"Geoffroy's Daggerbill","scientific_name":"Schistes geoffroyi","overview":"楔嘴蜂鸟（英文名：Geoffroy's Daggerbill，学名：Schistes geoffroyi），是雨燕目蜂鸟科楔嘴蜂鸟属的中等体型蜂鸟，分布于南美洲安第斯山脉东坡，从委内瑞拉至秘鲁。其显著特征包括独特的楔状喙尖和大部分绿色的羽毛。","appearance":"成年雄性楔嘴蜂鸟长8.6至9.3厘米，体重3.5至4.1克。头部上方为铜绿色，臀部呈铜色，喉部为闪光的金绿色，两侧有蓝紫色斑块，胸前有一段断续的白色带，下体绿色，尾下覆羽白色。尾部圆形，中央尾羽绿色，其余为青铜绿，末端有深蓝色亚端带，尾尖白色。雌鸟相似，但喉部颜色较暗淡。幼鸟可能与成年雌鸟类似。chapmani亚种冠部颜色均匀，喉侧斑块无白色，腹部白色较少。","call":"鸣唱为一系列类似昆虫的、间隔规律的简单“tsit”或嘶嘶声“sink”音符，每秒1.5至2.8个音符，从低矮的开放栖木上发出。","habits":"楔嘴蜂鸟生活在密集的云雾森林内部和边缘，海拔通常在900至2300米之间，偶尔可达2500米。它们在密集植被中觅食，从地面到中层高度，吸食多种灌木、藤蔓和小树的管状花蜜，也会在空中捕捉小型昆虫或从植被上觅食。","breeding":"繁殖季节在委内瑞拉为8月至11月，其他地区尚未确定。它们会用柔软的种子纤维和蜘蛛丝建造杯状巢，巢外壁装饰着苔藓。一窝产两枚蛋，仅由雌鸟孵化，孵化期为15至16天，雏鸟在孵化后20至22天离巢。","identification":"雄性楔嘴蜂鸟的喉部金绿色，两侧有蓝紫色斑块，雌鸟喉部颜色较为暗淡。与白喉楔嘴蜂鸟相比，本物种的喉部特征更为显著。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲，包括哥伦比亚东部、委内瑞拉北部至秘鲁东部和玻利维亚中部，具体为安第斯山脉东坡，从委内瑞拉的Sierra de Perijá和沿海山脉，向南穿过哥伦比亚东部和厄瓜多尔东部进入秘鲁，直至库斯科；chapmani亚种则从秘鲁库斯科延伸至玻利维亚中部。","other":"楔嘴蜂鸟在历史上曾被认为与白喉楔嘴蜂鸟为同一物种，统称为楔嘴蜂鸟。"},{"name":"白喉楔嘴蜂鸟","english_name":"White-throated Daggerbill","scientific_name":"Schistes albogularis","overview":"白喉楔嘴蜂鸟（英文名：White-throated Daggerbill，学名：Schistes albogularis），是雨燕目蜂鸟科楔嘴蜂鸟属的鸟类。主要分布在南美洲，自哥伦比亚西部至厄瓜多尔西部的安第斯山脉西坡。以绿色为主调，拥有独特的白喉特征和楔状喙尖。","appearance":"体长8.6至9.3厘米，体重3.5至4.1克。雄鸟具有闪亮的绿额，两侧喉部有紫蓝色斑块，上胸有一条明显的白色宽带，眼后有小白斑。雌鸟的额头不发光，喉侧斑块较小且主要为蓝色，喉部全白。喙尖窄而锐利。","call":"鸣声为一系列交替的高音节，'tsit...seet...tsit...seet...'，节奏不规则。","habits":"栖息于密集的云雾森林内部及边缘，常靠近溪流，活动高度从地面到中层。海拔范围在800至2000米之间。以吸食多种灌木、藤蔓和小树的管状花蜜为生，同时捕食空中或植被上的小型昆虫。","breeding":"关于繁殖季节的信息尚不清楚。","identification":"与楔嘴蜂鸟相比，雄鸟喉侧斑块更蓝紫色且更大，雌鸟的喉部全白。","protection":"IUCN：LC（无危）","distribution":"分布于哥伦比亚西部（西安第斯山和中央安第斯山西坡）至厄瓜多尔西部。在哥伦比亚卡利上方的云雾森林中特别常见，至少有3-4对/平方公里。","other":"在分类学上，曾被认为与楔嘴蜂鸟同种，现已明确分离。"},{"name":"紫冠仙蜂鸟","english_name":"Purple-crowned Fairy","scientific_name":"Heliothryx barroti","overview":"紫冠仙蜂鸟（英文名：Purple-crowned Fairy，学名：Heliothryx barroti），是雨燕目蜂鸟科仙蜂鸟属的鸟类。又称紫色王冠仙蜂鸟，体型较大的蜂鸟，以热带湿润低地森林为栖息地，偏好林缘、开阔地带散落树木和开花灌木，亦常见于花园中。其特征为闪亮的雪白下体、璀璨的翡翠绿色上体以及醒目的白色外侧尾羽。雄鸟与雌鸟整体相似，但雌鸟缺乏雄鸟的紫色冠羽，且尾羽较长。","appearance":"紫冠仙蜂鸟具有中等体型，长约9至13厘米，体重约5.5克。上体呈明亮的翡翠绿色，下体纯白，尾羽中间部分蓝黑色，外侧白色。头部两侧有一黑色面罩，通过眼睛下方终止于金属紫色斑点；脸部下方黑色面罩两侧为鲜艳的翡翠绿。喙中等长度，黑色且尖锐，能刺穿花朵基部获取花蜜。雄鸟拥有金属光泽的紫色前额冠羽，而雌鸟冠羽为绿色，尾羽比雄鸟更长。","call":"紫冠仙蜂鸟不甚鸣叫，偶尔发出高音、略带金属质感的\"sssit\"声，有时会连续快速发出一系列叫声。","habits":"紫冠仙蜂鸟栖息于热带湿润森林、阴凉种植园和成熟的次生林中，活动范围从海平面到海拔1675米。它们在树冠层活动，偶尔在林缘较低处觅食。以多种开花植物的花蜜为食，通过直接插入花冠或刺穿花基部盗取花蜜，同时也以小节肢动物，尤其是蜘蛛，为食，通过悬停和从叶面采集的方式捕食。","breeding":"繁殖期通常在10月至3月间，雌鸟独自筑巢、孵卵并照料幼鸟。巢为小型圆锥形杯状，由植物绒毛构成，位于细枝梢端，高度介于6至20米之间，常在水面上方。每次产卵两枚，孵化期16至17天，幼鸟在孵化后20至24天离巢。","identification":"紫冠仙蜂鸟与黑耳仙蜂鸟极为相似，但两者分布范围分离。雄性黑耳仙蜂鸟前额冠羽为绿色而非紫色，面部黑色面罩后部为紫色。雌性黑耳仙蜂鸟喉部和胸部有暗色斑点，而紫冠仙蜂鸟雌鸟下体为纯净白色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，从墨西哥东南部至厄瓜多尔西南部，包括中美洲的加勒比海沿岸，哥伦比亚、厄瓜多尔和秘鲁北部的太平洋沿岸，以及哥伦比亚的马格达莱纳河下游谷地。"},{"name":"黑耳仙蜂鸟","english_name":"Black-eared Fairy","scientific_name":"Heliothryx auritus","overview":"黑耳仙蜂鸟（英文名：Black-eared Fairy，学名：Heliothryx auritus），是雨燕目蜂鸟科仙蜂鸟属的鸟类。是蜂鸟科仙蜂鸟属的大型优雅蜂鸟。拥有短直喙，眼下方具黑色条纹，上体闪耀绿光，腹部洁白，尾部长而白，中央带黑。雄鸟耳羽覆盖处有紫色闪光斑块，雌鸟缺乏此特征，喉部和胸部具灰色斑点。广泛分布于除阿根廷、智利、巴拉圭和乌拉圭之外的南美洲大陆国家。","appearance":"体型：10.1–13.7厘米长，体重4–6.3克。雄鸟特征：头部光泽绿，眼周有黑色条纹，耳羽处紫色闪光，上体绿色闪烁，下体白色，尾长，外侧三根尾羽白色，内侧两根暗蓝色。雌鸟类似，但无紫色耳羽，喉胸具灰斑点，尾稍长，外侧三根尾羽白色基部有黑带。幼鸟似雌鸟，头颈羽毛边缘呈肉桂色。","call":"叫声包括短促高音的“tsit”和更丰富的“tchip”，间隔重复。","habits":"栖息于湿润森林及边缘地带，活动范围从中层林冠至树冠，偏好低海拔，常见于400米以下，可达800米。以多种开花植物的花蜜为食，包括灌木、藤蔓、仙人掌、附生植物和树木的花蜜，也通过刺穿花朵底部盗取花蜜。空中捕食昆虫。在巴西北部，全年留居，但在南部巴西有报道不规则迁徙。","breeding":"繁殖期全年，主要集中在7月至3月。雌鸟独建杯状巢于垂直枝上，离地面3至30米。巢尺寸：高40毫米，外径55毫米，内径35毫米。产卵2枚，尺寸16毫米×10毫米，重0.7克。孵化期15至16天，仅由雌鸟承担。雏鸟黑色，背覆稀疏灰背绒毛。离巢期23至26天。雌鸟离开巢穴时模仿落叶滑翔，可能是防掠食策略。","identification":"与紫冠仙蜂鸟区别在于，紫冠仙蜂鸟具紫色顶冠，黑耳仙蜂鸟无此特征。亚种间差异主要体现在喉部颜色。","protection":"IUCN：LC（无危）。CITES II级。在森林黑水区域相对常见，出现在多个保护区，如委内瑞拉的伊马塔卡森林保护区和巴西的Pedra Talhada州立公园。","distribution":"分布于亚马逊雨林区，从哥伦比亚东南部、厄瓜多尔东部，贯穿巴西北部亚马逊河北岸至委内瑞拉东北部和圭亚那地区。H. a. phainolaemus亚种见于巴西北部和马托格罗索州南部。H. a. auriculatus亚种分布于秘鲁东部、玻利维亚中部和巴西南部，东至塔帕若斯河，另在巴西东南部，从巴伊亚南至圣保罗州，偶向南延伸。","other":"黑耳仙蜂鸟与紫冠仙蜂鸟曾被视为同种，现被归为超种，是仙蜂鸟属的唯二成员。"},{"name":"角蜂鸟","english_name":"Horned Sungem","scientific_name":"Heliactin bilophus","overview":"角蜂鸟（英文名：Horned Sungem，学名：Heliactin bilophus），是雨燕目蜂鸟科角蜂鸟属的鸟类。以其短直的喙和雄鸟头部两侧闪耀的红、蓝、金色‘角’状羽饰而闻名。分布于南美洲的中央巴西、玻利维亚部分地区和苏里南南部。角蜂鸟适应性强，不仅栖息于河岸带和开阔的草原，还常出现在人类活动改造的生境中。","appearance":"角蜂鸟体长约9.5-11厘米，体重1.8-2.8克。雄鸟具独特的‘角’状羽饰，冠部深蓝色，上体金属绿色，下体白色，喉部黑色，形成鲜明对比。尾羽窄而尖，中央四根最长，颜色各异。雌鸟缺乏‘角’和金属光泽的头羽，顶冠绿色，喉部黄褐色或棕黄色。幼鸟似雌鸟。","call":"发出一系列复杂的啾啾声，包含吱吱、沙哑和嗡嗡音，追逐时尤为明显。叫声包括重复的‘tsit’或‘tseet’。","habits":"角蜂鸟偏好半开放到开放的生境，如干湿森林、草原和人类创造的环境，如花园。它们主要以开花灌木和树木的花蜜为食，如马鞭草科和唇形科植物，也会捕捉空中飞行的小昆虫。部分种群季节性迁徙，与植物花期相呼应。","breeding":"繁殖期主要在6月至10月，但也有4月开始的记录。雌鸟单独筑巢，使用柔软材料和蜘蛛网，装饰以苔藓，建于小灌木分叉枝上，离地面约1米高。每次产两枚椭圆形白蛋，孵化期约13天，由雌鸟独自承担。雏鸟孵化后裸露且呈黑色，20-22天后可离巢。","identification":"雄鸟的‘角’状羽饰和蓝黑相间的头部特征明显，雌鸟则较为朴素，喉部颜色与雄鸟不同。在同类中，角蜂鸟可通过其特有的羽饰和体型辨认。","protection":"IUCN：LC（无危）。CITES II（华盛顿公约二级附录）。角蜂鸟在当地常见，能适应人类活动区域，如花园和耕作区。近年来在亚马逊南部和埃斯皮里托桑托州扩张分布，可能与森林砍伐有关。","distribution":"分布于苏里南南部、巴西东部和东南部至玻利维亚东部，包括亚马逊州南部、埃斯皮里托桑托州、圣保罗州北部等地。在巴西的阿马帕州和阿克雷州有零星报道。","other":"角蜂鸟是唯一一个在其属内的物种，曾是国际鸟类贸易中极受欢迎的种类之一，但自1970年代末以来，这种交易已被限制。"},{"name":"叉扇尾蜂鸟","english_name":"Marvelous Spatuletail","scientific_name":"Loddigesia mirabilis","overview":"叉扇尾蜂鸟（英文名：Marvelous Spatuletail，学名：Loddigesia mirabilis），是雨燕目蜂鸟科叉扇尾蜂鸟属的鸟类。又称叉拍尾蜂鸟，中等体型的蜂鸟，单型属蜂鸟。该物种以其独特的尾羽和蓝绿色的喉部光泽著称，主要分布在秘鲁北部的安第斯山脉云雾森林中，是世界濒危物种之一。","appearance":"雄性叉扇尾蜂鸟体长15至17厘米，包括长达11至13厘米的尾羽；雌鸟体长9至10厘米，尾羽长5至7厘米。雄鸟拥有略向下弯曲的黑色喙，蓝色的冠羽，棕色颈背，上体大部分为绿色；其喉部有蓝绿色光泽，下体白色，中央有一条黑色线纹，尾羽非常长且特化，外侧羽毛仅剩羽轴，末端形成两个紫色的球拍状结构。雌鸟缺乏雄鸟的冠羽和喉部光泽，下体白色，尾羽虽长但无球拍状结构。幼鸟似成年雌鸟，但部分发育了喉部光泽，腹部有黑色中线，尾羽末端呈黑色。","call":"雄鸟在空中展示时会发出重复的高音金属声“tzzz...tzzz...”。叫声包括上滑的高音甜美音调“tswee”，通常以每秒约6个音符的速度快速连续发出，以及更尖锐重复的“tsik”。","habits":"叉扇尾蜂鸟栖息于成熟森林边缘、次生林和山地灌木丛，偏好有Rubus荆棘和Alnus桤木的环境，海拔介于2100至2900米。该物种全年留居其分布范围内。主要以Rubus、Bomarea formosissima和Staureja sericea等植物的花蜜为食，通过定点觅食而非悬停喂食。在食物竞争中处于劣势，受其他共栖蜂鸟如绿带尾蜂鸟、辉紫耳蜂鸟和绿紫耳蜂鸟支配。","breeding":"繁殖期可能在12月至2月间，基于生殖腺状态判断，但也有记录显示展示飞行可延至10月、11月和5月。关于繁殖行为的具体信息目前尚缺。","identification":"雄性叉扇尾蜂鸟最显著的特征是其尾羽末端的球拍状结构，这是与其他蜂鸟区别的关键点。雌鸟和幼鸟可通过缺乏冠羽和喉部光泽、以及尾羽的差异来识别。","protection":"IUCN：NT（近危）。根据2006年的评估，叉扇尾蜂鸟因栖息地减少、种群数量小及适宜生存地域有限，被列为濒危物种。美国鸟类保护协会已开始采取措施，如植树造林，以改善其生活环境。","distribution":"主要分布于秘鲁北部，沿Utcubamba河东岸，记录还显示在San Martín省有分布。具体而言，其分布限于北秘鲁的安第斯山脉区域。","other":"该物种在2005年得到了美国鸟类保护协会的支持，与其秘鲁合作伙伴ECOAN合作，与Pomacochas社区签署保护协议，保护约100英亩的叉扇尾蜂鸟重要栖息地。"},{"name":"纯顶星喉蜂鸟","english_name":"Plain-capped Starthroat","scientific_name":"Heliomaster constantii","overview":"纯顶星喉蜂鸟（英文名：Plain-capped Starthroat，学名：Heliomaster constantii），是雨燕目蜂鸟科星喉蜂鸟属的鸟类。色彩相对朴素，拥有引人注目的长而直的喙。栖息于中美洲的干燥至半干旱森林边缘，喜好沿溪流的森林边界。不仅采食花蜜，还大量捕食昆虫，常自高处的栖木上飞扑捕猎。性别相似，但成鸟与幼鸟在喉部颜色上有明显差异。","appearance":"纯顶星喉蜂鸟体型较大，具有一条非常长且笔直的喙。面部带有条纹，喉部深色，有一个白色的臀部斑点。两性外观相似，但幼鸟缺乏成鸟喉部的红色，喉部通常呈现黑色。成鸟的背部为暗绿色，带有不规则的白色斑块，耳羽区域呈灰暗色，眼后有白色条纹，下颊部有白色条纹。喉部为灰色，下喉部为闪烁的粉红至橙红色。下体为淡灰色，侧翼有稀疏的绿色斑点，下侧翼有白色羽毛丛。腹部白色，尾下覆羽灰暗，尾羽绿色，末端黑褐色，尖端白色。喙为暗黑色，虹膜为深棕色。","call":"其鸣唱为一系列尖锐的鸣叫声，穿插着变化的鸣音，如 'chip chip chip pi-chip chip chip ....' 或 'chi chi chi chi whit-it chi ...'。叫声包括高音、柔和的滑音 'tseep' 或 'cheek'，响亮的 'peek'，以及追逐时的尖锐颤音。","habits":"纯顶星喉蜂鸟居住在中美洲的干燥至半干旱森林边缘、荆棘林、咖啡种植园、次生林和部分开阔地带。它们主要在树冠层觅食，以花蜜为食，同时也会在空中捕食昆虫。在北部的分布范围内，个体在10月至11月和2月迁移，局部移动也很常见，这取决于开花时间。","breeding":"关于纯顶星喉蜂鸟的繁殖生态知之甚少。在墨西哥西部，繁殖季节为1月至6月，在哥斯达黎加为10月至1月。它们制作浅杯状的巢，由植物绒毛构成，外层覆盖苔藓，通常置于高树梢的枝头附近。","identification":"纯顶星喉蜂鸟与长嘴星喉蜂鸟相似，但后者占据更湿润的生境，前额有闪光的蓝绿色，下喉部颜色更偏向玫瑰色，侧翼更绿。与同属其他物种相比，纯顶星喉蜂鸟的色彩较为暗淡。","protection":"IUCN：LC（无危）","distribution":"纯顶星喉蜂鸟分布于中美洲，从墨西哥南部到哥斯达黎加西北部，包括索诺拉州南部至哈利斯科州、墨西哥西南部和危地马拉西部，以及从萨尔瓦多到洪都拉斯、尼加拉瓜，直至哥斯达黎加西北部。在亚利桑那州，它们偶尔出现，自1969年首次记录以来，几乎每年都能观察到。","other":"尽管人类活动可能短期内对纯顶星喉蜂鸟影响较小，但其种群数量被认为正在减少。"},{"name":"长嘴星喉蜂鸟","english_name":"Long-billed Starthroat","scientific_name":"Heliomaster longirostris","overview":"长嘴星喉蜂鸟（英文名：Long-billed Starthroat，学名：Heliomaster longirostris），是雨燕目蜂鸟科星喉蜂鸟属的鸟类。热带低地森林中的较大体型蜂鸟，分布于中美洲至南美洲东北部，常见于墨西哥南部至巴西东北部。其最显著的特征为极长且直的喙，以及边界清晰的白色髭纹。雌雄外观相似，幼鸟缺乏成鸟特有的红色喉部。在热带常绿森林及其边缘地带活动。","appearance":"体长约11-12厘米，雄鸟体重5.5-7.1克，雌鸟约6.5克。具有细长而几乎笔直的黑色喙。雄鸟头部顶部闪耀着蓝绿色光泽，其余上体呈较暗的青铜绿色，臀部中央有一条白色条纹；尾部短小，尖端方正，远端黑色，外侧2-3根尾羽尖端白色。脸部下方有黑色区域，延伸至暗金属紫色的喉部，胸部灰色，两侧青铜绿色，腹部淡白色，尾下覆羽灰白相间。雌鸟与雄鸟相似，但蓝色头部顶部减少或缺失，喉部较窄，呈深灰色。幼鸟喉部暗黑，有时带有紫色光泽，头部、胸部、背部和侧面的羽毛边缘宽大，呈黄褐色。","call":"发出丰富而清脆的‘tseep’或‘tsew’声，追逐时发出吱吱的鸣叫。","habits":"长嘴星喉蜂鸟主要在树冠层活动，但也出现在开阔地和溪流上空，通过快速飞行捕捉昆虫。它们偏爱大型树木的花蜜，尤其是长而狭窄花冠的红花树（Erythrina spp.），同时也会光顾藤本植物、灌木、旅人蕉和栽培香蕉的花朵。在边缘地带和次生林中寻找食物，可能保卫拥有众多花朵的树木。高空中反复捕捉飞虫和蚊子，偶尔从叶片上掠取节肢动物，包括蜘蛛和其他多种昆虫。","breeding":"繁殖期从晚雨季持续到早旱季，具体时间在墨西哥南部和中美洲为10月至次年2月至3月，在哥伦比亚北部为3月和9月至10月。巢穴为宽阔浅杯状，由苔藓、地衣、植物绒毛和蜘蛛丝构成，装饰有灰色地衣碎片，通常位于灌木或裸露的树枝上，高度4.5-12米。每窝产两枚白色卵，孵化期18.5-19天，雏鸟离巢时间为25-26天。雏鸟出生两周左右时，上体、喉部和胸部覆盖着短而密集的白色绒毛。离巢后，幼鸟仍由亲鸟喂养长达22-23天。在中美洲，二窝雏鸟记录在3月至4月。","identification":"长嘴星喉蜂鸟与纯顶星喉蜂鸟的区别在于其更长更直的喙，以及白色髭纹而非白色的眉纹。此外，它的侧面为绿色，不同于后者较为暗淡的色彩。","protection":"IUCN：LC（无危）。CITES II（华盛顿公约二级保护物种）。虽然在大部分地区数量不多，但能适应较大的环境干扰，甚至可能得益于森林砍伐，只要保留分散的树木和小树林。在多个保护区中出现，例如哥斯达黎加的卡拉拉生物保护区、科科瓦多国家公园和戈尔菲托国家野生动物保护区，特立尼达的阿萨赖特自然中心，哥伦比亚的塔罗纳国家公园，以及巴西的巴西利亚国家公园。","distribution":"分布于中美洲至南美洲东北部，包括墨西哥南部至玻利维亚东部和巴西东北部。具体而言，从墨西哥南部穿过中美洲，直至南美洲东部秘鲁和玻利维亚东部，向东穿过圭亚那进入巴西东北部，以及特立尼达岛。"},{"name":"纹胸星喉蜂鸟","english_name":"Stripe-breasted Starthroat","scientific_name":"Heliomaster squamosus","overview":"纹胸星喉蜂鸟（英文名：Stripe-breasted Starthroat，学名：Heliomaster squamosus），是雨燕目蜂鸟科星喉蜂鸟属的鸟类。体型较大的蜂鸟，主要分布在巴西东部至东南部，包括Pernambuco至São Paulo一带。其最显著的外部特征是雄鸟腹部中央的白色条纹和金属粉色的喉部，而雌鸟喉部呈现鳞片状外观。","appearance":"雄鸟拥有绿色身体，腹部中央有一条醒目的白纹，喉部呈现出耀眼的金属粉色，头顶为蓝绿色。雌鸟上半身为灰绿，下半身同色，中央有一条白色条纹，喉部看起来有鳞片感。幼鸟外观与雌鸟相似。","call":"其鸣叫声包括模糊的颤音“bzzzrrrr..bzzzrrr..chi-chi-chi-chi..bzrrr”，以及清脆的‘tsik’声。","habits":"纹胸星喉蜂鸟主要栖息于森林和半开放环境如草原，常在3至8米的高度活动。以多种开花植物的花蜜为食，同时也会在空中捕食小昆虫。它们通常为领地性鸟类，更倾向于驱逐同类而非其他蜂鸟。","breeding":"繁殖季节一般为2月至4月，但也有11月孵卵的记录。巢呈杯状，建于树的水平枝上，高度约6至8米，偶尔更高。每窝产两枚蛋，孵化期14至16天，由雌鸟承担，小鸟在21至24天后离巢。","identification":"与同类相比，纹胸星喉蜂鸟雄鸟的金属粉色喉部和腹部的白色条纹是辨识的关键特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于巴西东部，从Pernambuco向南至São Paulo，以及阿根廷东北部极少数记录。","other":"曾在1970年代末前，纹胸星喉蜂鸟被大量从巴西出口，但现在这一贸易已停止。"},{"name":"蓝角星喉蜂鸟","english_name":"Blue-tufted Starthroat","scientific_name":"Heliomaster furcifer","overview":"蓝角星喉蜂鸟（英文名：Blue-tufted Starthroat，学名：Heliomaster furcifer），是雨燕目蜂鸟科星喉蜂鸟属的鸟类。中型蜂鸟，拥有一个长而略弯的喙，雄鸟背部呈绿色，腹部为紫蓝色，尾部分叉。其最引人注目的特征是雄鸟颈部那令人炫目的金属粉色和紫色的喉部羽毛。雌鸟具有铜色颈背，灰白色的喉咙和白色的下腹部。分布于南美洲，包括玻利维亚、巴西、巴拉圭、阿根廷、乌拉圭等地。","appearance":"蓝角星喉蜂鸟体型中等，长度约12.6至13厘米，重量在5至6.5克之间。雄鸟具有绿色的头部和上背部，其余上部羽毛呈闪亮的铜绿色，下部羽毛和颈部两侧的延长羽毛则是耀眼的超群蓝色。雌鸟的上部羽毛为铜绿色，喉咙和下腹部为灰色，腹部中央有一条白线，两翼侧边有绿色斑点。尾巴在上方为青铜绿色，下方则为闪耀的蓝绿色，尾端有白色尖端。雌鸟和非繁殖期的雄鸟在下方呈现灰白色。","call":"蓝角星喉蜂鸟发出的叫声是一串下降的、纯哨音般的“tseep”声，间隔重复。","habits":"蓝角星喉蜂鸟主要栖息于森林边缘、灌木丛和低地草地，以多种开花植物的花蜜为食，如萝藦科、豆科、姜科、凤梨科、百合科、龙胆科、马鞭草科和仙人掌科的花朵。夏季时，它们被认为是阿根廷查科和巴西南部的Dolichandra cynanchoides（萝藦科）藤蔓的主要传粉者。雄鸟会保卫富含花蜜的领地。它们还会在空中捕捉昆虫。","breeding":"繁殖季节从11月持续到次年3月。雌鸟建造杯状巢，由柔软的种子纤维构成，外面装饰有苔藓，位于地面以上3至6米处。每窝产两枚蛋，大小约为15.5毫米×9毫米，重0.6克。孵化期为15至16天，由雌鸟单独承担。雏鸟黑色，背部有灰色绒毛。离巢时间为20至25天。首次繁殖通常在第二年。","identification":"蓝角星喉蜂鸟与其他蜂鸟的区别在于其独特的超群蓝色下部羽毛和雄鸟的金属粉色和紫色喉部。雌鸟与雄鸟的差异主要体现在颜色的深浅和尾部形状上。","protection":"IUCN：LC（无危）","distribution":"蓝角星喉蜂鸟的核心分布区包括玻利维亚东部、巴西南部、巴拉圭、阿根廷北部和乌拉圭北部。在哥伦比亚、秘鲁也有记录，且在厄瓜多尔有一次未经证实的目击记录。","other":"历史上，蓝角星喉蜂鸟曾被大量出口用于鸟市交易，直到20世纪70年代末期，这种活动才被终止。"},{"name":"绿洲蜂鸟","english_name":"Oasis Hummingbird","scientific_name":"Rhodopis vesper","overview":"绿洲蜂鸟（英文名：Oasis Hummingbird，学名：Rhodopis vesper），是雨燕目蜂鸟科绿洲蜂鸟属的鸟类。体型中等，具有独特的长而弯曲的喙。雄鸟上体呈橄榄绿色，拥有蓝色至红紫色的喉羽，尾羽深叉，具特色性的肉桂色臀部。广泛分布于秘鲁和智利北部沿海沙漠地带的多样植被环境中，包括城市区域和花园。其分布范围正向南扩展，已到达智利北部。该物种在极端干燥的沿海沙漠中生存，受洪堡洋流影响，主要局限于沿海斜坡。","appearance":"绿洲蜂鸟体长约11至13.5厘米，体重约4克。雄鸟上体为橄榄绿色，具肉桂色臀部和深叉的尾羽，尾羽中央羽毛灰橄榄色，其余部分紫褐色。雄鸟喉部呈现虹彩的玫瑰紫至紫色，侧面转为青绿色。下体白色至淡灰色，两胁带绿。雌鸟喉部无虹彩，下体淡灰色至淡黄色，尾羽较短，仅轻微叉开，尾羽上表面橄榄绿或青铜绿，除中央一对外，其余均具宽黑横纹和白色尖端。","call":"鸣叫声包括‘tzee-tzee-dee-dee’的歌曲，先是上升后下降，以及一系列旋律性的‘tick’和‘tzee’音符，速度和音调可变，快速的清脆颤音，以及‘chew’的丰富音符。","habits":"绿洲蜂鸟栖息于沿海和近海岸的多种环境，包括干旱灌丛和绿洲、河流沿岸地带、农田和花园。它们全年可能在不同海拔（从海平面至3,800米）活动，但大部分时间在秘鲁低于2,600米的高度。它们不迁徙，但会探索孤立的绿洲和山谷，可能进行季节性垂直迁移。","breeding":"绿洲蜂鸟雄鸟领地性强，通过U形穿梭表演吸引雌鸟，包括悬停、唱歌、展示亮丽的喉羽和尾羽摆动。筑巢可能全年进行，已知在智利的繁殖时间为9月至12月。巢为杯状，悬挂在树或灌木枝条上，一窝产2枚蛋。孵卵期大约16天，幼鸟离巢约27天。","identification":"绿洲蜂鸟与同类物种的区别在于其非常长的、稍微弯曲的喙和鲜明的肉桂色臀部，这些特征使其在分布区内不易与其他蜂鸟混淆。与之相似的紫领蜂鸟体型更小，喙虽略弯但不那么长，雌鸟下体为淡黄色而非白色，雄鸟Woodstar尾羽更短。","protection":"IUCN：LC（无危）","distribution":"绿洲蜂鸟主要分布在秘鲁西北部至智利北部，包括北智利的塔拉帕卡区和阿塔卡马至圣地亚哥大区之间的区域。自1960年代以来，其分布范围在阿塔卡马以南有所扩展。","other":"绿洲蜂鸟的三种亚种，R. v. vesper（指名亚种）、R. v. koepckeae和R. v. atacamensis，其中最后一种曾一度被视作独立物种，但自二十世纪中叶起，恢复了当前的亚种地位。"},{"name":"矛尾蜂鸟","english_name":"Peruvian Sheartail","scientific_name":"Thaumastura cora","overview":"矛尾蜂鸟（英文名：Peruvian Sheartail，学名：Thaumastura cora），是雨燕目蜂鸟科矛尾蜂鸟属的小型鸟类，以其独特的长尾羽毛而著称。分布于南美洲西部，从厄瓜多尔西南部至秘鲁全境，延伸至智利西北部。雄鸟拥有引人注目的黑白色长尾流苏，雌鸟和幼鸟则与其它小型蜂鸟相似，识别较为困难。","appearance":"雄性矛尾蜂鸟约14厘米长，重约2.5克，拥有黑色短直喙，上体金属绿色，尾羽特异，最内侧一对尾羽短小，外缘深绿内缘白色，次对尾羽极为延长，黑外缘白内缘，尖端黑色。雌鸟约7.5厘米长，重约2.6克，尾羽较短，颜色从基部的淡白色渐变为绿色，再过渡到黑色尖端，边缘有白色。雌雄鸟喉部颜色差异明显，雄鸟喉部在特定角度下呈现虹彩般粉红色，雌鸟喉部奶油色。","call":"雄性矛尾蜂鸟的叫声为尖锐持续的吱吱声，有时长达一分钟以上，从栖息处发出或在穿梭飞行时发出，短促版本在与同类争斗时出现。雌雄两性都会发出短促的'chip'叫声。","habits":"生活在干旱的沿海地带，常见于农田、花园和果园，海拔从海平面至约2800米。以花蜜为食，也会捕食小昆虫。雄鸟在繁殖季节会保卫领地，进行展示飞行和鸣叫。","breeding":"繁殖季节雄鸟会进行领土防卫，进行J形俯冲或水平穿梭的展示飞行，同时鸣叫。巢为小杯状，外饰可能用花朵代替苔藓。一年可能繁殖两次，具体时间未知，孵化期和离巢时间亦不清楚。","identification":"雄性矛尾蜂鸟的长尾流苏与其它蜂鸟显著不同，雌鸟与智利蜂鸟雌鸟难以区分，但可通过鸣叫声和尾羽形状进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲西部，从厄瓜多尔西南部至秘鲁全境，延伸至智利西北部。在厄瓜多尔的分布相对较新，记录少于10次。","other":"已知与智利蜂鸟有杂交现象。"},{"name":"火尾蜂鸟","english_name":"Sparkling-tailed Woodstar","scientific_name":"Tilmatura dupontii","overview":"火尾蜂鸟（英文名：Sparkling-tailed Woodstar，学名：Tilmatura dupontii），是雨燕目蜂鸟科火尾蜂鸟属的鸟类。体型微小的蜂鸟，具有明显的昆虫般的外观。主要分布于中美洲，从墨西哥中部至尼加拉瓜的山麓和高地，偏好生长有花丛的灌木地带和开放林地边缘。雄鸟拥有细长而深叉的尾巴，闭合时呈点状，尾羽末端带有白色条纹；雌鸟较为朴素，腹部呈现淡黄色调。","appearance":"火尾蜂鸟是小型蜂鸟，拥有长而直的喙。雄鸟上体金属绿，尾部中央两对尾羽青铜绿色，外侧三对尾羽紫黑色，带宽白尖，尾羽基部有一条栗色带和一条白色带。喉部闪耀着蓝紫色光泽，胸带白色，腹部暗金属绿。雌鸟上体金属青铜或青铜绿色，下体肉桂色，腹部颜色最深。尾部仅轻微开叉，中央两对尾羽青铜绿色，外侧三对尾羽基部青铜绿色，有宽黑带近尖端，尖端肉桂色或白色。","call":"雄鸟发出极高且略带音乐性的吱吱声，连续不断，音调略有升降，持续数秒，通常从高处显眼的栖木上发出。偶尔也会发出高而尖锐的啾啾声。","habits":"火尾蜂鸟生活在半开放的景观中，如松栎森林边缘、灌木丛生的次生林和灌木林。它们以蜜蜂般的方式缓慢飞行，在花朵间穿梭觅食，捕食昆虫，同时摄取花蜜。它们可能在季节性进行高度迁移。","breeding":"关于火尾蜂鸟的繁殖生态知之甚少。在墨西哥西部八月采集到的个体处于繁殖状态，因此繁殖季可能包含这一月份。","identification":"火尾蜂鸟最显著的识别特征是两侧臀部的大白色斑块。雄鸟的长叉尾和蓝紫色喉部也是关键特征。与墨西哥剪尾蜂鸟和华丽蜂鸟相比，火尾蜂鸟的喙更短且直。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥中部至尼加拉瓜。栖息于海拔750至2500米的地带，但局部或季节性可降至海平面附近。"},{"name":"细剪尾蜂鸟","english_name":"Slender Sheartail","scientific_name":"Doricha enicura","overview":"细剪尾蜂鸟（英文名：Slender Sheartail，学名：Doricha enicura），是雨燕目蜂鸟科中美剪尾蜂鸟属的鸟类。是中美地区特有的蜂鸟，体型较小，以其细长弯曲的黑色喙和独特的细长尾巴著称，广泛分布于墨西哥南部至萨尔瓦多的山区及山谷地带。","appearance":"雄性细剪尾蜂鸟长约11至12.5厘米，体重约2.3克；雌鸟稍小，长8至9厘米，重约2.6克。两性皆拥有长而向下弯曲的黑喙和眼后方的白色斑点。雄鸟头部、背部及腹部两侧呈绿色，喉部为粉紫色，胸腹部中央为白色；其尾巴异常长且深叉，中央羽毛绿色，其余黑色。雌鸟上体绿色，下体肉桂色，眼带黑色，尾羽较短且分叉度低，中央羽毛绿色，边缘羽毛肉桂色带宽黑边和白色尖端。","call":"鸣叫特征记录不多，已知的叫声是在栖息或觅食时发出的较为硬朗、快速的‘chip’声，有时连续或略带颤音。","habits":"细剪尾蜂鸟常栖息于半开放的山地景观，如森林空地、林地、次生林和灌木丛地，活动高度从地面到植被中层。它主要以花蜜和小型节肢动物为食，觅食时，雄鸟通常保持尾巴近似垂直，而雌鸟会摇摆并开合尾巴。","breeding":"繁殖信息有限，仅知在墨西哥南部的Chiapas地区，该物种于十月进行繁殖活动，具体繁殖细节尚待进一步研究。","identification":"雄性细剪尾蜂鸟的长尾和独特的喉部颜色使其容易与区域内其他小型蜂鸟区分开来。雌鸟的下体颜色和尾羽特征也是识别的关键。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥南部至萨尔瓦多的山脉和内陆谷地，包括Guatemala和Honduras。"},{"name":"墨西哥剪尾蜂鸟","english_name":"Mexican Sheartail","scientific_name":"Doricha eliza","overview":"墨西哥剪尾蜂鸟（英文名：Mexican Sheartail，学名：Doricha eliza），是雨燕目蜂鸟科中美剪尾蜂鸟属的鸟类。小型蜂鸟，仅分布在墨西哥的尤卡坦半岛北部和韦拉克鲁斯州中部的干燥灌木丛中。其最显著的外部特征是雄鸟的紫色喉部和长而略弯的喙，以及长长的尾巴，通常保持闭合成一点。","appearance":"雄性墨西哥剪尾蜂鸟上半身呈金属绿或青铜色，下腹部白色，两侧绿色，拥有闪闪发光的玫瑰粉色喉部，腹部白色，两侧带有青铜绿色斑点。雌鸟和幼鸟更暗淡，上半身主要是绿色，下半身白色，带有褐色肉桂色的侧面和尾下覆羽。雌鸟的尾巴较短，只有适度的叉开（缺口），外侧尾羽主要是赤褐色，带有黑色亚端带和白色尖端。","habits":"墨西哥剪尾蜂鸟偏好开阔地带，如低矮灌木丛和龙舌兰植物区。它们在墨西哥的干燥灌木丛中栖息，常见于路边和花园等开放生境。以花蜜为食，也会摄取小节肢动物。","breeding":"繁殖期在韦拉克鲁斯从五月开始，在尤卡坦则在八月至四月间。筑巢材料包括苔藓、蜘蛛网和菊科植物种子，巢为杯状，每次产卵两枚。","identification":"雄性墨西哥剪尾蜂鸟与细剪尾蜂鸟相似，但后者尾部更长，喉部更偏紫色。雌性墨西哥剪尾蜂鸟下方颜色比细剪尾蜂鸟更深。与Calothorax属（瑰丽蜂鸟和华丽蜂鸟）的区别在于嘴型稍短且弯曲度较小。","protection":"IUCN：NT（近危）","distribution":"墨西哥东南部，分为两个隔离的族群，一在韦拉克鲁斯州中部，另一在尤卡坦半岛北部沿海地区。"},{"name":"紫辉林星蜂鸟","english_name":"Amethyst Woodstar","scientific_name":"Calliphlox amethystina","overview":"紫辉林星蜂鸟（英文名：Amethyst Woodstar，学名：Calliphlox amethystina），是雨燕目蜂鸟科林星蜂鸟属的鸟类。这种小型蜂鸟背部呈绿色，具有一条白色臀带，雄鸟喉部闪烁着粉紫色光泽，尾羽深叉。雌鸟喉部白色，尾羽较短，腹部及下尾覆羽带有肉桂色。分布于南美洲东部哥伦比亚至委内瑞拉、圭亚那、巴西、秘鲁、玻利维亚、厄瓜多尔，直至阿根廷东北部和巴拉圭，以及南哥伦比亚的部分地区。","appearance":"紫辉林星蜂鸟体型微小，长度约6至8.4厘米，体重介于2.3至2.5克。雄鸟上体为暗青铜绿色，具白色臀斑和虹彩紫辉喉部，下方有白色带纹，下体绿色，侧腹棕色；雌鸟上体相似，下体白色，喉部点缀绿斑，两胁和下尾覆羽肉桂色。尾羽短而主为暗绿色，末端有黑色横带。","call":"鸣叫特征未详细描述。","habits":"栖息于多种半开放至开阔的生境，包括湿润森林边缘、林中空地、草原和灌木丛，海拔高度可达1500米。以多种植物花朵的花蜜为食，也捕食空中昆虫。在巴西东部，受其他种类蜂鸟支配。","breeding":"繁殖季节为11月至次年4月，至少在巴西东部如此。雌鸟用柔软植物材料筑杯状巢，外部装饰苔藓，通常位于植被中的水平枝条上，高至15米。一窝产卵2枚，孵化期13至14天，由雌鸟承担，幼鸟20至22天离巢。","identification":"与白腹林蜂鸟在部分地区有重叠，但紫辉林星蜂鸟雌鸟下体的肉桂色更为显著，尾羽白色尖端更窄。与C. jourdanii的区别在于后者雄鸟上体颜色更淡，尾羽有棕色，雌鸟缺乏苍白喉部。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲，从东部哥伦比亚、委内瑞拉、圭亚那到巴西大部分地区，除亚马逊盆地主区外，向南至阿根廷东北部，再向西和北进入巴拉圭、玻利维亚、秘鲁和厄瓜多尔，略入南哥伦比亚。","other":"在人类改造的环境如花园和公园中能良好生存。"},{"name":"巴哈马林星蜂鸟","english_name":"Bahama Woodstar","scientific_name":"Nesophlox evelynae","overview":"巴哈马林星蜂鸟（英文名：Bahama Woodstar，学名：Nesophlox evelynae），是雨燕目蜂鸟科 Nesophlox 属的小型鸟类，分布于Lucayan群岛，包括Bahama和凯科斯群岛。其显著特征为雄鸟的紫色喉部和额部，以及雌鸟的橙色侧翼和尾缘。","appearance":"巴哈马林星蜂鸟体型小，长度约7.8至9.5厘米，体重2.5至3.3克。雄鸟具短而略向下弯的黑色喙，背部绿闪，有小型白色眼后斑，喉部与前额紫闪，胸部白色，腹部红褐色夹杂绿色，两胁红褐色；尾深叉状，中央尾羽绿闪，其余尾羽内网部分红褐色。雌鸟上体暗绿，有小型白色眼后斑，下体灰白，胸白色，腹部红褐色；尾圆形，中央尾羽绿闪，其余尾羽红褐色，具宽黑亚端带。幼鸟似成年雌鸟，但具狭窄的淡色羽尖和灰褐色喉咙。","call":"叫声包括尖锐的金属音'tit'或'tit-it'，常连续发出，有时迅速。雄鸟在展示飞行时还会用尾巴发出金属声。","habits":"栖息于各种岛内环境，包括沿海地带至松树林，花园和公园。以花蜜为食，包括本土和引入的灌木、藤蔓和树木的花蜜，同时捕食空中飞虫。雄鸟在开花的灌木和树木中保卫领地。","breeding":"全年筑巢，主要在1月至4月间，但观察到雌鸟在12月于新普罗维登斯岛上进行筑巢、孵化和喂养雏鸟的活动。巢为杯状，由细纤维和蜘蛛网构成，内衬柔软的棉状物质，外部装饰有小块树皮，建于小枝丫或枝梢，距地面1至7米。每窝产两枚白色卵，孵化期15至16天，仅雌鸟孵化。雏鸟20至24天离巢，之后继续跟随成鸟20至30天。","identification":"雄性古巴翠蜂鸟全身绿色，而雌鸟下部暗淡，不同于巴哈马林星蜂鸟。红喉北蜂鸟雄鸟无长尾，喉部红色而非紫色，雌鸟下部几乎没有橙色，尾部无橙色。","protection":"IUCN：LC（无危）, CITES II","distribution":"分布于Bahamas（除Inagua）和Caicos Is，偶尔记录于美国南佛罗里达州。","other":"曾被认为包含两个亚种，但易那圭林星蜂鸟现被视为独立物种。"},{"name":"易那圭林星蜂鸟","english_name":"Inagua Woodstar","scientific_name":"Nesophlox lyrura","overview":"易那圭林星蜂鸟（英文名：Inagua Woodstar，学名：Nesophlox lyrura），是雨燕目蜂鸟科Nesophlox属的独特物种。该蜂鸟仅分布于巴哈马群岛的Inagua区的大、小伊纳瓜岛，以其独特的外观和叫声而著称。","appearance":"成年易那圭林星蜂鸟体长7.8至8.2厘米，体重介于2.1至2.7克之间。雄鸟拥有闪光的紫红色额头和喉部，其上体呈现绿色金属光泽，胸部白色，腹部混合红褐色和绿色，尾羽深叉，外侧尾羽呈琴键状。雌鸟上体颜色较暗淡，喉部有绿色斑点，胸白色，腹部红褐色，尾部圆形。","call":"鸣叫包括尖锐的金属声“tit”或“tit-it”，通常连续发出，有时速度很快。雄鸟在展示飞行中也会发出金属质感的声音。","habits":"栖息于岛屿上的多种生境，包括沙丘灌木丛、淡水河流附近、花园和公园，但在干燥季节可能不会出现在红树林。在干旱的二月，该物种在花丛丰富的城市花园中数量众多。活动范围包括保卫小型领地，围绕着优质花蜜源，如盛开的芦荟。","breeding":"繁殖季节尚不清楚，但似乎包含十月。筑巢材料包括植物纤维和蜘蛛网，内衬柔软纤维，覆盖小片树皮，通常位于地面1至3米高处。关于繁殖生态的其他信息未知。","identification":"与巴哈马林星蜂鸟相比，成年雄鸟有金属红紫色额头和较长的叉尾。","protection":"IUCN：LC（无危）","distribution":"分布于北美的大、小伊纳瓜岛，属于巴哈马群岛的一部分。","other":"2015年的研究支持其独立物种地位，基于形态学、叫声、歌曲、求偶展示和遗传数据。"},{"name":"红喉林星蜂鸟","english_name":"Magenta-throated Woodstar","scientific_name":"Philodice bryantae","overview":"红喉林星蜂鸟（英文名：Magenta-throated Woodstar，学名：Philodice bryantae），是雨燕目蜂鸟科 Philodice 属的鸟类。体型微小，尾羽较长，飞行时呈类似大黄蜂的缓慢风格。雄鸟拥有紫色喉部和醒目的白色颈环，其余部分呈现绿色调，两胁带橙色。雌鸟较难辨别，但其小巧的体型、飞行姿态、橙色胁部、眼后白点以及臀部两侧的白色斑块为其特征。广泛活跃于森林边缘的小花丛中，亦会光顾喂食器。","appearance":"雄鸟长9厘米，重3.3克；雌鸟7.5厘米，重3.5克。雄鸟具短直黑喙，上体青铜绿，中央尾羽端部黑色，侧尾羽黑色而内网橙红色；眼后白斑，喉部金属紫，鲜明白色颈环环绕前颈；胸腹部绿色，腹侧橙色，臀部两侧有白色或淡黄色斑块。雌鸟上体似雄鸟，耳羽灰色，喉部淡黄色，白色颈环不明显，胸腹绿色与橙色混杂；尾羽双圆形，侧尾羽橙色，末端黑色带纹及淡黄色橙尖。幼鸟似成年雌鸟，下方更淡，头部和颈背具淡黄色边缘，侧尾羽尖端较小（雄鸟）或较大（雌鸟）。","call":"其歌声音调低沉，快速混杂着喷溅和咕噜音。叫声包括低沉的干涩滚动声'drr'（极快重复三音节）、干涩的'cht'声，以及追逐时发出的低沉哨音'tew'。","habits":"栖息于中美洲的半开放至开放景观，如森林边缘、空地、稀疏林地、次生林和灌木牧场，海拔700至1850米（哥斯达黎加）和1100至1750米（巴拿马）。以低树（Inga、Quararibea）、灌木（Lantana）和草本（Lobelia）花朵中的花蜜为食。雄鸟在喂食时通常保持长叉尾闭合上翘，仅在攻击性展示时张开。通过捕猎昆虫补充营养。","breeding":"繁殖季节在哥斯达黎加为11月至3月或4月，巴拿马未明确。雄鸟进行俯冲展示，可能在小群体中（潜在的领地群）。巢穴尚未被描述，孵化期和雏鸟离巢时间未知。","identification":"与同类物种区分主要依据其独特的紫色喉部、白色颈环、橙色胁部以及特定的鸣叫声。雌鸟与同属其他物种的区别在于其较小的体型、飞行方式、橙色胁部、眼后白点及臀部两侧的白色斑块。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，北起哥斯达黎加，西至巴拿马（Veraguas省），主要在太平洋斜坡区域。","other":"红喉林星蜂鸟曾被归入Nesophlox和Calliphlox属，现被分类于Philodice属，与紫喉林星蜂鸟同属。"},{"name":"紫喉林星蜂鸟","english_name":"Purple-throated Woodstar","scientific_name":"Philodice mitchellii","overview":"紫喉林星蜂鸟（英文名：Purple-throated Woodstar，学名：Philodice mitchellii），是雨燕目蜂鸟科 Philodice 属的鸟类。体型极小的蜂鸟科鸟类，主要分布在中美洲巴拿马东部至南美洲西部的哥伦比亚和厄瓜多尔，活动于安第斯山脉西侧的云雾森林地带，海拔高度在800至2400米之间。其最显著的特征是雄鸟拥有闪耀的紫喉，白色胸带，长而分叉的尾巴，以及臀部两侧的白色斑点。","appearance":"紫喉林星蜂鸟体长6.8至7.5厘米，体重3.0至3.3克。雄鸟拥有短直的黑色喙，上体呈暗铜绿色，两翼臀部有白色斑块，喉咙和颈部两侧闪烁着紫罗兰色，胸部白色，腹部暗铜色，侧腹和下腹呈红褐色。尾巴分叉，棕色偏紫，中央尾羽较短，外侧尾羽最长，最外侧一对狭窄。雌鸟上体与雄鸟相似，眼后有一细白线，喉咙淡白色，两侧有暗色斑点，胸前有白色带，下胸绿色，腹部红褐色；中央尾羽颜色与背部相同，其余尾羽为肉桂色，末端有黑色亚端带。幼鸟与成年雌鸟相似。","call":"鸣叫特征尚了解不足，已知的叫声包括一系列尖细的‘chit’音符，通常以2至4个音符的爆发形式出现，以及类似‘kyee-kyee-kyee-kyee’的吱吱声。在空中盘旋时，翅膀发出低沉的蜜蜂般的嗡嗡声。","habits":"紫喉林星蜂鸟栖息于云雾森林边缘和次生林，以花蜜为食，偏好如Cordia和Inga等开花树木。雄鸟会保卫在开花树上的领地，同时也会捕食空中的小型昆虫。它们的活动范围广泛，从海平面到2400米的高度均有分布，但在1000米以上的高度更为常见。","breeding":"繁殖季节在哥伦比亚西南部为12月至次年5月，其他地区的繁殖时间未知。它们会在高大的树木厚枝上，距离地面8至12米处，用细纤维和蜘蛛网搭建微小的杯状巢穴。雌鸟孵化两枚蛋约需15至17天，幼鸟离巢时间未知。","identification":"雄鸟的紫喉和白色胸带是与其他蜂鸟区别的关键特征。雌鸟的淡白色喉咙和眼后的白线也是辨识的重要标志。与白腹林蜂鸟相比，雌鸟的白色中心区域不会如此广泛。","protection":"IUCN：LC（无危）","distribution":"紫喉林星蜂鸟的分布范围从巴拿马东部的Darién省，贯穿哥伦比亚西部安第斯山脉的两侧，向南延伸至厄瓜多尔中部，南部至厄瓜多尔的El Oro和Loja地区。","other":"紫喉林星蜂鸟依赖本土开花树木，尤其是Inga属植物，作为主要的花蜜来源。它在La Planada和Las Tangaras保护区（哥伦比亚）内被发现。"},{"name":"细尾林星蜂鸟","english_name":"Slender-tailed Woodstar","scientific_name":"Microstilbon burmeisteri","overview":"细尾林星蜂鸟（英文名：Slender-tailed Woodstar，学名：Microstilbon burmeisteri），是雨燕目蜂鸟科细尾林星蜂鸟属的鸟类。仅存于细尾林星蜂鸟属。体型小巧，尾羽修长，分布于南美洲玻利维亚中部至阿根廷西北部的山区森林地带。","appearance":"雄鸟长约7至9厘米，含约3厘米长的尾羽，喙短而直，上体呈铜绿色，喉部有红紫色羽毛，侧边形成类似髭须的长簇，下体灰白，两侧绿斑点，尾羽下覆羽淡肉桂色，尾羽极窄呈叉状，末端钝圆。雌鸟脸颊较深，有小白色眼后纹，下体肉桂色，臀部两侧有白色斑块，尾羽短而方形，中央羽毛绿色，其余肉桂色带黑边。幼鸟似成年雌鸟。","call":"鸣声知之甚少，喂食或悬停时发出一系列沉闷的“chip”音，有时双倍重复。悬停时翅膀发出低沉的蜂鸣声。","habits":"栖息于海拔1100至2600米的落叶林、灌木斜坡、藤蔓缠绕的密林及部分开阔地带。有季节性高度迁移的强烈迹象，可能为南半球迁徙鸟。觅食于较高植被层，快速振翅如同蜜蜂，常被其他蜂鸟支配。以昆虫和小花中的花蜜为食。","breeding":"巢筑于树干枝杈处，高约3至6米，杯状，由柔软植物纤维构成，外表覆盖苔藓，以蛛网固定。巢中有两枚白色蛋，具体孵化时间和育雏时间未知。","identification":"与白腹林蜂鸟相比，细尾林星蜂鸟有更长的尾羽，雄鸟喉部两侧有突出的羽毛簇，雌鸟下体大多呈橙色。","protection":"IUCN：LC（无危）","distribution":"分布于玻利维亚（从中部至圣克鲁斯西部）到阿根廷北部（胡胡伊省、萨尔塔省、图库曼省）。历史记录显示曾出现在拉巴斯的云加斯（玻利维亚西北部）。"},{"name":"瑰丽蜂鸟","english_name":"Lucifer Sheartail","scientific_name":"Calothorax lucifer","overview":"瑰丽蜂鸟（英文名：Lucifer Sheartail，学名：Calothorax lucifer），是雨燕目蜂鸟科瑰丽蜂鸟属的鸟类。中等体型的绿色蜂鸟，以其略微弯曲的喙和独特的向外展开的喉部羽毛著称。主要分布在北美的高海拔地区，包括美国西南部至墨西哥中部，冬季则迁移至墨西哥中部。偏好沙漠地带，尤其是生长有龙舌兰植物的区域。","appearance":"瑰丽蜂鸟体长约10厘米，拥有长长的、略带弯曲的喙。雄鸟具有虹彩般的羽毛，尾部呈叉状，头部为绿色，喉部有一片醒目的紫色羽毛，胸部为灰白色。雌鸟体型稍大，羽毛色泽较暗淡，喉部呈浅色，腹部覆盖着白色或肉色的羽毛，通常带有鲜红边缘。","call":"未提供具体描述。","habits":"瑰丽蜂鸟主要栖息于海拔1100-1700米的峡谷、山坡和干燥的河床，这些地方生长有沙漠灌木和仙人掌。它们以龙舌兰和其他色彩鲜艳的沙漠花朵中的花蜜为主食，同时也会捕食蜘蛛和小型昆虫。飞行风格典型，能从花朵中吸食花蜜，空中捕捉昆虫，并直线飞往特定目的地。","breeding":"在求偶期间，雄鸟通过在雌鸟上方盘旋并突然俯冲，翅膀或尾巴发出啪啪声来吸引雌鸟，然后带着叉开的尾羽飞离，整个展示持续30到45秒，可能每小时重复数次。雌鸟在干燥、岩石斜坡上的沙漠灌木或仙人掌上筑巢，高度约0.61-3.05米，有时会建在旧巢之上。每季产两枚白色卵，孵化期约为15天，雏鸟在巢中停留约23天。","identification":"雄鸟的长而尖锐的尾羽与美丽蜂鸟（Beautiful Hummingbird）的钝尾形成对比，是识别的重要特征之一。雌鸟则通过其独特的下体颜色和喙的曲度来区分。","protection":"IUCN：LC（无危）","distribution":"瑰丽蜂鸟分布于美国西南部至墨西哥中部，包括西南得克萨斯、新墨西哥州极西南部至亚利桑那东南部，以及墨西哥的中央和北部地区。在冬季，它们迁徙至墨西哥中部。","other":"在繁殖季节，雄鸟会在雌鸟的巢附近进行飞行展示，这种行为在已研究的蜂鸟中似乎独一无二。"},{"name":"华丽蜂鸟","english_name":"Beautiful Sheartail","scientific_name":"Calothorax pulcher","overview":"华丽蜂鸟（英文名：Beautiful Sheartail，学名：Calothorax pulcher），是雨燕目蜂鸟科瑰丽蜂鸟属的鸟类。小型蜂鸟。其最显著的外部特征是雄鸟拥有的闪亮的紫红色喉部羽毛和长长的叉状尾巴。分布于墨西哥中南部，偏好干燥山地灌木丛生地带。","appearance":"雄性华丽蜂鸟上体呈金属青铜绿色，下体白色至灰白色，两翼及尾羽基部黑色，尾羽尖端白色，尾羽中央两对呈金属青铜绿色，外侧三对为青铜黑色。雌鸟上体同样金属青铜绿色，但头部颜色较暗淡，下体浅灰色，两侧转为肉桂色，尾羽较短，圆形，中央两对羽毛明亮青铜绿色。幼鸟似雌鸟，但尾羽更窄、更长且分叉更深，有时喉部可见粉红羽毛。","call":"雄鸟在求偶展示中的飞行部分会重复发出高而细薄、略带尖锐的“t-swiik t-swiik...”或“w-siiu w-siiu...”声。物种的叫声为高音、啾啾的鸣叫声。","habits":"一般认为华丽蜂鸟全年留居，但在繁殖季节后，一些个体可能会迁移到奥阿哈卡近海平面处。它主要在地面附近觅食，但也可能在任何高度的植被中寻找花蜜，其饮食范围广泛，细节尚不明确。除了吸食花蜜，还会从栖息处捕食小昆虫。","breeding":"雄鸟在求偶时会向雌鸟展示摇摆和俯冲飞行。繁殖季节大约从五月持续到十一月。巢穴是由精细植物绒毛制成的杯状结构，外层有丝状物，通过蛛网固定在树枝上。每窝产卵两枚。关于繁殖生态学的更多信息尚待研究。","identification":"与同属的Lucifer蜂鸟非常相似，主要区别在于雄性华丽蜂鸟的尾羽更长，尾羽尖端更圆润，喙部较短且曲度较小。Lucifer蜂鸟雄鸟的外侧尾羽尖端更为尖锐。","protection":"IUCN：LC（无危）","distribution":"分布局限于墨西哥中南部，从瓜纳华托中部到普埃布拉南部，南至瓦哈卡。栖息于干旱和半干旱的灌木丛生地带，半开放区域有树木和灌木，以及河岸森林，主要位于内陆山谷，海拔介于1000至2200米。"},{"name":"小吸蜜蜂鸟","english_name":"Vervain Hummingbird","scientific_name":"Mellisuga minima","overview":"小吸蜜蜂鸟（英文名：Vervain Hummingbird，学名：Mellisuga minima），是雨燕目蜂鸟科吸蜜蜂鸟属的体型微小的鸟类。仅略大于著名的吸蜜蜂鸟。自18世纪起便为鸟类学家所熟知，曾一度被认为是世界上最小的鸟。其名字源自拉丁文，'minima'意为‘最小’，而'Melli'和'suga'分别代表‘蜂蜜’和‘吸吮’，形象地描述了其采蜜行为。广泛分布于牙买加和海地，常见于人类活动区域。","appearance":"小吸蜜蜂鸟长约6厘米，包含1厘米的喙。体重约2至2.4克，雄雌外观相似，但雄鸟的尾羽较雌鸟更为分叉，且呈深黑色。全身覆以暗淡的金属绿色羽毛，腹部颜色稍浅。雄鸟的喉部和胸部有淡灰色斑点，雌鸟的喉部为灰白色，尾羽末端有白色尖端。","call":"雄鸟的鸣唱复杂，由多种音节组成，部分音节在一次歌唱中可能重复。歌声清脆高亢，穿透力强，有时在领地内或求偶展示时，甚至在与其他雄鸟相遇时会发出干涩的‘chittering’斥责声。","habits":"小吸蜜蜂鸟栖息于各种环境，除密林内部外，包括画廊森林、干燥森林、沙漠灌木丛、花园乃至城市区域。它不进行传统意义上的迁徙，但会随食物丰度进行高度调整。以花蜜为主食，也捕捉小型昆虫。不保卫固定领地，但会在特定位置停留捕食。","breeding":"繁殖季节从12月至次年8月，雌鸟用蛛网、毛发和苔藓等材料搭建杯状巢穴，通常位于地面附近。每窝产卵两枚，卵极小，平均长度约1厘米，重约0.38克。孵化期为16至19天，幼鸟约在21至25天后离巢。","identification":"与同类中的吸蜜蜂鸟相比，小吸蜜蜂鸟缺乏虹彩羽毛，使其显得较为朴素。与雌鸟和幼年的吸蜜蜂鸟类似，但体型更小，尾羽更短，背部羽毛更偏蓝色调。","protection":"IUCN：LC（无危）","distribution":"分布于牙买加和海地（多米尼加共和国和海地），以及附近的小岛屿，包括在北美区域的多米尼加和海地。","other":"尽管体型微小，小吸蜜蜂鸟在繁殖区域和非繁殖区域均有广泛的分布，适应性强，能利用多种生境，包括人类改造的环境。"},{"name":"吸蜜蜂鸟","english_name":"Bee Hummingbird","scientific_name":"Mellisuga helenae","overview":"吸蜜蜂鸟（英文名：Bee Hummingbird，学名：Mellisuga helenae），是雨燕目蜂鸟科吸蜜蜂鸟属的鸟类。别名: 侏儒蜂鸟、神鸟、森林女神、花冠、彗星，是蜂鸟科吸蜜蜂鸟属的鸟类，原生于加勒比海的古巴岛。世界上最小的鸟，以极小的体型和鲜艳的色彩著称。分布于古巴及松树岛。","appearance":"成年吸蜜蜂鸟体长5-6厘米，体重1.6-2.6克。雄鸟是最小的鸟类，喙直而黑，头部和喉咙呈鲜艳的红色，上体蓝色，下体灰白色。雌鸟稍大，上体绿色，下体灰白，尾部圆形，末端有白色斑点。幼鸟外观类似雌鸟。","call":"主要发出高音调的混乱鸣叫，有时在喂食时发出高音的“tsit”声。","habits":"栖息于古巴的林地，偏好水平位置的花朵。以多种植物的花蜜为食，偶尔捕食小昆虫。飞行迅速，翅膀振动频率极高，声音似蜂鸣。","breeding":"繁殖期为3月至6月。雌鸟独自筑巢，巢位于树梢，由植物纤维构成，内衬柔软植物绒毛。每窝产卵两枚，孵化期约21-22天，雏鸟在18天左右离巢。","identification":"吸蜜蜂鸟以其微小的体型和相对短的喙易于识别。雄鸟的红头和蓝背与雌鸟的绿背形成鲜明对比。","protection":"IUCN：NT（近危）。CITES II。吸蜜蜂鸟数量因生境丧失而下降。","distribution":"仅限于古巴和松树岛，主要分布于成熟森林地带，包括瓜纳哈卡比贝斯半岛、扎帕塔沼泽和托阿刀片。","other":"吸蜜蜂鸟的羽毛具有虹彩光泽，其舌部快速运动以摄取花蜜，对植物授粉起到重要作用。"},{"name":"红喉北蜂鸟","english_name":"Ruby-throated Hummingbird","scientific_name":"Archilochus colubris","overview":"红喉北蜂鸟（英文名：Ruby-throated Hummingbird，学名：Archilochus colubris），是雨燕目蜂鸟科北蜂鸟属的鸟类。北美东部唯一的繁殖蜂鸟，广泛分布于加拿大中南部、美国东部至墨西哥湾沿岸的林地、公园和花园。拥有红宝石般闪耀的喉部和小巧身形，雄鸟喉部鲜艳，雌鸟下体灰白，偶见翼侧淡黄色。繁殖季节结束后迁徙至巴拿马南部过冬。其繁殖区边界在第100经线以东，与东部落叶林和北方混交林的分布相吻合。","appearance":"体型较小，长度7.5-9厘米，雄鸟平均体重3克，雌鸟平均3.5克。背部和冠部呈金属绿，雄鸟喉部有醒目的红宝石色，雌鸟喉部灰白色。下体灰白色，两性均具绿色和灰色斑点。翅膀和尾巴黑色，雌鸟外侧尾羽尖端有白色。飞行时翅膀发出嗡嗡声，雄鸟的声音更高且音调变化多。","call":"发出快速、尖锐的吱吱声，主要用于威胁。求偶时，雄鸟会用翅膀发出快速的\"tik-tik tik-tik tik-tik\"声。","habits":"栖息于开放的林地、森林边缘、草地、花园和公园。春季迁徙时，部分个体能连续飞越墨西哥湾，全程约900公里。以花蜜为主食，也捕食昆虫，偏好红色、橙色和粉色的管状花朵。","breeding":"春季雄鸟先到达繁殖地建立领地，雌鸟随后到达。雌鸟单独筑巢，通常位于树梢3-12米高处，使用蛛丝固定巢穴。每窝产2枚白色卵，孵化期12-14天，雏鸟18-22天离巢。","identification":"与黑颏北蜂鸟难以区分，尤其是雌鸟和亚成年雄鸟，但红喉北蜂鸟上体绿色更鲜明，嘴较短且直，外翼羽毛略窄，差异细微。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖加拿大中南部、美国东部至墨西哥湾沿岸；冬季迁徙至中美洲，主要在墨西哥和佛罗里达过冬。","other":"迁徙期间，红喉北蜂鸟能够通过积累脂肪储备，实现跨越墨西哥湾的壮举，飞行时间长达20小时。"},{"name":"黑颏北蜂鸟","english_name":"Black-chinned Hummingbird","scientific_name":"Archilochus alexandri","overview":"黑颏北蜂鸟（英文名：Black-chinned Hummingbird，学名：Archilochus alexandri），是雨燕目蜂鸟科北蜂鸟属的鸟类。体型较小，广泛分布于多种林地和灌木丛生环境。雄鸟具有独特的紫色和黑色喉部。雌鸟下体白色，几乎不含淡黄色调。尾巴摆动频繁，常访问糖水喂食器和花园。夏季常见于美国西部大部分地区，略入加拿大。冬季分布延伸至墨西哥城南部，近来在美国墨西哥湾沿岸变得规律。与红喉北蜂鸟难以区分，尤其是雌鸟和幼年雄鸟，但分布范围有限重叠。","appearance":"小型蜂鸟，体长约8.25厘米，体色为金属绿，上体和翼覆羽呈青铜绿色，下体灰白，侧翼泛绿。雄鸟具黑色面颊和下颚，紫光闪烁的喉部饰羽，尾部深叉状。雌鸟尾部圆形，外侧三对尾羽尖端白色，无喉部饰羽。幼鸟羽毛边缘带淡褐色，雄鸟幼鸟可能在喉咙处有紫色羽毛。","call":"发出快速、高音的啁啾声。","habits":"栖息于开放的半干旱地带，靠近水源，如山地、森林、果园、草地和灌木丛。以花蜜为食，用长舌舔食，或在空中捕食昆虫。繁殖季节表现出领地行为，围绕喂食器和小食物源，尤其在繁殖季节更为防御。","breeding":"筑巢于隐蔽的树枝或树上，使用植物纤维、蜘蛛丝、绒毛和苔藓。偏好离地面6-12英尺的裸露水平枝条。每窝产两枚白色蛋，直径约8毫米，每年可能繁殖2-3次，孵化期13-16天。幼鸟通过母鸟反哺昆虫和花蜜长大，约20-21天后离巢。","identification":"与红喉北蜂鸟、红喉北蜂鸟和科氏蜂鸟等物种相似，辨识需依据头部形状、翅膀羽毛宽度和尾羽特征。雌性黑颏北蜂鸟的内侧初级飞羽比外侧更宽或相同，而红喉北蜂鸟的内侧初级飞羽明显更窄。","protection":"IUCN：LC（无危）","distribution":"繁殖区：北美，包括加拿大西南部、美国西部、墨西哥北部和西北部；非繁殖区：墨西哥西部。","other":"黑颏北蜂鸟已知会与其他几种蜂鸟杂交，包括红喉北蜂鸟、艾氏煌蜂鸟、宽尾蜂鸟和科氏蜂鸟。"},{"name":"安氏蜂鸟","english_name":"Anna's Hummingbird","scientific_name":"Calypte anna","overview":"安氏蜂鸟（英文名：Anna's Hummingbird，学名：Calypte anna），是雨燕目蜂鸟科科氏蜂鸟属的鸟类。北美洲特有的蜂鸟，自1930年代以来显著扩展了其分布范围，如今广泛分布于太平洋沿岸的美国州份，甚至北至不列颠哥伦比亚省，东至亚利桑那州南部，且在德克萨斯州西部的存在感日益增强。这种鸟利用城市和郊区栽培的异域植物及蜂鸟喂食器，数量显著增长，分布区不断扩张。安氏蜂鸟全年可见于许多地方，特别是在冬季，适应了较寒冷的气候，利用人类提供的糖水喂食器度过冬季。","appearance":"安氏蜂鸟体型中等偏大，体长9.9至10.9厘米，翼展12厘米，体重2.8至5.7克。背部呈青铜绿色，腹面灰白色，具有一条长长的直而细的喙。雄鸟拥有引人注目的玫瑰红色冠羽和喉部，颜色在阳光下显得鲜艳夺目，但在光线不足时可能显得暗淡或灰色。雌鸟和幼鸟的冠羽较为暗淡，喉部灰色，可能带有少量红色光泽，腹部同样为灰色。","call":"雄性安氏蜂鸟发出刮擦金属般的叫声，通常在树上或灌木丛中鸣叫。","habits":"安氏蜂鸟居住在开放或灌木丛生的环境中，包括沙漠灌木丛和灌木丛地带。它们常在城市和郊区的花园和院子中被观察到，频繁造访糖水喂食器。随着分布范围向北扩展至不列颠哥伦比亚省，甚至成为阿拉斯加东南部的常客，冬季则南迁至下加利福尼亚南部和墨西哥局部地区。它们以花蜜为主食，同时捕食空中飞行的小昆虫。","breeding":"繁殖季节，雄鸟会进行壮观的俯冲展示，吸引雌鸟的注意。雌鸟独自筑巢，位于灌木或树上，有时附着在电线或其他人造基底上，使用植物纤维、羽毛和动物毛发构建，外层伪装以苔藓、植物残骸，偶尔还有城市废弃物。繁殖期从冬季中期至夏季，具体时间取决于地理位置和气候条件。","identification":"安氏蜂鸟与其他蜂鸟的区别在于其较大的头部和较粗壮的体型。雄鸟拥有独特的玫瑰色头冠和喉部，不同于北美其他任何种类。雌鸟和幼鸟的下体较脏灰色，喉部中央常有一片深色斑块。与黑颏北蜂鸟和科氏蜂鸟相比，其喙相对更短、更直。","protection":"IUCN：LC（无危）","distribution":"安氏蜂鸟的分布范围包括北美的加拿大西南部、美国西部以及墨西哥西北部。在繁殖季节，它们广泛存在于从不列颠哥伦比亚省到亚利桑那州的区域，而在非繁殖季节，则可能出现在德克萨斯州西部和墨西哥的局部地区。","other":"安氏蜂鸟有效利用城市和郊区栽培的异域植物及蜂鸟喂食器，这一行为促使其数量增加和分布范围扩大。"},{"name":"科氏蜂鸟","english_name":"Costa's Hummingbird","scientific_name":"Calypte costae","overview":"科氏蜂鸟（英文名：Costa's Hummingbird，学名：Calypte costae），是雨燕目蜂鸟科科氏蜂鸟属的鸟类。体型小巧，成熟个体仅长至7.6至8.9厘米，翼展约11厘米，平均体重雄鸟为3.05克，雌鸟为3.22克。其活动范围覆盖美国西南部和墨西哥西北部的干旱地区，冬季迁至墨西哥西部。","appearance":"雄性科氏蜂鸟拥有绿色背部和侧身，黑色小尾巴和翅膀，以及白色下颚和尾下的斑点。最显著的特征是其紫色的头部和喉咙，喉咙的羽毛向后展开。雌鸟上身呈灰绿色，腹部为白色，不如雄鸟色彩鲜艳。","call":"雄鸟在求偶展示时会发出高音振动，由尾羽产生，同时还会在附近枝头发出尖锐的鸣叫。","habits":"科氏蜂鸟栖息于干燥沙漠地带及花园中，以花蜜和小昆虫为食，能够在飞行中悬停进食。在寒冷夜晚，它们会进入类似冬眠的状态，代谢率显著降低。","breeding":"雌鸟会在尤卡树茎或树枝上用植物纤维、绒毛和蜘蛛丝搭建杯状巢穴，产下两枚白色卵，孵化期约为15至18天。幼鸟在20至23天后离巢。","identification":"雄鸟以其独特的紫色冠和喉咙与其它蜂鸟相区别，而雌鸟需通过其灰绿色的上身和白色的腹部来识别。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于美国西南部和墨西哥西北部，非繁殖期则迁往墨西哥西部。","other":"已知存在与安氏蜂鸟、黑颏北蜂鸟及宽尾煌蜂鸟的杂交现象。"},{"name":"大瑰喉蜂鸟","english_name":"Bumblebee Hummingbird","scientific_name":"Selasphorus heloisa","overview":"大瑰喉蜂鸟（英文名：Bumblebee Hummingbird，学名：Selasphorus heloisa），是雨燕目蜂鸟科煌蜂鸟属的鸟类。体型微小、类似蜜蜂的蜂鸟，分布于墨西哥山区的湿润森林中。雄鸟拥有引人注目的玫瑰粉色喉部，其尾羽较短，带有白色角和锈色基部。雌鸟喉部暗斑点状，尾羽模式与雄鸟相似。该物种与瑰喉蜂鸟形态极其相似，但分布范围互不重叠。","appearance":"大瑰喉蜂鸟体型极小，约5.9至7.5厘米长，重量介于2至2.7克之间，属于最小的蜂鸟之一。雄鸟上体呈金属青铜绿至金铜色，喉部闪耀着金属光泽的紫红色至蓝紫色，尾羽中央对较为短小，外侧尾羽基部锈色，末端黑色并带有宽阔的白色尖端。雌鸟喉部白色，布满金属青铜色斑点，下体颜色较雄鸟更偏红肉桂色，尾羽黑色部分更多，白色尖端不那么纯白。","call":"大瑰喉蜂鸟的鸣唱被描述为高而细长的‘sss ssssssssis’或‘seeuuuuu’声，逐渐减弱直至结束，通常从栖木上发出。此外，它们还会发出高音的‘chips’声，与同属其他物种类似。飞行时，雄鸟的翅膀会发出类似昆虫的嗡嗡声，尤其在求偶展示时更为明显。","habits":"大瑰喉蜂鸟栖息于湿润和半湿润森林、松栎林地及其邻近的灌木区，偏好低至中层森林地带。它们在花朵领域中采取水平姿势悬停取食，尾巴微微翘起。尽管体型小巧，它们有时也会在较大蜂鸟的领地内觅食而不引发争斗。以花蜜为主食，同时捕食小型节肢动物。","breeding":"雄性大瑰喉蜂鸟在求偶时会展开其绚丽的喉部羽毛，同时将尾巴翘起，面向雌鸟做出有节奏的垂直动作。繁殖季节一般在4月至7月间，但在12月也有记录。Ortega-Álvarez等人在奥阿哈卡的研究中观察到1月底至3月初的筑巢活动。巢穴为杯状，由苔藓和地衣构成，可能还混杂其他纤维材料，位于鳄梨树（Persea americana）的细枝上，距地面约10米。孵化期和幼鸟离巢时间尚不清楚。","identification":"大瑰喉蜂鸟与瑰喉蜂鸟极为相似，但两者分布范围互不重叠。雌性大瑰喉蜂鸟与星蜂鸟的雌鸟相似，但前者尾羽较长，喉部斑点更密集，两胁颜色更深。与棕煌蜂鸟、艾氏煌蜂鸟和宽尾煌蜂鸟的雌鸟相比，大瑰喉蜂鸟的喙更短，体型略小。","protection":"IUCN：LC（无危）","distribution":"大瑰喉蜂鸟主要分布于墨西哥的两大山脉，包括东北、中部和南部地区的塔毛利帕斯至格雷罗和瓦哈卡，以及西北和西部地区的锡那罗亚、奇瓦瓦至哈利斯科。有记录显示，曾在美国亚利桑那州东南部的Huachuca山脉出现过一次。"},{"name":"瑰喉蜂鸟","english_name":"Wine-throated Hummingbird","scientific_name":"Selasphorus ellioti","appearance":"雄性瑰喉蜂鸟拥有扩展的、闪烁着玫瑰粉光泽并带有紫罗兰色调的喉部羽毛，其尾羽较短，基部锈色，尾尖带白色。雌鸟的喉部呈白色，密集地分布着暗色斑点，尾羽模式与雄鸟相似。两者皆有绿色上体，白色腹部，两侧为肉桂色。雌鸟的尾羽黑色部分更多，锈色部分减少，外侧尾羽尖端常染以肉桂色。","call":"雄性瑰喉蜂鸟在展示求偶行为时，会持续发出一系列高音、略带嗡嗡声的尖锐叫声，有时会转为颤音。此外，它还会发出高亢、尖锐、急促的连续‘sip-sip’或‘cheup cheup’声。雄鸟在喂食时悬停或与其他雄鸟争斗时，翅膀会发出‘thrum’的声音。","habits":"瑰喉蜂鸟偏好栖息在湿润和半湿润森林、松栎混交林及其周边的灌木丛。它们主要以花蜜为食，能够轻易地从其他蜂鸟的领地偷取花蜜，因体型和飞行模式类似蜜蜂。它们在植被的各个层次觅食，偏好低至中等高度的位置，悬停取食。它们可能也会摄取小型节肢动物。","breeding":"瑰喉蜂鸟的繁殖季节尚未得到详细记录，但可能从8月持续到次年2月。关于其繁殖生态的其他细节知之甚少。","identification":"瑰喉蜂鸟与大瑰喉蜂鸟极为相似，但两者的分布范围并不重叠。雄性瑰喉蜂鸟的外侧初级飞羽尖端不如大瑰喉蜂鸟那样细长。雌性瑰喉蜂鸟与棕煌蜂鸟、艾氏煌蜂鸟和宽尾煌蜂鸟的雌鸟相比，具有更短的喙和略小的体型。","protection":"IUCN：LC（无危）；然而，其数量估计在20,000至50,000只成熟个体之间，被认为正在下降。墨西哥政府将其列为受威胁物种，因为其高山森林栖息地正受到农业开垦和放牧的压力。","distribution":"瑰喉蜂鸟分布于中美洲，从墨西哥南部至洪都拉斯，主要栖息于海拔1,500至3,500米的山地森林，包括半湿润至湿润的松栎混交林和常绿森林，以及邻近的灌木地带。","other":"瑰喉蜂鸟与大瑰喉蜂鸟虽相似，但地理分布不重叠，大瑰喉蜂鸟仅出现在特胡安特佩克地峡以北的地区。"},{"name":"宽尾煌蜂鸟","english_name":"Broad-tailed Hummingbird","scientific_name":"Selasphorus platycercus","overview":"宽尾煌蜂鸟（英文名：Broad-tailed Hummingbird，学名：Selasphorus platycercus），是雨燕目蜂鸟科煌蜂鸟属的鸟类。北美和中美洲高山地区常见的蜂鸟之一。其最显著的特征是雄鸟的玫瑰红喉部和闪耀的绿色上体。分布于美国中西部、墨西哥至危地马拉西部，冬季会迁徙至较低海拔。","appearance":"中等体型，约10厘米长，翼展13.3厘米，重约3.6克，雌鸟略大于雄鸟。背部呈金属绿色，腹部白色，两胁带淡肉桂色。雄鸟拥有玫瑰红喉斑，雌鸟和幼鸟喉部有绿色斑点，眼圈苍白。尾羽宽阔，末端圆形，展开时可见白色端点。","call":"发出尖锐的“cheet cheet cheet cheet...”叫声。雄鸟在求偶时会展示翅膀发出响亮的金属颤音。","habits":"栖息于高山草甸和开阔林地，偏好松木-杜鹃林、针叶林和山地灌丛。以花蜜和小昆虫为食，飞行技巧高超，能悬停于空中吸取花蜜。","breeding":"繁殖季节与花期同步，雄鸟通过高空飞行和翅膀颤音吸引雌鸟。雌鸟单独筑巢，巢由蜘蛛网粘合苔藓和地衣构成，通常产2枚白色蛋，孵化期16至19天。","identification":"与星蜂鸟相比体型较大，略小于棕煌蜂鸟。雄鸟独特的玫瑰红喉部和雌鸟的斑点喉部是辨识关键。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国中西部、墨西哥及危地马拉西部，冬季迁徙至中美南部。","other":"已有多项关于其生理机能和进食生态的详细研究。"},{"name":"棕煌蜂鸟","english_name":"Rufous Hummingbird","scientific_name":"Selasphorus rufus","appearance":"成年雄鸟几乎全身橙色，胸部洁白，背部带有绿色，喉部虹彩斑斓，色彩从红到橙再到黄绿不等。雌鸟和幼鸟在侧面和尾巴上有橙色，以区别于安氏蜂鸟和黑颏北蜂鸟。体型小，体长约9.5厘米，翼展约11.4厘米，体重约3.4克。雄鸟背部和尾巴呈锈红色，尾羽尖端深绿色；雌鸟背部和上部绿色，下部白色，喉部有暗斑点，尾羽中央绿色，边缘锈红色。","call":"雄鸟在飞行时翅膀会发出金属般的嗡嗡声，音量随情境而变化。","habits":"栖息于各种林地环境，尤其在迁徙期间常见于郊区、草地和其他灌木丛生的地方。以花蜜和微小昆虫为食。","breeding":"繁殖季节未知，但在实验室和野外研究中被用于认知能力的研究，包括学习和记忆。雄鸟倾向于在密集花朵的区域建立领地，而雌鸟则在较稀疏的花朵区域活动。","identification":"与艾氏煌蜂鸟颜色和大小相似，两者在野外难以区分，尤其是雌鸟和幼鸟。雄鸟通过完全锈红色的背部和椭圆形的展示飞行在繁殖地识别。","protection":"IUCN：NT（近危）","distribution":"繁殖于美国阿拉斯加州东南部、加拿大西部和美国西北部，非繁殖期分布在美国南部、墨西哥北部和中部。","other":"棕煌蜂鸟在生理学和迁徙研究中具有独特价值，特别是在其迁徙路径上，所有观察到的棕煌蜂鸟都是过客，这为研究提供了便利。"},{"name":"艾氏煌蜂鸟","english_name":"Allen's Hummingbird","scientific_name":"Selasphorus sasin","overview":"艾氏煌蜂鸟（英文名：Allen's Hummingbird，学名：Selasphorus sasin），是雨燕目蜂鸟科煌蜂鸟属的鸟类。主要栖息于美国西海岸的加州和俄勒冈南部沿海地带。以绿背、红喉和锈色侧腹著称，雄鸟的金属光泽羽毛在阳光下闪耀。其分布范围相对较小，面临人类活动和栖息地丧失的威胁。","appearance":"艾氏煌蜂鸟体型小，约3至3.5英寸长，体重2至4克。雄鸟具绿色背部和前额，锈色侧腹、臀部和尾羽，喉部为耀眼的橙红色。雌鸟和幼鸟颜色相似，但喉部有斑点而非虹彩，雌鸟绿色居多，尾羽带白色尖端。幼鸟与雌鸟极为相似，仅通过细节分辨。","call":"雄鸟在求偶时发出高音金属颤鸣，翅膀振动产生嗡嗡声，声音比宽尾煌蜂鸟更高，但不如其响亮。","habits":"栖息于灌木林、花园和草地，偏好沿海地区。迁徙模式中，雄鸟先于春季返回北方，雌鸟随后抵达准备繁殖。高度领土性，雄鸟会驱赶入侵的同类和其他蜂鸟，甚至攻击体型远大于自身的猛禽。","breeding":"繁殖期在春季，雌鸟在大树如橡树、松树、道格拉斯冷杉和红木林中筑巢，用植物纤维、绒毛和蜘蛛网加固，巢置于地面以上。每次产1-2枚白色卵，孵化期15-17天。幼鸟约三周后离巢，母鸟继续喂养数周。","identification":"雄性艾氏煌蜂鸟与棕煌蜂鸟最相似，关键区别在于尾羽形状和R2尾羽的缺刻情况。雌鸟与棕煌蜂鸟幼鸟难以区分，需通过测量和尾羽R2形状辨别。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国西海岸的加州北部至俄勒冈南部沿海，非繁殖期迁至墨西哥中部。","other":"已开始适应受干扰环境，利用外来植物和鸟食器作为食物来源。"},{"name":"粉喉煌蜂鸟","english_name":"Volcano Hummingbird","scientific_name":"Selasphorus flammula","overview":"粉喉煌蜂鸟（英文名：Volcano Hummingbird，学名：Selasphorus flammula），是雨燕目蜂鸟科煌蜂鸟属的鸟类。主要分布在哥斯达黎加和巴拿马西部。以鲜艳的粉紫色喉咙而著称，体型小巧，长约7.5至8厘米，雄鸟体重约2.5克，雌鸟略重，约2.8克。该物种有三种亚种，分布于不同的高海拔山地。","appearance":"雄性粉喉煌蜂鸟上体呈青铜绿色，尾羽外缘为锈红色，中央尾羽带黑色尖端，喉部为醒目的紫罗兰色，下体大部分为白色，胸侧带有淡肉桂色斑点。雌鸟外观相似，但中央尾羽为绿色，其余尾羽基部锈红色，带黑色次端带和淡色尖端，下体白色，喉部点缀着暗青铜色斑点。幼鸟似雌鸟，但上体边缘更偏黄褐色。","call":"觅食时会发出轻柔的chip声。雄鸟还会发出下降音调的‘teeeeeuu’声和争斗时的twittering‘责备’声，后者在与同性竞争时尤为明显。","habits":"粉喉煌蜂鸟栖息于高海拔的半开放地带，包括高山草原、火山灰沉积区的次生植被、牧场边缘和森林边界。繁殖季节结束后，它们会迁移到较低海拔，甚至移动到相邻山脉。主要以花蜜为食，偏好小花，也利用蜜蜂和花刺鸟留下的孔洞获取长花冠植物的花蜜。捕食方式包括空中捕食昆虫和从叶面或蜘蛛网上拣食。","breeding":"繁殖期从8月或9月持续至翌年2月。雄鸟会守卫领地，进行求偶飞行表演，尤其是针对雌鸟。巢穴由植物绒毛和蛛网构成，外覆苔藓和地衣，筑于灌木或小树的最外层枝条末端，高度介于1至5米之间。孵化期和离巢时间尚不清楚。","identification":"与辉煌蜂鸟相比，粉喉煌蜂鸟雄鸟的中央尾羽有独特的缺口，雌鸟中央尾羽为绿色。亚种simoni下体更偏黄褐色，雄鸟喉部为玫瑰红色。","protection":"IUCN：LC（无危）；CITES: II级","distribution":"主要分布于哥斯达黎加的火山地区，如Irazú、Turrialba、Poás、Barva（或Barba）火山，以及巴拿马西部的Cordillera de Talamanca山脉和Barú火山。在繁殖季节，部分个体会下降至低至1350米的海拔。","other":"粉喉煌蜂鸟出现在哥斯达黎加发行的20000科朗纸币上。"},{"name":"辉喉煌蜂鸟","english_name":"Glow-throated Hummingbird","scientific_name":"Selasphorus ardens","overview":"辉喉煌蜂鸟（英文名：Glow-throated Hummingbird，学名：Selasphorus ardens），是雨燕目蜂鸟科煌蜂鸟属的鸟类。一种极度濒危的小型蜂鸟，仅分布在巴拿马中西部山区的狭窄范围内。其特征为雄鸟拥有绿色背部，锈色胁部，粉红至红色喉咙，以及白色颈圈。雌鸟喉部斑驳，体侧淡黄色，上体绿色，尾羽中部绿色，其余部分锈色，带有黑色条纹和淡黄色尖端。该物种生活在海拔约750至1800米的山地森林边缘。","appearance":"辉喉煌蜂鸟长约7厘米，两性均有短而直的黑色喙。雄鸟上体呈铜绿色，尾羽黑色带锈色边缘，喉咙粉红至红色，下方有白色颈圈，胸部中央和腹部白色，余下体侧淡黄至肉桂色，带绿色斑点，尾下覆羽淡黄白色。雌鸟上体亦为铜绿色，中央尾羽绿色，其余尾羽锈色基部，近端黑色带，深淡黄色尖端，喉部淡黄灰色斑点，其余下体特征与雄鸟相似。幼鸟类似雌鸟，但头部和颈背羽毛边缘锈色，尾部绿色较多。","call":"关于辉喉煌蜂鸟的叫声和声乐行为，目前尚无相关记录。","habits":"辉喉煌蜂鸟栖息于塔拉曼卡山脉森林的边缘和开阔地带，海拔介于750至1800米之间。其具体迁徙模式未知，但可能局限于局部区域。该鸟种的觅食行为和饮食习惯尚不清楚，但预计与近亲辉煌蜂鸟相似，以花蜜和小昆虫为主食。","breeding":"辉喉煌蜂鸟的繁殖生态学至今未有研究报道，包括繁殖期、求偶、筑巢、交配、产卵、孵化和育雏等信息。","identification":"雄性辉喉煌蜂鸟与辉煌蜂鸟雄鸟相比，前者尾羽大部分锈色，喉咙橙色。雌性辉喉煌蜂鸟与雌性辉煌蜂鸟非常相似，但中央尾羽锈色边缘更少。两物种在野外可能难以区分。","protection":"IUCN：EN（濒危）；CITES: II级。物种分布受限，仅存于少数地区，全球成熟个体估计不足1000只。栖息地受到农业、咖啡种植园、放牧、农药污染和燃烧威胁，森林碎片化严重。部分分布区位于圣菲国家公园，但保护区管理资源有限。","distribution":"辉喉煌蜂鸟仅限于巴拿马中西部山区，包括奇里基省的塞罗科罗拉多/塞罗弗洛雷斯和维拉瓜斯省的圣塔费/塞罗图特。20世纪以来，记录仅限于这两个区域。","other":"辉喉煌蜂鸟自1988年首次被IUCN评估为受威胁物种，随后于1994年被列为易危，2013年升级为濒危。"},{"name":"辉煌蜂鸟","english_name":"Scintillant Hummingbird","scientific_name":"Selasphorus scintilla","overview":"辉煌蜂鸟（英文名：Scintillant Hummingbird，学名：Selasphorus scintilla），是雨燕目蜂鸟科煌蜂鸟属的鸟类。也是哥斯达黎加太平洋坡和巴拿马西部地区最小的蜂鸟。与北美的Allen's和Rufous蜂鸟以及巴拿马的Glow-throated蜂鸟亲缘关系最近。辉煌蜂鸟以其醒目的橙色喉咙和独特的翼颤声而著称。","appearance":"辉煌蜂鸟体型微小，仅6.5-8厘米长，包括喙在内。雄鸟体重约2克，雌鸟略重，约2.3克。雄鸟拥有青铜绿色上体，带黑色条纹的红褐色尾巴，以及引人注目的红色喉咙，与肉桂色下体之间有一白色颈环。雌鸟的喉咙呈淡黄色，带有小绿斑，侧腹更富红褐色。年轻个体类似雌鸟，但上体羽毛边缘呈红褐色。","call":"雄性辉煌蜂鸟发出清脆的‘tsip’叫声。","habits":"辉煌蜂鸟栖息于灌木丛生的森林边缘、咖啡种植园，偶尔出现在花园中，海拔高度从900至2000米，非繁殖季节可达2500米。它们在繁殖季节会守卫着Salvia花朵附近的领地，表现出强烈的领土性。","breeding":"繁殖期间，雌鸟独自负责筑巢和孵化。她会在灌木丛中1至4米高处搭建一个由植物纤维构成的小杯状巢，产下两个白色蛋。孵化期大约持续15至19天，幼鸟则在20至26天后离巢。","identification":"雄性辉煌蜂鸟以其鲜艳的橙色喉咙与所有其他蜂鸟区分开来。雌鸟与Volcano蜂鸟相似，但可通过其红褐色侧腹和腹部进行区分。年轻个体的上体羽毛边缘的红褐色是识别的关键。","protection":"IUCN：LC（无危）","distribution":"辉煌蜂鸟分布在中美洲的哥斯达黎加中北部和巴拿马西部，包括繁殖区域。","other":"辉煌蜂鸟在当地较为常见，但由于分布范围有限，对其基本生物学的了解相对较少。"},{"name":"星蜂鸟","english_name":"Calliope Hummingbird","scientific_name":"Selasphorus calliope","overview":"星蜂鸟（英文名：Calliope Hummingbird，学名：Selasphorus calliope），是雨燕目蜂鸟科煌蜂鸟属的鸟类。是最小的北美繁殖鸟类，以其英勇的名字致敬史诗诗歌的缪斯女神Calliope。雄鸟在展示其独特的紫红色喉羽时，犹如一颗闪耀的小星星。在寒冷的西北山区成功繁殖，尽管体型微小，却能进行长达9,000公里的长途迁徙，成为世界上最小的长距离迁徙鸟类。","appearance":"雄鸟具有紫红色的喉羽，由独立的光线状羽毛组成，雌鸟和幼鸟的喉部为白色，可能带有少量的紫红色斑点。两性的中央尾羽对宽大，占羽毛长度的五分之四。成年雄鸟的上身呈金属青铜绿色，雌鸟和幼鸟相似，但背部颜色更偏向铜色。雌鸟和幼鸟的下体有淡黄色的洗染。","call":"雄鸟在吸引雌鸟时会发出尖锐的zing声，并伴随U形俯冲飞行，尾羽发出噼啪声。","habits":"栖息于高山草甸、流溪旁的白杨灌丛和开放森林，以花蜜为食，同时捕食空中飞虫。冬季在墨西哥的松栎林和灌木边缘地带度过。","breeding":"在4月至5月间，雄鸟先于雌鸟抵达繁殖地，占据领地并吸引多个雌鸟。雌鸟独自筑巢，通常选择松树下的悬枝，巢形似松果，可重复使用多年。每窝产卵两枚，孵化期约15至16天，雏鸟约20天后离巢。","identification":"与同属的棕煌蜂鸟和艾氏煌蜂鸟相比，星蜂鸟体型较小，尾部较短，中央尾羽的锈色仅限基部，而其他物种的尾羽锈色更为明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大西南部和美国西部，冬季迁至墨西哥西部。","other":"星蜂鸟的迁徙模式可能因人类环境改变而在美国东南部有所扩展。"},{"name":"紫领蜂鸟","english_name":"Purple-collared Woodstar","scientific_name":"Myrtis fanny","overview":"紫领蜂鸟（英文名：Purple-collared Woodstar，学名：Myrtis fanny），是雨燕目蜂鸟科紫领蜂鸟属的鸟类。是紫领蜂鸟属的唯一物种，与紫辉林星蜂鸟亲缘关系密切。体型小巧，分布于南美洲的厄瓜多尔和秘鲁，偏好干燥灌木地带及沿海沙漠。","appearance":"紫领蜂鸟长约7.5至8厘米，重约2.3至2.5克。喙短而下弯，上部青铜绿色，雄鸟拥有闪耀的蓝绿色喉部，下方环绕紫色饰带，其余下体呈污白色。雌鸟下体呈淡褐色，喉部和腹部有少许白色，尾部较短且圆，中央羽毛蓝绿色，其余黑底白尖。两个亚种相似，M. f. megalura尾羽更长。","call":"雄鸟在求偶展示时发出一系列高音的“ti-ti-ti-trl”声，弧底时则机械地发出鼻音般的“anh-anh-anh-anh-anh”。追逐时会发出快速下降的高音“ti-ti-ti-ti”。另有快速干涩的“chi-chi-chi”叫声。","habits":"紫领蜂鸟栖息于开放景观，如干燥的海岸灌木丛、开阔的林地和花园。海拔分布自海平面至3000米，尤其在1000至2000米间常见。以花蜜为食，采用陷阱线觅食策略，同时捕食空中昆虫。","breeding":"繁殖季节在厄瓜多尔为3月至6月，在秘鲁为6月至10月。雄鸟进行半圆形求偶飞行展示。雌鸟用植物纤维和蜘蛛网在细枝分叉处筑杯状巢，通常离地2至4米。孵化期15至16天，雏鸟在19至22天后离巢。","identification":"紫领蜂鸟与紫辉林星蜂鸟有亲缘关系，但可通过其特有的紫色颈环和体型差异加以区分。雌鸟与雄鸟的色彩差异明显。","protection":"IUCN：LC（无危）","distribution":"紫领蜂鸟分布于南美的厄瓜多尔西部和南部，以及秘鲁西部至阿雷基帕省。北部从卡哈马卡至胡安科。"},{"name":"智利蜂鸟","english_name":"Chilean Woodstar","scientific_name":"Eulidia yarrellii","overview":"智利蜂鸟（英文名：Chilean Woodstar，学名：Eulidia yarrellii），是雨燕目蜂鸟科智利蜂鸟属的小型鸟类。智利特有种，仅在北部阿塔卡马沙漠的特定河谷中发现，如Lluta、Azapa和Vitor山谷。曾经极为丰富，现在极度濒危，数量锐减至仅约300只成熟个体。蜂鸟体型小巧，肌肉发达，翅膀呈桨状，能够进行各种飞行技巧，包括倒飞和悬停以吸食花蜜。","appearance":"智利蜂鸟体长7.5至8厘米，体重2.3至2.6克，是智利最小的鸟类。雄鸟上身呈现橄榄绿色光泽，下体白色，喉部闪耀着紫红色，尾羽中央短小而绿，两侧较长且黑褐色微弯。雌鸟上身同雄鸟，下体淡黄色调，腹及大腿最深色；尾羽中央绿色，两侧黑色基部带淡黄，末端宽白。幼鸟似雌鸟，但具斑点喉部，可能有加长的外侧尾羽。","call":"发出一系列轻微粗糙的“tsick”声，比矛尾蜂鸟的叫声更嘶哑，雄鸟展示时会发出高音的‘zrrrrrrr’声。","habits":"栖息于干旱地带的河流谷地，偏好本土灌木丛和花园，活动范围从海拔200米至750米，偶尔记录到高达3000米。通常单独觅食，偶尔大量聚集在开花树旁。以多种花卉、灌木、仙人掌和树木的花蜜为食，包括本土植物Geoffroea decorticans、Schinus molle和Inga feulles以及外来植物Lantana、Hibiscus和Citrus等。同时捕食空中小型昆虫。","breeding":"繁殖信息有限，已知在五月、八月和九月有筑巢记录，可能一年两次或全年繁殖。巢多建于橄榄树中，高度约2.3米。幼鸟和部分筑巢记录表明可能有季节性繁殖行为。","identification":"与矛尾蜂鸟相似，但雄鸟尾羽不具延长的白色羽毛，雌鸟喉部较淡，腹部更白色。飞行时尾部常翘起，不如矛尾蜂鸟频繁振动尾羽。","protection":"IUCN：CR（极危）","distribution":"分布于南美洲的智利北部（阿塔卡马沙漠的Lluta、Azapa和Vitor河谷）和秘鲁南部（Tacna和Moquegua地区，记录不详）。","other":"面临农业扩张、农药使用和与矛尾蜂鸟的竞争威胁，后者数量远超智利蜂鸟，可能造成杂交问题。"},{"name":"短尾蜂鸟","english_name":"Short-tailed Woodstar","scientific_name":"Myrmia micrura","overview":"短尾蜂鸟（英文名：Short-tailed Woodstar，学名：Myrmia micrura），是雨燕目蜂鸟科短尾蜂鸟属的唯一物种。该鸟体型极小，尾部异常短小，分布于厄瓜多尔西部及秘鲁西北部的沙漠和灌木丛地带。雄鸟拥有闪亮的紫罗兰色喉部饰羽，边缘环绕白色，雌鸟则无明显喉部饰羽，腹部略带肉桂色，尾端有白色尖端。","appearance":"短尾蜂鸟体长约6厘米，体重约2.3克。雄鸟上体呈闪光绿色，具独特白色侧喉纹，喉部饰羽闪耀紫罗兰色，胸部和腹部白色，两胁颜色较暗淡。雌鸟下体呈淡肉桂色至白色，尾羽中央绿色，其余黑色并带有白色尖端。尾部非常短，静止时尾尖不及翼尖。","call":"雄性短尾蜂鸟在展示飞行时会发出一系列高音的‘tititi’和‘sweee’音调，清脆悦耳。","habits":"短尾蜂鸟常栖息于低海拔的干旱灌木和沙漠地带，主要在地面附近觅食，以花蜜为食，同时捕食小型节肢动物。在雨季期间，它们似乎会离开沿海地区。","breeding":"繁殖季节主要在3月至5月，雄鸟进行U形求偶飞行。雌鸟用植物绒毛和蜘蛛网在细枝丫处筑巢，巢离地面高度0.6至2.6米。每次产卵2枚，孵化期15至16天，幼鸟约22至23天后离巢。","identification":"短尾蜂鸟与同域其他蜂鸟种类的区别在于其极短的尾部，静止时尾尖不会触及翼尖，且尾羽末端有白色尖端。雌鸟与紫领蜂鸟区别明显，后者体型更大，尾部较长，喙更长且弯曲。","protection":"IUCN：LC（无危）","distribution":"短尾蜂鸟分布于南美洲的厄瓜多尔西南部和秘鲁西北部，主要栖息于低地沙漠和灌木丛地带，偶尔在海拔高达1,200米的地方出现。","other":"短尾蜂鸟与粉髯林蜂鸟共同保持着南美洲最小鸟类的称号。"},{"name":"白腹林蜂鸟","english_name":"White-bellied Woodstar","scientific_name":"Chaetocercus mulsant","appearance":"雄鸟具有笔直的黑色喙，上体为深蓝绿色，眼后有白色纹线，与胸部宽阔的白色带相连；胸甲虹彩般红紫色，腹部和两侧有白色斑块，尾巴分叉，外侧尾羽仅余轴状。雌鸟上体青铜色，眼周有灰色面具，眼后线淡黄色；下体灰褐色，喉咙浅肉桂色，腹部和侧部有白色斑块；尾巴圆形，中央尾羽绿色，外侧尾羽肉桂色，尾端有宽黑带。幼鸟与雌鸟相似。","call":"鸣叫声包括较低沉的“djup”音和更高音调的迟钝“chip”。飞行时不仅产生机械般的嗡嗡声，还会发出更高音调的铃铛般颤音。","habits":"主要生活在哥伦比亚至玻利维亚的安第斯山脉，常见于海拔2,200至2,800米，低至1,500米，高至4,000米的地带。栖息于湿润森林边缘、牧场和耕作区。白腹林蜂鸟在所有植被层中觅食，以多种开花植物和树木如龙舌兰、印加豆、天竺葵的花蜜为食，同时摄取小型节肢动物。","breeding":"繁殖生态知之甚少。已知的一个巢穴在四月被发现于厄瓜多尔，位于约10米高的树上。","identification":"雄鸟以其亮白色腹部、紫色喉部和分叉尾羽区别于其他种类。雌鸟需通过更明亮、更清晰的白色腹斑和下背部两侧更大的白色斑块来区分。","protection":"IUCN：LC（无危）","distribution":"南美洲，从哥伦比亚中部和东部安第斯山脉断续分布至秘鲁，最远到达玻利维亚的科恰班巴省。","other":"白腹林蜂鸟的体重约为3.8至4克，体型小，适应人类环境，可能比预想的更为普遍。"},{"name":"小林蜂鸟","english_name":"Little Woodstar","scientific_name":"Chaetocercus bombus","overview":"小林蜂鸟（英文名：Little Woodstar，学名：Chaetocercus bombus），是雨燕目蜂鸟科林蜂鸟属的鸟类。体型微小，类似蜜蜂的蜂鸟，分布于南美洲的哥伦比亚西南部至秘鲁中北部，栖息于安第斯山脉的半湿润和湿润落叶林区。","appearance":"小林蜂鸟长度约6到7厘米，雄鸟全身呈深青铜蓝绿色，具有玫瑰色的喉部，眼后有淡黄色条纹，连接至淡黄色胸部，尾部叉开，最外侧羽毛仅有羽轴而无羽片。雌鸟背部呈青铜绿，腹部大部为肉桂色，两翼和臀部具淡褐色，尾部圆钝，末端有一黑色横带。","call":"鸣叫声包含‘tsitsitsi..tzzeee-tzzeee..chichip’的混合音调，包括尖锐声、颤音和嗡嗡声。进食和悬停时发出干燥的‘chip’声或双重‘chichip’声，互动或追逐时会发出刺耳的‘kswee-kswee-ti-ti-ti’声。","habits":"主要栖息在半湿润和湿润的落叶森林过渡地带，海拔从海平面至2,300米（西部厄瓜多尔）或900至3,000米（东部厄瓜多尔和秘鲁）。以花蜜为食，活动范围从地面至森林中层，访问各种开花植物和树木。","breeding":"关于繁殖生态学的信息未知。","identification":"与白腹林蜂鸟相比，雌性小林蜂鸟体型更小，腹部锈色更加广泛。","protection":"IUCN：NT（近危）。受持续的森林砍伐、农业、定居点和采矿影响，其森林生境不断丧失。","distribution":"分布于南美洲，具体包括哥伦比亚西南部（最南端的纳里尼奥省）、厄瓜多尔西部至秘鲁北部，以及厄瓜多尔东部和秘鲁北中部局部地区。","other":"小林蜂鸟曾被归类于Acestrura属，后于20世纪晚期调整至Chaetocercus属。"},{"name":"粉髯林蜂鸟","english_name":"Gorgeted Woodstar","scientific_name":"Chaetocercus heliodor","overview":"粉髯林蜂鸟（英文名：Gorgeted Woodstar，学名：Chaetocercus heliodor），是雨燕目蜂鸟科林蜂鸟属的鸟类。体型微小的蜂鸟，们以类似大黄蜂的飞行方式著称，分布于南美洲的委内瑞拉至厄瓜多尔西部，主要栖息于安第斯山脉的云雾森林边缘和次生林地带。","appearance":"粉髯林蜂鸟是木星蜂鸟中最娇小的一种，总长度介于5.8到6.4厘米之间，跻身全球最小鸟类之列。雄鸟呈现深蓝绿色金属光泽，喉部拥有粉紫色的闪亮羽毛，眼后有一灰线，胸部灰色，两胁有白色斑点。雌鸟的上体呈铜绿色，臀部红褐色，下体为肉桂红棕色，尾巴圆润，末端有黑色条纹。C. h. cleavesi亚种的雄鸟颜色更深，喉部紫红色较淡，尾巴更短。","call":"在喂食或悬停时，粉髯林蜂鸟会发出单个干燥的'chit'声，有时会重复成'doubled chichit'或'tripled chichichit'，翅膀振动时产生低沉的嗡嗡声，类似蜜蜂。","habits":"粉髯林蜂鸟在海拔1,200至3,000米之间活动，偏好半开放到开放的环境，如湿润森林边缘、咖啡种植园和树丛地带，偶尔造访较低的paramo区域。它们从植被中间层到树冠层寻找花蜜，Inga树的花朵是重要的食物来源之一。它们不守卫领地，因体型小巧和缓慢飞行而能在其他蜂鸟的领地内觅食。除了花蜜，还会从枝头捕捉小昆虫。","breeding":"在哥伦比亚的部分地区，繁殖季节从4月持续至10月。它们用柔软的植物材料构建杯状巢穴，外表装饰有苔藓、叶片碎片和小树枝，通过蜘蛛网固定在垂直或水平的树枝上。关于繁殖生态的其他信息尚不清楚。","identification":"粉髯林蜂鸟雄鸟具有独特的粉紫色喉部羽毛，雌鸟臀部红褐色和尾巴末端的黑色条纹是辨识关键。与同属其他物种相比，它们的飞行更显笨拙，体型更小。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的安第斯山脉区域，从委内瑞拉梅里达州向南贯穿哥伦比亚直至厄瓜多尔西部，C. h. cleavesi亚种则位于厄瓜多尔东北部的苏昆比奥斯和莫罗纳-圣地亚哥省之间。","other":"粉髯林蜂鸟在部分地区的数量稀少至局部常见，但由于其体型微小和隐蔽的行为，可能比实际观察到的更为普遍。"},{"name":"圣马林蜂鸟","english_name":"Santa Marta Woodstar","scientific_name":"Chaetocercus astreans","appearance":"成年雄鸟拥有闪耀的紫红色喉斑，周围镶有白色边框，尾羽尖锐。雌鸟具有黑色面罩和浅褐色腹部，年轻雄鸟外观类似雌鸟，但喉部有斑点。木星蜂鸟特有的标志是臀部附近的白色斑点。","call":"其声音特征了解不多，可能的歌声是一系列有规律重复的、单一的、音调变化的吱吱声。在进食和悬停时会发出一系列单独的清脆‘tsit’声或双重‘ti-tsit’叫声。悬停时翅膀发出低沉的蜜蜂般的嗡嗡声。","habits":"通常栖息于云雾森林中适中的海拔高度，偶尔会下降至接近海平面。经常在高树顶端的裸枝上休息。","identification":"通过其独特的喉部色彩和臀部的白色斑点与其他蜂鸟种类相区分。","distribution":"分布于南美洲，具体为哥伦比亚东北部的圣马塔山脉。"},{"name":"埃斯林蜂鸟","english_name":"Esmeraldas Woodstar","scientific_name":"Chaetocercus berlepschi","overview":"埃斯林蜂鸟（英文名：Esmeraldas Woodstar，学名：Chaetocercus berlepschi），是雨燕目蜂鸟科林蜂鸟属的极小型蜂鸟，为西厄瓜多尔特有种。雄鸟拥有紫罗兰色喉部，绿色‘背心’覆盖于白色腹部之上，臀部两侧有白色斑点，尾部纤细且略呈叉状。雌鸟缺乏明显的喉部斑块，腹部带有锈色，脸部有一黑色条纹，尾部较短。栖息于沿海地区的落叶与半湿润森林，活动范围主要限于沿海山丘地带。","appearance":"雄性埃斯林蜂鸟体型微小，具有白色眼后纹，闪耀的紫色喉部，白色腹部与绿色头部及背部形成鲜明对比，尾部深叉且外侧尾羽尖锐。雌鸟淡黄色腹部带有淡淡的鲑粉色，尤其是成年皮肤的腹部和两胁，绿色背部，尾部圆润，肉桂色并带有黑色次端带，中央尾羽绿色。幼鸟特征类似雌鸟，但腹部和眼后纹为白色，上体绿色，尾部短而圆，有肉桂色基部和淡肉桂至白色的尖端。","call":"埃斯林蜂鸟在求偶时会发出机械般的翅膀声音，类似于大型昆虫的‘嗡嗡’声，同时也会发出快速连续的高音啾鸣，尤其是在花丛中觅食时。","habits":"栖息于沿海低地至海拔750米的半落叶至常绿湿润森林，偏好靠近海岸的山丘地带。它们在繁殖季节（11月至4月）活动于低海拔区域，这些地区多被人类开发用于牧场和农业，但邻近大片森林。偶尔在成熟的湿润森林内繁殖。","breeding":"繁殖期为11月至4月，营巢于小死树顶端，巢由巴尔萨木纤维和多种菊科种子构成，用蛛网粘合并以苔藓伪装。每次产卵2枚，卵白色。雄鸟在求偶时会飞至小死树顶的繁殖枝上，当雌鸟到达时，雄鸟飞升直至消失，再急速下降并发出机械声。","identification":"与小林蜂鸟雌鸟相似，但埃斯林蜂鸟雌鸟具有白色眼后纹，绿色中央尾羽，腹部更偏黄色。雄鸟间差异在于埃斯林蜂鸟的紫色喉部，而小林蜂鸟的喉部为红粉色，上体和下体更为绿色。","protection":"IUCN：VU（易危）","distribution":"埃斯林蜂鸟仅分布于南美洲西厄瓜多尔的太平洋沿岸，其栖息地包括沿海低地至海拔750米的半落叶至常绿湿润森林。","other":"埃斯林蜂鸟的生存依赖于保护区域，如Machalilla国家公园，但该区域需加强管理。Las Tunas社区视其为‘他们的鸟’，并将其视为保护旅游的一部分。"},{"name":"棕尾林蜂鸟","english_name":"Rufous-shafted Woodstar","scientific_name":"Chaetocercus jourdanii","overview":"棕尾林蜂鸟（英文名：Rufous-shafted Woodstar，学名：Chaetocercus jourdanii），是雨燕目蜂鸟科林蜂鸟属的鸟类。体型小巧、类似大黄蜂的蜂鸟，以直喙和闪亮的紫红色喉部为显著特征。雌雄差异明显，雌鸟体色更接近肉桂色，尾羽红棕色且不分叉。主要栖息于云雾森林边缘、次生林和花园中，有季节性迁移行为。在安第斯山脉，需与粉髯林蜂鸟相区别，后者雄鸟喉部紫色羽毛更长，雌鸟缺乏绿色中央尾羽。在较低海拔地区，与紫辉林星蜂鸟有区别，前者雄鸟尾羽较长，雌鸟喉部白色，尾端带白色。分布限于哥伦比亚和委内瑞拉。","appearance":"雄鸟体长约6至8厘米，具直而黑的喙，上体呈瓶绿色，喉部紫罗兰色，胸部白色，腹部绿色，翼后方有白色斑块，尾羽深叉状，黑色基部橙色。雌鸟上体铜绿色，下体肉桂色，尾羽双裂，中央尾羽绿色，其余部分红棕色带暗色横纹。幼鸟与雌鸟相似。亚种rosae雄鸟喉部玫瑰红色，andinus亚种喉部较偏玫瑰色，少紫色。","call":"雄鸟在树梢发出上升的3至4音节的‘tssit, tssit, tssit, tssit’叫声。","habits":"栖息于灌木丛、山地森林边缘、咖啡种植园，偶尔进入低矮的páramo地带，海拔900至3000米。在雨季会向低海拔移动，干季则移向较高处。在植被中层至上层觅食，采食多种开花植物和Inga树的花蜜，通过空中捕捉昆虫。不设固定领地，因体型小且飞行缓慢，可在其他蜂鸟领地内觅食。","breeding":"繁殖季节信息有限，但在哥伦比亚11月观察到处于繁殖状态的个体和两只未成年个体。具体繁殖行为、筑巢、交配等细节未知。","identification":"与粉髯林蜂鸟雄鸟相比，棕尾林蜂鸟的喉部呈圆形而非扇形，上体颜色显得更淡（更绿而非蓝绿），尾羽更长，基部和轴为红棕色。雌鸟可通过两色尾羽（暗色和红棕色）与粉髯林蜂鸟和雌鸟区分开。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲东北部，主要在委内瑞拉北部和哥伦比亚北部，偶尔在特立尼达岛有记录。在委内瑞拉的苏克雷州和莫纳加斯州有发现，特立尼达岛上的记录被认为是偶然的。亚种rosae分布在法尔孔州至米兰达州之间，andinus亚种见于哥伦比亚和委内瑞拉边境的Sierra de Perijá山脉，哥伦比亚东部安第斯山脉，以及委内瑞拉Táchira至Lara州之间的安第斯山脉。","other":"在特立尼达岛上极为罕见，多数目击记录来自北方山脉，多集中在1月至6月，最近一次记录在8月。"},{"name":"斑鼠鸟","english_name":"Speckled Mousebird","scientific_name":"Colius striatus","overview":"斑鼠鸟（英文名：Speckled Mousebird，学名：Colius striatus），是鼠鸟目鼠鸟科鼠鸟属的鸟类。以其极长的尾巴、褐色的上体和棕色的下体为显著特征。耳羽具白斑，脚呈红色。在非洲广泛分布，是该属最常见和分布最广的物种之一。","appearance":"斑鼠鸟体长约35厘米，尾部长约17至24厘米，体重在36至80克之间，通常约为50至55克。体色为暗淡的鼠灰色至灰棕色，腹部较浅，头部具黑灰色的前额、颊部和喉部，细密的黑条纹装饰在颈部和胸部，背部和臀部隐约可见。雌雄同形同色，但幼鸟的特征包括较短的冠羽、黑色裸露的颈背、背部中央有一条狭窄的白色条纹、翼覆羽边缘黄色，以及上下颌颜色的变化。不同的亚种在头部对比度、喉部颜色、条纹量、腿部颜色和虹膜颜色上有所差异。","call":"斑鼠鸟发出连续的‘tsu-tsu’声在飞行中，以及‘tisk-tisk’的警报声。","habits":"斑鼠鸟栖息于森林边缘、灌木丛、草地、花园等地，偏好开放的灌木丛生境，避开密闭的森林和干旱地带。它们以小群体活动，多达十只鸟，偶尔可达50只，主要以果实、树叶、花、花蜜为食，有时也吃昆虫。在食物稀缺时会迁移到较低海拔。","breeding":"全年均可繁殖，但在某些地区有季节性高峰，如南非的8月至1月。巢建于灌木或树上，由各种材料制成，内衬精细物质，平均孵化期为10至13天，幼鸟在17至18天首次飞行，父母和助手鸟喂养幼鸟长达一个月。","identification":"斑鼠鸟与其他鼠鸟的区别在于其黑灰色的脸部和灰棕色的冠羽，以及独特的叫声和行为。与白头鼠鸟相比，它具有不同的喙色和缺乏裸露的灰色眼眶区域。","protection":"IUCN：LC（无危）","distribution":"分布自喀麦隆向东至厄立特里亚和埃塞俄比亚，向南穿过东非至南非南部，广泛分布于坦桑尼亚全境。适宜多种生境，除雨林和更干旱的地区。","other":"斑鼠鸟在一些地区被视为严重的园艺害鸟，尤其是在埃塞俄比亚。"},{"name":"白头鼠鸟","english_name":"White-headed Mousebird","scientific_name":"Colius leucocephalus","overview":"白头鼠鸟（英文名：White-headed Mousebird，学名：Colius leucocephalus），是鼠鸟目鼠鸟科鼠鸟属的鸟类。拥有蓬松的白色头部，灰褐色的身体，以及一条长长的尾巴。主要分布于东非的干旱灌木丛生地带，包括南部索马里、肯尼亚部分地区，其分布范围仅延伸至埃塞俄比亚南部和坦桑尼亚北部。","appearance":"成年白头鼠鸟长约32厘米，其中超过一半的长度由其细长、逐渐变尖的尾巴构成。羽毛总体呈灰色，背部、颈部和胸部带有黑色和白色的条纹。最显眼的是其白色的冠羽、头顶和脸颊。飞行时，背部的一条白色条纹尤为明显。眼睛周围有一片深色裸露皮肤。喙部上半部分为蓝白色，下半部分为淡黄色。幼鸟的喉咙和胸部呈淡黄色。北部亚种（C. l. turneri）比南部形式（C. l. leucocephalus）颜色更深。","call":"白头鼠鸟的联络叫声是一种粗糙的叽喳声，还有一种下降式的歌曲。","habits":"白头鼠鸟生活在半干旱地区的干燥荆棘植被中，常见于沿水道的茂密灌木丛，通常位于海拔1400米以下。它们是定居物种，可能有一些游荡和分散的移动。以果实（如茄科植物）、叶芽和花朵（如金合欢）为食。通常以6到11只的小群体出现。","breeding":"繁殖记录显示，白头鼠鸟在索马里的7月、肯尼亚西南部和中部的6月至8月、坦桑尼亚的2月、5月至7月和11月进行筑巢。巢穴是一个开放的杯子形状，由树枝和柔韧材料制成，放置在密集的带刺灌木或树上。每窝产卵约3枚，蛋壳呈哑光白色。","identification":"与斑鼠鸟相似，但白头鼠鸟通常生活在更干燥的环境中，通过其白色的冠羽、条纹背部和大部分浅色的喙来区分。","protection":"IUCN：LC（无危）","distribution":"白头鼠鸟主要分布在非洲东部，具体包括南部索马里、肯尼亚的部分地区，其分布边缘触及埃塞俄比亚南部和坦桑尼亚北部。"},{"name":"红背鼠鸟","english_name":"Red-backed Mousebird","scientific_name":"Colius castanotus","overview":"红背鼠鸟（英文名：Red-backed Mousebird，学名：Colius castanotus），是鼠鸟目鼠鸟科鼠鸟属的鸟类。以其红或栗色的背部斑块而得名。常见于安哥拉西部和刚果民主共和国的森林边缘、灌木丛和农田地带，是当地知名的鸟类。","appearance":"红背鼠鸟体长30至38厘米，尾长20至26厘米，体重39至82克。头部、背部和翅膀为棕色，下背部和臀部有醒目的栗色斑块；尾羽长且层次分明，呈棕色；头侧和喉部灰白色；下体灰棕色，胸部略带紫红色，腹部淡黄色；上喙黑色，带有灰色斑点，下喙白色；脚和趾珊瑚红至鲜红；虹膜上半部黄色，下半部较暗呈绿色。与较为相似但体型较小的斑鼠鸟相比，红背鼠鸟背部和臀部的亮栗色更明显，且无胸部和翼覆羽的条纹。幼鸟臀部色彩较淡，翼覆羽边缘浅棕色，上喙绿色，下喙深色，虹膜深棕色。","call":"觅食时，红背鼠鸟群保持高音的持续啾啾声，其他叫声包括尖锐的'chee chee chee'声，与条纹鼠鸟的叫声难以区分。","habits":"广泛栖息于多种生境，从密林到开阔的林地和空地，偏好林地草原、森林边缘和河岸植被；也可见于荆棘灌木丛、农田、棕榈树林；海拔高度从海平面至2000米。以水果为主食，常食用栽培作物（如木瓜、香蕉、芒果、无花果）；也吃花、花蕾和嫩叶；偶尔捕食白蚁。与红脸鼠鸟形成混群。","breeding":"繁殖季节在12月和1月，但全年都有处于繁殖状态的个体。巢为碗状，相对较大，结构粗糙，但杯底铺有细软材料；巢位一般位于树上3至4米的高度，藏于茂密枝叶间。已知巢中蛋数为1至4枚，蛋壳呈白色，尺寸约21.7至22.6毫米×17至18毫米；孵化由双亲共同承担，持续12至14天；雏鸟仅有稀疏的灰色绒毛，约11天后离巢，但直到21天大才能飞行。","identification":"红背鼠鸟与斑鼠鸟区别在于背部和臀部的亮栗色，以及缺乏翼覆羽、喉部和胸部的条纹。","protection":"IUCN：LC（无危）","distribution":"红背鼠鸟主要分布在安哥拉西部，从扎伊尔省（Soyo）向东至马兰热（可能延伸至Lunda Norte），并向南至纳米贝（Moçâmedes）。","other":"红背鼠鸟在圈养环境下的最长寿命记录为12年零3个月。"},{"name":"白背鼠鸟","english_name":"White-backed Mousebird","scientific_name":"Colius colius","overview":"白背鼠鸟（英文名：White-backed Mousebird，学名：Colius colius），是鼠鸟目鼠鸟科鼠鸟属的体型较大的鸟类。其独特之处在于灰白色条纹的超长尾羽，尾部长度几乎与身体等长，可达29-32厘米，体重介于38-64克之间。白背鼠鸟分布于非洲西部和中部南部地区，从纳米比亚和博茨瓦纳南部向东至南非中央特兰斯瓦尔和东开普省。","appearance":"成年白背鼠鸟具有轻灰色头部、羽冠和上体，背部有一条窄白色条纹，两侧由更宽的黑色条纹包围，通常被翅膀遮掩，仅在特定姿态下可见。明亮的酒红色臀部斑块显著，长长的尾羽呈渐变状。面部的眉纹区、下巴和上喉部为深灰至黑色，腹部为淡黄色，胸部带有紫罗兰色调。翅膀下方呈现引人注目的黑白相间图案，喙为蓝白色，尖端黑色，腿和脚为珊瑚红色，虹膜呈深棕色。幼鸟缺乏成鸟的酒红色臀部斑块，下巴和喉咙颜色较浅，胸部呈淡黄色，喙上部为蓝绿色，下部为暗灰色。","call":"发出短促尖锐的嗡嗡声，接触和飞行叫声类似于但比斑鼠鸟更为悦耳，例如\"zwee, wewit\"，每个短语通常以2-3个尖锐、甜美的哨音开始，逐渐过渡到一系列14个噼啪声，持续约15秒，以\"krik, krik\"结束。","habits":"栖息于多种树木和灌木丛生的环境，尤其偏好半干旱和干旱地带的河流带树丛，如金合欢、Euclea和Rhus。它们是定居性鸟类，但在某些条件下可能进行游荡移动。主要食物来源为各种水果、叶子、花朵和花蜜，已知在南非的饮食中包含27种水果、7种叶子和4种花朵。在卡鲁地区，Lycium的浆果被认为尤为重要；在纳米布沙漠，Salvadora persica极为重要。其他重要食物来源包括Phoenix、Sideroxylon、Ehretia、Ficus、Rhus、Diospyros、Euclea和Olea等属植物，这些同样为斑鼠鸟和红脸鼠鸟所重视。","breeding":"全年皆可繁殖，高峰期出现在9月至12月（雨季），多数地区繁殖期延长至次年1月至4月。一夫一妻制，领地性，但合作繁殖，巢杯形状，内部尺寸约为60毫米×45毫米，由枝条、茎和草构成，衬以细草、植物绒毛、蜘蛛网、羊毛和羽毛，经常用开花的枝条装饰。巢建于1.2至6米高（最常见1.5至2.5米）的浓密、常带刺的树木或灌木旁，偶尔靠近黄蜂巢。每窝平均产蛋3.1枚，总数1至8枚，间隔至少一天产一枚，孵化由双亲共同承担，但孵化期未知。雏鸟孵化26天后能够进行短距离飞行。","identification":"与其他鼠鸟种类相比，白背鼠鸟具有独特的背部白色条纹和两侧的黑色条纹，以及鲜明的酒红色臀部斑块。喙为蓝白色，尖端黑色，腿和脚为珊瑚红色，这些特征帮助区分它与斑鼠鸟等近缘种。","protection":"IUCN：LC（无危）","distribution":"分布于非洲的纳米比亚至博茨瓦纳南部，向东南延伸至南非，包括中央特兰斯瓦尔和东开普省。","other":"在适宜的农业灌溉区域和相关的人类居住地，如果园、农场和花园中，白背鼠鸟数量有所增加，显示了对人类活动的适应性。"},{"name":"蓝枕鼠鸟","english_name":"Blue-naped Mousebird","scientific_name":"Urocolius macrourus","overview":"蓝枕鼠鸟（英文名：Blue-naped Mousebird，学名：Urocolius macrourus），是鼠鸟目鼠鸟科长尾鼠鸟属的鸟类。体长33-36厘米，头部羽毛松软，颈部羽毛呈独特的蓝色光泽；尾羽细长，使整个身体显得较为丰满，体色以灰白至褐色为主。喙部及眼部周围裸露皮肤为红黑色，脚趾结构独特，四趾均能向前伸展，利于抓握树枝。广泛分布于非洲的干燥地区，从西非至东非，包括撒哈拉沙漠边缘地带。","appearance":"蓝枕鼠鸟身长约33至36厘米，包括20至28厘米的延长尾羽。成鸟体羽灰白偏暗，头部后方和颈背有鲜艳的蓝绿色斑块，尾羽细长并呈陡峭梯度排列，雄鸟尾羽更长。上体略带棕色调的灰，下体灰黄，脸部裸露部分和眼周皮肤为深红色，上喙大部为深红色，余部黑色，脚呈紫红色。幼鸟无蓝色斑块，面部皮肤粉红，喙绿，冠羽较短。","call":"蓝枕鼠鸟会发出响亮清晰的哨音“tieee”，每3至5秒重复一次，尤其当单独站立于树顶时。觅食时，叫声变得较短弱，间隔时间拉长至10至15秒。群体在离开觅食区前会集体发出“trie-trie”，飞行前则连续快速发出“tsie-tsie...”。飞行中，叫声变为“trui-tru-tri”、“triu-triu”或“tri-truu-truu...”。求偶期间，雌鸟乞食声为“cruir-uu-tuit-truit”，雄鸟则发出“tiuee-tuiee...”。","habits":"蓝枕鼠鸟栖息于半干旱地区的开放林地和灌木丛，包括荆棘灌木丛、草原、开阔的金合欢林地；常见于沿水道和井边的灌木丛、枣椰树园、农田、村落边缘、城镇及花园。分布海拔自海平面至1900米，在肯尼亚通常低于1600米，但在埃塞俄比亚可达2000米。在旱季，它们会从草原林地迁移到河流谷地和人类居住区。主要以果实为食，辅以树叶、花朵和花蕾。","breeding":"繁殖期全年都有，但随地区不同有所差异，通常在雨季或雨季刚过时达到高峰：尼日利亚的5月至6月，北苏丹的5月至6月和12月至2月，埃塞俄比亚的4月至7月，肯尼亚的5月，扎伊尔的3月至6月。一夫一妻制，在圈养条件下，配偶关系可维持数年，可能具有领域性，也可能为合作繁殖。巢穴由雌雄共同构建，位于3至4.5米高的树或荆棘丛中，通常为浅杯状，由枝条构成，内衬草和根须。","identification":"与红脸鼠鸟的区别在于蓝枕鼠鸟的颈部蓝色斑块和灰而非黄的下体羽毛。不同亚种间存在颜色深浅和体型大小的差异。","protection":"IUCN：LC（无危）","distribution":"蓝枕鼠鸟广泛分布于非洲，从塞内加尔至埃塞俄比亚和肯尼亚，遍及索马里，在尼日利亚北部已变得不常见。在西非至东非的干旱地区，包括撒哈拉沙漠边缘地带，均有其踪迹。"},{"name":"红脸鼠鸟","english_name":"Red-faced Mousebird","scientific_name":"Urocolius indicus","overview":"红脸鼠鸟（英文名：Red-faced Mousebird，学名：Urocolius indicus），是鼠鸟目鼠鸟科长尾鼠鸟属的鸟类。常见于非洲南部的鼠鸟科长尾鼠鸟属鸟类。从刚果民主共和国、赞比亚和坦桑尼亚南至南非开普省均有分布。栖息于灌木丛生的稀树草原、灌木丛、开放林地、花园和果园。","appearance":"红脸鼠鸟长约34厘米，其中尾部占半数长度。头部和胸部呈淡肉桂色，拥有红色的喙和眼罩。上体和尾羽为蓝灰色，仅臀部呈淡灰色，腹部为白色。两性相似，但幼鸟无冠羽，面部为绿色。共有五个认可的亚种。","call":"发出清晰悦耳的三到四个音节的哨声，如'tree-ree-ree'或'ti-wi-wi-wi'，首音稍重，无论是在飞行中还是栖息时都会鸣叫。","habits":"主要栖息于有灌木丛的稀树草原，广泛出现在各种灌木、灌木丛和林地，避免密集森林和开阔草地。常见于河流灌木丛、棕榈树林、果园和花园。以果实为主食，偶尔食用叶片、花蕾、花朵和花蜜。在南非，观察到它们会摄取Aloe marlothii的花蜜。也会食用一些动物性食物，如绦虫。","breeding":"繁殖季节通常在9月至翌年4月，筑巢于荆棘树或灌木中，高度约1.3至6米，巢由干枝构成，内部衬以柔软材料。每窝产2至6枚蛋，孵化期约为两周。巢中可能有多只雌鸟共同产卵。幼鸟出生后约10天可能离巢，14至20天后离巢。","identification":"与蓝枕鼠鸟相比，颜色更深，额部为肉桂色，颈后无蓝色斑块。与Colius属物种的区别在于其灰暗的羽毛和眼部周围裸露的红色皮肤。","protection":"IUCN：LC（无危）","distribution":"广泛分布在南部非洲，包括刚果民主共和国南部、赞比亚、坦桑尼亚至南非开普省。"},{"name":"角咬鹃","english_name":"Eared Quetzal","scientific_name":"Euptilotis neoxenus","overview":"角咬鹃（英文名：Eared Quetzal，学名：Euptilotis neoxenus），是咬鹃目咬鹃科角咬鹃属的大型鸟类。以山地松林和松橡树林为家，主要分布于墨西哥西北部的Sierra Madre Occidental山脉，偶尔在东南亚利桑那州作为稀客出现。其最显著的特征是头部两侧的细长耳羽，通常不易在野外观察到。雄鸟的头、喉为暗黑色，胸呈青铜绿色，腹部及下尾覆羽鲜红，背及上翼覆羽绿至蓝绿色。雌鸟相似但色泽较淡，幼鸟则有更广泛的黑色下尾覆羽。","appearance":"角咬鹃体型较大，长度约33至36厘米，具有一副短而粗的喙和宽阔的方形尾巴。雄鸟头部黑色，胸部青铜绿色，腹部及下尾覆羽鲜红，背部及上翼覆羽绿至蓝绿色，尾羽上部蓝绿色，下部白色。雌鸟头部、胸部及上腹部灰色，下腹部红色较浅。幼鸟头部及胸部褐色，下尾覆羽大部分为黑色，仅尾端有白色。两性均具有细长的耳羽，但野外很难察觉。","call":"角咬鹃的叫声独特，包括一系列音量渐增的哨音，低强度的尖叫声逐渐升高，响亮的尖叫声以\"chuck\"结尾，以及飞行中发出的尖锐笑声。","habits":"栖息于中高海拔的松林、松橡树林及松常绿森林，高度介于1700至3000米之间。它们偏好沿溪流的森林地带。角咬鹃以昆虫、小型脊椎动物和果实为食，包括马德龙树的红色果实。它们在飞行中捕食或悬停摘食。","breeding":"角咬鹃在树洞中筑巢，通常选择旧啄木鸟的洞穴，巢位高度5至9米。巢内无衬垫，孵化期和育雏期较长，分别为28至31天和17至21天。巢址可能位于松树、冷杉、枫树或白杨树。","identification":"角咬鹃与同域的其他咬鹃相比，体型更大，头部较小，喙呈灰蓝色，色彩模式独特。与高山美洲咬鹃和优雅美洲咬鹃相比，尾部下侧的白色部分更多，且无条纹。雄鸟三者的红绿相间的外观相似，但在当地居民眼中，它们通常不被区分开来。","protection":"IUCN：LC（无危）","distribution":"主要分布于墨西哥西北部的Sierra Madre Occidental山脉，偶尔出现在美国东南亚利桑那州和新墨西哥州东南部。","other":"由于栖息地受伐木影响大幅减少，角咬鹃面临威胁。"},{"name":"彩绿咬鹃","english_name":"Pavonine Quetzal","scientific_name":"Pharomachrus pavoninus","overview":"彩绿咬鹃（英文名：Pavonine Quetzal，学名：Pharomachrus pavoninus），是咬鹃目咬鹃科绿咬鹃属的鸟类。居住在新热带区，具体位于亚马逊盆地的北部，自哥伦比亚延伸至玻利维亚。彩绿咬鹃以其独特的羽毛色彩、红喙（仅限雄鸟；雌鸟喙色灰暗）、以及其栖息在安第斯山脉以东低地雨林的分布而著名。","appearance":"雄性彩绿咬鹃具有金色头部，金属蓝绿色上体和上胸，红腹至尾下覆羽。雌鸟色彩较暗淡，喙色黑中带红，腹部棕色，尾下覆羽具灰色条纹。两性均有延长的翼覆羽和上尾覆羽，后者可延伸至尾尖甚至更远。尾下覆羽黑色。","call":"彩绿咬鹃的叫声是一系列五个悠扬的音符，通常描述为“ew ewwo-ewwo-ewwo-ewwo”，并伴随下降的哨声后跟有力的音符“heeeeeear, chok！”。","habits":"栖息于排水良好的高海拔（terra firme）森林中间层和边缘，偏好低地雨林。它们偶尔加入混种群觅食。食性上，主要以果实为食，偶尔捕食昆虫。飞行时使用快速、波动的翼拍。","breeding":"在亚马逊地区，2月观察到巢穴位于森林中枯木9米高的洞中。在秘鲁东北部苏库萨里地区，7月中旬观察到巢中有成熟的雏鸟，巢穴位于死树干约5米高处。","identification":"与金头绿咬鹃相似，但平均体型略小，喙色不同，头部色泽更少金色，羽毛较短。雌鸟与金头绿咬鹃雌鸟的区别在于喙色、头部和胸部色调以及尾下覆羽图案。","protection":"IUCN：LC（无危）","distribution":"彩绿咬鹃全年栖息于亚马逊盆地，分布于委内瑞拉、巴西、哥伦比亚东南部、厄瓜多尔东部、秘鲁和玻利维亚北部。具体可见于委内瑞拉的亚马逊和罗赖马州，巴西的亚马逊和罗赖马州，玻利维亚的贝尼和潘多州等地。","other":"彩绿咬鹃属于咬鹃科，其趾排列独特，第一和第二趾向后，适合于在树上站立而非行走或跳跃。它们主要通过飞行或在树冠下层停留的方式活动。"},{"name":"金头绿咬鹃","english_name":"Golden-headed Quetzal","scientific_name":"Pharomachrus auriceps","overview":"金头绿咬鹃（英文名：Golden-headed Quetzal，学名：Pharomachrus auriceps），是咬鹃目咬鹃科绿咬鹃属的鸟类。最显著特征为头部闪耀的金色和翅膀及胸部的金属光泽绿色羽毛，分布于中美洲东部巴拿马到南美洲北部玻利维亚的湿润中海拔森林。","appearance":"雄性金头绿咬鹃体重约154-182克，全长33-36厘米，尾羽延长可达8-10厘米。上体闪烁着金属光泽的金色绿色，视光线角度不同可能呈现蓝色。雄鸟头部呈金色青铜色，而雌鸟的头部和胸部则为较暗的棕色，嘴部颜色在雄鸟中为黄色，雌鸟为灰褐色。两性均具有黑色下尾，但雌鸟有时可见灰色白尖。幼鸟为棕色黑色，颈部和胸部有零星的绿色光泽羽毛。","call":"发出悠远、哀伤的鹰鸣式哨声，重复6-8次，类似‘whe-wheeu, whe-wheuu, whe-wheeu...’，还有急促的嘶鸣声‘why-dy-dy-dy-dyyrrr’，‘hoo-whoooooy’以及悲伤的喉音‘ka-kaaaur’。","habits":"栖息于中高海拔的湿润森林，偶尔出现在林缘、开阔地带的散树环境，高度从1200米至3100米不等。它们通常独居，但在繁殖季节形成一夫一妻制的配对。以果实为主食，偶尔捕食昆虫，对于果实种子的传播起到关键作用。","breeding":"在繁殖季节，雄鸟通过领地标记和鸣叫吸引雌鸟。它们会在腐朽的树干或旧树的空洞中挖掘巢穴，雌鸟产下1-2枚淡蓝色的蛋，主要由雌鸟孵化。幼鸟出生时盲目且无毛，孵化和喂养任务由双亲共同承担，幼鸟大约在25-30天后离巢。","identification":"与彩绿咬鹃的区别在于喙和头部的颜色。与非常相似的凤头绿咬鹃相比，雄鸟头部金色青铜色，无前额冠羽，雌鸟下尾无条纹。幼鸟的次级飞羽有浅色边缘，尾羽末端有模糊的淡色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东部巴拿马至南美洲北部玻利维亚，具体包括巴拿马的Cerro Pirre山区，哥伦比亚南部至秘鲁东部和玻利维亚北部的安第斯山脉。","other":"该物种在繁殖区和非繁殖区的分布信息中，提到了巴拿马、哥伦比亚、厄瓜多尔、委内瑞拉和秘鲁等地的具体地理范围。"},{"name":"白尾梢绿咬鹃","english_name":"White-tipped Quetzal","scientific_name":"Pharomachrus fulgidus","overview":"白尾梢绿咬鹃（英文名：White-tipped Quetzal，学名：Pharomachrus fulgidus），是咬鹃目咬鹃科绿咬鹃属的鸟类。优雅的大体型咬鹃。其特征为黑色尾羽尖端带白色，缺乏冠羽。上体与胸部呈金色调绿色，腹部鲜红色，喙黄色。雌鸟具灰色喙，下胸灰棕色，尾下覆羽带白色条纹及尖端。仅分布于南美洲委内瑞拉北部和哥伦比亚北部山区，常在成熟云雾林中单独或成对活动。","appearance":"雄性白尾梢绿咬鹃拥有金绿色调的上体和胸部，鲜红的腹部，黑色的翅膀与尾部，尾羽下方白色尖端明显。喙黄色，脚棕色。雌鸟外观较不鲜艳，喙灰棕色至铜灰色，下胸和腹部灰棕色，尾羽尖端狭窄白色。幼鸟的翼羽边缘有淡色，尾羽白色尖端更窄，羽毛形状比成鸟尖锐。","call":"鸣唱为响亮而忧郁的一系列‘WHOOOou hoo hoou’声，叫声与斑林隼相似。","habits":"栖息于海拔900至2500米的成熟云雾林，从亚热带至温带森林，有时也会出现在次生林和森林边缘。以果实和浆果为主食，偶尔捕食大型蜥蜴。飞行迅速，但不会长距离飞行。","breeding":"繁殖季节为旱季末期，大约1月至4月间。巢通常位于死树干的旧啄木鸟洞穴中，高4至10米。每窝产2至4枚白色或淡彩色蛋。幼鸟孵化后裸身，快速换羽，无明显的绒羽阶段。约三周后离巢，第二次基本换羽后获得成年羽毛。","identification":"白尾梢绿咬鹃在其分布区内无重叠物种，体型大于区域内其他咬鹃。与金头绿咬鹃和彩绿咬鹃相比，前额羽毛更长，头部颜色更金黄，尾羽下部三分之一白色，形成显著区别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲委内瑞拉北部山地和哥伦比亚东北部的圣玛尔塔山脉，海拔900至2500米。在哥伦比亚的Sierra Nevada山区也有分布。","other":"尽管是分布范围最小的绿咬鹃，但在其范围内相对常见。"},{"name":"凤尾绿咬鹃","english_name":"Resplendent Quetzal","scientific_name":"Pharomachrus mocinno","overview":"凤尾绿咬鹃（英文名：Resplendent Quetzal，学名：Pharomachrus mocinno），是咬鹃目咬鹃科绿咬鹃属的鸟类。是咬鹃科中体型最大、色彩最为绚烂的物种，分布于中美洲从墨西哥南部至巴拿马西部的热带云雾林中。不仅是危地马拉的国鸟，还是该国货币名称的灵感来源。雄鸟拥有长达身体长度的翡翠绿色尾羽，雌鸟虽不如雄鸟鲜艳，但同样具有独特的绿色光泽。","appearance":"凤尾绿咬鹃的体长在36至40厘米之间，雄鸟尾羽在繁殖季节可达到64厘米。体重约为210克。雄鸟的头部装饰有类似头盔的冠毛，胸部为醒目的红色，身体其余部分呈现金属绿至蓝紫色的变幻光泽。雄鸟成鸟的喙呈黄色，而雌鸟的喙为灰色。雌鸟体型较小，尾羽较短，缺乏雄鸟的耀眼色彩。","call":"凤尾绿咬鹃的叫声异常高亢，通常被描述为尖锐的kyow声，它们常成对鸣叫，声音单调却持续重复。","habits":"凤尾绿咬鹃主要栖息于中美洲的云雾森林，高度在900至3200米之间。它们是特化的食果动物，偶尔捕食昆虫、蛙类等。对于它们而言，牛油果及其家族成员是极其重要的食物来源。它们会吞下整个果实，之后通过反刍的方式帮助种子的传播。","breeding":"繁殖季节通常在每年的三月至五月间开始。雌鸟会在腐朽的大树上挖掘巢穴，产下1至3枚淡蓝色的蛋，孵化期大约为17至19天。雄鸟和雌鸟都会参与孵卵，雄鸟在白天负责，而雌鸟则在夜间接手。孵化后，父母双方共同喂养幼鸟，以水果、昆虫和小型动物为食。","identification":"凤尾绿咬鹃雄鸟的独特长尾和鲜艳色彩使其极易辨认。雌鸟与雄鸟相比，体型较小，色彩较为低调，尾羽较短。与其他咬鹃科鸟类相比，凤尾绿咬鹃的体型更大，颜色更加丰富。","protection":"IUCN：NT（近危）","distribution":"凤尾绿咬鹃分布于中美洲，从墨西哥南部至巴拿马西部。两个亚种分布区域不同，P. m. mocinno在墨西哥南部、萨尔瓦多北部、尼加拉瓜西北部、危地马拉和洪都拉斯，而P. m. costaricensis则在哥斯达黎加和巴拿马西部。","other":"凤尾绿咬鹃在中美洲文化中具有重要地位，被视为自由与财富的象征。"},{"name":"凤头绿咬鹃","english_name":"Crested Quetzal","scientific_name":"Pharomachrus antisianus","overview":"凤头绿咬鹃（英文名：Crested Quetzal，学名：Pharomachrus antisianus），是咬鹃目咬鹃科绿咬鹃属的鸟类。其显著特征为雄鸟头部和背部闪烁着金属绿色光泽，腹部为红色，独特的额顶羽簇为本物种独有。分布于南美，从委内瑞拉至玻利维亚北部，常见于海拔1200-3000米的山地森林。","appearance":"成年凤头绿咬鹃体长约33-34厘米。雄鸟头部与上体呈现金属绿色光泽，胸部至腹部为红色。雄鸟额顶具短羽簇，喙橙黄色，雌鸟头部及上胸为褐色，无额顶羽簇。雌雄两性均具有红色眼睛。","call":"其鸣叫声为响亮而抑扬顿挫的“way-way-wáyo”，报警声为连串的“ka-ka-ka-ka”。","habits":"栖息于中高海拔的热带和亚热带湿润森林，偏好云雾林边缘及成熟的次生林地带。以果实为主食，繁殖季节也会捕捉昆虫和小型脊椎动物。通常单独或成对活动，偶尔聚集于丰富食物源。","breeding":"关于凤头绿咬鹃的繁殖细节记录较少，一般在适宜的栖息环境中筑巢繁殖。","identification":"与相似的金头绿咬鹃相比，凤头绿咬鹃雄鸟的额顶羽簇较短，雌鸟头部颜色较暗淡。此外，凤头绿咬鹃的尾部没有延长的尾羽流苏。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的安第斯山脉沿线，从委内瑞拉至北玻利维亚，包括哥伦比亚、厄瓜多尔和秘鲁等地。","other":"虽然在某些地区较为罕见，如哥伦比亚的Munchique国家公园，但在其大部分分布区内被认为是相对常见的物种。"},{"name":"古巴咬鹃","english_name":"Cuban Trogon","scientific_name":"Priotelus temnurus","overview":"古巴咬鹃（英文名：Cuban Trogon，学名：Priotelus temnurus），是咬鹃目咬鹃科古巴咬鹃属的鸟类。古巴特有种，亦是古巴的国鸟。其羽毛颜色与古巴国旗相呼应，包括蓝绿色的背、灰色的胸及醒目的红色腹。广泛分布于古巴主岛及其周边大岛，尤其偏好山地森林。","appearance":"古巴咬鹃体长23至28厘米，体重47至75克。雄鸟具红粉的喙，面部黑色，眼虹膜红色，头顶及颈背暗蓝，背部绿带金属光泽。雌雄羽色相似，但雌鸟腹部红色较淡。幼鸟色彩较暗淡。尾羽呈月牙形，翅膀有黑白条纹。","call":"发出重复的‘toco-toco-tocoro-tocoro…’悦耳歌声，间歇性长时段重复。另有低沉哀婉的呼唤声，定位困难。","habits":"栖息于湿、干森林及靠近水道的灌木丛，偏爱阴凉地带，海拔可达1300米。以昆虫、果实和花为食，偶尔捕食小型蜥蜴。飞行风格断续嘈杂。","breeding":"繁殖季主要在4月至7月，巢建于啄木鸟遗弃的洞穴或自然空洞中，离地面高度至少4.5米。每窝产卵3至4枚，白色或蓝白色。孵化及育雏细节未知。","identification":"蓝绿色背、灰色胸、红色腹，尾羽月牙形，易于识别。叫声独特，便于定位。","protection":"IUCN：LC（无危）","distribution":"分布于古巴主岛及周边大岛，如卡马圭省岸外的几个大岛和青年岛（Isla de la Juventud）。","other":"曾广泛分布于松树岛南部，现已变得罕见。"},{"name":"伊岛咬鹃","english_name":"Hispaniolan Trogon","scientific_name":"Priotelus roseigaster","overview":"伊岛咬鹃（英文名：Hispaniolan Trogon，学名：Priotelus roseigaster），是咬鹃目咬鹃科古巴咬鹃属的鸟类。特有于加勒比海的伊斯帕尼奥拉岛（海地和多米尼加共和国）。仅有的两种加勒比海咬鹃之一，以其金属绿色的背部、灰色胸部、红色腹部和带有鲜明白色尖端的深蓝色尾巴而闻名。作为海地的国鸟，伊岛咬鹃是该岛上独有的壮观物种。","appearance":"伊岛咬鹃拥有醒目的外观，其上体呈金属绿色，喉部和胸部灰色，腹部鲜红。尾巴的底面为暗色，但每根尾羽末端有显著的白色斑点。雄鸟和雌鸟的外观相似，但雌鸟的翼盖和次级飞羽缺少窄白条纹。成年雄鸟的平均测量值为翼长135.2毫米，尾长154毫米，喙基至尖端长17.3毫米，跗跖长16.8毫米。雌鸟的平均测量值为翼长136.6毫米，尾长154毫米，喙基至尖端长16.5毫米，跗跖长16.4毫米。","call":"伊岛咬鹃的鸣唱缓慢，可以在相当远的距离被听到，声音低沉，有颤音。叫声包括尖锐的‘whee’声和柔和的咕咕声，尽管鸣叫频繁，但由于其声音的拟声效果，定位鸣叫的鸟并不容易。","habits":"伊岛咬鹃栖息于亚热带或热带湿润的山地森林和重度退化的森林中，主要在海拔500至3000米的高度活动。它在冬季可能会进行一定程度的垂直迁移，降至更低的海拔。在海地，由于广泛的栖息地丧失，它现在仅限于Hotte山脉和Selle山脉。","breeding":"繁殖季节从三月至七月，伊岛咬鹃会在树洞中筑巢，包括使用伊岛啄木鸟的树洞。已知的巢穴中通常有两枚蛋，蛋壳颜色为浅绿色，无斑点。蛋的尺寸范围从27.9 x 23.5毫米到31.4 x 23.9毫米。孵化期和雏鸟成长期的长度未知，估计世代长度为7.3年。","identification":"伊岛咬鹃在其分布范围内没有相似物种，与近缘的古巴咬鹃相比，它的尾巴更典型，具有明显的白色尖端。雄鸟和雌鸟在外表上相似，但雌鸟的翼盖和次级飞羽没有窄白条纹。","protection":"IUCN：LC（无危）","distribution":"伊岛咬鹃仅分布于伊斯帕尼奥拉岛，包括海地和多米尼加共和国。它在海地的分布受到限制，主要存在于Hotte山脉和Selle山脉，而在多米尼加共和国较为常见，尤其是在相对未受干扰的Sierra de Baoruco山区。","other":"伊岛咬鹃的食物主要包括昆虫，但也吃小型脊椎动物如壁虎和水果，尤其是西印度漆树（Brunellia comocladifolia）的果实。"},{"name":"花尾美洲咬鹃","english_name":"Lattice-tailed Trogon","scientific_name":"Trogon clathratus","overview":"花尾美洲咬鹃（英文名：Lattice-tailed Trogon，学名：Trogon clathratus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。主要分布在中美洲的哥斯达黎加和巴拿马，以其独特的淡色眼睛和鲜明的绿红相间羽毛著称。","appearance":"成年雄鸟拥有黄色喙和近乎白色的虹膜，脸部、喉部为黑色，头部、颈背、上身和胸部为绿色，腹部至下尾覆羽呈玫瑰红色。雌鸟相似，但上身为灰褐色，取代了雄鸟的绿色，胸部橄榄灰色。幼鸟类似成鸟，但尾羽更尖，条纹更粗，雄鸟胸部大部分为棕色。","call":"发出一系列约15个响亮、回音强烈的‘kwa’音节，音调和音量逐渐升高至中间部分，随后变得更快、更低沉和更柔和。","habits":"栖息于成熟的湿润到湿润的山脚和低山区森林的中层和较低的树冠，常在森林内部活动，偶尔出现在边缘和阴凉的半开放景观。海拔高度范围在90至1360米之间，雨季结束时会下降到较低海拔。","breeding":"繁殖季节从二月持续到五月，巢穴位于腐烂树木或枯木中的洞穴，有时在树栖白蚁丘中，通常离地面5至8米。饮食以水果和大型昆虫为主，偶尔捕食小青蛙和蜥蜴。","identification":"与非常相似的灰尾美洲咬鹃相比，花尾美洲咬鹃具有更鲜艳的腹部颜色、更深蓝色的尾巴和不同的尾下覆羽图案。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲的哥斯达黎加和巴拿马，主要沿加勒比海斜坡，局部在巴拿马的太平洋斜坡也有发现。"},{"name":"灰尾美洲咬鹃","english_name":"Slaty-tailed Trogon","scientific_name":"Trogon massena","overview":"灰尾美洲咬鹃（英文名：Slaty-tailed Trogon，学名：Trogon massena），是咬鹃目咬鹃科美洲咬鹃属的鸟类。常见于中美洲热带雨林低地。其显著特征为红腹、绿头背及橙色喙。分布自墨西哥南部至厄瓜多尔东北部，偏好栖息于茂密森林内部，亦可见于边缘地带及开阔地带的大树上层。","appearance":"雄鸟个体上身呈金属绿色，背部略带金色，头部和臀部偏蓝绿色，翅膀暗灰色并带有细小黑白色条纹，腹部深红色，尾下覆羽灰石板色，喙橙色，眼环橙红。雌鸟整体暗灰色，仅腹部红色，喙上部暗灰色，下部橙色。幼鸟具白色尾尖及翼缘，腹部颜色类似雌鸟。","call":"发出一系列深沉的鸣叫声，被描述为‘wuk, wuk, wuk’，另有安静的‘huh-huh-huh-huh’声及‘chuckling chatter’。","habits":"栖息于热带雨林中层至树冠，偏好湿润低地，偶尔在次生林、河岸林、咖啡种植园及红树林出现。以果实和昆虫为食，常跟随白脸卷尾猴以捕食被惊扰的昆虫。","breeding":"繁殖季节从2月至7月不等，通过尾羽展示吸引配偶。巢穴筑于白蚁巢或腐木中的洞穴，高度可达15米，通常产两到三个白色或蓝白色的蛋，双亲共同孵化。","identification":"与黑尾美洲咬鹃和白眼美洲咬鹃相似，但可通过尾下覆羽颜色、喙色及是否存在白带区分。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，具体涵盖墨西哥东南部至厄瓜多尔东北部，包括中美洲低地及局部海拔高达1,400米的地区。"},{"name":"白眼美洲咬鹃","english_name":"Choco Trogon","scientific_name":"Trogon comptus","overview":"白眼美洲咬鹃（英文名：Choco Trogon，学名：Trogon comptus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。分布于哥伦比亚西部和厄瓜多尔西北部的雨林中，以其独特的白色眼睛和多彩的羽毛著称。","appearance":"雄鸟身长约28厘米，体重约104克，具有黄色喙，黑色脸庞和喉部，白色虹膜，绿色头部、背部和胸部略带蓝色调，臀部和尾羽紫蓝色，腹部及尾下覆羽鲜红色；雌鸟喙上颚呈板岩色，头部、背部、翅膀及尾羽灰暗，胸部至腹部中部灰色，下腹部至尾下覆羽红色。","call":"其鸣唱是一系列缓慢重复的7至15个'cow'音符，叫声为快速连续的'krr-krr-krr'。","habits":"栖息于低地至海拔1800米的湿润森林和边缘地带，偏好丘陵地形，通常在树冠层长时间停留，偶尔飞扑捕食水果或昆虫。","breeding":"繁殖季节未知，但在三月曾观察到处于繁殖状态的个体。","identification":"与灰尾美洲咬鹃的区别在于喙为黄色而非橙色，与厄瓜多尔咬鹃不同，胸部无白色斑点。","protection":"IUCN：LC（无危）","distribution":"南美洲：哥伦比亚西部，厄瓜多尔西北部。","other":"为限制分布物种，出现在Nechí Lowlands和Chocó生物多样性热点区。"},{"name":"厄瓜多尔咬鹃","english_name":"Ecuadorian Trogon","scientific_name":"Trogon mesurus","overview":"厄瓜多尔咬鹃（英文名：Ecuadorian Trogon，学名：Trogon mesurus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。曾被视为黑尾美洲咬鹃的一个亚种，主要分布于南美洲厄瓜多尔西部和秘鲁西北部的湿润森林中。雄鸟拥有鲜艳的红色腹部，而雌鸟则呈灰色调，两者皆具有白色的虹膜。该鸟种的自然历史研究尚浅，但已知其以果实和节肢动物为食。","appearance":"雄性厄瓜多尔咬鹃上体为亮丽的绿色，具蓝色臀部，上胸与绿色喉部相连，下胸至腹部为深红色，两者间由白色带状条纹相隔。雌鸟上体及喉部为淡灰石板色，头侧黑色，翼覆羽黑色石板色，下胸和腹部为亮红色。两性尾羽上表面绿色，下表面均为黑色。","call":"鸣唱为一系列悠闲的口哨声或呼呼声，通常起始缓慢而后增强。","habits":"栖息于海拔1000米以下的湿润森林、次生林和森林边缘地带，常长时间静立于树干枝上，偶尔飞出捕食果实或昆虫。","breeding":"巢筑于活跃的树栖白蚁巢穴中，一窝产三枚卵，由两性共同孵化。","identification":"与白眼美洲咬鹃相似，但后者缺乏白色胸带，雄鸟无红眼环，且颜色更为纯绿。不与黑尾美洲咬鹃或灰尾美洲咬鹃共域。","protection":"IUCN：LC（无危）","distribution":"分布于厄瓜多尔西部和秘鲁西北部，主要栖息于低地至海拔约2000米的湿润森林和半落叶林。","other":"其分类地位经过遗传学研究后，于21世纪初被确认为独立物种。"},{"name":"黑尾美洲咬鹃","english_name":"Black-tailed Trogon","scientific_name":"Trogon melanurus","overview":"黑尾美洲咬鹃（英文名：Black-tailed Trogon，学名：Trogon melanurus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。主要分布在中美洲的巴拿马至南美洲的委内瑞拉，广泛见于亚马孙雨林。这种大型咬鹃以其红腹和粗壮的黄色喙著称，雄鸟的头部、颈部、上部和胸部呈绿色，具有一条白色胸带，与红色腹部形成鲜明对比；雌鸟头部和胸部呈灰色。在巴拿马和北部南美洲的热带森林中，生活在树冠和中层。","appearance":"黑尾美洲咬鹃体长28至30厘米，体重52至122克。雄鸟具有黄色喙和橙红色眼环，脸部和喉部黑色，头顶、颈背、上身和胸部绿色，白色胸带和红色腹部形成鲜明对比。尾羽上部深蓝色，下部暗灰色。雌鸟喙上部灰暗，头部、上身、翅膀和尾巴呈暗灰色调，喉部至中腹部颜色较浅，下腹部红色延伸至尾下覆羽。T. m. macroura亚种翼部斑纹更粗，尾羽上部蓝绿色更明显，翼和尾更长；T. m. eumorphus亚种翼部较暗，尾部更蓝，白色胸带更窄。","call":"发出缓慢的一系列低沉‘coop’声，类似灰尾美洲咬鹃的叫声，但音符更响亮、更浑厚，可能发音更快，连续发出‘kwo-kwo-kwo...’的叫声，最多可达46个音符，以每两秒一个音符的速率发出。还发出一种冒泡般的咕噜颤音。","habits":"栖息于低地和山麓森林，包括潮湿的低地森林边缘和二次生长林地，在巴拿马甚至渗透到红树林地带。在哥伦比亚，海拔可达2200米（通常更低），在安第斯山脉东侧达到500米。在委内瑞拉，雨林高度可达100米（奥里诺科河以北），在奥里诺科河以南可达1000米。亚马逊地区，它们出现在树冠和亚树冠的过渡森林和沼泽森林，包括画廊森林，以及高地和低洼森林。","breeding":"繁殖季节在巴拿马为3月，在哥伦比亚西北部1月至5月间发现处于繁殖状态的个体，3月开始筑巢；在法属圭亚那为7月至10月，在秘鲁东部和亚马逊其他地区为6月至7月。已知的巢穴位于活跃的白蚁巢内，通常与Dolichoderus蚂蚁共存，巢室平均直径17.9厘米，高15厘米，入口隧道直径7.3厘米，长度19.1厘米，向上倾斜56度。每窝产卵2至3枚，接近白色。","identification":"与灰尾美洲咬鹃相似，但可通过红喙和雄鸟特有的白色胸带来区分。雌鸟与灰尾美洲咬鹃雌鸟的区别在于黄色下颌。T. m. macroura与指名亚种的区别在于翼部斑纹更粗，尾羽上部蓝绿色更明显，翼和尾更长；T. m. eumorphus与指名亚种的区别在于翼部较暗，尾部更蓝，白色胸带更窄。","protection":"IUCN：LC（无危）","distribution":"分布于巴拿马运河区东部至委内瑞拉北部，亚马逊盆地，包括巴拿马、哥伦比亚、委内瑞拉、法属圭亚那、苏里南、巴西、秘鲁等地。在巴拿马、哥伦比亚、法属圭亚那、苏里南和秘鲁较为常见。","other":"在玻利维亚，黑尾美洲咬鹃在雨季会从干燥森林迁移到低地雨林。"},{"name":"黑头美洲咬鹃","english_name":"Black-headed Trogon","scientific_name":"Trogon melanocephalus","overview":"黑头美洲咬鹃（英文名：Black-headed Trogon，学名：Trogon melanocephalus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。美丽的中等体型黄色腹部咬鹃，活跃于热带低地森林，分布自墨西哥南部至哥斯达黎加北部。其显著特征包括黑色上身、蓝色眼环和尾部下方带有大块白色标记。","appearance":"雄雌均有完整的蓝灰色眼环，尾部下侧有白色大块斑纹。雄鸟头部、颈部和胸部为均匀的黑色或石板黑色，背部和上翼覆羽呈亮金属蓝绿色到金绿色。雌鸟颜色相似但整体较暗淡，上身为深石板灰黑色，缺乏雄鸟的虹彩光泽。幼鸟尾部大部分为暗黑色，翅膀上有更多白色斑点。","call":"以响亮的加速连发‘咯咯’声著称，类似鼻音更重的横斑蚁鵙歌声。","habits":"偏好开放生境，如种植园、次生林、河岸林和季节性落叶森林。在海拔600米以下的多种森林类型中活动，包括热带湿润和干燥森林。主要食物为果实和节肢动物，尤其喂养雏鸟时以大型毛虫和其他大型昆虫为主。","breeding":"繁殖季节为3月至7月，巢穴位于白鼻白蚁（Nasutitermes）的大型树栖蚁丘中，由一对伴侣共同挖掘。每窝产卵数量通常为三枚，双亲轮流孵卵约17至19天，雏鸟约在孵化后16至17天离巢。","identification":"与其他黄色腹部咬鹃明显不同，具有全黑尾羽宽端白色和暗色眼睛与浅蓝色眼环。雄鸟上体光泽蓝黑色，雌鸟上体为暗石板灰色。与纹肩黑唐纳雀和斑尾美洲咬鹃相比，后两者尾羽具条纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，从墨西哥东南部至哥斯达黎加北部，包括伯利兹、哥斯达黎加、萨尔瓦多、危地马拉、洪都拉斯、墨西哥和尼加拉瓜。","other":"在适当的栖息地中常见，种群数量稳定，能适应牧场、森林边缘和退化生境。"},{"name":"黄纹美洲咬鹃","english_name":"Citreoline Trogon","scientific_name":"Trogon citreolus","overview":"黄纹美洲咬鹃（英文名：Citreoline Trogon，学名：Trogon citreolus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。美丽的咬鹃科鸟类，仅见于墨西哥西部。体长约27厘米，以其醒目的黄色腹部和绿色背部著称。该物种栖息于干燥至半干燥的林地、灌木丛及果园等环境，有时在小群体中聚集于结果树上。","appearance":"雄性黄纹美洲咬鹃具有蓝灰色的喙、黄色的眼睛，头部和胸部呈灰黑色，腹部为黄色，翅膀黑灰色，背部金属绿色，臀部深蓝色，尾巴上方蓝绿色带黑尖，尾巴下方大部分白色。雌鸟头部、胸部和背部较暗灰色，腹部黄色略淡。幼鸟眼睛颜色较暗，尾巴下方黑色较多。","call":"鸣声类似于黑头咬鹃，快速连续的低沉、喉音短音，类似蚁鸟的叫声。","habits":"栖息于干旱到半干旱的林地，包括低海拔沿海丛林、荆棘灌木地、刺林、红树林和种植园。以昆虫和水果为食，尤其在特定季节偏爱不同的食物类型。","breeding":"繁殖期为5月至8月，选择在树上的白蚁巢中筑巢，每巢产2-4枚卵。","identification":"与黑头咬鹃的区别在于头部和胸部更灰而非纯黑，黄色的眼睛，背部绿色少有蓝色调，尾巴下方白色更多。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲，特别是在墨西哥西部，包括Ocozocoautla de Espinosa地区。","other":"作为生态系统工程师，其巢穴为热带干林中的多种生物提供关键的洞穴资源。"},{"name":"白尾美洲咬鹃","english_name":"White-tailed Trogon","scientific_name":"Trogon chionurus","overview":"白尾美洲咬鹃（英文名：White-tailed Trogon，学名：Trogon chionurus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。常见的咬鹃科鸟类，分布于巴拿马西部至厄瓜多尔西部的热带雨林中。雄鸟具有深蓝光泽的头部和胸部，背部呈青绿色至蓝紫色，腹部亮黄色，尾巴蓝绿色，末端黑色，尾下覆羽几乎全白。雌鸟颜色较为灰暗，尾下覆羽具白色大斑点。","appearance":"雄性白尾美洲咬鹃的头部、颈部和上胸部呈深蓝色，带有金属光泽，背部和臀部蓝紫色，腹部橙黄色，翅膀黑底白边。雌鸟头部、胸部和背部灰色，腹部橙黄色，翅膀较暗，尾下覆羽白色带宽大的黑色基部。两性均有淡蓝色眼环，喙蓝白色至近白色。","call":"白尾美洲咬鹃的鸣声为一系列约16个快速的'kyoh'或'cow'音节，声音逐渐增强。还可能发出低沉的咕噜声或单个'chuck'声。","habits":"栖息于海拔1000米以下的湿润热带和亚热带森林、森林边缘、次生林和河岸林。以果实、浆果和昆虫为食，通常单独或成对活动。","breeding":"繁殖期信息不详，但已知其筑巢于树洞中，每窝产卵2枚，卵尺寸约为28.1 x 22.5毫米，重量约8.5克。","identification":"与绿背美洲咬鹃的区别在于，绿背美洲咬鹃雄鸟的尾下覆羽有黑色和白色条纹，而白尾美洲咬鹃尾下覆羽几乎全白，仅尾端有黑色。雌性白尾美洲咬鹃尾下覆羽有白色大斑点，而绿背美洲咬鹃雌鸟尾下覆羽有更明显的黑白条纹。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，具体为巴拿马西部至哥伦比亚西部和厄瓜多尔西部的热带雨林中。","other":"直到最近，白尾美洲咬鹃与绿背美洲咬鹃被认为是同一种，后经基因分析和声音、羽毛差异证实为两种独立物种。"},{"name":"拜氏美洲咬鹃","english_name":"Baird's Trogon","scientific_name":"Trogon bairdii","overview":"拜氏美洲咬鹃（英文名：Baird's Trogon，学名：Trogon bairdii），是咬鹃目咬鹃科美洲咬鹃属的独特鸟类。拥有深紫蓝色头部和胸部，背部呈青绿色，下体白色，喙和眼环淡蓝色。雌鸟主要呈灰色，腹部红色，与绿背美洲咬鹃最为相似，但具淡蓝色眼环，灰喙，下体有细白条纹。分布局限于哥斯达黎加和巴拿马的太平洋沿岸。","appearance":"体长25至28厘米，体重约95克。雄鸟头部和大部分胸部为蓝黑色，其余下体为鲜亮的红色。上体金属蓝绿色，翼部大多黑色，主翼覆羽外缘白色，尾羽上侧绿至蓝紫色并尖端黑色，下侧几乎全白仅尾尖黑色。雌鸟更暗淡，上体深石板色，喉部和胸部较浅灰色，下体红少，尾下覆羽有黑白相间条纹。幼鸟似雌鸟，但尾羽更尖，条纹不规则；雄鸟腹橙色少，雌鸟则无。","call":"叫声为一系列犬吠般的音符，起初平稳，随后加速突然下降，有时以几个间隔较大的低音符结束。受惊时发出尖锐的咯咯声。","habits":"栖息于湿润雨林内部树冠，偶尔出现在边缘、高大的次生林和阴凉半开放的林地中。以水果和昆虫为主食，也会从地面捕食猎物。小脊椎动物在其饮食中占比较小部分。","breeding":"繁殖期在4月至8月之间，巢建于枯死树木腐朽树干中的洞穴内。每次产卵2到3枚，孵化期16至17天，雏鸟约25天离巢。","identification":"与绿背美洲咬鹃极为相似，但注意其红下体，淡蓝色眼环，灰喙，尾下覆羽具有细白条纹。","protection":"IUCN：NT（近危）","distribution":"分布于中美洲的哥斯达黎加（北至塔尔科莱斯河附近）和巴拿马西部的奇里基省。主要限于哥斯达黎加的保护区，巴拿马境内罕见。"},{"name":"绿背美洲咬鹃","english_name":"Green-backed Trogon","scientific_name":"Trogon viridis","overview":"绿背美洲咬鹃（英文名：Green-backed Trogon，学名：Trogon viridis），是咬鹃目咬鹃科美洲咬鹃属的鸟类。原为白尾美洲咬鹃的亚种之一，因线粒体基因、鸣声和羽色差异而被确立为独立种。雄鸟通体金属绿背、蓝黑头胸与亮黄腹相映，雌鸟则以灰褐头胸取代雄鸟的鲜艳色彩。广泛分布于亚马孙地区，在巴西东南沿海及特立尼达岛亦有隔离种群。","appearance":"体长25–28厘米，雄鸟体重77–99克，雌鸟74–107克。雄鸟头顶至胸部呈虹彩深蓝黑色，具亮蓝眼圈及蓝白色喙；背金属绿，腰与上尾覆羽渐呈紫蓝；上尾金属铜绿，端部黑色；翼覆羽具黑白细纹，初级飞羽外缘白色；腹部及尾下覆羽鲜黄；尾下白色，中央具黑斑。雌鸟羽色暗淡，头及上体灰褐，无金属绿蓝色；腹部黄色，翼覆羽及外侧尾羽端部具白色斑。幼鸟似雌鸟，雄幼鸟上体略显铜绿，尾羽及翼覆羽白斑更宽。","call":"鸣声为连续15–20声短促而均匀的“cow”或“kyoh”音，后段略增强，与白尾美洲咬鹃逐渐加速且尾音更高的叫声明显不同；亦会发出低沉的咕噜声、单声“chuck”及鼻音责骂般的“kwa…kwa…kwo-kwo-kwo-kwo-kwo”。在委内瑞拉，有慢速（约2.5声/秒）与快速（约4声/秒）两种型态。","habits":"留鸟，栖息于低地及丘陵的原始或择伐后的湿润雨林、林缘、空地、种植园、次生林、河岸林及年轻灌丛；海拔在哥伦比亚可达1200米，委内瑞拉800–1300米，秘鲁局部1350米，巴西通常不超过950米。常单独或成对活动，偶尔加入混合种觅食群；主要于树冠及亚树冠层12–25米处静栖猎食。","breeding":"繁殖期因地区而异：委内瑞拉2–4月，哥伦比亚6月，厄瓜多尔7月，苏里南2–7月并延至12月，法属圭亚那8–9月及12–3月，巴西1月、3月及9月。巢筑于离地2–40米的树栖白蚁巢或树洞中，双方共同挖掘，通常产卵2–3枚，卵白色光泽，28.1–34.5×22.5–25.5毫米；孵化及育雏期未详。","identification":"与白尾美洲咬鹃相比，本种雄鸟具蓝眼圈，头胸深蓝黑而无狭窄白色胸带，尾下黑斑更少；雌鸟头胸灰褐而非灰蓝，尾羽具白色端斑。与同属紫头美洲咬鹃的区别在于眼圈颜色、头胸色调及尾下黑斑面积。","protection":"IUCN: LC（无危）。","distribution":"繁殖区与非繁殖区一致。分布于安第斯山脉以东，自哥伦比亚向南经秘鲁至北玻利维亚，向东至圭亚那、特立尼达及巴西东部（至马拉尼昂和马托格罗索；另有阿拉戈斯州、巴伊亚至圣保罗州沿海隔离种群）。","other":"曾被误列为Trogon strigilatus，现依国际动物命名法规确立为 绿背美洲咬鹃。本种为单型种。"},{"name":"斑尾美洲咬鹃","english_name":"Gartered Trogon","scientific_name":"Trogon caligatus","overview":"斑尾美洲咬鹃（英文名：Gartered Trogon，学名：Trogon caligatus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。分布于中美洲至南美西北部，包括墨西哥、整个中美洲及哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。该鸟长23至25厘米，重38至57克，具有独特的雌雄异型性，雄鸟头部、颈项及上胸部呈蓝紫色，雌鸟则为灰色调。","appearance":"雄性斑尾美洲咬鹃拥有浅蓝灰的喙和淡黄色的眼环，头至中胸为蓝紫色，面部和喉部黑色，胸前有一条狭窄的白色带，下腹部鲜黄；背部金属绿色，翼板隐约有黑白相间的虫蚀状斑纹，飞羽深色，初级飞羽外缘白色；尾巴相对较短，上方蓝紫色并尖端黑色，下方有精细的黑白色条纹和宽白边形成三道带。雌鸟则头部、脸部、上胸和背部灰色，眼环不完整，腹部颜色较暗淡，尾下覆羽图案与雄鸟不同。","call":"其叫声为一系列快速的空洞下滑音符，'kyu-kyu-kyu-kyu-kyu-kyu'，无加速，音调高于灰尾美洲咬鹃，类似于棕鸺鹠的叫声；还包括滚动的叽喳声。","habits":"斑尾美洲咬鹃通常栖息于半开放景观，如森林边缘、开阔地、林带森林、次生林和遮荫咖啡和可可种植园，偶尔进入密集的常绿森林和雨林。它以果实和小型无脊椎动物为食，可能比其他咬鹃更倾向于吃水果，但也会捕食多种昆虫和其他无脊椎动物。有时会加入混合物种觅食群。","breeding":"繁殖季节从3月至6月在墨西哥，5月至7月在萨尔瓦多，2月至6月在哥斯达黎加。在大型的树栖黄蜂巢、蚂蚁巢或白蚁巢中筑巢，或在腐朽树木的洞穴中，每窝产卵2到3枚。","identification":"与非常相似的纹肩黑唐纳雀主要通过头部颜色和叫声区分。与紫头美洲咬鹃的分离主要基于分布和声音。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲东部至南美西北部，具体包括墨西哥东部至哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉。在墨西哥北部至南美西北部，包括墨西哥、整个中美洲及哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉均有记录。","other":"关于物种的分类和系统发育，直到21世纪初，斑尾美洲咬鹃和亚马逊咬鹃曾被认为是紫头美洲咬鹃的亚种。"},{"name":"亚马逊咬鹃","english_name":"Amazonian Trogon","scientific_name":"Trogon ramonianus","overview":"亚马逊咬鹃（英文名：Amazonian Trogon，学名：Trogon ramonianus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。分布于南美的亚马逊雨林区域，包括哥伦比亚、厄瓜多尔、秘鲁、玻利维亚、委内瑞拉和巴西。其雄鸟头部、颈部至中胸部呈深金属蓝黑色，脸部与喉部黑色，与头蓝色部分界限不明显，胸部有一狭窄白色带，腹部黄色明亮，上体绿色或蓝绿色。雌鸟头部、面部、上胸和上体为暗灰色，腹部黄色较淡。该物种在成熟雨林中较为常见。","appearance":"亚马逊咬鹃体型约23至25厘米，雄鸟体重44至46克。雄鸟拥有深金属蓝黑色的头部、颈部和上胸部，脸部和喉咙黑色，与头部其余部分颜色接近，仅由一窄白带隔开，腹部黄亮，背部呈现金属绿至蓝绿色，尾羽上方深蓝色，尖端黑色，下方具细黑白色条纹和宽白色末端。雌鸟头部、脸部、上胸部和背部为暗灰色，腹部颜色较雄鸟淡，尾羽下侧条纹模式不同。两亚种间差异微小，类似个体间变异。","call":"亚马逊咬鹃的鸣唱是一连串相对短暂而快速的剪短‘cow’音或‘mewing whistles’，音符常成双‘cadow-cadow-cadow’或‘whi-ew-whi-ew’，并伴有多种滚动的叽叽喳喳叫声。","habits":"亚马逊咬鹃栖息于亚马逊雨林的多样化生境，包括过渡森林、高地森林、棕榈和竹子林以及永久洪水林，通常在海拔500米以下，偶尔可达1000米。它们可能以果实和小型动物（如昆虫和蛙类）为食，通过从栖木飞扑和悬停的方式捕食。它们有时会加入混合物种群跟随行军蚁。","breeding":"关于亚马逊咬鹃的繁殖信息极为有限。已知的一个巢穴位于活跃的白蚁巢中，离地面3.5米，入口圆形，直径约10.5厘米，内部孵化室未详细测量，含有两个轻度孵化的白色蛋，蛋表面沾染褐色斑点。","identification":"亚马逊咬鹃与同域的绿背咬鹃（白尾）相似，但后者眼环更灰，尾羽下侧白色末端更宽，且无白色胸带将上身与下腹部区分开。两亚种间差异细微，主要体现在个体间的变异上。","protection":"IUCN：未评估（由于未单独评估，基于广泛定义的violaceous trogon）","distribution":"亚马逊咬鹃的分布范围涵盖南美亚马逊盆地的西部和南部，从哥伦比亚东部安第斯山脉的山脚，向南延伸至玻利维亚北部，向东横跨巴西的亚马逊盆地。北部的分布边界在委内瑞拉西部（奥里诺科河流域上游）和亚马逊河北岸至黑河北岸。南部和东部分布边界沿亚马逊河至巴西东部。","other":"亚马逊咬鹃的分类历史上曾有争议，近期分子研究揭示了其与violaceous trogon和其他种的系统发育关系，导致了物种地位的确认。"},{"name":"紫头美洲咬鹃","english_name":"Guianan Trogon","scientific_name":"Trogon violaceus","overview":"紫头美洲咬鹃（英文名：Guianan Trogon，学名：Trogon violaceus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。原属紫头美洲咬鹃复合体，近年被拆分为独立种，分布于特立尼达岛、委内瑞拉、圭亚那三国及巴西北部低地至海拔1000米的湿润森林、次生林、咖啡可可荫栽等多样生境。体长23–25厘米，体重38–57克；雄鸟头颈部具紫蓝金属光泽，背翠绿，胸腹鲜黄；雌鸟灰褐为主，具断环黄眼环；尾下覆羽黑白细横斑。以果实及大型昆虫为主食，在树冠及林缘悬停啄食，常混入混群。繁殖期2–6月，多在离地10–15米的胡蜂巢、蚁巢或腐木中凿洞营巢，每窝2–3枚卵。","appearance":"雄鸟具淡蓝灰色喙及完整淡黄色眼环；头至胸中覆亮紫蓝色，黑色面罩及喉部以白色胸带过渡至亮黄色胸腹；上体金属翠绿，翼覆羽隐约黑白色虫蚀纹，远处看似暗灰褐；飞羽暗色，初级飞羽外缘白；尾相对短，上表面紫蓝且末端黑色，下表面黑白色细横斑，末端3道宽白带。雌鸟上喙脊线黑，眼环上下断裂，无紫蓝及翠绿，翼覆羽密布黑白横斑；腹部黄色较暗，胁部带灰，尾下覆羽黑内缘形成黑白斑驳。幼雄似成雄但翼斑褐且尾下白斑少；幼雌似雌鸟。","call":"鸣唱为连续快速而空洞的下倾哨音“kyu-kyu-kyu-kyu-kyu-kyu”，节奏较绿背美洲咬鹃快、音高较灰尾美洲咬鹃高，常被误认为巴西鸺鹠。叫声包括滚动的喋喋不休声。","habits":"栖息于低地至1200米的常绿林、次生林、林缘、疏林、荫栽咖啡可可园及有灌木树丛的开阔地。在苏里南可见于沙脊林、稀树草原及内陆森林；在亚马逊地区偏好过渡林、高地旱林及永久淹水林的林冠与林缘。以果实及小型无脊椎动物为食，可能比同属更偏果食；记录取食 Cecropia、Didymopanax morotononi 果实及金额啄木鸟啄开的橙子。悬停啄取枝叶上的果实及昆虫，常于低树与鸫科、裸鼻雀科共食，并加入混合鸟群。","breeding":"委内瑞拉2月、特立尼达11月至翌年6月均见繁殖个体。巢筑于离地约10–15米的胡蜂巢、Azteca 蚁巢、白蚁巢、腐木或蕨类根团中。每窝2–3枚卵，雏鸟期至少17天，其余繁殖细节资料缺乏。","identification":"与绿背美洲咬鹃极似，但体型略小，具完整眼环，尾纹不同且鸣唱更快；与同属灰尾美洲咬鹃主要区别在头部羽色及声音。","protection":"IUCN: LC（无危）。委内瑞拉稀少且局部分布，特立尼达与苏里南常见。","distribution":"繁殖区：特立尼达岛、委内瑞拉、圭亚那三国及巴西北部毗邻地区。","other":"系统分类上曾被归入独立属 Chrysotrogon；分子研究提示与绿背美洲咬鹃及蓝顶美洲咬鹃亲缘近。因羽色与鸣声重叠，部分学者认为拆分依据不足。"},{"name":"蓝顶美洲咬鹃","english_name":"Blue-crowned Trogon","scientific_name":"Trogon curucui","overview":"蓝顶美洲咬鹃（英文名：Blue-crowned Trogon，学名：Trogon curucui），是咬鹃目咬鹃科美洲咬鹃属的鸟类。雌雄异型明显的鸟类。雄鸟头部呈蓝色，眼圈橙色；雌鸟头部灰色，眼圈白色明显。广泛分布于南美洲亚马逊盆地，包括巴西、阿根廷、玻利维亚、哥伦比亚、厄瓜多尔、巴拉圭和秘鲁。栖息于多种森林环境，从低地雨林到次生林边缘。","appearance":"体长约24厘米，体重39至63克。雄鸟头部蓝绿色，眼圈橙色，冠部、颈部两侧和胸部呈现金属光泽的绿蓝色，背部青铜绿色，翅膀密集的细纹看似灰色，下腹部红玫瑰色，尾羽下部具黑白色条纹。雌鸟头部、背部和上尾灰色，翼斑有白色条纹，下腹部粉红色，尾羽下部黑白色条纹更细窄。","call":"发出快速而均匀节奏的‘kow’音节，持续约4至5秒后突然停止。","habits":"栖息于多种森林类型，包括雨林边缘、次生林、干燥半落叶林等，活跃于树冠层至林下层。食物主要包括昆虫、蜘蛛及小果，常加入混合物种觅食群。海拔分布从低地至1750米。","breeding":"繁殖季节因地区而异，最早于5月开始，在阿根廷可延至12月。筑巢于白蚁丘洞穴，每窝产2-3枚蛋。","identification":"雄鸟与雌鸟在头部颜色、背部光泽和下腹部色彩上有显著差异。雄鸟头部蓝绿色，雌鸟头部灰色。雄鸟T. c. peruvianus背羽带蓝色光泽，胸带白色较少，尾羽下部条纹更窄。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲亚马逊盆地以南，从巴西中央至东海岸，以及安第斯山脉东侧的哥伦比亚、秘鲁、玻利维亚、巴拉圭和阿根廷北部。","other":"已知三个亚种：指名亚种、peruvianus和behni，它们在羽毛颜色和图案上有细微差别。"},{"name":"苏鲁美洲咬鹃","english_name":"Surucua Trogon","scientific_name":"Trogon surrucura","overview":"苏鲁美洲咬鹃（英文名：Surucua Trogon，学名：Trogon surrucura），是咬鹃目咬鹃科美洲咬鹃属的鸟类。咬鹃目咬鹃科的鸟类，广泛分布于南美东南部，包括巴西东部至圣保罗北部、巴拉圭东部、阿根廷东北部以及乌拉圭。其最显著的特征为雄鸟的蓝紫色头部和胸部，绿色背部，以及白色带黑边的尾下覆羽。","appearance":"苏鲁美洲咬鹃长约26至28厘米，体重56.3至78克。雄鸟具有黑色面颊和喉部，眼周有橙色环，冠、颈和胸为皇家蓝色，背部铜绿渐变为尾上侧的青绿色。折翼处细密的虫蚀纹使其看起来灰暗，腹部呈粉红色，两胁灰色。尾下覆羽为白色，末端有黑色横纹。雌鸟整体呈灰色，腹部红色开始较低，眼周有小白点，尾下覆羽有黑白相间的图案。幼鸟与成年雌鸟相似。","call":"其鸣唱为一系列上升的‘kwa’音符，类似绿背美洲咬鹃，但节奏更快，音调中等偏高，每秒约3个音节，最后一音节音量降低。","habits":"栖息于原始森林和高大次生林的中层至高层，也出现在半落叶林木地带，最高可达2000米海拔。以昆虫（包括幼虫和成虫）、果实和偶尔的花朵为食，常加入混合物种觅食群。在南巴西，北方种群似乎全年定居，而南方种群则在南半球冬季向北迁移。","breeding":"繁殖季节从9月至12月，可能延续至次年1月。巢穴位于腐朽树木或树蚁窝中，已知一窝含三枚蛋，蛋壳略带光泽，白色，尺寸约为28-29.3mm x 21.4-22mm。","identification":"雄性苏鲁美洲咬鹃与绿背美洲咬鹃的区别在于其更快的鸣唱节奏和不同的色彩模式，尤其是眼周的橙色环和腹部颜色。雌鸟则通过其独特的灰色外观和尾下覆羽的黑白图案与其它咬鹃种类区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于巴西东南部（巴伊亚至圣保罗南部）、巴拉圭东部、阿根廷东北部至乌拉圭，以及巴西东南部（托坎廷斯东南部至里约热内卢西部和南马托格罗索州）。","other":"在多个保护区中均有分布，包括巴西的Caraça私有保护区、Serra do Cipó国家公园、Rio Doce州立公园、Sooretama和Augusto Ruschi生物保护区、Itatiaia和Serra dos Órgãos国家公园、Três Picos州立公园；阿根廷的Chaco、Pre Delta和Río Pilcomayo国家公园、El Bagual保护区；以及巴拉圭和乌拉圭的多个保护区。"},{"name":"亚马逊黑喉咬鹃","english_name":"Amazonian Black-throated Trogon","scientific_name":"Trogon rufus","overview":"亚马逊黑喉咬鹃（英文名：Amazonian Black-throated Trogon，学名：Trogon rufus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。分布于南美的亚马逊雨林低地，自哥伦比亚东南部至委内瑞拉南部、东部，经圭亚那、厄瓜多尔东部、秘鲁东部，至巴西北部、西部及中东部。该物种具有明显的雌雄异型性，雄鸟头部、上胸和背部呈绿色，面部和喉咙黑色，腹部金黄色；雌鸟相应部位呈棕色。幼鸟外观较成鸟暗淡。","appearance":"亚马逊黑喉咬鹃体长约23-24厘米，体重约54-57克，其特征为白色带黑色条纹的下尾羽、黄色喙及灰黑色与白色交织的翼覆羽。雄鸟拥有绿色的头、上胸和背，黑色的脸和喉咙，以及金色腹部。雌鸟的头、上胸和背为棕色，上尾羽红褐色，腹部黄色。幼鸟与成鸟相似，但色彩较暗，年轻雄鸟有棕色喉咙、胸部和翼覆羽。","call":"鸣声为连续的‘krrrrrr’声，而歌曲为典型的几声清晰哨音序列，‘cuh cuh cuh cuh’。","habits":"栖息于潮湿热带森林的较低层次，偏好深荫环境，通常直立不动地停栖。它们以昆虫和部分果实为食，常在飞行中捕食，是所在范围内最嗜食昆虫的咬鹃种类之一。它们会利用其他捕食者如浣熊惊飞的昆虫作为猎物。","breeding":"在距离地面1-6米的浅洞穴中筑巢，巢穴未经衬垫，每窝产两枚白色卵。","identification":"与绿背美洲咬鹃、紫头美洲咬鹃和亚马逊咬鹃存在差异，可通过腹色、冠羽颜色、尾下覆羽图案和眼环颜色以及鸣声来辨别。","protection":"IUCN：LC（无危）","distribution":"繁殖区域：南美亚马逊雨林，覆盖哥伦比亚东南部、委内瑞拉南部和东部、圭亚那、厄瓜多尔东部、秘鲁东部以及巴西北部、西部和中东部。","other":"历史上曾与三种咬鹃视为同种，现已确认为独立物种。"},{"name":"优雅美洲咬鹃","english_name":"Elegant Trogon","scientific_name":"Trogon elegans","overview":"优雅美洲咬鹃（英文名：Elegant Trogon，学名：Trogon elegans），是咬鹃目咬鹃科美洲咬鹃属的鸟类。曾与铜尾美洲咬鹃合并为一种，现已独立。包括分布于中美洲的亚种elegans与lubricus。羽色以铜绿背、鲜红腹及中央尾羽金属铜绿为标志，雌雄异形，雌鸟具特征白眉纹。栖于海拔0–1900米的干旱至半干旱松栎林、荆棘林及溪谷落叶林，自危地马拉莫塔瓜谷向南至哥斯达黎加尼科亚半岛。留鸟，无迁徙记录。","appearance":"体长29厘米，体重约68克。雄鸟：头、颈背至上胸亮铜绿带金属光泽；下胸具明显白色横带，腹部及尾下覆羽鲜红；背及尾铜绿，中央尾羽末端宽黑；翼灰褐，尾下白色具细窄黑白横纹。雌鸟：头至上背灰褐，后枕略现铜绿；眼后具显著白色“泪滴”眉纹；下体色淡，腹及尾下覆羽淡红；尾羽色暗，尾下横纹较雄鸟粗。幼鸟似雌鸟，但无红色，下体偏褐白，尾羽横纹更宽。","call":"繁殖期雄鸟持续发出粗哑、蛙鸣般“kahr”或“khowur”下降音，常连叫5–10次后停顿再重复；雌鸟音调略低。遇警或驱赶入侵者时发出急促金属“w-k-k”。","habits":"留鸟。栖于干旱—半干旱松栎林、荆棘灌丛及溪谷落叶林，海拔0–1900米。日常静伏林冠或亚树冠，垂直栖姿；以“飞捕—飞啄”方式突袭昆虫或摘取果实，偶悬停取食。食物以果实（榕果、樱桃）与昆虫（蚱蜢、鳞翅目幼虫）并重，繁殖季昆虫比例高。","breeding":"繁殖期4–7月。一夫一妻制，配对后共用旧啄木鸟洞（北扑翅䴕等）为巢，偏好大径枯树洞，距地2.5–15米。每窝2–3枚白色卵，双亲轮流孵卵约19日；雏鸟15–17日龄出飞，尾极短，双亲继续分雏带喂约1月；年育1窝，若败可再营巢。","identification":"与铜尾美洲咬鹃相比，雄鸟中央尾羽铜绿而非铜色，尾下覆羽具细窄黑白横纹（非灰白细纹）；雌鸟背更褐，尾下横纹清晰。与分布重叠的高山美洲咬鹃相较，后者尾下几乎全黑，仅具白端，雌鸟无显著白眉纹。","protection":"IUCN: LC（无危）。中美洲种群稳定，局部常见至甚常见。","distribution":"繁殖区：中美洲自危地马拉莫塔瓜谷、萨尔瓦多、洪都拉斯西部内陆，南至尼加拉瓜西北部及哥斯达黎加西北部（至尼科亚半岛基部）。无迁徙记录，全年留居。","other":"历史上曾与铜尾美洲咬鹃同属一种，现已确认 elegans 群为独立种级单元。"},{"name":"高山美洲咬鹃","english_name":"Mountain Trogon","scientific_name":"Trogon mexicanus","overview":"高山美洲咬鹃（英文名：Mountain Trogon，学名：Trogon mexicanus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。又称墨西哥咬鹃，栖息于中美洲高海拔松林和松栎混交林，分布于墨西哥至洪都拉斯的高山区，偶尔在较低海拔出现。","appearance":"体长约29-31厘米，体重约69克。雄鸟具有橙红色眼圈和黄色喙，头顶、颈背、上体和胸部绿色，腹部鲜红色，胸部有一条白色横带，翅膀有斑点，尾巴上部绿蓝，末端黑色，下部黑色带宽白尖。雌鸟上颌色暗，有断续的白色眼环，头部、胸部和上体棕色，翼板浅褐色，胸带白色，下胸部淡棕色，腹部红色至尾下覆羽；尾巴上部赤褐色，末端黑色，下部有黑白相间的外网，内网黑色带宽白尖。幼鸟似雌鸟，但有淡黄色斑点，眼周有裸露的黄色皮肤环，腹部淡黄色。","call":"鸣唱由3-15个双音哨声组成，'kyow-kyow kyow-kyow kyow-kyow'，有时接以较轻的加速音节串，'hu-hu-hu-hu-hu-hu-huhuhuhu'；叫声包括咕哝和嘈杂的嘁嘁喳喳声。","habits":"栖息于墨西哥高地的松栎和松常绿（\"雪松\"）以及湿润的山地森林的中上层，海拔高度1200-3500米，偶尔在更低处发现。偏好危地马拉西部山脉的橡树和雪松带，海拔800-2900米。在洪都拉斯，高于1200米的松林和松栎林（有时低至600米）。能够容忍次生林环境。","breeding":"食性包括昆虫和小型果实，通过飞行捕捉或摘取。繁殖期间，它会挖掘或利用其他物种已挖掘的巢穴，通常在腐朽的木头中，高度在地面以上4英尺以内，偶尔高达12英尺。雌鸟产两枚白色蛋，双亲共同孵卵，但雌鸟承担更多时间的孵化任务，孵化期为19天。","identification":"与优雅美洲咬鹃相似，但其上尾绿色，下尾图案不同，翼板稍暗，雌鸟无眼后白纹。与较小的白领美洲咬鹃相比，主要在较低海拔发现，尾下部有更细密的条纹。","protection":"IUCN：LC（无危）。","distribution":"分布于中美洲，从墨西哥至洪都拉斯的高山区，偶尔出现在较低海拔。","other":"能够适应人类土地利用，如在有适宜遮荫树木（如橡树）的咖啡种植园中生存。"},{"name":"白领美洲咬鹃","english_name":"Collared Trogon","scientific_name":"Trogon collaris","overview":"白领美洲咬鹃（英文名：Collared Trogon，学名：Trogon collaris），是咬鹃目咬鹃科美洲咬鹃属的鸟类。分布于中美洲至南美洲的热带低地湿润森林。其体型相对较小，雄鸟上体呈金属绿色，腹部红色；雌鸟上体橄榄棕色，腹部较暗淡的红色。分布范围广泛，从墨西哥东部至亚马逊雨林，包括巴西东南部。","appearance":"白领美洲咬鹃雄鸟头部、颈部、背部及臀部呈现亮丽的金属绿色，面部黑色，翅膀覆羽具黑白斑纹，腹部鲜红。雌鸟上体橄榄棕色，腹部红色较雄鸟暗淡。尾羽上表面绿色带黑尖，下表面黑白条纹，尾端白色宽大。翼覆羽幼鸟呈褐色，成鸟具精细的黑白斑点。","call":"叫声地理变异显著，墨西哥及中美洲的种群发出哀怨的两到三个音符的叫声，而南美种群则发出一系列圆润的哨音，通常带有结巴的前奏。","habits":"白领美洲咬鹃栖息于多种森林类型，包括湿润常绿森林、开阔林地、种植园、云雾林和松林。它主要在树冠层较低部分至较高下层栖息，以小果实和无脊椎动物为食，如毛虫、蟋蟀、蝉、甲虫和竹节虫。它通常单独或成对出现，有时非繁殖季节会形成小群体。","breeding":"繁殖季在不同地区变化大，最早11月开始于法属圭亚那，最晚4月于委内瑞拉。在腐木或树上白蚁巢中的浅洞筑巢，通常可见大部分鸟体。每窝产两枚卵，由双亲共同孵卵和抚育幼鸟。","identification":"与橙腹咬鹃（Trogon aurantiiventris）和美洲咬鹃最为相似，前者腹部橙色而非红色，后者通常栖息海拔更高，尾部下表面条纹更细。雄性美洲咬鹃有窄红眼环，雌鸟面部黑色。","protection":"IUCN：LC（无危）","distribution":"分布于中美洲至南美洲，包括墨西哥东部、亚马逊雨林和巴西东南部。在南美洲，栖息于低地湿润常绿森林；在墨西哥和中美洲，还包括湿润山地、半落叶和松树常绿森林，海拔高度可达2,400米（墨西哥）和2,300米（哥斯达黎加）。","other":"该物种包含多个亚种，其中T. c. aurantiiventris曾被认为是独立物种。"},{"name":"美洲咬鹃","english_name":"Masked Trogon","scientific_name":"Trogon personatus","overview":"美洲咬鹃（英文名：Masked Trogon，学名：Trogon personatus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。是中等体型的咬鹃，常见于南美洲的湿润高山森林，尤其是安第斯山脉和特普伊山。其最显著的特征是头部、胸部和背部的金属光泽绿羽，以及腹部的红色羽毛，中间以白色带状羽毛隔开。","appearance":"雄性美洲咬鹃平均长度约27厘米，体重约56克。头部、胸部和上胸部呈现出各种金属光泽绿色，红铜色或金绿色，具体色彩随亚种而异。腹部和下胸部为红色，被一条狭窄的白色带状羽毛所分隔。眼环颜色在不同亚种间从红色到橙色不等。雌鸟则上部呈棕色，下身粉红至红色，白色眼环部分，有时较窄或不明显。","call":"其鸣唱为柔和连续的4至8个\"kwa\"音符，音调比同属的白领美洲咬鹃略高，同时会发出下降的颤音，常重复。","habits":"美洲咬鹃栖息于湿润和潮湿森林的亚冠层和树苗下层，包括苔藓森林和云雾林，森林边缘，以及破碎山区的次生林和开阔林地。它们的海拔分布范围广泛，从700米至3600米不等，具体依地理位置而异。","breeding":"繁殖季节为4月至8月，筑巢于半腐烂木头中挖出的洞穴，高度可达3米。每次产卵2枚，关于繁殖的其他信息尚不详。","identification":"与白领美洲咬鹃非常相似，但美洲咬鹃的绿色羽毛带有更多蓝色调，翅膀上的条纹更细，尾巴上方的绿色带有铜色光泽。雌鸟的区别在于全黄色的喙、黑色的脸和喉咙，以及尾巴下方精细的条纹。","protection":"IUCN：LC（无危）","distribution":"分布于南美，从哥伦比亚至秘鲁，以及委内瑞拉中南部。"},{"name":"中美黑喉咬鹃","english_name":"Northern Black-throated Trogon","scientific_name":"Trogon tenellus","overview":"中美黑喉咬鹃（英文名：Graceful Black-throated Trogon，学名：Trogon tenellus），是咬鹃目咬鹃科美洲咬鹃属的鸟类。咬鹃科的鸟类，其分布范围从洪都拉斯东南部延伸至哥伦比亚西北部的低地森林。雄鸟拥有绿色蓝调的上部羽毛，雌鸟则呈棕色，两者均具有黄色腹部，淡蓝色眼环和黄色喙。曾被认为是黑喉咬鹃复合种的一部分。","appearance":"中美黑喉咬鹃体型中等，长度约为23.5至26厘米。雄鸟具有黑色面部，搭配淡蓝色眼环和暗金属绿色的头部，绿色的胸部以U形终止，被细白胸带隔开，下方是黄色的下胸部、腹部和尾下覆羽。尾巴下侧黑白相间，尾尖白色较大。雌鸟相似但头部和背部呈棕色，尾上覆羽红褐色。成年个体喙色淡黄，幼鸟喙色较暗。","call":"典型的鸣唱由低沉、柔和的音符组成，通常两到三个音符一组，偶尔可达六个，表现为‘cow cow’或‘cow cow cow’的序列，音质丰富，带有哨音特质。","habits":"中美黑喉咬鹃偏好湿润森林环境，常见于林下层或中层。它们的饮食主要包括水果和昆虫，有时会跟随中央美洲松鼠猴群，捕食猴子惊扰出的节肢动物。在巴拿马，该物种偏爱无花果树。","breeding":"繁殖信息未详述。","identification":"雄鸟与斑尾美洲咬鹃的区别在于头胸部颜色（更绿而非钴蓝色）、眼环颜色（淡蓝而非黄色）以及鸣声。雌鸟的棕色较为独特，不同于斑尾美洲咬鹃雌鸟的石板灰色。与其它咬鹃的辨识点包括腹下部的条纹图案和眼环颜色。","protection":"IUCN状态未知。","distribution":"分布于中美洲至南美洲的低地森林，范围从洪都拉斯东南部至哥伦比亚西北部。在洪都拉斯和尼加拉瓜北部，仅见于海拔400米以下的湿润低地森林；在哥斯达黎加，亦可见于成熟次生林甚至可可种植园，海拔最高可达1370米；在巴拿马，最高海拔记录为850米。","other":"在哥斯达黎加的拉塞瓦生物站，随着次生林的成熟，该物种开始进入。"},{"name":"乔科黑喉咬鹃","english_name":"Choco Black-throated Trogon","scientific_name":"Trogon cupreicauda","overview":"乔科黑喉咬鹃（英文名：Choco Black-throated Trogon，学名：Trogon cupreicauda），是咬鹃目咬鹃科美洲咬鹃属的鸟类。分布于南美的哥伦比亚西部和厄瓜多尔西部低地。该鸟具有明显的雌雄异型性，雄鸟上体闪耀蓝绿色，雌鸟上体呈褐色，两者皆拥有黄色腹部、淡蓝色眼圈和黄色喙。","appearance":"雄鸟头部、上胸及背部呈现绿蓝光泽，喉部黑色，眼周环绕黄色环带，上尾羽铜绿色，下尾羽黑白相间，尾端白色斑点大。雌鸟头部、上体为褐色，下体黄色，下尾羽同样黑白条纹，但铜绿色较雄鸟暗淡。幼鸟体色较雌鸟更为暗淡，上体具粗大的虫蚀状纹，下尾羽尖端无明显黑斑。","call":"其叫声为缓慢、均匀间隔的5至9个模糊哨音组成的系列。","habits":"乔科黑喉咬鹃栖息于森林地带，通常在较低至中等高度静坐不动。它们的活动范围和迁徙习性尚需进一步研究。","breeding":"繁殖习性与同属其他物种相似，具体细节待研究。","identification":"雄鸟通过头部和胸部颜色（更绿而非钴蓝）、更黄的喙和声音与斑尾美洲咬鹃相区分。雌鸟独特的棕色与斑尾美洲咬鹃雌鸟的灰蓝色形成对比。尾部下方的棕色斑块用于辨别雌性乔科黑喉咬鹃。","protection":"IUCN状态未知，需关注其保护级别。","distribution":"主要分布在南美哥伦比亚西部和厄瓜多尔西部的低地森林。","other":"其系统发育历史复杂，最近的研究确认其为独立物种，此前曾被认为是黑喉咬鹃复合种的一部分。"},{"name":"大西洋黑喉咬鹃","english_name":"Atlantic Black-throated Trogon","scientific_name":"Trogon chrysochloros","overview":"大西洋黑喉咬鹃（英文名：Atlantic Black-throated Trogon，学名：Trogon chrysochloros），是咬鹃目咬鹃科美洲咬鹃属的鸟类。主要分布在南美的巴西东部、南部，巴拉圭以及阿根廷东北部。这种鸟拥有黄色的腹部，淡蓝色的眼环和黄色的喙。雄鸟个体上体呈蓝绿色光泽，而雌鸟则为棕色。尾羽下方黑白相间，尖端白色宽大。","appearance":"大西洋黑喉咬鹃是一种中等体型的咬鹃，具有长长的方形尾巴和小异趾足，短腿，常直立静坐。雄鸟拥有蓝绿色的头部、上胸和背部，眼环显着的蓝绿色；雌鸟头部和背部为棕色。两性的下胸和腹部均为黄色，尾羽下方黑白条纹，尖端白色。雄鸟个体的绿蓝色上体与雌鸟的棕色形成鲜明对比。","call":"其典型鸣唱为一系列忧郁单调的音符，通常由四到十一个音符组成，节奏较快速，每秒约2.36个音符，音高相对较高。","habits":"大西洋黑喉咬鹃生活在森林地带，通常在低至中等高度静止不动，偏好在树冠层的下部活动。它们以昆虫和少量果实为食，采用悬停捕食的方式获取食物。有时会跟随觅食的浣熊群，利用它们驱赶出的昆虫作为食物来源。","breeding":"繁殖季节在10月至翌年1月，筑巢于腐朽的树干或树桩中，巢由木屑构成，内部直径约10.4厘米，深度26.5厘米。每窝产卵数为3枚，卵呈白色，大小约为25 x 21毫米至29 x 23毫米，孵化期略超18天，双亲共同孵卵。","identification":"与绿背咬鹃区分明显，后者雄鸟头部黑色，尾羽下方无条纹，雌鸟头罩黑色而非棕色。大西洋黑喉咬鹃雄鸟具有独特的蓝绿色上体，而雌鸟上体为棕色。","protection":"IUCN：NT（近危）","distribution":"繁殖区域：巴西东部和南部，巴拉圭，阿根廷东北部。非繁殖区域：暂无明确记录。","other":"历史上，由于栖息地丧失，该物种在巴西维索萨地区的局部已灭绝。"},{"name":"绿颊咬鹃","english_name":"Narina Trogon","scientific_name":"Apaloderma narina","overview":"绿颊咬鹃（英文名：Narina Trogon，学名：Apaloderma narina），是咬鹃目咬鹃科非洲咬鹃属的鸟类。主要分布在非洲森林和林地的中型咬鹃科鸟类。其身体以绿色和红色为主，全长约32至34厘米。虽然在广泛的区域内分布，但由于森林砍伐，某些地区的数量已显著减少。","appearance":"绿颊咬鹃具有鲜明的性别二态性，雄鸟拥有明亮的金属绿色上体羽毛，而雌鸟的面部和胸部羽毛呈脏灰色至棕色。雄鸟的腹部为鲜艳的猩红色，雌鸟则为粉灰色。两性均具宽阔的黄色喙。雄鸟的裸露眼圈和喉部皮肤呈蓝绿色，雌鸟则为蓝色或青铜蓝绿色。幼鸟类似雌鸟，但腹部颜色较淡，翅膀内侧羽尖白色或淡黄色。","call":"绿颊咬鹃在繁殖季节会发出低沉的‘huooo-huooo’声，由雄鸟发出，用于领地宣示或吸引配偶。声音起初几乎听不见，随后逐渐升高至高潮。","habits":"绿颊咬鹃主要栖息于雨林、河岸森林和低地森林，偶尔也会出现在次生林、灌木丛和山谷森林中。它们偏好海拔较低的地区，但在东非部分地区，它们会季节性迁移到较低海拔。绿颊咬鹃主要以昆虫为食，偶尔也会捕食小型脊椎动物。","breeding":"繁殖季节因地区而异，一般在雨季前后。绿颊咬鹃为一夫一妻制，双方共同参与巢穴的维护和幼鸟的喂养。巢穴通常建在树洞中，高度在1至12米之间。每窝产卵1至4枚，孵化期为16至18天，幼鸟的抚育期约为25至28天。","identification":"绿颊咬鹃与黄颊咬鹃的区别在于后者面部有大面积的裸露黄色皮肤，而绿颊咬鹃仅具有小面积的蓝绿色斑点。此外，绿颊咬鹃的尾巴无条纹，与斑尾咬鹃有明显区别。","protection":"IUCN：LC（无危）","distribution":"绿颊咬鹃广泛分布于非洲，从西非的塞拉利昂到东非的埃塞俄比亚，南至南非东部和南部。在刚果、乌干达、马拉维和赞比亚等地常见，而在博茨瓦纳北部和卡普里维地带的河流森林中的种群面临威胁。","other":"绿颊咬鹃的分布范围广泛，栖息地选择多样，这使得它在物种保护层面被列为无危级别。"},{"name":"黄颊咬鹃","english_name":"Bare-cheeked Trogon","scientific_name":"Apaloderma aequatoriale","overview":"黄颊咬鹃（英文名：Bare-cheeked Trogon，学名：Apaloderma aequatoriale），是咬鹃目咬鹃科非洲咬鹃属的鸟类。活跃于西非低地雨林内部，以独特的黄色裸露面部皮肤和绿色头部、背部著称。分布于尼日利亚东南部至加蓬南部和刚果民主共和国中部、东北部。","appearance":"成年黄颊咬鹃体长28-31厘米，雄鸟具白色至绿色喙基部黄色，头部至中胸及整个上体呈蓝绿色光泽，下胸粉红红色，翼板细纹灰黑相间，尾羽上部蓝绿色，中央羽紫色，外侧三羽大部白色，下尾大多白色。雌鸟面部棕色，喉部及胸部染肉桂棕色。幼鸟似雌鸟，但较暗淡，具白色眼环和面部垂饰，次级飞羽内侧有大白色尖端。","call":"鸣声为一系列6-8个忧伤下降的‘chuu’音符，每15-20秒重复一次，成年鸟在巢穴喂食时发出低沉的哼鸣声。","habits":"栖息于原始低地雨林、封闭冠层沼泽森林、低洼藤本丰富的洪水森林和冠层相对完好的砍伐森林。主要以大型绿毛虫、甲虫、蛾类、螳螂和直翅目昆虫为食，也会捕食软壳蜗牛和草或苔藓纤维。捕猎方式类似燕尾（Dicrurus），有时会追逐猎物至地面。","breeding":"一月在喀麦隆南部开始繁殖，加蓬在一月至二月和十一月，可能无固定季节。一夫一妻制，雄鸟选择巢址并争夺所有权。巢穴位于腐朽树木的2-8米高处，通常产两枚白色到粉色蛋，孵化期约16天，雏鸟期间由双亲共同喂养，持续约16天。","identification":"与绿颊咬鹃相比，黄颊咬鹃体型略小，尾巴比例更短，面部无蓝色斑点而有黄色裸露区，且下尾纯白色而非棕色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于喀麦隆、中非共和国、刚果共和国、刚果民主共和国、赤道几内亚、加蓬和尼日利亚。在尼日利亚，仅在克罗斯河国家公园奥班分区有记录。在喀麦隆的科鲁普国家公园较为常见。在加蓬部分地区，密度可达每10公顷一只歌唱雄鸟。在刚果的奥扎拉和努瓦巴莱-恩多基国家公园，密度最高可达每10公顷三对。","other":"参与唱歌聚集，涉及3至10只成年雄鸟连续鸣叫，可能与繁殖有关，但确切功能不明。"},{"name":"斑尾咬鹃","english_name":"Bar-tailed Trogon","scientific_name":"Apaloderma vittatum","overview":"斑尾咬鹃（英文名：Bar-tailed Trogon，学名：Apaloderma vittatum），是咬鹃目咬鹃科非洲咬鹃属的鸟类。其最显著的外部特征为尾部底部重叠的黑白条纹，这一图案在尾羽顶部边缘亦可见。主要分布在中非的湿润山地森林中，如尼日利亚东南部、喀麦隆西部、安哥拉中部、乌干达和刚果民主共和国东部、肯尼亚至莫桑比克等地。","appearance":"斑尾咬鹃体长约28-30厘米，体重约55克。雄鸟的喙呈黄或绿黄色；眼下方有黄色或橙色裸露皮肤斑块，上方为黄色或灰色；头部和喉部蓝黑色，带青铜绿光泽；胸线为蓝紫色；上体鲜绿色；中胸至腹部为红色；翼板有黑灰相间的条纹；尾羽上部主要为蓝或紫黑色，最外侧三根尾羽有黑白相间条纹；下尾密布黑白相间条纹；下翼有明显的白色条纹。雌鸟头部棕色，胸为肉桂棕色。幼鸟腹部白色，翼羽覆羽尖端为淡白色。","call":"鸣唱为一系列6-15个下降音调的“teew”音符，随着序列进展声音逐渐增大，类似于雀斑夜鹰的叫声。雌鸟发出哀怨的“chee-uu”声。","habits":"栖息于海拔900-3000米的湿润山地森林中，通常位于森林中层，高度4-20米，很少低于8米。在喀麦隆，它们被发现在原始森林和老次生林中，偏好山顶和围绕峡谷的树冠覆盖的山脊。在马拉维，偶尔出现在山地草原和种植松树林中。在坦桑尼亚的Rubeho山脉，记录到低至600米的高度。在Bioko岛，从900米至2000米，包括苔藓森林和地衣森林。","breeding":"繁殖期在Bioko为11月至1月，在喀麦隆为10月和12月至2月，在扎伊尔为2月至5月，在乌干达为3月，在肯尼亚为11月至2月（雨季开始后），在坦桑尼亚为9月和11月至2月，在安哥拉发现巢雏在9月，在马拉维为10月至11月，领土活动从8月至12月。可能实行一夫一妻制；在马拉维的领地大小变化大，1-7.5公顷，多数鸟偶尔访问小的邻近森林区域觅食，即使领地相对较大（10公顷）。巢为枯死树木中的洞穴，通常离地面约2米（在Bioko为1-1.5米）。产卵数为2枚，有时3枚；孵化和雏鸟成长期未有记录。","identification":"与其他非洲咬鹃属鸟类的区别在于其尾部的条纹。幼鸟与雌鸟相似，但腹部为白色，翼羽覆羽尖端有淡色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于尼日利亚东南部和喀麦隆西部，安哥拉中部，乌干达和刚果民主共和国东部，肯尼亚至莫桑比克。在喀麦隆，常见于Kupé山，而在其他西部高地的五座山上较为少见；在Bioko岛上，虽然害羞且难以观察，但在原始森林中频繁记录；在扎伊尔的Itombwe山区很常见。在东非普遍罕见：近年来在内罗毕周边森林消失；在坦桑尼亚的阿鲁沙国家公园和乌干达的三个国家公园中发现；在卢旺达，Nyungwe森林中密度适中，即使在最佳栖息地中也是如此。在赞比亚，Chowo森林中，Nyika高原下闭合树冠下的密度高达12对/25公顷；树冠不连续时，密度常为2-3对/10公顷。在马拉维的Chiradzulu可能已灭绝。在20世纪30年代早期，莫桑比克的Namuli山曾相当常见，但近期无数据。","other":"尽管在某些地区常见，但整体上斑尾咬鹃的数量趋势因栖息地破坏而下降。"},{"name":"蓝尾咬鹃","english_name":"Javan Trogon","scientific_name":"Apalharpactes reinwardtii","overview":"蓝尾咬鹃（英文名：Javan Trogon，学名：Apalharpactes reinwardtii），是咬鹃目咬鹃科蓝尾咬鹃属的鸟类。仅分布于印尼爪哇岛西部的火山带，栖息于海拔900-2500米的山地和丘陵森林中。拥有彩虹般的色彩，包括红色喙、黄色胸、橙色腹、橄榄绿头颈、蓝绿色背和紫色与绿色的脸部裸露皮肤。","appearance":"雄性蓝尾咬鹃长约34厘米，头部黄绿色，上体蓝绿色，翼羽有黄色条纹，尾部深金属蓝色；喉部和腹部黄色，胸部有一条淡灰绿色的带；喙红，眼周蓝，脚橙色。与非常相似的苏门答腊咬鹃相比，体型更大，尾更长，喙更粗，臀部绿色。雌鸟翼羽上的条纹更淡更窄。","call":"发出尖锐下降的颤音，有时会发出响亮的‘turrr’声。","habits":"通常安静地在森林中层停留，偶尔加入混合觅食群，飞行时风拍声嘈杂。栖息于山地雨林的下层，主要在较低的山坡上。","breeding":"繁殖记录见于4月至6月，8月，9月，10月和12月；11月观察到的5只鸟可能是一个家庭群。每窝产卵1-2枚，可能最多3枚，更多细节未知。","identification":"与苏门答腊咬鹃的区别在于更大的体型、更长的尾巴、更重的喙和绿色的臀部。","protection":"IUCN：VU（易危）","distribution":"分布于爪哇岛西部山区，最近的记录来自Halimun、Salak和Gede-Pangrango山脉。","other":"曾与苏门答腊咬鹃合并在同一物种——蓝尾咬鹃，但因体型、重量和羽毛差异而被分离。"},{"name":"苏门答腊咬鹃","english_name":"Sumatran Trogon","scientific_name":"Apalharpactes mackloti","overview":"苏门答腊咬鹃（英文名：Sumatran Trogon，学名：Apalharpactes mackloti），是咬鹃目咬鹃科蓝尾咬鹃属的鸟类。色彩鲜艳的森林居民，特有于印尼苏门答腊岛的山地和丘陵森林（海拔750至2200米）。具有橄榄绿头部和胸部，鲜黄喉部和腹部，蓝绿色背部，糖果红喙，以及蓝绿色裸露面部皮肤。雄鸟拥有深红色臀部斑块，雌鸟则无。","appearance":"雄性苏门答腊咬鹃身长约30厘米，头部黄绿色，上体蓝绿色，翼板有黄色条纹，臀部深栗色，尾巴金属蓝色；喉部和腹部黄色，胸部有一灰绿色带；红喙，蓝眼环，橙脚。雌鸟翼板上的条纹更淡且窄。与蓝尾咬鹃相似，但体型较小，尾巴较短，喙较小，雄鸟有栗色臀部。","call":"发出刺耳的下降颤音和哨声‘wih-whee-whirrr！’。","habits":"行动缓慢，常静坐于森林中层。以绿色毛虫、蚱蜢、竹节虫、甲虫、蝽象为食，也会吃果实；曾记录到捕食地面长达10厘米的蜥蜴。栖息于亚热带或热带湿润山地森林，主要在较低的山坡上，海拔范围750至2200米。","breeding":"繁殖期在3月，已知雏鸟在5月和6月被采集。每窝产卵1至2枚。无其他繁殖信息。","identification":"与蓝尾咬鹃的区别在于体型更小，尾巴更短，喙更小，雄鸟有栗色臀部而非全绿色臀部。雌鸟的翼板条纹更淡更窄。","protection":"IUCN：LC（无危）；受限范围物种，仅在苏门答腊和马来半岛东亚区有分布。区域内不常见，但在克里尼非常常见。","distribution":"分布于苏门答腊山区。","other":"曾被认为是蓝尾咬鹃的同种，统称为蓝尾咬鹃。"},{"name":"黑头咬鹃","english_name":"Malabar Trogon","scientific_name":"Harpactes fasciatus","overview":"黑头咬鹃（英文名：Malabar Trogon，学名：Harpactes fasciatus），是咬鹃目咬鹃科咬鹃属的鸟类。色彩鲜艳但行动迟缓的中型鸟类。仅分布于印度和斯里兰卡的森林中，以昆虫为主食，具有明显的性别差异，雄鸟头部黑色，腹部红色，雌鸟头部棕色，下体橙色。叫声独特，为一系列变调的吠声。","appearance":"雄鸟头部至中胸灰黑，带有白色胸线，中胸至尾下覆羽粉红；上体黄褐色，翼板具狭窄白纹，尾羽红褐带黑端。雌鸟头部和胸部暗淡棕色，模糊的淡色胸线，翼板具淡色条纹。幼鸟似雌鸟，但头部和胸部灰色。亚种malabaricus体型略大，尾巴较长，雄鸟头部和胸部为烟黑色。","call":"发出喉音丰富、悦耳的‘cue-cue-cue-...’叫声，类似oriole，两种亚种的歌声有细微差别。","habits":"栖息于热带和亚热带地区的密林中层，偏好有竹丛的环境，海拔可达1500米，偶尔至2000米。主要以毛虫、蛾、甲虫等昆虫为食，有时黄昏时分仍会觅食。通常跟随混群觅食。在斯里兰卡，常见于2200米的高海拔。","breeding":"繁殖季节在印度为2月至6月，斯里兰卡为3月至5月。巢穴为天然洞穴，有时部分由鸟挖掘，位于断木顶部或断裂处，距地面不到6米。每窝产卵2-4枚，白色有光泽，由两性共同孵化。","identification":"与异域分布的红枕咬鹃有明显区别，后者有红色颈背，而黑头咬鹃没有，且有更宽的白色胸线。雌鸟尾下覆羽可见黑色。亚种间也有差异，尤其是malabaricus体型更大，尾巴更长。","protection":"IUCN：LC（无危）","distribution":"分布于印度的西高止山脉、中部山区和东部山林，以及斯里兰卡的湿润森林。在斯里兰卡的干热和山地国家较少见。","other":"在印度某些地区正变得罕见，可能对森林碎片化敏感。"},{"name":"红枕咬鹃","english_name":"Red-naped Trogon","scientific_name":"Harpactes kasumba","overview":"红枕咬鹃（英文名：Red-naped Trogon，学名：Harpactes kasumba），是咬鹃目咬鹃科咬鹃属的鸟类。以其腹部鲜红至黄色的羽毛和深色的胸及上体而著称。雄鸟拥有黑色头部，亮红色枕部和下体，棕色背部，黑白相间的翅膀，而雌鸟则呈灰褐色头部和上胸部，淡黄色腹部。广泛分布于马来半岛、印尼苏门答腊岛、婆罗洲等地的低地森林中。","appearance":"红枕咬鹃的雄鸟具有黑色头部，亮红色的枕部和下体，棕色橙色背部，以及黑白条纹的翅膀。雌鸟则较为朴素，头部和上胸部为灰褐色，下体为淡黄色。两者均具有明亮的蓝色眼环和喙。幼鸟与雌鸟相似。成年鸟体长约32-34厘米，体重约72克。","call":"红枕咬鹃发出一系列咕噜声的叫声，如“kyew, kyew, kyew, kyew”，声音低沉且间隔均匀。","habits":"红枕咬鹃栖息于湿润的低地和山脚森林，主要在600米以下的高度活动，偶尔在婆罗洲的山地森林中可达1200米。它们是树栖性鸟类，不善于行走或跳跃，飞行能力有限，属于非迁徙物种。它们以果实和昆虫为食，采用掠食的方式捕获猎物。","breeding":"关于红枕咬鹃的繁殖信息有限，已知它们在腐朽树干的洞穴中筑巢，产卵数量通常在1到3枚之间，孵化期大约16至19天。雏鸟出生时盲而裸，但能迅速长出羽毛。","identification":"红枕咬鹃最显著的特征是雄鸟枕部的亮红色羽毛，这有助于与同类中的其他物种区分开来。雌鸟与雄鸟在颜色上有明显差异，有助于识别。","protection":"IUCN：NT（近危）","distribution":"红枕咬鹃主要分布在马来半岛南部、苏门答腊岛、婆罗洲的低地森林，以及部分山区森林。在泰国半岛地区，由于栖息地丧失，其数量稀少且受到威胁。","other":"红枕咬鹃面临的主要威胁是栖息地的丧失和退化，特别是在苏门答腊和婆罗洲，非法伐木和土地转换对其生存构成了严重挑战。"},{"name":"紫顶咬鹃","english_name":"Diard's Trogon","scientific_name":"Harpactes diardii","overview":"紫顶咬鹃（英文名：Diard's Trogon，学名：Harpactes diardii），是咬鹃目咬鹃科咬鹃属的鸟类。雄鸟拥有醒目的深红下体，黑色头部，以及粉红色颈背。雌鸟头部和上胸部呈褐色，下体较雄鸟更偏玫瑰粉色，胸前有一条清晰的白线。分布于马来半岛、苏门答腊岛和婆罗洲的热带雨林。","appearance":"成年紫顶咬鹃体长约34厘米，体重约101克。雄鸟具有黑色头部和上胸部，眼周环紫色，中冠至后冠部带紫色，颈背呈强烈粉红色，胸线淡粉色；背部和尾上覆羽淡棕色，腹部和臀部鲜红色，下尾覆羽带有黑纹。雌鸟头部和上胸部为暗褐色，下体比雄鸟更偏向玫瑰粉色。幼鸟外观似雌鸟。","call":"紫顶咬鹃的叫声是一系列回荡的上升式“kau”音节，第二个音节比第一个高，随后的声音下降，最后几个音节通常略低。","habits":"紫顶咬鹃栖息于低地和山脚的热带阔叶林中，常成对出现，活动于森林中间层。其食物包括毛虫、甲虫、竹节虫、蝗虫和其他昆虫，以及果实。","breeding":"繁殖期从2月持续到8月，具体而言，在马来西亚为2月至5月中旬，在婆罗洲为5月中旬至8月。筑巢、交配、产卵等繁殖行为详情尚需进一步研究。","identification":"雄性紫顶咬鹃的特征在于其黑色头部和鲜红下体，而雌鸟则通过头部的褐色和胸前清晰的白色线条与红头咬鹃雌鸟区分开，后者白色项圈较细且不完整。","protection":"IUCN：NT（近危）。在泰国半岛因栖息地丧失而受到威胁，新加坡自1940年后已灭绝。在婆罗洲较为常见，但在加里曼丹的Tanjung Puting国家公园中较为罕见。","distribution":"繁殖区域包括马来半岛、苏门答腊岛和婆罗洲。在苏门答腊岛，见于Bukit Barisan Selatan国家公园和Berbak游戏保护区；在婆罗洲，于沙巴的Cocoa Research Station数量最多。","other":"Dayak Iban社区认为听到紫顶咬鹃的叫声预示着不祥之兆。"},{"name":"粉胸咬鹃","english_name":"Philippine Trogon","scientific_name":"Harpactes ardens","overview":"粉胸咬鹃（英文名：Philippine Trogon，学名：Harpactes ardens），是咬鹃目咬鹃科咬鹃属的鸟类。主要分布在菲律宾，除了米沙鄢群岛的西部、巴拉望和苏禄群岛。其最显著的外部特征是雄鸟的黑色头部和粉色胸部，以及红色腹部，而雌鸟则具有淡黄色的下部和橄榄褐色的头部。粉胸咬鹃在菲律宾的森林中被视为一种特殊的物种。","appearance":"成年粉胸咬鹃体长约29至30厘米，体重介于82至114克之间。雄鸟具有一张带有鲜绿基部的黄色喙，黑色头部和喉咙，面部皮肤呈蓝紫色，冠羽泛着赤褐色；颈部和背部呈浅棕色，臀部颜色较浅；尾巴红褐色，末端有黑色条纹；胸部灰色带粉，胸前线鲜红，其余下体粉红色。雌鸟上部类似雄鸟但颜色更暗淡，头部和喉咙为棕色，胸部和腹部橙褐色，翼面有深褐色斑纹。幼鸟似雌鸟，但翼面有粗糙的斑纹。不同亚种在喉部斑纹、喙的大小和色彩上有细微差异。","call":"粉胸咬鹃的鸣声为一系列柔和的音符，先上升加速再逐渐下降减速，整个过程不到1.5秒，有时每隔大约10秒重复一次。","habits":"粉胸咬鹃栖息于各种类型的低地和中海拔山地原始森林的下层和中层，偶尔也会出现在次生林中，海拔高度可达2000米，但在200至600米之间更为常见。它们偏好密集的植被，特别是在山谷和溪流旁。已知它们会捕食昆虫，如蚱蜢和棍虫。","breeding":"粉胸咬鹃会在枯死树木的洞穴中筑巢，巢位距地面约6米，每窝产卵3枚。","identification":"雄性粉胸咬鹃与雌鸟的显著区别在于雄鸟的黑头、粉胸和红腹，而雌鸟则呈现较为暗淡的色调，以橙褐色为主。与其他咬鹃属鸟类相比，粉胸咬鹃的色彩更加鲜明。","protection":"IUCN：LC（无危）。尽管自19世纪以来可能经历了大幅度的减少，粉胸咬鹃目前在全球范围内并不受到威胁，但在某些局部地区，如Bohol岛和Sibulan岛，可能面临高度威胁。","distribution":"粉胸咬鹃分布于菲律宾的大部分地区，除了米沙鄢群岛的西部、巴拉望和苏禄群岛，主要在低地和中海拔山地森林中。","other":"粉胸咬鹃因其羽毛和颜色，常与菲律宾史诗中的神话鸟Ibong Adarna相联系。"},{"name":"灰胸咬鹃","english_name":"Whitehead's Trogon","scientific_name":"Harpactes whiteheadi","overview":"灰胸咬鹃（英文名：Whitehead's Trogon，学名：Harpactes whiteheadi），是咬鹃目咬鹃科咬鹃属的小型攀禽，主要分布在婆罗洲的北部山区。雄鸟头部、颈背及下体呈鲜艳的红色，喉部黑色，胸部灰色，上体为淡富丽的棕色；雌鸟相似，但以橙褐色取代红色。此鸟种以英国探险家John 白头刺莺命名。","appearance":"灰胸咬鹃体型厚实，长度约29至33厘米。雄鸟头部、颈背及下体鲜红，喉部黑色，胸部灰色，上体为淡富丽的棕色，尾部下方大部分白色，翅膀黑色带细白纹。雌鸟颜色较为暗淡，以橙褐色为主，翅膀上的条纹为棕色而非白色。幼鸟与雌鸟相似，但全身颜色更加统一，缺乏成年鸟的黑色喉部和灰色上胸。","call":"灰胸咬鹃的叫声包括一系列响亮、节奏均匀的四到五个粗犷音节，通常被描述为'kwau kwau kwau kwau'或'wark wark wark wark'，偶尔发出滚动的'burr'声，有时后跟下降的'kekekeke'。","habits":"偏好潮湿、阴暗的山地森林，常见于海拔900至2000米的地区，常在密林的中层静坐。它是一种害羞而低调的鸟，容易在密集的树冠层中被忽视。它通常与混合物种群落中的其他鸟类如栗头噪鹛和灰褐噪鹛、黑喉绿阔嘴鸟和巽他鹃鵙共同出现。","breeding":"繁殖生态知之甚少。已知的繁殖时间在4月，幼鸟在6月被发现，家庭群体在7月观察到。然而，巢穴和蛋的详细描述仍未知，关于其繁殖生物学的许多细节，如孵化和筑巢周期、卵数、离巢时间、雏鸟照顾的分工等，都尚未明确。","identification":"灰胸咬鹃与同属的其他咬鹃相比，具有独特的银灰色‘围裙’，橙棕色背部，深色面部，蓝色喙和眼周皮肤。雄鸟的红色和雌鸟的橙褐色是主要的识别特征。","protection":"IUCN：LC（无危）","distribution":"主要分布于婆罗洲北部山区，具体范围从基纳巴卢山至杜利特山和隆朱特山（印尼部分）。","other":"灰胸咬鹃的种群数量虽然没有量化，但被认为正在减少，主要威胁来自栖息地丧失，尤其是通过伐木和转变为农业用途。"},{"name":"橙腰咬鹃","english_name":"Cinnamon-rumped Trogon","scientific_name":"Harpactes orrhophaeus","overview":"橙腰咬鹃（英文名：Cinnamon-rumped Trogon，学名：Harpactes orrhophaeus），是咬鹃目咬鹃科咬鹃属的色彩鲜艳的鸟类。雄鸟头部乌黑，背部橙褐色，胸部和腹部鲜红夺目；雌鸟则拥有黄色下部和灰褐色头部。主要分布于东南亚的马来半岛、泰国和婆罗洲的低地及山脚森林。","appearance":"雄鸟体长约25厘米，体重45至61克，头戴黑色兜帽，喙蓝，眉纹及眼圈狭窄，上身和尾上覆羽呈淡棕色，下体粉红色，尾下覆羽白色带黑边。雌鸟头部深褐色，颊部和眼周栗色，臀部和下体锈色至黄褐色。幼鸟外观似雌鸟。两个亚种（H. o. orrhophaeus 和 H. o. vidua）在体型、喙大小、下体颜色及是否存在红色臀部上有细微差异。","call":"发出一系列下降的“tyaup”音符组成的歌曲，伴有尖锐的爆炸声“purrr”。","habits":"栖息于东南亚湿热低地和山脚森林的较低层，偏好Dipterocarps树为主的森林，偶尔出现在泥炭沼泽森林。不迁徙，以昆虫为主食，如蝉、竹节虫，偶尔捕食棍虫和叶虫。通常单独捕猎，有时小群体行动。","breeding":"繁殖季节在马来西亚为3月至6月，在婆罗洲主要为3月。筑巢于腐朽树木的较低部分，高度约1至1.5米，自行挖掘洞穴作为巢址。每窝产卵2枚，由双亲孵化。","identification":"与红腰咬鹃极为相似，但橙腰咬鹃体型略大，下体更偏粉色，无红色臀部。两亚种间主要通过地理分布区分。","protection":"IUCN：VU（易危）","distribution":"繁殖区域：马来半岛、印尼苏门答腊岛和婆罗洲。非繁殖区域：暂无具体信息。","other":"曾因栖息地提供良好掩护而得以保护，但近年来亚洲的森林砍伐威胁了其生存环境。"},{"name":"红腰咬鹃","english_name":"Scarlet-rumped Trogon","scientific_name":"Harpactes duvaucelii","overview":"红腰咬鹃（英文名：Scarlet-rumped Trogon，学名：Harpactes duvaucelii），是咬鹃目咬鹃科咬鹃属的鸟类。以其醒目的蓝嘴裂和眼上同样颜色的斑块而引人注目。雄鸟拥有鲜艳的红色臀部和下体，雌鸟则有橙色臀部、黄色胸部和粉红色腹部。生活在低地至山脚的常绿阔叶林中，以静坐和缓慢的动作著称。","appearance":"红腰咬鹃体长23至24厘米，体重34至43克。雄鸟头部黑色，喙蓝色，眼眉和眼眶环也是蓝色；上体和尾羽上覆羽为丰富的淡褐色至黄褐色，红色臀部，尾羽上覆羽和下体为鲜红色；尾羽下方白色，边缘黑色。雌鸟头部和喉部暗棕色，胸部较淡的黄褐色，腹部粉红色，臀部和尾羽上覆羽呈粉色。幼鸟类似雌鸟，但缺少粉色调，臀部和尾羽上覆羽更带锈色。","call":"发出非常柔和、快速的约12个音符的连续声，\"yau-yau-yau...\"，加速，渐弱；受惊时，发出安静的呼噜声\"kir-r-r-r\"。","habits":"红腰咬鹃栖息于低地至山脚的常绿阔叶林，通常从枝头觅食，但动作迟缓。其自然生境包括亚热带或热带湿润的低地森林、亚热带或热带沼泽和亚热带或热带湿润的山地森林。","identification":"雄鸟与雌鸟在外形上有明显差异，雄鸟的红色臀部和下体极为醒目，而雌鸟的色彩较为柔和，有橙色臀部、黄色胸部和粉红色腹部。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛、印度尼西亚苏门答腊岛、Batu Is.（苏门答腊岛西部）、Riau Is.（苏门答腊岛中部东部）、邦加岛和勿里洞岛（苏门答腊岛南部东部）、Natuna Is.（婆罗洲西北部）以及婆罗洲。"},{"name":"橙胸咬鹃","english_name":"Orange-breasted Trogon","scientific_name":"Harpactes oreskios","overview":"橙胸咬鹃（英文名：Orange-breasted Trogon，学名：Harpactes oreskios），是咬鹃目咬鹃科咬鹃属的鸟类。属于咬鹃科咬鹃属，是东南亚、大巽他群岛特有种。以其独特的橙黄色下体在雄鸟和雌鸟中均易识别。在中国，被列为国家二级重点保护动物，保护状态自1989年起生效。","appearance":"成年橙胸咬鹃体长25至31厘米，体重49至57克。雄鸟具有橄榄黄头，蓝眼环，上体及上尾部为赤褐色，翼板上有明显的白色宽条纹，上胸部为灰色基底的黄色，下胸部橙色渐淡至腹部。雌鸟头部和上体颜色更灰褐，上胸灰色，下体黄色。幼鸟外观似雌鸟，雄鸟幼鸟上体颜色偏暖棕色。","call":"发出连续三到四个均匀音调的鸣叫，前有1至3个音符的引入，通常为“tau-tau-tau”，有时伴有快速的训斥音。","habits":"栖息于低地和丘陵森林，包括半常绿和常绿森林、沼泽森林，偏好森林中层和下层。也可见于受扰动的竹林、稀树丛林、开放干燥森林和混合落叶森林，活动高度多样，有时接近地面。以昆虫、蜘蛛、蜥蜴、水果和植物材料为食，会跟随混群。","breeding":"繁殖期在泰国为2月至4月，马来西亚为1月至5月，筑巢于腐木或死竹中的空洞，高度多低于2米，平均高度2.1米。每窝产卵2至3枚，孵化期17至18天，育雏期12至14天以上，巢的成功率仅8%。","identification":"与同属物种相比，橙胸咬鹃的橙黄色下体是最显著的区别。不同亚种在上体颜色、尾长和冠羽深浅上有细微差异。","protection":"IUCN：LC（无危），但在中国被列为国家二级重点保护动物，保护状态自1989年起生效。","distribution":"分布于东南亚，包括泰国、马来西亚半岛、婆罗洲、苏门答腊、爪哇和尼亚斯岛，以及中国的南部地区。在泰国、马来西亚半岛、婆罗洲等地，分布高度可达1100至1500米。","other":"橙胸咬鹃在不同的栖息地中展现出适应性，包括次生林和接近森林的树木丛。"},{"name":"红头咬鹃","english_name":"Red-headed Trogon","scientific_name":"Harpactes erythrocephalus","overview":"红头咬鹃（英文名：Red-headed Trogon，学名：Harpactes erythrocephalus），是咬鹃目咬鹃科咬鹃属的鸟类。以其雄鸟鲜艳的红色头部而闻名。广泛分布于喜马拉雅山脉、中国南部至印尼苏门答腊岛。体色鲜明，雄鸟具有独特的暗红色头部和腹部，背部呈棕褐色，翅膀带有黑白相间的条纹。雌鸟的红色部分被橄榄棕色所替代。在中国，《中国濒危动物红皮书·鸟类》将其列为易危物种，同时它也被联合国列入《濒危野生动物名录》，并且是中国国家重点保护二级野生动物。","appearance":"成年红头咬鹃平均长度约34厘米。雄鸟的头部、颈部和上胸部呈现暗淡的猩红色，有一条狭窄的白色带横跨中胸，下部胸部到腹部为淡红色至粉红色。雌鸟的头部、颈部和上胸部为橄榄棕色，下胸部至腹部同样为淡红色至粉红色。两者均拥有锈褐色的背部，翅膀带有黑色和白色的斑点，尾巴中央的羽毛为深棕色，边缘的羽毛为白色。雄鸟的喙为钴蓝色带黑尖，雌鸟的喙为浅蓝色。","call":"雄鸟的叫声类似欧亚金莺，发出一系列间隔开的五到六个柔和的“tyaup”音节，每分钟重复一次。偶尔会发出拉长的‘pluu-du’音，音调显著下降。","habits":"红头咬鹃偏好热带雨林和次生常绿阔叶林，通常在树荫下的树枝上等待猎物，单独或成对出现。它们主要在清晨和黄昏时分活跃，以绿色直翅目昆虫、竹节虫、蝉、千足虫、苍蝇、甲虫、蜈蚣、木虱和飞蛾为食，也食用叶子和浆果。","breeding":"繁殖期在4月至7月之间，筑巢于离地面1.5至5米的自然树洞中，雌雄共同参与巢穴挖掘、孵化和育雏。每窝产2至4枚圆形、奶油色、有光泽的蛋，孵化期约为18天，雏鸟在13.4天后离巢。","identification":"雄鸟的红色头部和胸部是其显著特征，与雌鸟的橄榄棕色头部形成对比。与紫顶咬鹃相比，红头咬鹃的雌鸟缺乏斑点状的下尾羽。","protection":"IUCN：LC（无危）；中国国家重点保护野生动物名录：Ⅱ级（2021.02.05）","distribution":"红头咬鹃广泛分布于喜马拉雅山脉和中国南部至印尼苏门答腊岛。在中国，常见于云南、广西、广东、福建、台湾等地。","other":"红头咬鹃在泰国的一些地区可能受到猎捕的威胁。"},{"name":"红腹咬鹃","english_name":"Ward's Trogon","scientific_name":"Harpactes wardi","overview":"红腹咬鹃（英文名：Ward's Trogon，学名：Harpactes wardi），是咬鹃目咬鹃科咬鹃属的鸟类。以其独特的外观和分布而知名。雄鸟具有深粉红色的喙，眼圈淡蓝色，头部、胸部和上体呈板岩色并带有紫红色晕染，最显著的是其鲜红色的腹部和额头。雌鸟则呈现橄榄棕色，头顶部和下体黄色。分布于印度东北部至越南北部的山区，包括不丹、中国西藏、云南以及缅甸北部。","appearance":"体长约35至38厘米，体重约115至120克。雄鸟拥有酒紫色背部，鲜红色腹部，额头有一簇红色绒羽，眼周环淡蓝色。雌鸟的色泽较暗，以橄榄棕色为主，头部和下体呈黄色。喙尖颜色，雄鸟为深红色，雌鸟为黄色。两者皆有明显的淡色眼环。","call":"发出一系列快速的‘klew’或‘klu’音符，通常会逐渐加速并降低音调，每秒重复约5次。另有粗糙的‘whirrur’声和流水般的喋喋声，后者音符每秒约15个。","habits":"栖息于高大亚热带山地森林的低层，偏好Quercus和Castanopsis等树种组成的森林，常见于有藤蔓覆盖的温带常绿阔叶林。活动范围通常位于海拔1500至3200米之间，冬季可能下降至300米。以昆虫、果实和种子为食，展现出典型的咬鹃行为特征。","breeding":"关于繁殖行为的信息有限，但已知在3月至4月间发现处于繁殖状态的个体，具体筑巢细节尚未被记录。","identification":"雄鸟与雌鸟在外表上有明显差异，雄鸟的鲜艳色彩和雌鸟的橄榄色调形成对比。在同属物种中，可通过色彩和体型进行辨认。","protection":"IUCN：LC（无危），保护级别：Ⅱ级（2021.02.05）","distribution":"繁殖区域主要分布在不丹、印度东北部、中国西藏西部至云南西部、缅甸北部及越南北部。在非繁殖季节，有迹象显示会向较低海拔迁移。","other":"以英国植物学家兼探险家Francis Kingdon-Ward的名字命名，以纪念他对科学的贡献。"},{"name":"鹃三宝鸟","english_name":"Cuckoo-roller","scientific_name":"Leptosomus discolor","overview":"鹃三宝鸟（英文名：Cuckoo-roller，学名：Leptosomus discolor），是鹃三宝鸟目鹃三宝鸟科鹃三宝鸟属的鸟类。鹃三宝鸟科的唯一成员，体型大、头宽、腿短，眼位极高，整体形态独特。雄鸟头与下体浅灰，背部具金属绿紫虹彩；雌鸟通体红褐，下体密布暗斑。见于马达加斯加及科摩罗群岛各类森林，偶至林缘灌丛与人工种植园。飞行似猛禽，常于林冠层栖停，雄鸟与配偶频繁作高空炫耀盘旋，并发出极响亮持久的三音节哀婉哨音。","appearance":"体长38–50厘米，体重160–301克。雄鸟眼先至枕部具细黑带，与黑色顶冠相连；背、肩及尾呈金属绿，随光角变化泛紫；头侧及下体浅灰。雌鸟头颈深栗褐并具暗色横斑；背、翼覆羽及尾暗褐，散见栗色斑块；喉部带棕黄，下体白至浅黄，满布深褐色不规则粗斑。喙黑色；虹膜深褐（雌鸟稍淡，偶呈灰绿）；脚浅黄褐至亮橘红（雌鸟略淡）。幼鸟似雌鸟而色暗，枕部灰绿，肩羽灰褐具窄皮黄缘；雄鸟亚成体先长出虹彩背羽，后下体转为灰色。亚种gracilis体型最小，雄鸟喉胸灰蓝与腹白分界鲜明，雌鸟上体更浅，下体斑点更密；intermedius体型居中，雌雄虹彩均较发达，雌鸟尾羽更栗，下体深肉桂色并具栗色端斑。","call":"鸣声极响亮且远传，多全年于飞行中发出，亦于满月夜鸣叫。雄鸟常作3–4（偶5）声高扬笛音，音调略降“weeell weeell weeell”；兴奋时更颤。另发啄木鸟式“woo we-we-we-war-war”或低沉“rieww pupupupupupup”告警；联络声轻柔“wheeu”或“pup”。炫耀飞行伴“kwi-yu”，雌鸟偶回以“blublublubooo”。部分长鸣可持续15–25分钟，起句带颤“huhuhuwewhew”，收句粗哑“wha-ha-ha-ha”。孵化雌与雏受威胁时张嘴发“ghaaa”鼾声。Grande Comore的gracilis鸣声更流畅高亮，3声为主“pee-eww pew pew”，首二声高、末声短促；Anjouan的intermedius音略低，末音更简单，偶发5–7短哨易与马岛大鹦鹉混淆，雌鸟尚发音乐性“pop-poop-plik”。","habits":"栖于雨林、海岸林、刺灌丛、落叶林、走廊林、桉树种植园及公园空地，海拔自海平面至2050米，科摩罗诸岛多在400–1200米。马达加斯加种群喜林冠，科摩罗种群多在中层。基本留鸟，可短距离换域飞行数公里；非繁殖期有散漫游荡，马达加斯加西部曾有4月与9月集群记录，东西季节性迁移证据不足。捕食以“停栖-突袭”或空中追击为主，食物以昆虫（蝗、毛虫、竹节虫、螳螂、蝉、蚱蜢）和爬行动物为主，常整吞80–200毫米的变色龙（Furcifer、Calumma）与叶尾守宫（Uroplatus）；圈养亦食禽鱼下脚、罐头牛肉。Mayotte巢雏全喂变色龙，马达加斯加巢雏则多为蝉与毛虫。","breeding":"繁殖期科摩罗约9月中旬至12月，马达加斯加11月为主，Anjouan可能更长（4月下旬尚见3–4周幼鸟）。推测单配制，终年成对。群集空中炫耀，曾见10只同舞或4雄向1雌示偶。巢筑于天然树洞（深可达1.2米），卵直接产于木底，每窝4–5枚，卵白略染米绿或乳黄，平均45×38毫米。仅雌孵卵，雄负责投喂，孵化期约20天；雏覆白色长绒，双亲共同喂雏，30天左右离巢。天敌包括马岛獴（Cryptoprocta ferox）及多种猛禽。","identification":"飞行时宽翅缓拍似猛禽，但头巨大、嘴小、翼击无力，易与阔嘴三宝鸟区别：本种体型更大，嘴色暗。与科摩罗其他两种近似种相比，亚种 gracilis 雄鸟喉胸灰蓝与腹白对比强烈，雌鸟上体更浅褐，下体斑点于浅色底上更浓；亚种 intermedius 雌雄虹彩均发达，尾羽更栗，下体深肉桂并具栗端斑。","protection":"IUCN: LC（无危）。虽栖息地持续破坏，但在马达加斯加西部干热林及科摩罗种植园、花园仍常见，Mohéli与Mayotte数量稳定。Gracilis亚种估计约100对，intermedius 亦被视为罕见，推测不足100对，1985–1989年数量曾显著下降，亟需研究。","distribution":"繁殖区：马达加斯加全岛及科摩罗群岛（Mwali/Mohéli、Maore/Mayotte、Ndzuani/Anjouan、Ngazidja/Grande Comore）。非繁殖区：基本留鸟，仅作局部游荡。","other":"系统分类上，gracilis因体型、羽色与鸣声差异曾被提为独立种，intermedius在羽色上介于二者之间；三亚种总分异值已达6分，未来或全被提升为独立种。 proposed race anjouanensis已并入intermedius。"},{"name":"棕顶佛法僧","english_name":"Purple Roller","scientific_name":"Coracias naevius","overview":"棕顶佛法僧（英文名：Purple Roller，学名：Coracias naevius），是佛法僧目佛法僧科佛法僧属的鸟类。体型中等、颜色较为暗淡的佛法僧，广泛分布于非洲次撒哈拉区域。其最显著的特征是头顶的粉色至赤褐色冠羽和鲜明的白色眉纹，背部呈橄榄绿色，腹部粉紫色并带有白色细纹。偏好干旱的灌木林和开阔的草原地带。","appearance":"成年棕顶佛法僧体长可达35至40厘米，体重介于125到200克之间。头部和下体颜色随地理位置而异，北部种群的头冠更偏向赤褐色，而南部种群的头冠则更偏橄榄绿。下体羽毛为紫粉色，点缀着白色的条纹。翅膀长且圆润，尾巴末端平截。喙和腿脚颜色未提及。","call":"发出响亮但略显粗哑的‘ka’或‘gaa’声，连续快速均匀地重复，有时会以4至6音节的‘gugudigow’或‘gu, gu, gidaga’的咕噜声作为前奏，这种叫声在飞行中尤为常见。","habits":"栖息于干燥的灌木丛生环境，如荆棘林和较干燥的森林地带。常在高树顶端或电线杆上长时间观察地面，寻找昆虫、蜘蛛、蝎子和小型蜥蜴等猎物。具有领地意识，繁殖季节会驱赶其他同类、小型猛禽和乌鸦。","breeding":"繁殖季节因地区而异，通常在雨季到来时开始。在自然树洞、旧啄木鸟洞、悬崖、河岸、管道或石墙空隙中筑巢，通常产下2至4枚光滑的白色卵，由双亲共同孵化和喂养幼鸟。","identification":"与非洲其他Coracias属物种相比，下体斑纹独特，羽毛中无淡天蓝色调；与非洲Eurystomus属的佛法僧区别在于其长而黑的喙和橄榄色而非土黄色的背部。雄雌同形同色，幼鸟头部和下体颜色较浅，橄榄色较多。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲大陆，北至几内亚草原和南苏丹草原，东至埃塞俄比亚，南至赞比亚和莫桑比克。在热带北部，全年可见于几内亚北部和苏丹南部的草原；在热带南部，常见于津巴布韦、赞比亚和马拉维的非繁殖季节。","other":"其种群密度在某些地区相当高，如加纳阿克拉平原的公路旁每200米就有一只，肯尼亚塔萨沃国家公园曾记录密度约为5只/平方公里。"},{"name":"西棕胸佛法僧","english_name":"Indian Roller","scientific_name":"Coracias benghalensis","overview":"西棕胸佛法僧（英文名：Indian Roller，学名：Coracias benghalensis），是佛法僧目佛法僧科佛法僧属的鸟类。直译: 印度佛法僧，广泛分布于南亚热带地区，从阿拉伯半岛东部到印度、孟加拉国和斯里兰卡。这种非候鸟有时会进行短途迁移。其特征在于头部和胸部的蓝色色调，以及明亮的蓝翼和腹部。该物种在印度被正式命名为模式产地。","appearance":"西棕胸佛法僧长约30-34厘米，体重约166-176克。其脸部和喉咙呈粉红色，头部和背部为棕色，臀部和翅膀对比鲜明的亮蓝色。飞行时，翼上的亮蓝色标记尤为显眼。两性外观相似，幼鸟则颜色较暗淡，背部和下体偏褐色。喙基部呈黄橙色，眼周皮肤为淡黄色，腿和脚为黄褐色。","call":"发出单调音节的接触叫声，从短促的‘chack’到更长、更粗糙的‘tschow’。在滚飞展示时发出‘Kaarsch’叫声，当接近入侵者时频率和音量增加。成鸟在巢中时会发出刺耳的求食声，而刚独立的幼鸟觅食时会发出猫般的叫声。","habits":"常在开阔地带活动，包括农田、牧场、种植园、棕榈树林、干燥的金合欢和Prosopis树林、路边带电线和路旁草地。适应了人类改变的环境，如村庄、城市郊区的旧现代建筑、公园、运动场、大花园和草地环岛。在南印度，主要栖息于农田、河岸和开阔森林区。以大型节肢动物和小型脊椎动物为食，如蚱蜢、蟋蟀、蜘蛛、蜥蜴、蛇、青蛙、老鼠和偶尔的小鸟。","breeding":"繁殖季节在北部分布区为3月至6月（偶尔7月），南部分布区为1月至3月。通常为一夫一妻制，形成明显的领地，雄鸟在半滚动飞行中巡逻领地并鸣叫。在简单的巢穴中产卵，如石墙洞、屋檐下、屋顶溢水管、树洞或死椰子树顶的空洞。巢穴由两性共同装饰，使用草、枝条、羽毛、纸张和碎布。每窝产3-5枚蛋，孵化期17-19天，幼鸟30-35天后离巢。","identification":"与三宝鸟的区别在于西棕胸佛法僧的喙为黑色。与蓝胸佛法僧相比，西棕胸佛法僧头部和胸部的蓝色较少。西棕胸佛法僧的翼上有独特的亮蓝色条纹。","protection":"IUCN：LC（无危）","distribution":"从阿拉伯半岛东部至印度、孟加拉国和斯里兰卡。在巴基斯坦，常见于Chotiari大坝周围的湿地、Jiwani沿海湿地、Punjab的Taunsa大坝和Chenab河沿岸。夏季偶尔访问阿富汗的Jalalabad。在叙利亚、沙特阿拉伯、马斯拉岛、卡塔尔、也门、索科特拉岛、巴林等地有记录。在伊朗、伊拉克、阿联酋、科威特、黎巴嫩、土耳其、以色列、约旦、埃及也有记录。在中国大陆，偶尔出现在西南地区。","other":"西棕胸佛法僧在印度受到法律保护，被列为三个印度邦的州鸟。在伊朗，受伊斯兰法典保护。由于广泛的分布和似乎增加的种群数量，被IUCN列为无危物种。"},{"name":"紫翅佛法僧","english_name":"Purple-winged Roller","scientific_name":"Coracias temminckii","overview":"紫翅佛法僧（英文名：Purple-winged Roller，学名：Coracias temminckii），是佛法僧目佛法僧科佛法僧属的鸟类。以独特的深紫色羽毛著称，仅头部和臀部呈现醒目的天蓝色。分布于印度尼西亚苏拉威西次区域，包括苏拉威西岛、邦卡岛、莱姆贝岛、曼特劳岛、穆纳岛和布通岛。此鸟又被称为Celebes roller、Sulawesi roller或Temminck's roller。","appearance":"紫翅佛法僧体长约30至40厘米，体重介于144至164克之间。全身羽毛深紫色，头顶和上尾覆羽呈明亮的天蓝色，背部为暗橄榄色。翅膀和尾巴颜色饱和且无斑纹，与非洲的棕顶佛法僧相似，但紫翅佛法僧的头顶和上尾覆羽为天蓝色，腹部无条纹。幼鸟的头顶颜色较暗淡，翼覆羽橄榄色，下体为烟灰色，仅腹部带有紫色调。雄鸟和雌鸟外观相似。","call":"紫翅佛法僧发出刺耳、干燥的摩擦声，通常为连续的“ka-ka-ka-ka…”叫声，有时也会发出单个的‘chowwEER’叫声。","habits":"栖息于部分封闭、树木茂密的地区，远离原始森林，海拔高度可达1000至1150米，包括森林边缘、开阔的林地、沼泽森林、灌木丛生的草地、农田和村庄边缘的花园与小农场。在海拔800米以下至海平面，常见于轻型林地、树林草原等环境。该鸟主要在苏拉威西岛低地和山脚地带活动，常单独或成对出现在显眼的枯枝上。","breeding":"繁殖期记录到的蛋出现在11月，已发现的雏鸟在9月末和12月初的巢穴中，3月份观察到喂养幼鸟的情况。至今发现的巢穴均位于树洞中，高度在5至20米之间，包括一个节疤孔、一个旧啄木鸟的洞穴，以及一株死棕榈树的树干上约10米高处。一窝通常产三枚蛋，关于繁殖的其他信息尚不清楚。","identification":"与非洲的棕顶佛法僧相比，紫翅佛法僧的头顶和上尾覆羽为天蓝色，腹部无条纹。与同域分布的三宝鸟和异域分布的翠蓝三宝鸟相比，紫翅佛法僧具有黑色的喙、天蓝色的头顶和上尾覆羽、橄榄色的背部，以及纯紫色的翅膀，没有天蓝色斑块。","protection":"IUCN：LC（无危）","distribution":"紫翅佛法僧主要分布在苏拉威西岛及其周边的曼特劳岛、邦卡岛、莱姆贝岛、穆纳岛和布通岛。在繁殖区域与非繁殖区域无明显差异。","other":"紫翅佛法僧已被记录到捕杀成年麻雀，这是其饮食中较为罕见的记录。"},{"name":"扇尾佛法僧","english_name":"Racket-tailed Roller","scientific_name":"Coracias spatulatus","overview":"扇尾佛法僧（英文名：Racket-tailed Roller，学名：Coracias spatulatus），是佛法僧目佛法僧科佛法僧属的鸟类。分布在非洲南部，自安哥拉至博茨瓦纳北部、津巴布韦、马拉维及莫桑比克等地。其最显著的特征是尾部带有独特的勺状尖端流苏。","appearance":"体长28至30厘米，尾部流苏可达额外8厘米。头部前额和眉纹白色，冠部暗绿色，背部锈色，尾部蓝色。下体淡蓝色，具白色条纹。飞行时可见紫色上翼带有一条天蓝色条纹。喙黑色，眼棕色，腿黄褐色。幼鸟色彩较淡，缺乏延长的尾羽。","call":"发出响亮而粗糙的类似小狗吠叫的声音，称为“cha”或“tchek”，在飞行或停栖时反复发出。","habits":"栖息于成熟的布氏森林、干燥的胶木森林、泰克森林和茂密的金合欢灌木丛，最高可达马拉维1200米和赞比亚1800米。以昆虫、蝎子和小型蜥蜴为食，通常单独或成对活动，偶尔会形成6至7只的小群。","breeding":"繁殖季节在赞比亚和津巴布韦为9月至12月，在马拉维为10月至11月。巢筑于树干或树枝上的洞穴中，高度约7米，通常使用旧啄木鸟或鵗的巢穴。每窝产2至4枚白色蛋。","identification":"与蓝胸佛法僧和紫胸佛法僧相似，但具有独特的尾羽流苏。幼鸟色彩较淡，缺乏延长的尾羽。","protection":"IUCN：LC（无危）","distribution":"分布于非洲南部，包括安哥拉、刚果民主共和国东南部、坦桑尼亚南部、博茨瓦纳北部、津巴布韦、马拉维和莫桑比克。","other":"在一些国家公园如坦桑尼亚的米库米和鲁阿哈、赞比亚的卡富埃和南卢安瓜、马拉维的卡松古、伦格威和利翁德以及津巴布韦的万基都有发现。"},{"name":"紫胸佛法僧","english_name":"Lilac-breasted Roller","scientific_name":"Coracias caudatus","overview":"紫胸佛法僧（英文名：Lilac-breasted Roller，学名：Coracias caudatus），是佛法僧目佛法僧科佛法僧属的鸟类。以其独特的色彩和壮观的飞行展示闻名。这种中等体型的攀禽广泛分布于东非和南非，常见于开阔的林地和稀树草原。被认为是肯尼亚的非官方国鸟。","appearance":"紫胸佛法僧体长约28至30厘米，尾部有长达8厘米的流苏状羽毛。头部较大，体态结实。额部白色，头顶至颈背橄榄绿，背部棕色，臀部深蓝色，尾上覆羽湛蓝。翅膀深蓝色，小翼羽至其余翼羽较淡蓝色，初级飞羽基部和尖端鲜亮的湛蓝。尾部橄榄蓝，最外侧羽毛湛蓝带暗色尖端，形成黑色流苏。脸颊橙粉色，下喉和胸部呈淡紫色，腹部蓝色。雌雄同色，幼鸟色泽较暗，缺乏尾流苏，额头和眉纹呈肉桂色，脸颊和胸部有宽阔的灰白色条纹。","call":"紫胸佛法僧发出响亮的喉音‘rak rak rak’，在飞行中重复迅速，有时在展示飞行时上升至嘈杂的‘kaaa, kaarsh’。","habits":"紫胸佛法僧栖息于有间隔树木的阿卡西亚木林地、纯草地、滚动灌木丛地、轻森林、河边树林和耕作地。不接近人类居住区。在海拔0至1700米之间活动，迁徙模式复杂，部分群体为留鸟，部分进行季节性迁移，如索马里西北部和埃塞俄比亚中部的群体迁至南索马里和南埃塞俄比亚过冬。","breeding":"繁殖期从4月至6月，部分地区可延至9月。在自然树洞中筑巢，通常选择枯树如金合欢或猴面包树，或白蚁丘。每窝产2至4枚光滑的白色蛋，孵化期22至24天，幼鸟孵化后19天羽毛丰满，35天后离巢，再由父母喂养约10天。","identification":"与蓝胸佛法僧相比，紫胸佛法僧体形更圆润，胸部和脸部为蓝色，尾巴更短，末端呈方形。与蓝头佛法僧区别在于冠部更绿，脸颊带橙色，喉咙粉红色。","protection":"IUCN：LC（无危）","distribution":"主要分布于东非和南非，包括索马里、埃塞俄比亚、肯尼亚、马拉维、赞比亚、津巴布韦和南非东北部。偶尔在阿拉伯半岛南部出现。","other":"在肯尼亚极为常见，被非正式地视为国家象征。"},{"name":"蓝头佛法僧","english_name":"Abyssinian Roller","scientific_name":"Coracias abyssinicus","overview":"蓝头佛法僧（英文名：Abyssinian Roller，学名：Coracias abyssinicus），是佛法僧目佛法僧科佛法僧属的鸟类。分布于非洲萨赫勒地带南部，自毛里塔尼亚至科特迪瓦，东至厄立特里亚、索马里和肯尼亚，亦见于西南沙特阿拉伯和西也门。其适应性强，常出现在温暖开阔地带，有树的环境，乃至农田和人类居住区。","appearance":"成年蓝头佛法僧体长28至31厘米，体重99.5至140克，背部呈暖褐色，其余羽毛以蓝色为主。头部淡蓝色，前额和下巴白色；上半身棕色，臀部、尾羽覆盖物和尾羽中心深蓝色；尾羽大部明亮的天蓝色，最外侧尾羽显著延长，形成细长的黑色流苏状；翅膀深蓝色，包括较小的翼羽覆盖物，其余翼羽覆盖物鲜亮的浅天蓝色；整个下体淡蓝色，喉咙到上胸部有薄薄的白色条纹。幼鸟缺乏流苏状尾羽，比成鸟暗淡，胸背部位带有棕色，蓝色部分泛橄榄色，翅膀上的紫蓝色与浅蓝色界限不明显。","call":"飞行中发出粗哑的‘rack’或‘gak’声，通常音量较大，类似其他佛法僧种类；停歇时发出爆炸性的‘aaaarh’声，持续约0.5至1秒；面对入侵者挑战时，发出‘aaaaar-aaaaar’声；在空中展示时，典型的飞行叫声会迅速重复并拉长，变成尖锐的‘ra-ra-ra-ra-gaa-gaa-gaa-aaaaaar, aaaaaar’声，持续2至3秒。","habits":"主要栖息于干燥的灌木草原，偏好树木稀疏的地带，如牧场、耕地、谷物和木薯田、荆棘金合欢灌木草原、湿地周边区域、林间空地、路边以及烧过的灌木丛。也常见于乡村住宅区、村落、城镇公园和郊区绿地。活动范围广泛，从塞内加尔到厄立特里亚和埃塞俄比亚东部，北至撒哈拉沙漠边缘，南至刚果民主共和国北部和肯尼亚西北部雨林地带边缘。","breeding":"繁殖季节从2月至7月，包括阿拉伯半岛（4月至6月），但在埃塞俄比亚可能更晚（4月至10月）。一夫一妻制，通过空中展示保卫领地，突然俯冲下降，水平飞速前进，尖叫并快速翻滚，再次上升并重复这一过程。筑巢于树木小洞中（如猴面包树）、棕榈树干（如海枣）或人类居住建筑下的檐口或砖墙空隙中，高度3至8米。每窝产3至6枚（通常4枚）光滑的白色卵，尺寸23.5至31.5毫米×18.5至26毫米。孵化和离巢期未知，但有记录显示三枚卵全部成功孵化。","identification":"与紫胸佛法僧相比，蓝头佛法僧具有更长的尾羽流苏和蓝色喉咙；与蓝胸佛法僧的区别在于更纤细敏捷的外观、较短的颈部（飞行轮廓）、较短的翅膀、较长的尾巴，以及翼羽为紫色蓝而非黑色。成鸟两性相似，幼鸟缺乏流苏状尾羽，颜色较为暗淡。","protection":"IUCN：LC（无危）；广泛分布，频繁至常见，局部地区数量众多。在西南阿拉伯可能有2500对，其中三分之二位于也门。在多个国家公园中出现，如塞内加尔的Djoudj、象牙海岸的Comoe、喀麦隆的Waza、苏丹的Dinder、埃塞俄比亚的Awash和乌干达的Kabalega Falls。因现代农业和小城镇城市化的扩展而受益。未有迫害记录。","distribution":"分布于非洲，从毛里塔尼亚至科特迪瓦，东至厄立特里亚、索马里和肯尼亚北部，偶尔进入沙漠地区，北至毛里塔尼亚努瓦迪布和苏丹北部尼罗河上游；也见于西南阿拉伯。","other":"在多个国家公园中发现，包括塞内加尔的Djoudj、象牙海岸的Comoe、喀麦隆的Waza、苏丹的Dinder、埃塞俄比亚的Awash和乌干达的Kabalega Falls。"},{"name":"蓝胸佛法僧","english_name":"European Roller","scientific_name":"Coracias garrulus","overview":"蓝胸佛法僧（英文名：European Roller，学名：Coracias garrulus），是佛法僧目佛法僧科佛法僧属的鸟类。以明亮的蓝色头部、下体和前翼，黑色的飞羽，以及粉棕色的上背、背部和三级飞羽为显著特征。分布广泛，自欧洲至中亚，冬季迁徙至非洲南部，主要在干燥的灌木草原和开阔地带活动。","appearance":"蓝胸佛法僧是一种中等体型的佛法僧，长度约29-32厘米，翼展可达52-58厘米，整体呈鲜艳的蓝色，背部橙褐色。成鸟具有亮蓝色的头部、颈部和下体，嘴基部白色，眼纹细黑，上体橄榄绿色，背部、臀部和尾羽覆羽深蓝色，翼覆羽蓝绿色，边缘紫色，主翼羽基部天蓝色，其余黑色，仅内侧次级飞羽紫色，下翼面鲜紫蓝色，尾羽蓝绿色，基部较暗，中央尾羽灰色，最外侧尾羽尖端黑色且稍长。幼鸟色泽较暗，头部和尾部橄榄绿，胸部和小翼覆羽带红褐色，脸颊、下巴至胸部有窄白条纹，尾羽无黑色角状突起。性别相似，幼鸟较为暗淡。","call":"蓝胸佛法僧发出的是粗哑的乌鸦般的叫声，在繁殖季节时，会发出一系列类似‘rak’的叫声，有时拉长为‘raaah’。","habits":"栖息于温暖、阳光充足的低地，海拔高度从欧洲的1000米，西班牙南部的1200米，到摩洛哥的2300米，再到吉尔吉斯斯坦的3100米。偏好有橡树森林、成熟的松树林、果园、混合农田、宽阔河谷和分散的多刺或叶树的开阔乡村。冬季迁徙至非洲南部，主要在干燥的灌木草原和开阔平原生活。","breeding":"蓝胸佛法僧在5月至7月间繁殖，通常独居并有领地意识，偶尔在巢间距70-200米的半群居状态下繁殖，极少数情况下距离缩短至5-10米。巢址选择在大树、建筑物、悬崖或河岸的天然洞穴中，不做内部铺垫。一窝产卵3-6枚，通常4-5枚，单次繁殖，孵化期17-19天，主要由雌鸟负责。雏鸟孵化后裸身无视，13天后闭合的刺状羽鞘形成，17天后羽鞘开始打开；离巢期25-30天，多数为26-27天，离巢后仍由成鸟喂养至少3周。","identification":"与蓝头佛法僧相比，蓝胸佛法僧缺乏尾羽流苏，体型更为壮实。成鸟间差异不大，但幼鸟颜色较暗淡，头部和尾部呈橄榄绿色，胸部和小翼覆羽微带红褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在欧亚大陆的西部和中部，冬季迁徙至非洲南部，中国新疆也有分布记录。","other":"蓝胸佛法僧在迁徙过程中受到猎杀威胁，尤其是在地中海周边国家和阿曼。农业实践导致潜在巢址和狩猎栖木的丧失，农药减少了昆虫食物的供应。"},{"name":"蓝腹佛法僧","english_name":"Blue-bellied Roller","scientific_name":"Coracias cyanogaster","overview":"蓝腹佛法僧（英文名：Blue-bellied Roller，学名：Coracias cyanogaster），是佛法僧目佛法僧科佛法僧属的鸟类。分布于非洲，从塞内加尔到刚果民主共和国东北部，常见于成熟湿润的萨瓦纳草原，以Isoberlinia树木为主。其显著特征为深蓝色的背部，粉白或乳白色的头部与胸部，翅膀、臀部和上尾覆羽呈紫蓝色，尾部和翼条为淡天蓝色，尾羽末端有适度长度的飘带。","appearance":"蓝腹佛法僧体长约28至30厘米，尾部的飘带可达6厘米，体重介于110至178克之间，性别差异不明显。成年个体羽毛色彩鲜艳，背部深蓝，头部、颈部和胸部呈粉白或乳白色，翅膀、臀部和上尾覆羽紫蓝色，尾部和翼条淡天蓝色。幼鸟羽毛较暗淡，尾部无飘带。","call":"发出快速、干燥的‘嘎嘎嘎嘎’声或‘咯咯咯咯’声，音节长短不一，有时加速成嘲笑般的笑声。","habits":"栖息于成熟Isoberlinia树林，靠近雨林地带，以及人类活动区的萨瓦纳草地。主要以大型昆虫和小型脊椎动物为食，偶尔也会食用油棕果仁。捕食方式多样，常从高树上观察，地面捕食占80%，空中追逐捕食占20%。成对或三至七只小群体活动。","breeding":"繁殖期从4月至7月在塞内加尔和冈比亚，3月至5月在塞拉利昂，2月至9月在象牙海岸。巢穴位于离地约10米的树洞或棕榈树中，每次产四枚白色蛋，孵化期约18天，幼鸟离巢时间报道不一，从18天至34天不等。可能在一年中两次繁殖。","identification":"蓝腹佛法僧通过其独特的体色和尾部飘带易于识别。与同属物种相比，其深蓝色背部和粉白或乳白色头部及胸部构成鲜明对比。","protection":"IUCN：LC（无危）","distribution":"分布于塞内加尔至几内亚，东至南苏丹南部和刚果民主共和国北部。在西非广泛分布，从塞内加尔到刚果民主共和国东北部，常见于成熟湿润的萨瓦纳草原。","other":"在一些动物园和教育设施中有人工饲养的记录。"},{"name":"棕胸佛法僧","english_name":"Indochinese Roller","scientific_name":"Coracias affinis","overview":"棕胸佛法僧（英文名：Indochinese Roller，学名：Coracias affinis），是佛法僧目佛法僧科佛法僧属的鸟类。最显著的外部特征是胸部呈紫色，与西棕胸佛法僧相近但颜色更深，背部橄榄色较暗，全身蓝调更浓。广泛分布于尼泊尔东部、印度东北部至中国中南部、马来半岛北部及中南半岛，常出现在轻木麻黄林地、椰林、开阔湿地、稻田边缘等地。","appearance":"体长约30至34厘米，上体呈淡灰绿色，翼上覆羽深蓝，臀部和尾上覆羽紫蓝，尾羽基部紫而末端浅蓝，头顶中蓝，面部、喉部、胸部及腹部中间呈淡灰色，有时略带蓝色条纹或紫晕，腹侧灰蓝。喙黑，眼褐色，腿和脚角黄色。雌雄相似，幼鸟色彩较淡，头部与身体同色，缺乏明显鲜艳色彩。","call":"一般沉默，但在繁殖季节会发出尖锐鼻音的‘grrK-grrK-grrK...’系列叫声，结尾声调稍长且缓慢。","habits":"偏好开阔地带，如农业景观，常在电线上等显眼处栖息，偶尔缓慢摆动尾巴。基本定居，但有局部迁徙现象，如在缅甸南部仅于9月至翌年5月常见，冬季在不丹向低海拔迁移。食性与西棕胸佛法僧无显著差异，详细资料不详。","breeding":"繁殖季节至少在泰国-马来半岛为4月至5月，可能更早。巢筑于死椰树上，距地面9至12米高，有时与三宝鸟共享领地，两物种可在相邻树木筑巢。具体繁殖细节资料有限。","identification":"与西棕胸佛法僧相比，棕胸佛法僧胸部更偏紫色，背部颜色更深，全身色调更蓝。叫声更高且更鼻音。","protection":"IUCN：LC（无危）","distribution":"分布于东喜马拉雅山脉东部至中国中南部，北至尼泊尔、不丹和印度东北部（比哈尔邦、阿萨姆邦），东至中国西南部（四川南部、云南），南至泰国半岛和中南半岛。在中国大陆，可见于中南部地区。","other":"随着森林砍伐和城市化发展，数量似乎有所增加。在国家公园如泰国的Khao Yai和越南的Nam Bai Cat Tien等地区有记录。"},{"name":"蓝喉三宝鸟","english_name":"Blue-throated Roller","scientific_name":"Eurystomus gularis","overview":"蓝喉三宝鸟（英文名：Blue-throated Roller，学名：Eurystomus gularis），是佛法僧目佛法僧科三宝鸟属的鸟类。大型头部厚实的鸟类，以青铜色身体、蓝色喉咙、淡黄色喙和蓝色尾羽为显著特征。常见于非洲热带雨林的原生和次生森林中，偏好树梢位置。该物种分布于中非和西非，从几内亚至喀麦隆，南至安哥拉北部，西至乌干达东南部。","appearance":"蓝喉三宝鸟长约25厘米，雄鸟体重82-117.5克，雌鸟体重88-108克。成鸟体色主要是栗褐色，带有紫色蓝色翅膀，栗色翼覆羽，浅叉状蓝色尾巴和小块蓝色喉部。喙明亮黄色。幼鸟比成鸟颜色更暗淡，上体有鳞片状外观，喉部栗褐色，侧面灰白色，腹部和下体覆羽淡蓝色；喙黄色带暗褐色鼻脊。","call":"叫声为尖锐的单音节或双音节嘶叫，如'khlee'或'gleek'，类似黑嘴弯嘴犀鸟的声音，但音符较短，有时连续重复多达17次，持续约5秒。","habits":"生活在低地雨林中，包括未受干扰的原生森林、次生森林、村庄、山丘和河流附近，也出现在小规模孤立的森林碎片、画廊森林、有大树的农场和种植园，偶尔在草原林地中。高度可达1600米。主要以飞行中的昆虫为食，如蚂蚁、甲虫、白蚁、盾蝽、臭虫、蜜蜂、苍蝇、蟋蟀、蟑螂和飞蛾。偶尔吃小水果、蜈蚣和小型青蛙。在黄昏时分聚集10-20只的小群，与阔嘴三宝鸟混群，但通常单独或成对出现。","breeding":"繁殖期在2月至5月间，筑巢在10-40米高的枯木洞穴中。每窝产2-3枚光滑的白色蛋，平均尺寸为32毫米×36毫米。孵化和离巢期未知。","identification":"与阔嘴三宝鸟相似，但蓝喉三宝鸟具有蓝色喉咙和更鲜明的青铜色体羽。幼鸟与成鸟在颜色上有明显差异。","protection":"IUCN：LC（无危）","distribution":"分布于中非和西非，具体包括几内亚至喀麦隆，南至安哥拉北部，西至乌干达东南部。也见于比奥科岛。"},{"name":"阔嘴三宝鸟","english_name":"Broad-billed Roller","scientific_name":"Eurystomus glaucurus","overview":"阔嘴三宝鸟（英文名：Broad-billed Roller，学名：Eurystomus glaucurus），是佛法僧目佛法僧科三宝鸟属的鸟类。体长27-29厘米，拥有醒目的黄色宽嘴和温暖的红褐色背部与头部，胸部呈淡紫色。主要分布于非洲热带地区，除干燥地带外，广泛分布于非洲大陆和马达加斯加岛。","appearance":"成年阔嘴三宝鸟的头部和上部为红肉桂色，臀部和尾羽覆羽蓝色，翅膀深紫蓝色，尾羽浅叉，中央部分蓝黑色，尖端蓝黑色；喉部、胸部和腹部淡紫色，尾下覆羽灰蓝色。喙短而宽，带钩，强健有力，鲜黄色。雄雌相似，幼鸟的红肉桂色较暗淡，胸部棕色，其余下体部分淡灰色或蓝绿色，大覆羽亦为蓝绿色。","call":"发出刺耳的嘶哑声，如'grrrrrr'和'k-weeek, k-weeek'音节，还有兴奋的尖叫'crik-crik-crik-crik'。","habits":"偏好开阔林地，有高树的草原和耕地，以及雨林附近的大型开阔地带。在白天大部分时间静止不动，傍晚时会成群捕食空中飞舞的蚂蚁和白蚁，主要以昆虫为食，偶尔也吃蜥蜴、蜘蛛、水果和种子。","breeding":"繁殖季节在西非为3月至7月，东非为1月至4月和9月至11月，南非为9月至12月，马达加斯加为10月至12月。一夫一妻制，筑巢于树洞中，有时使用之前鹦鹉的巢穴，每窝产2-3枚白色蛋。","identification":"与蓝喉三宝鸟相比，体型更大，颜色更鲜艳，喉咙为淡紫色而非蓝色，尾上覆羽主要为淡蓝色而非深棕色，尾下覆羽蓝色而非棕色。","protection":"IUCN：LC（无危）","distribution":"分布于撒哈拉以南非洲大部分地区，以及马达加斯加岛，常见于湿季繁殖，旱季向赤道湿润地带迁移。","other":"已知四个亚种，其中苏阿赫利阔嘴三宝鸟( suahelicus)比指名亚种小14%，体重轻近30%。"},{"name":"三宝鸟","english_name":"Oriental Dollarbird","scientific_name":"Eurystomus orientalis","overview":"三宝鸟（英文名：Oriental Dollarbird，学名：Eurystomus orientalis），是佛法僧目佛法僧科三宝鸟属的鸟类。亦称: 老鸹翠、东方宽嘴转鸟、阔嘴鸟。显著特征是亮红色的喙和脚，以及蓝绿色的身体。分布广泛，从喜马拉雅山脉至斯里兰卡、亚洲东北部、菲律宾、新几内亚、澳大利亚、俾斯麦群岛和所罗门群岛都有其踪迹。在中国，被视为国家三有保护鸟类。","appearance":"三宝鸟体型敦实，头部扁平，长度可达30厘米。背部和翼盖呈现深褐色，带有强烈的蓝绿色光泽。腹部和尾下覆羽颜色较浅，喉部和尾下有光泽的亮蓝色。飞行羽毛为更深的蓝色。成鸟喙橙红色，尖端黑色，翼端有显眼的淡蓝色斑块，此斑块在飞行中尤为明显。雌雄相似，但雌鸟色彩略淡。亚成鸟喙呈棕色，足部红色，喉部缺乏蓝色，整体色彩较暗。","call":"通常较为沉默，常见叫声为重复的短促、粗糙、沙哑的‘rak’或‘chak’声。兴奋时会发出一系列较长的类似音符，如‘krak-kak-kak’或‘kek-ek-ek-ek-k-k’。","habits":"偏好开放的林地，包括热带雨林的冠层和边缘、河流边的树林、茂密的次生林、开阔地、农田、公园、运动场和荒地。主要在傍晚和黄昏时活动，从裸露的树枝或电线杆上捕食飞行中的昆虫，如甲虫、螳螂、蟋蟀、蝉、蛾、蚂蚁和白蚁。偶尔也会从地面捕食小蜥蜴。飞行姿态独特，滑翔能力强，结束时能灵巧地转弯。","breeding":"繁殖期因地区而异，北部地区为6月，日本为5月至6月，印度和缅甸为3月至5月，苏门答腊为1月至4月，巴布亚新几内亚为11月至3月，澳大利亚为10月至1月。一夫一妻制，强烈捍卫领地。巢建于树洞中，通常是旧啄木鸟或拟啄木鸟的巢穴，高度在8至20米之间。每窝产卵3至5枚，孵化期约22至23天，雏鸟至少需23天才能离巢。","identification":"与翠蓝三宝鸟 相比，三宝鸟的羽毛颜色更绿，少紫色。亚成鸟与成鸟的主要区别在于色彩的暗淡和定义不足的斑点。","protection":"IUCN：LC（无危）。在分布范围内常见，但在日本变得稀少，可能由于栖息地丧失。在菲律宾，曾数量众多，现罕见，同样由于大规模森林砍伐。Simeulue岛上的oberholseri亚种状态需调查。在斯里兰卡，iris亚种曾罕见，后在Sinharaja森林被重新发现。","distribution":"分布于喜马拉雅山脉从尼泊尔至斯里兰卡，亚洲东北部，菲律宾，新几内亚，澳大利亚，俾斯麦群岛和所罗门群岛。在澳大利亚，于9月至翌年4月繁殖，冬季迁往新几内亚和邻近岛屿。","other":"三宝鸟不自筑巢，常利用天然洞穴或鹊巢繁殖。"},{"name":"翠蓝三宝鸟","english_name":"Azure Dollarbird","scientific_name":"Eurystomus azureus","overview":"翠蓝三宝鸟（英文名：Azure Dollarbird，学名：Eurystomus azureus），是佛法僧目佛法僧科三宝鸟属的鸟类。分布于北摩鹿加群岛，包括哈马黑拉岛至Bacan。曾被认为是三宝鸟的亚种，但分子系统发生学研究显示其为独立物种。","appearance":"体长约27至35厘米，全身呈深紫蓝色光泽，翼上有明显的浅色斑块，喙部宽厚，尖端钩状，鲜红色；眼周和腿为暗红色。与体型较小、尾部较短的三宝鸟相比，其整体颜色更深，无绿色光泽，橙色喙和脚更加鲜明。幼鸟为暗灰色，喙基部灰色，腿为暗橙色。","call":"发出嘶哑、略带摩擦声的叫声，连续而稳定，有时会下降成似笑的声音。","habits":"栖息于原始森林、选择性砍伐的森林、林缘和开阔地带，偶尔出现在离森林不远的椰子林和花园中。主要活动于低地至海拔465米的高度。以昆虫为食，包括甲虫，狩猎方式与三宝鸟相似。","breeding":"繁殖信息稀少，可能主要在每年上半年筑巢。已知有幼鸟在四月初被采集，成年雄鸟在繁殖季节被发现，七月到九月观察到家庭群体。具体繁殖细节未知。","identification":"与三宝鸟相比，翠蓝三宝鸟的整体颜色更均匀深沉，缺乏绿色金属光泽，喙和脚的颜色更为鲜艳。幼鸟与成鸟在颜色上有明显区别。","protection":"IUCN：NT（近危）。虽然过去曾被视为易危，现在评估为近危，总数量估计为2500至10000只，或成熟个体1500至7000只，且数量正在减少。面临森林破坏和农业扩张的威胁。","distribution":"分布于印尼的北摩鹿加群岛，从哈马黑拉岛至Bacan。","other":"在半开放森林区域的存在有限，似乎不能适应严重退化的生境，可能被三宝鸟取代于开放农田区。"},{"name":"短腿地三宝鸟","english_name":"Short-legged Ground Roller","scientific_name":"Brachypteracias leptosomus","overview":"短腿地三宝鸟（英文名：Short-legged Ground Roller，学名：Brachypteracias leptosomus），是佛法僧目地三宝鸟科地三宝鸟属的鸟类。体型健硕，羽毛图案复杂，腿部异常短小。其尾部角落的白色斑点在飞行中格外醒目。该鸟行踪隐秘，数量稀少，仅在搜寻时才可能一睹其风采。栖息于马达加斯加东部雨林的低至中海拔区域，与同类相比，更多时间在树上活动，甚至高居树冠层。","appearance":"成年短腿地三宝鸟体长介于30至38厘米，体重范围在154至217克。雄鸟背部呈青铜绿色，后冠和颈背有蓝紫色光泽，面部上方有一条淡色的浅黄色眉纹；臀部和尾羽上覆羽蓝绿色，尾羽除中央一对外，其余皆带有深色亚端斑和浅色尖端；翅膀覆羽上有半月形白斑，边缘黑色勾勒，暗色初级飞羽在飞行时可见白色翼带；面部两侧为栗棕色，点缀着白色斑点，逐渐过渡到褐色条纹的浅黄色喉部；胸部有白色胸带，其余下体为黄白色并带有棕色横斑，腹部和臀部斑纹最轻；虹膜呈棕色；喙强壮而略弯，颜色为深棕色或角棕色，基部有淡黄色边，鼻孔靠近上喙基部，被刚毛状羽毛覆盖，口内淡黄色；腿为棕黄色至金黄色，脚趾绿黄色，爪为棕色或绿黄色。雌鸟与雄鸟相似，但体型略小。幼鸟色彩较暗，更偏棕色，头顶有白色点斑，没有后颈的蓝紫色光泽，胸部带纹较淡，下体羽毛尖端为棕色而非横斑，下颌骨可能为白色，其他部分黑色带白色尖端。","call":"短腿地三宝鸟的鸣唱是一连串重复的高音‘boop’音符，声音清脆而短暂。","habits":"短腿地三宝鸟生活在马达加斯加东部雨林的湿润地带，从低地延伸至中等海拔，几乎完全居住在未受干扰的深色森林中，拥有高大的树木、潮湿的土壤和厚厚的落叶层。它偏好未受破坏的密林环境，偶尔也会出现在植被相对开放的斜坡上，或靠近茂密的灌木丛边缘。海拔分布范围从海平面至1500米，但更倾向于低海拔地区。似乎具有领地性和定居习性，活动范围不大。以昆虫为主食，包括蚂蚁、蚁狮、甲虫及其幼虫、毛虫、蜈蚣、蝉、螃蟹、蚱蜢、螽斯、千足虫、球形千足虫、捕蝇草、蛞蝓、蜗牛、蜘蛛、竹节虫、小型脊椎动物如变色龙、蛙类、壁虎、蜥蜴、蛇等。","breeding":"繁殖季节一般在12月开始，若有需要会于次年1月再次筑巢。求偶和交配活动通常发生在10月至1月间，也有观察到10月至12月间处于繁殖状态的个体，以及1月初的幼鸟。该鸟可能为一夫一妻制。已知的两个巢穴位于树洞中，高度分别为18.1米和22米，深度分别为1.5米和未知。巢穴有时会在受到蜜蜂侵扰后被重新挖掘。孵化由雌鸟承担，期间雌鸟每天离巢3至4次，每次持续21至109分钟，雄鸟偶尔会提供喂食。孵化期约为22至26天，单只幼鸟在约30天的巢期后离巢。","identification":"与其他地三宝鸟相比，短腿地三宝鸟具有更长的翅膀，使它成为家族中最善于在树冠层活动的成员。此外，它的短腿和独特的叫声也是辨识要点。","protection":"IUCN：VU（易危）","distribution":"短腿地三宝鸟分布于马达加斯加东部，北起达拉伊纳和塔萨坦纳那山，南至安多哈拉国家公园，包括西北部的马农加里沃、马索阿拉半岛和中部高原边缘的安乔佐罗贝。","other":"短腿地三宝鸟面临栖息地快速丧失的威胁，由于沿海平原的低地雨林已被砍伐或严重退化，加之商业采伐在某些区域构成额外威胁，若现有趋势继续，该物种偏好的低海拔未受保护森林将在数十年内消失。"},{"name":"鳞斑地三宝鸟","english_name":"Scaly Ground Roller","scientific_name":"Geobiastes squamiger","overview":"鳞斑地三宝鸟（英文名：Scaly Ground Roller，学名：Geobiastes squamiger），是佛法僧目地三宝鸟科鳞斑地三宝鸟属的独特鸟类，主要分布于马达加斯加东部的雨林地带。其头部和下体覆盖着独特的黑白鳞状图案，拥有蓝白色的尾尖，飞行中十分醒目。体长约25至32厘米，体重在137.5至165克之间，雌鸟略小于雄鸟。","appearance":"鳞斑地三宝鸟体型丰满，腿长，头部和下体为淡黄白色，带有棕色和黑色的鳞状斑纹。中央冠部、眼后和耳羽下方有不规则的黑色条带，腹部和臀部的鳞纹较少，颜色更偏向土黄色。颈背呈锈色，肩羽、三级飞羽和翼覆羽为青铜绿色，翼覆羽上有蓝色或蓝灰色镶边的白色新月形标记。次级飞羽和初级飞羽深棕色，可见土黄白色的翼斑。尾羽锈色，基部青铜绿色，外侧尾羽有暗色次端斑和天蓝色尖端，中央四根尾羽完全青铜绿色。虹膜棕色，有橙粉色肉质眼环延伸至眼后显著斑块。喙钝而微弯，暗黑褐色，切割边缘稍浅，鼻孔由刚毛状羽毛遮盖。腿粉橙色，爪灰白色。幼鸟头顶、颈背、胸部和两侧颜色暗淡，下颌和腹部中心污白色，颈部两侧有成鸟类似的黑色条纹，飞行和尾羽图案类似成鸟，但翼覆羽标记不明显。","call":"领地叫声为一系列柔和空洞的'whoo-oop'或更调制的'mowooop'音符，持续约1秒，向上微微弯曲，音调高于短腿地三宝鸟，间隔5至30秒重复，清晨或黄昏从0.1至5米高的栖木发出，每次持续可达22分钟。联系叫声为单个'whoop'，比领地叫声更低更长。觅食时发出短暂的'ko-uh'声。警报时发出干燥的churr声和尖锐刺耳的hiss声，后者类似于马达加斯加苇鸟的声音。受到威胁时发出尖锐的'kwek'声，被惊吓时发出快速颤音'frrret'，尖锐嘶哑的'kwish-sh'声逐渐减弱，或低沉的嘶嘶声。","habits":"生活在马达加斯加东部低地至中海拔雨林，偏好未受干扰的阴暗区域，大树林立，植被密集，土壤湿润，落叶层深厚。以无脊椎动物为主食，如蚯蚓、蚂蚁、甲虫、毛虫、蜈蚣、蟋蟀、千足虫、蛞蝓和蜘蛛，也会捕食小型脊椎动物，如蛙类、矮变色龙、板蜥、新生哺乳动物和鼠类。主要在地面搜索食物，通过等待和短跑交替的方式觅食，会翻动树干和用喙挖掘落叶层中的猎物。偶尔在空中捕食昆虫和蝴蝶。可能在黄昏和夜间活动。","breeding":"繁殖季节为9月至1月，筑巢于异常茂密的草本覆盖区，通常靠近溪流。在斜坡的土堤中挖掘长0.5至1米，直径6.5至10厘米的洞穴，巢室宽约20厘米，高15厘米，内部有时铺有枯叶和泥土颗粒。每窝产一枚或两枚白色蛋，大小约55mm×30mm。仅雌鸟孵卵，至少18天，期间由雄鸟供给食物。雌鸟抚育雏鸟，双亲平等喂养，每天平均向单个雏鸟提供12件食物。离巢期约为24天。雏鸟离巢后，成鸟会用枯叶和树枝覆盖巢穴入口。雌鸟在雏鸟离巢后的第一周内始终陪伴，雄鸟则会间歇性离开群体，当幼鸟达到60天大时，父母的照料似乎停止。","identification":"与短腿地三宝鸟相比，鳞斑地三宝鸟体型更大，颜色更鲜艳，领地叫声音调更高。幼鸟与成鸟的区别在于头部、颈背、胸部和两侧的颜色较暗淡，下颌和腹部中心呈污白色，翼覆羽标记不明显。","protection":"IUCN：VU（易危）","distribution":"主要分布于马达加斯加东部的低地至中海拔雨林。","other":"鳞斑地三宝鸟面临的主要威胁是栖息地的快速破坏，尤其是沿海平原的低地雨林被清除或严重退化。尽管如此，最近在清理区域和次生林的观察表明它可能不仅限于原始森林环境。"},{"name":"地三宝鸟","english_name":"Pitta-like Ground Roller","scientific_name":"Atelornis pittoides","overview":"地三宝鸟（英文名：Pitta-like Ground Roller，学名：Atelornis pittoides），是佛法僧目地三宝鸟科马岛地三宝鸟属的鸟类。单型种，体长约25至29厘米，体重介于74至114克之间。以其钴蓝色头部、黑色面罩和白色眉纹及喉咙为显著特征，活跃于马达加斯加东部和北部的雨林中。","appearance":"地三宝鸟体型紧凑，长腿，色彩丰富，体长25至29厘米，雄鸟体重83至89.5克，雌鸟87至108克，平均体重74至114克。两性均有明显区别，头部呈钴蓝色，面部有黑色面具，细长的白色眉纹上方边缘点缀着白色斑点的黑羽，前额和中央后冠的羽毛边缘呈棕色并稀疏地斑点白色，拥有醒目的蓝色喉部，边缘以蓝色为界；背部为青铜绿色，外侧尾羽为天蓝色，深棕色初级飞羽带有窄小的蓝白色斑点，颈背呈锈色延伸形成第二条胸带，边界为蓝色；两侧为橙红色，其余腹部为白色；虹膜深棕色；喙细长呈黑褐色，鼻孔基部部分被羽毛遮盖；腿为暗淡的粉灰色，爪子颜色从粉灰到蓝灰不等。幼鸟较为暗淡，喉部有黑色或棕色斑点，蓝色头部带有棕色斑纹，白色标记更偏黄色，眼线为黄色斑点棕色。","call":"在非繁殖季节保持安静。领土呼叫为一系列穿透力强、音调低至中等的单音节呼啸声，类似“whoop”，比鳞斑地三宝鸟更高而短促，但比栗头地三宝鸟更低沉且不那么双音节，持续约0.5秒，每3至10秒重复5至20次，通常在2至3米的高度发出，大多在黎明时分，但也可能在早晨或傍晚时听到；觅食时发出轻柔的咯咯声；警报时发出尖锐、干燥的咔哒声和响亮的斥责嘶嘶声。","habits":"生活在从低地到高海拔的雨林中，偏好植被密集、落叶层深厚且枯木丰富的未受干扰区域，也出现在较干燥的森林甚至次生森林和邻近未受干扰森林的种植园；局部地区亦见于重度退化次生森林。在Ambohitantely特殊保护区的研究显示，其可在1250公顷至28公顷的森林碎片中生存，但在更小的碎片中未被发现。海拔从海平面到2000米，最常见于800至1600米间。主要以昆虫如蚂蚁、甲虫、蝴蝶、蟑螂和其他昆虫以及蠕虫为食，偶尔也会捕食小型脊椎动物如变色龙和青蛙。几乎完全是陆地上的觅食者，主要在地面搜索小型动物；有时站立不动，随后短跑，然后迅速出击或跳跃捕捉昆虫。","breeding":"繁殖季节主要在10月至2月，尽管有记录显示9月份已成对出现。可能为一夫一妻制且具有领地性。在倾斜的土岸上挖掘巢穴，长度0.5至1米，直径9至10厘米，末端为球形腔室，宽约20厘米，内部铺有枯叶。产卵数为2至4枚光滑的白色卵，大小为33.1至36.7毫米×26.7至29.5毫米；由雌鸟单独孵化，雄鸟偶尔在此期间喂食雌鸟，双方共同喂养幼鸟；孵化和离巢期未有记录。","identification":"缺乏鳞斑地三宝鸟复杂的鳞片状标记，头部和身体也不像栗头地三宝鸟那样呈锈色。在体型、颜色和行为上与其他地三宝鸟有明显差异。","protection":"IUCN：LC（无危）","distribution":"分布在马达加斯加东半部，从极北的安珀山国家公园和Daraina到极南的Andohahela国家公园和Tsitongambarika森林，还包括西北部（Sambirano地区）和中部高原（Ambohitantely、Ankazomivady、Ankaratra和Kalambatritra特殊保护区附近），以及两个近岸岛屿，即Sainte Marie（1830年代）和Nosy Mangabe（至少在1980年代）。","other":"自2006年以来，地三宝鸟已被成功地在圈养环境中繁殖。"},{"name":"栗头地三宝鸟","english_name":"Rufous-headed Ground Roller","scientific_name":"Atelornis crossleyi","overview":"栗头地三宝鸟（英文名：Rufous-headed Ground Roller，学名：Atelornis crossleyi），是佛法僧目地三宝鸟科马岛地三宝鸟属的鸟类。独特色彩的鸟类，以深红色头部和胸部、橄榄绿色上体及带有暗色斑点的浅黄色腹部为显著特征。该物种主要栖息于马达加斯加东部的高山雨林，特别是在海拔800至2000米之间最为常见。","appearance":"这种约25厘米长的鸟类，雄雌两性外观相似，拥有深红褐色的头部和胸部，橄榄绿色的上体，以及带暗斑的浅黄色下体。其颈部有一条狭窄的黑色项圈，上面点缀着白色竖向条纹，胸部上方有明显的白色条纹。翅膀关节处有一片虹彩般的淡蓝色斑块，尾巴较短，喙和腿呈灰色。","call":"其领地叫声是一系列清晰的‘whoop’、‘pop’或‘glop’音节，每个音节略带抑扬顿挫，与地三宝鸟的叫声类似但音调更高，更富二合音（近距离时）。叫声最高音在所有雨林地三宝鸟中。非繁殖季节通常较为安静。","habits":"生活在马达加斯加东部低地到高海拔的湿润雨林中，偏好未受干扰的黑暗森林，尤其是苔藓覆盖的山地森林，大型树木和阴暗纠结的下层植被密集，腐朽倒木丰富，土壤潮湿，落叶层深厚。活动范围从785米至2000米，最常见于1250至1750米之间。主要以昆虫为食，如蚂蚁、甲虫（如Typhloscaris andringitrae）、甲虫幼虫、蝴蝶、毛虫、蟑螂、苍蝇、千足虫、蛾子、蜗牛和黄蜂；偶尔也吃植物物质。几乎完全在地面觅食，间歇性地快速奔跑、攀爬、跳跃过障碍物，积极搜索地面；有时从悬垂的叶子上捕获昆虫。黄昏、夜间和白天都可能活动。","breeding":"繁殖可能发生在12月至1月，已知的繁殖行为包括一只展示中的雄鸟同时点头向下和摇尾向上，同时发出叫声。似乎为一夫一妻制并具有领地性。在斜坡土堤中挖掘洞穴，洞长0.3至0.5米，直径15至20厘米，末端为巢室。每窝产卵两枚；缺乏关于孵化和雏鸟离巢期的数据。","identification":"与鳞斑地三宝鸟相比，缺乏复杂的鳞状标记；与地三宝鸟相比，下体颜色更淡，头部图案更复杂。幼鸟比成鸟更为暗淡，身体更多橄榄色，冠部和颈背有蓝紫色调，仅有微弱的黑色喉部（更接近灰褐色，无白色条纹）。","protection":"IUCN：NT（近危）。尽管分布广泛，但密度似乎相当零散。在至少12个保护区中被发现。受到刀耕火种农业引起的栖息地破坏威胁，但受影响程度小于其他雨林物种。","distribution":"在马达加斯加的东北至南部，包括Tsaratanana和Manongarivo山脉北部，Marojejy国家公园东北部，Andohahela国家公园南部，以及Masoala半岛、Anjozorobe和Kalambatritra特殊保护区。","other":"曾被认为是马达加斯加雨林中最为罕见的地三宝鸟科成员之一，但现在被认为分布更广，数量比最初认为的要多。"},{"name":"长尾地三宝鸟","english_name":"Long-tailed Ground Roller","scientific_name":"Uratelornis chimaera","overview":"长尾地三宝鸟（英文名：Long-tailed Ground Roller，学名：Uratelornis chimaera），是佛法僧目地三宝鸟科长尾地三宝鸟属的鸟类。独特的地三宝鸟科鸟类，拥有长尾和长腿，头部和胸部有明显的斑纹。在马达加斯加西南部的刺林地带低海拔沙质土壤上生活，极其隐蔽且羞怯的物种，仅被那些专门寻找它的人发现。其鸣声独特，由一系列快速的‘tuk’音组成。","appearance":"体长34至47厘米，包括长达28.5厘米的尾巴。雄鸟具有沙色冠羽和上体，饰以深褐色和黑色条纹；尾部有约15至20条深褐色横带，最外侧三对尾羽为天蓝色；翼覆羽天蓝色，主翼羽和次级飞羽上有两道醒目的黑白相间条纹；眉纹淡黄色，耳羽宽大呈棕色，脸颊有白色髭纹，颊纹和颈纹黑色，形成白色喉部轮廓；其余下体浅灰色，胸部几乎纯白。虹膜棕色，喙黑色，腿淡粉棕色，后趾短，长度13至17毫米。雌鸟较雄鸟小，胸带较窄，尾巴更短。幼鸟的上体为淡暖棕色，饰有黑色斑点，脸颊和眼先较成鸟少黄褐色，黑色围裙（尤其是雌鸟）较窄，翅膀和尾部羽毛较暗淡的蓝色，尾巴比成鸟更短。","call":"领地叫声为平稳的系列低沉而柔和的音符，‘boobooboo...’，音调逐渐下降，可听到至少200米外，通常由雄鸟发出，从日出开始持续约1小时，有时白天，常在夜间，尤其在05:30至06:15和18:40至19:15时，持续最多20分钟。一对中的任一性别会发出一系列咯咯声或突然的‘too-tuc too-tuc too-tuc...’声，当配偶彼此距离在10米以内时发出，持续10至40秒，有时以尖锐的非发声刮擦音结束，可能由拍打翼尖或鞭击动作产生，偶尔伴随展示。","habits":"栖息于马达加斯加西南部的亚热带荆棘灌木丛和较高的落叶林（8至12米高）中，偏好多刺的Didiereaceae（尤其是Didierea madagascariensis）、树状的大戟科（尤其是Euphorbia stenoclada）和猴面包树（Adansonia）覆盖的沙地。几乎完全在地面觅食，交替静止和积极搜索，用喙翻找灌木和树木下的深叶堆，寻找小型动物；奔跑能力强；飞行能力差，但偶尔会在空中捕捉蝴蝶。黄昏和夜晚以及白天活跃。","breeding":"繁殖季节为10月至1月（特别是在11月至12月），雨季开始时，成对形成，通常在10月至11月。一夫一妻制并保卫领地。每对每年挖掘1至6个巢穴，每个巢穴通常间隔50米，但仅使用其中一个。巢穴为向下倾斜的沙坑，长约0.8至1.2米，直径8厘米，末端为直径约20厘米的巢室，铺有干燥植被。每对产2至4枚白色卵，大小约28毫米×25毫米；孵化期和育雏时间未知，但雏鸟在24至26天后离巢，可能直到第30天还会返回巢穴。","identification":"在马达加斯加南部刺林区范围内独一无二，与同属其他物种无混淆之虞。","protection":"IUCN：VU（易危）","distribution":"分布在非洲马达加斯加沿海远西南部，范围北至Mangoky河，南至Fiherenana河，东至内陆丘陵，西至海岸线，总覆盖面积约为10,500平方公里。","other":"虽然能容忍一定程度的生境扰动，如游荡牛群，但在靠近村落的地方也能看到，但密度似乎与最近道路的距离正相关，暗示着当地人类群体的负面影响。"},{"name":"绿背翡翠","english_name":"Green-backed Kingfisher","scientific_name":"Actenoides monachus","overview":"绿背翡翠（英文名：Green-backed Kingfisher，学名：Actenoides monachus），是佛法僧目翠鸟科栗领翡翠属的鸟类。大型森林翠鸟，分布于印尼苏拉威西岛及周边岛屿。雄鸟头部呈现深蓝色或绿松石色，雌鸟头部具有复杂的图案，幼鸟颜色较为暗淡。物种面临栖息地丧失的威胁。","appearance":"成年雄鸟头部为深蓝色或绿松石色，眼先黑色，脸颊略带蓝色，下颏和喉咙为白色。颈部有一圈狭窄的暗红色领隔，背部、翅膀和尾巴呈黑橄榄绿色。雌鸟额头和眼眉略宽，呈红橙色。幼鸟胸部更暗，颏部浅黄灰色，嘴角黄色。嘴亮红色，虹膜深褐色，腿部橙红色。亚种间存在地域性差异。","call":"绿背翡翠发出悠长的口哨声，狩猎时会发出‘rark-rark-kraa’的声音，遇险时发出警告声。","habits":"栖息于低地雨林、茂密的森林和河岸近水处，高度可达900米。单独或情侣共同捕食，主要以大蜈蚣和甲虫为食，偶尔捕食小鱼、小蛇和蜥蜴。","breeding":"在树干上钻洞为巢，繁殖期在每年3月至4月，卵的大小、数量及孵化持续时间目前未知。","identification":"与斑头翡翠相似，但可通过背部颜色和下体花纹进行区分。","protection":"IUCN：NT（近危）","distribution":"分布于印尼苏拉威西岛及周边的Manadotua和Lembeh等岛屿，包括北苏拉威西、中苏拉威西和南苏拉威西。","other":"物种受到森林砍伐的威胁，导致其栖息地丧失。"},{"name":"斑头翡翠","english_name":"Scaly-breasted Kingfisher","scientific_name":"Actenoides princeps","overview":"斑头翡翠（英文名：Scaly-breasted Kingfisher，学名：Actenoides princeps），是佛法僧目翠鸟科栗领翡翠属的鸟类。大型森林翠鸟，分布于印尼苏拉威西岛。拥有深紫色至蓝色头部，棕色背部，淡色颈圈，以及白色下体。其独特的鳞状斑纹是辨识关键。","appearance":"成年斑头翡翠长约24-25厘米，头部呈深紫蓝，背部为棕色，带有明显的淡色颈圈。雌雄差异在于雄鸟基部有淡色标记，雌鸟则有淡色眉纹和髭纹。上体与下体覆盖有大胆的鳞状斑纹，幼鸟斑纹更重，喙色依地理位置而异，从红色到角质色，再到橙棕色。","call":"鸣唱为上升后下降的哀怨哨音，\"weeeeyu\"，并伴有激动的叽喳声。","habits":"栖息于山地森林的浓密下层，高度从900至2000米，偶尔低至250米。以昆虫、甲虫、蝉若虫及小型蜥蜴为食。活动范围主要在森林较低层次，但也可见于低冠层和中层。","breeding":"繁殖季节据信在7月至8月，筑巢于土崖壁上的洞穴中，曾有记录发现一窝四枚蛋。具体繁殖细节尚待进一步研究。","identification":"与绿背翡翠相似，但可通过后者均匀的暗绿色背部和恒定的鲜红喙色区分。","protection":"IUCN：LC（无危）","distribution":"分布于印尼苏拉威西岛，包括东北部、西北部及中部，以及东南部（现认为是独立物种）。","other":"三个亚种的保护状况由BirdLife International分别评估。"},{"name":"须翡翠","english_name":"Moustached Kingfisher","scientific_name":"Actenoides bougainvillei","overview":"须翡翠（英文名：Moustached Kingfisher，学名：Actenoides bougainvillei），是佛法僧目翠鸟科栗领翡翠属的鸟类。大型、色彩艳丽的森林翠鸟，身长27至32厘米，以红橙色头部和蓝色翅膀、尾部为显著特征。分布于太平洋所罗门群岛的布干维尔岛和瓜达尔卡纳尔岛，栖息于高海拔的原始森林中，极为隐秘，鲜为人知。","appearance":"须翡翠拥有橙红色的头部、背部和下体，蓝紫色眼纹相连于颈背，形成独特标记。蓝紫色的胡须状条纹、翅膀和尾部鲜明，背部下方和尾上覆羽呈淡蓝色，腹部浅黄，喉部白色，嘴粗长，呈鲜红色。雌雄相似，但雌鸟背部橄榄绿，头部颜色更深，与背部颜色渐变融合。","call":"须翡翠的鸣叫声为响亮清脆的系列铃声，通常在黎明前和黄昏后发出，有助于确认其存在。","habits":"须翡翠栖息于未受干扰的成熟森林中，海拔高度在800米以上，可能低至550米。它们活跃于晨昏，可能具有夜行性倾向。主要以昆虫和小型脊椎动物为食，包括蟹、软体动物、小鱼、蛙、蠕虫和小爬行动物。","breeding":"须翡翠在树洞中筑巢，具体繁殖习性细节尚不清楚，但据观察，它们会多次潜水清理巢穴周围的污垢。","identification":"与白眉翡翠的区别在于后者下体颜色较淡，头部图案不同，且生活在较低海拔。与所罗门三趾翠鸟和瓜岛三趾翠鸟相比，须翡翠体型更大，头部图案和喙色明显不同。","protection":"IUCN：LC（无危）","distribution":"须翡翠分布于所罗门群岛北部的布干维尔岛山区和中南部的瓜达尔卡纳尔岛，栖息于海拔900至1,100米的封闭森林中。","other":"须翡翠曾与瓜达尔卡纳尔须翡翠被归为同一物种，但现在认为是两个独立的物种。"},{"name":"斑林翡翠","english_name":"Spotted Wood Kingfisher","scientific_name":"Actenoides lindsayi","appearance":"斑林翡翠长约26厘米，具有鲜明的特征：上身绿色带斑点，下身白色带有暗色鳞状纹。雄鸟头部有黑色条纹贯穿至后脑，绿色冠羽和臀部，以及完整的红褐色颈环、喉咙和眼下的带纹，眼后有亮蓝色胡须状条纹。雌鸟的冠羽颜色较淡，胡须状条纹为绿色。喙部上颚黑色，下颚橙黄色，虹膜深棕色，腿和脚呈绿肉色。幼鸟颜色较为暗淡，喙灰色，尖端和基部黄色。","call":"其主要鸣叫声为突然的、结巴式颤音，持续约1秒，随后是5到6个连续下降的拉长音符，每个约0.4秒，整套鸣叫声持续大约6到9秒。此外，还有清晨发出的响亮口哨声“ptuuooo”，时长0.8秒。","habits":"斑林翡翠栖息于菲律宾的湿润原始森林，偏好低地和丘陵地带。它们以昆虫、甲虫、蜗牛以及一些小型脊椎动物为食，常在地面寻找猎物。通常独居或成对出现，活动于森林较低层的密集覆盖处。","breeding":"关于斑林翡翠的繁殖行为知之甚少，推测它们可能在树上的白蚁巢中筑巢，但这尚未得到证实，因为同属其他物种倾向于在树洞或地面筑巢。产卵于巢穴地面，无额外垫料。","identification":"斑林翡翠在菲律宾地区无类似物种，其独特的绿色斑点和蓝绿色胡须状条纹使其易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于菲律宾的吕宋岛、卡坦端内斯岛、马里杜克岛、内格罗斯岛和帕奈岛，主要栖息于北部和中西部地区的湿润森林。"},{"name":"蓝顶翡翠","english_name":"Hombron's Kingfisher","scientific_name":"Actenoides hombroni","overview":"蓝顶翡翠（英文名：Blue-capped Kingfisher，学名：Actenoides hombroni），是佛法僧目翠鸟科栗领翡翠属的鸟类。色彩斑斓的中型翠鸟，仅分布于菲律宾的棉兰老岛。其最显著特征是雄鸟的蓝紫色冠羽和颊纹，雌鸟则为绿调。体长约27厘米，嘴呈红色。","appearance":"雄鸟拥有深蓝紫色的冠羽和须纹，脸颊红橙色，下颏和喉咙白色。上翕镶有蓝紫色，下翕的肩胛骨，覆翼呈蓝绿色调并有精细斑驳黑点。雌鸟额头老绿色，须纹橙红色，上覆轻微绿色斑点。幼鸟类似成鸟，但羽毛颜色略暗。嘴红色，喙尖带黑褐色，虹膜深褐色，腿部颜色为棕色及深橄榄色。","call":"鸣声为快速的颤音，随后是间隔较长的脉冲音符，以及每隔三秒发出的短促双音节声，有时以一秒钟间隔的尖叫。","habits":"栖息于棉兰老岛山区海拔800至2400米的热带雨林，偏好未受干扰的原始森林。主要食物包括大型昆虫、蜗牛、青蛙和小型爬行动物，偶尔也会捕食鱼类。活动范围广泛，常在树叶或泥土中寻找猎物。","breeding":"繁殖季节可能在3月至5月间，具体日期未知。营巢于土崖壁或河流堤坝，挖掘隧道式巢穴，深约60厘米，宽20厘米，高10厘米，洞穴内部无衬垫，直接在地面产卵。","identification":"蓝顶翡翠通过其独特的冠羽颜色和体型易于识别，雄鸟与雌鸟在冠羽和须纹颜色上有明显差异。","protection":"IUCN：LC（无危）","distribution":"仅分布于棉兰老岛（菲律宾东南部），主要栖息于海拔1000至2400米的山地森林。","other":"自20世纪70年代以来，因森林砍伐导致栖息地破坏严重，数量大幅减少。"},{"name":"栗领翡翠","english_name":"Rufous-collared Kingfisher","scientific_name":"Actenoides concretus","overview":"栗领翡翠（英文名：Rufous-collared Kingfisher，学名：Actenoides concretus），是佛法僧目翠鸟科栗领翡翠属的中型翠鸟，体长约22-25.5厘米，体重60-90克。雄鸟拥有醒目的绿色冠羽和黑色眼纹，雌鸟背部及翅膀为深橄榄绿色，带有鳞片状纹。分布于马来半岛、印尼苏门答腊岛和婆罗洲的热带森林，面临栖息地丧失的威胁。","appearance":"雄鸟头部呈绿色，眼纹黑色，脸颊至颈项有深蓝色长斑，胸前有红棕色领环，背部蓝绿色，带黄色斑点；雌鸟上部橄榄绿色，具斑点，眼纹较大。成鸟嘴黄色，虹膜深棕色，腿脚黄绿色。幼鸟类似成鸟，但颜色较为暗淡。","call":"发出响亮、上升的重复哨声“kwee-i”，每秒约一次，有时间隔更长，亦会发出柔和颤音和低沉的咯咯声。","habits":"生活在亚洲大陆的森林地带，高度从海平面至800米，甚至可达1700米。主要以无脊椎动物为食，包括昆虫、蜘蛛、蝎子和蜗牛，偶尔捕食小鱼、蛇和蜥蜴。常在树叶或泥土中寻觅猎物。","breeding":"繁殖季节在马来西亚为4-6月，婆罗洲和苏门答腊为12月至翌年3月。营巢于土崖或河岸，挖掘隧道式巢穴，卵直接产于洞穴地面，每窝产2枚卵，雏鸟约22天离巢。","identification":"通过绿色冠羽、黑色眼纹和红棕色领环与区域内其他翠鸟区分开来。雌雄差异在于背部和翅膀的颜色。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛、苏门答腊岛和婆罗洲，主要栖息在低地森林和山地森林。"},{"name":"钩嘴翠鸟","english_name":"Hook-billed Kingfisher","scientific_name":"Melidora macrorrhina","overview":"钩嘴翠鸟（英文名：Hook-billed Kingfisher，学名：Melidora macrorrhina），是佛法僧目翠鸟科钩嘴翠鸟属的唯一鸟种。体型较大，常见于新几内亚及其附近岛屿的低地森林地带，以其独特的长钩嘴和宝石蓝斑点羽毛为显著特征。","appearance":"钩嘴翠鸟体长约27厘米，重85-110克。雄鸟头部黑色，前额两侧宝石蓝色羽毛点缀，下体白色，可能带浅黄或粉红调。雌鸟前额黄绿色，下体较淡。嘴粗长，具明显钩状顶端，上颌黑色，下颌角质色。虹膜深褐色，腿灰绿色。喙部厚实，翼尖长，尾短圆。","call":"鸣叫声在黄昏和黎明时最为频繁，发出长哨音后接快速升高的短音，类似乒乓球落地声，有时连续重复。","habits":"栖息于低地雨林、次生林、灌木林，以及部分清理过的地区和老橡胶、柚木种植园，海拔700米以下，偶尔高达1280-1500米。夜间或黄昏活动，日间喂雏时活跃。以大型昆虫和蛙类为食，可能挖掘土壤寻找猎物。","breeding":"繁殖期在旱季，7月至10月。在树上的白蚁巢侧壁挖巢，深度3-6米，巢室宽11-12厘米。每窝产2-3枚卵，孵化可能异步，雄鸟白天参与孵化和育雏。","identification":"与同属物种相比，钩嘴翠鸟的钩状嘴更为显著，雄鸟头部宝石蓝斑点独特，雌鸟前额黄绿色。亚种waigiuensis体型略大，jobiensis雄鸟冠羽更深蓝色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于新几内亚岛及周边岛屿，包括低地森林、次生林、种植园等地。在瓦里拉塔国家公园和卡乌野生动物区较为常见。","other":"系统学历史记录显示，钩嘴翠鸟的分类地位曾有变动，现为Melidora属的唯一成员。"},{"name":"横斑翠鸟","english_name":"Banded Kingfisher","scientific_name":"Lacedo pulchella","overview":"横斑翠鸟（英文名：Banded Kingfisher，学名：Lacedo pulchella），是佛法僧目翠鸟科横斑翠鸟属的鸟类。色彩鲜艳的树栖翠鸟，分布于东南亚低地热带森林。雄鸟拥有亮丽的蓝色头部，带黑蓝条纹的背部，橙色的脸颊和胸腹；雌鸟则全身布满橙黑条纹，外观宛如虎纹。栖息于低地至山地森林，最高可达海拔1100米。","appearance":"横斑翠鸟体型较小，长20-24.5厘米，雄鸟重40.8-48.5克，雌鸟重46.5-54.3克。雄鸟具亮蓝色头顶，橙色面颊、颈圈，蓝黑条纹的背、翅、尾，白色颏喉和橙色胸腹；雌鸟全身橙黑条纹，白喉，橙白下体。幼鸟较暗淡，嘴上颌棕色，下颌橙色，尖端淡色。","call":"发出悠长的哨音，初始为‘wheeeoo’，随后是连续15个短促三音节‘chiwiu’或‘taweo’，音量逐渐减弱，后期转为双音节，强调首音。","habits":"栖息于低地雨林、竹林、山地森林，高达1100米，有时在次生林、沼泽森林和亚高山森林。主要捕食昆虫，偶尔捕食小鱼、甲壳类和蜥蜴，常从高处或低处的栖木捕猎。","breeding":"繁殖期在1月至5月之间，巢穴通常挖掘在腐朽树干中，或树蚁巢中，高度可达3米。每窝产卵2-5枚，具体时间随地域而异。","identification":"雄鸟与雌鸟外观差异显著，雄鸟蓝顶橙胸，雌鸟橙黑条纹遍布全身。与同属其他物种相比，横斑翠鸟的头部羽毛会定期上下摆动。","protection":"IUCN：LC（无危）；在泰国、越南、马来西亚、印尼等地的国家公园中可见。","distribution":"分布于缅甸、泰国、柬埔寨、越南、老挝、马来西亚、苏门答腊、爪哇和文莱，曾存在于新加坡，现已灭绝。","other":"唯一属于Lacedo属的物种，曾广泛分布，但森林砍伐威胁了其生存。"},{"name":"普通仙翡翠","english_name":"Common Paradise Kingfisher","scientific_name":"Tanysiptera galatea","overview":"普通仙翡翠（英文名：Common Paradise Kingfisher，学名：Tanysiptera galatea），是佛法僧目翠鸟科仙翡翠属的鸟类。广泛分布在摩鹿加群岛和新几内亚的低地热带雨林，常见于海拔300米以下，最高可达820米。以其红喙和色彩斑斓的羽毛著称。","appearance":"成年普通仙翡翠体长33-43厘米，雄鸟体重58-65克，雌鸟55-69克。头部特征明显，蓝紫前额，蓝顶蓝枕，脸颊和腮部呈蓝紫色。背部有蓝黑色半领，尾部中央抽出两根细长的绶带，末端白色膨大成拍状，外缘蓝色。嘴红色，虹膜深褐色，腿黄褐色。幼鸟头部羽毛深褐色，眼先处红色，眼眉长而黑，双翼、尾巴深褐色，覆羽内衬明亮红色，尾巴中央蓝色，下浅黄色，有黑色小覆羽。","call":"发出1至4声忧伤的哨音，音调相同，逐渐加速至颤音，持续约1.5秒。多鸟齐鸣时，尾巴高扬，还发出低沉忧伤的哨音\"wheeyou\"，下滑持续1.5秒，或上扬更长（2-3秒）。另有粗糙的叽喳声和尖锐的尖叫。","habits":"栖息于季风森林和低地热带雨林，偶尔出现在海拔820米的地方。常在沿水草地的画廊森林、草原中的森林碎片、次生林和旧的柚木种植园。依赖树栖白蚁巢作为栖息地的一部分。以蚯蚓为主食，也吃螺类、甲虫、蚱蜢、毛虫、蜈蚣和小型蜥蜴。在湿润季节更多地在地面觅食。","breeding":"繁殖季节为10月至翌年3月（7月在巴布亚新几内亚）。在离地面2-6米的树上白蚁巢中筑巢，巢穴由两性共同挖掘，平均深度15厘米，直径13厘米。每窝产卵5枚，双方共同育雏。幼鸟占种群比例高，达60%，但幼鸟死亡率也高，平均寿命超过5年。","identification":"与阿鲁仙翡翠相似，但体型更大，冠色较淡，尾羽外侧白色而非蓝色，喙较粗壮。辨识最安全的方式是通过叫声。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界，主要在印尼摩鹿加群岛和新几内亚，常见于低地热带雨林，从海平面到300米，偶尔高达820米。","other":"15个已识别的亚种分布在新几内亚和周边岛屿。"},{"name":"黑翅仙翡翠","english_name":"Kofiau Paradise Kingfisher","scientific_name":"Tanysiptera ellioti","overview":"黑翅仙翡翠（英文名：Kofiau Paradise Kingfisher，学名：Tanysiptera ellioti），是佛法僧目翠鸟科仙翡翠属的鸟类。长尾树翠鸟，特征显著，拥有海蓝色顶冠，深蓝色上体，白色臀部和下体，尾羽完全白色且中央尾羽显著延长。分布于印尼Kofiau岛（四王群岛，新几内亚西北部）的低地森林。","appearance":"成年黑翅仙翡翠长约33-34厘米，包括其长达10-11厘米的尾羽流苏。头部和上体呈深蓝色，冠羽淡蓝，臀部、尾羽及下体纯白。尾羽中央羽毛显著加长，略呈锥形，尖端扁平。喙鲜红，虹膜暗棕色，腿脚呈灰褐至黄褐色。幼鸟色彩较暗淡，翅膀覆羽边缘微黄，背部及臀部泛淡棕色，腹部带棕黄色调，尾羽上方蓝色下方灰色，喙色深褐，尖端稍浅。","call":"鸣唱为快速颤音，音调逐渐上升后突然停止，持续约1.5至2秒，与普通仙翡翠相似但更短促，带哀婉音调。叫声为三声柔和、哀伤、高音下滑的哨音，有时结尾轻微上扬。","habits":"栖息于Kofiau岛上的高大阴凉原始森林和次生林，成鸟也可见于遮荫的花园。以昆虫和蠕虫为食，常在地面挖掘土壤寻找食物，包括蜗牛、甲虫、蚱蜢、毛毛虫、蜈蚣、蚯蚓和小型爬行动物。飞行和活动特征未详述。","breeding":"繁殖期未具体说明，但已知会在距地面约1.2米高的白蚁侵蚀过的树洞中筑巢，巢穴尺寸约为15厘米×13厘米。雌鸟产卵数为5枚，由双亲共同孵化和育雏。","identification":"与非常相似的普通仙翡翠相比，黑翅仙翡翠的尾羽完全白色，中央尾羽仅轻微变窄，末端不明显扁平。幼鸟与成鸟在色彩上有细微差别。","protection":"IUCN：NT（近危）","distribution":"分布于印尼的Kofiau岛（四王群岛，新几内亚西北部），在繁殖区域内广泛存在于原始森林、次生林及轻度林木覆盖的村舍花园。"},{"name":"比岛仙翡翠","english_name":"Biak Paradise Kingfisher","scientific_name":"Tanysiptera riedelii","overview":"比岛仙翡翠（英文名：Biak Paradise Kingfisher，学名：Tanysiptera riedelii），是佛法僧目翠鸟科仙翡翠属的鸟类。树栖翠鸟，仅分布在印度尼西亚的比岛，属于Cenderawasih湾附近的岛屿群。该鸟以亮丽的天蓝色背部、白色腹部和尾流为显著特征，拥有红色的喙。IUCN将其保护状态评估为近危。","appearance":"成年比岛仙翡翠约36厘米长，包括其延长的尾羽。头部、颈背及上体呈亮光泽的天蓝色，臀部和尾基白色，下体亦为白色。中央尾羽异常延长，末端呈球拍状，基部白色，中央部分蓝色。喙橙红色，虹膜深棕色，腿脚绿灰色至黄褐色。幼鸟色泽较暗，尾羽较短，带有淡褐色斑纹，喙色暗褐。","call":"发出低沉独特的二声吠叫，有时在二重唱中发出上升和加速的尖锐“puuu puu pipipipipipi!”叫声。","habits":"比岛仙翡翠栖息于原始森林和退化森林中，偏好在森林中层静坐，上下摇摆尾巴。它们主要以昆虫、蜗牛、甲虫、蚱蜢、毛毛虫、蜈蚣、蚯蚓及小型爬行动物为食，常在地面上用喙挖掘土壤捕食。","breeding":"两性共同在距地面约1.2米的白蚁丘中挖洞筑巢，巢穴尺寸约为15厘米×13厘米。雌鸟一般产5枚卵，双方共同孵化和喂养雏鸟。","identification":"与相似物种普通仙翡翠相比，比岛仙翡翠的冠和颈背颜色更鲜亮的蓝色，尾部白色部分更多，喙更粗壮。","protection":"IUCN：NT（近危）","distribution":"该物种仅限于印度尼西亚的Biak岛及邻近的Supiori岛，位于北Geelvink湾（新几内亚西北部）。","other":"比岛仙翡翠可能是由少数普通仙翡翠创始个体到达比岛并经历隔离后形成的，随后经历了'遗传革命'，形成新的物种。"},{"name":"蓝仙翡翠","english_name":"Numfor Paradise Kingfisher","scientific_name":"Tanysiptera carolinae","overview":"蓝仙翡翠（英文名：Numfor Paradise Kingfisher，学名：Tanysiptera carolinae），是佛法僧目翠鸟科仙翡翠属的树栖翠鸟，仅见于印度尼西亚的Numfor岛，位于新几内亚西北海岸。尽管常见，但由于栖息地森林受到伐木影响，IUCN将其列为近危物种。","appearance":"蓝仙翡翠体长34至38厘米，尾羽显著。全身紫蓝色，上体与翅膀色泽更为鲜艳，下背部、臀部、尾部和腹下部为白色。尾羽中央一对延长至7至8厘米，末端呈白色球拍状。喙鲜红，虹膜深棕色，腿橄榄褐色。幼鸟上体暗蓝，尾黑，下体肉桂色至红紫色，具黑色条纹。","call":"其叫声类似大杜鹃，但音量更大，为一系列鼻音，由慢渐快，最后快速颤音。","habits":"栖息于Numfor岛的森林、林地、农田及海岸植被，偏好低地环境。以螺类、大型昆虫如蚱蜢、甲虫为主食，狩猎技巧与其他翠鸟相似，常在近水树荫下等候猎物，地面觅食，挖掘土壤捕食。","breeding":"繁殖期未详，营巢于白蚁侵蚀的树洞，距地面约1.2米，巢穴尺寸约为15厘米×13厘米。雌鸟产卵数通常为5枚，双方共同孵卵及育雏。","identification":"蓝仙翡翠在Numfor岛上是唯一的天堂翠鸟，长尾、白尾尖、红喙为明显特征，与同属其他种区别明显。","protection":"IUCN：NT（近危）","distribution":"仅分布于Numfor岛，位于印度尼西亚Biak群岛，新几内亚西北海岸。"},{"name":"阿鲁仙翡翠","english_name":"Little Paradise Kingfisher","scientific_name":"Tanysiptera hydrocharis","overview":"阿鲁仙翡翠（英文名：Little Paradise Kingfisher，学名：Tanysiptera hydrocharis），是佛法僧目翠鸟科仙翡翠属的鸟类。生活在河流森林中的神秘翠鸟。主要分布在印尼阿鲁群岛和新几内亚中南部，以其独特的外观和生活方式吸引着科学家和鸟类爱好者的关注。","appearance":"阿鲁仙翡翠两性有明显区别。雄鸟的头部、身体和翅膀呈现深蓝色，肩部、下背部、尾部、披风接近黑色，下体全白，尾巴蓝色。最具特色的是两条长达12厘米的深蓝色长飘带尾羽，末端呈白色球拍状。翅膀覆羽为黑色。嘴部鲜红，虹膜深棕色，腿为橄榄褐色。雌鸟上体棕褐色，下体白色，尾部较短无飘带。","call":"关于阿鲁仙翡翠的鸣叫特征，目前信息不足，可能与普通仙翡翠相似，表现为一系列下降的音符。","habits":"这种翠鸟栖息于密集的低地雨林，包括比普通仙翡翠更为干燥的环境。它们似乎过着定居的生活，主要以昆虫和昆虫幼虫为食，从树叶上或地面上觅食。","breeding":"在阿鲁群岛，繁殖期为4月，最近发现的幼鸟出现在5月。据报道，它们在树上的白蚁巢中筑巢。每窝产卵数量未知，但双方共同参与孵化和育雏。","identification":"与普通仙翡翠相比，阿鲁仙翡翠体型较小，冠部颜色更深，外侧尾羽为蓝色而非白色，喙部略细。最可靠的区分方式是通过鸣叫声。","protection":"IUCN：DD（数据缺乏）。阿鲁仙翡翠在新几内亚大陆被认为是稀有物种，但在阿鲁群岛曾被报道为常见，不过近期信息缺失。在Trans-Fly地区北部Kiunga以北，其状态被描述为罕见至常见。","distribution":"主要分布于印尼的阿鲁群岛和新几内亚的中南部，特别是在Trans-Fly区域。","other":"阿鲁仙翡翠的生态、生物学和种群水平仍需更多研究数据。"},{"name":"白尾仙翡翠","english_name":"Buff-breasted Paradise Kingfisher","scientific_name":"Tanysiptera sylvia","overview":"白尾仙翡翠（英文名：Buff-breasted Paradise Kingfisher，学名：Tanysiptera sylvia），是佛法僧目翠鸟科仙翡翠属的鸟类。色彩鲜艳的树冠翠鸟，拥有非常长的白色尾羽，锈红色下体，鲜红的喙。头部和翅膀呈蓝色，带有黑色眼罩和沿背脊延伸的白色条纹。夏季在澳大利亚远北昆士兰和新几内亚东南部的湿润热带雨林繁殖，筑巢于白蚁丘的地道中。昆士兰的个体在年中迁徙至新几内亚。","appearance":"白尾仙翡翠身长29-37厘米，包括尾羽流苏；雄鸟重38-61克，雌鸟44-61克。指名亚种（sylvia）有蓝色头部，黑色眼罩，深蓝上体带背部白色斑点，白色臀部；尾部蓝色，中央羽毛白色且细长至末端，比其余尾羽长7-18厘米；下体橙色；喙红色；虹膜深棕色至黑色；腿脚粉红色。雌鸟与雄鸟区别在于尾部较短，中央尾羽边缘蓝色，背部和臀部有变化不定的暗淡条纹。幼鸟较为暗淡，额头呈肉色，翼羽尖端肉色，背部黑色，上方有一肉白色斑块，臀部羽毛边缘蓝色，下体橙色羽毛边缘和尖端黑色，喙棕色，腿脚黄绿色。","call":"在澳大利亚，发出由4-5个（最多14个）响亮的‘chop’音符组成的管道叫声，音调逐渐升高；在巢附近发出柔和的降调颤音，受激时发出刺耳快速响亮的声音；受到惊吓时发出尖锐的叽叽喳喳声，驱赶同类时亦如此；从两周大起，幼鸟发出非常嘈杂的嘶哑尖叫。指名亚种（sylvia）在新几内亚的越冬地通常较为安静，除非被声音回放所激惹。","habits":"栖息于季风雨林，低地森林，以及山地森林，海拔可达900米，在澳大利亚，但在新几内亚通常低于500米。一般靠近溪流，出现在孤立的森林斑块，但很少见于湿润硬叶林。白蚁丘是其繁殖栖息地的重要组成部分。在一些地区与普通仙翡翠共存，占据较高层次的森林；在其他地区两者相互排斥。","breeding":"繁殖季节在巴布亚新几内亚为2月，在昆士兰州为11月至翌年2月。巢由双方共同挖掘，一般在地面的白蚁丘中，有时在树上的白蚁丘，巢隧道位于距地面13-17厘米处，宽4-5厘米，长13-20厘米，以未铺垫的巢室结束，高14厘米，宽17厘米；同一巢址可能连续使用长达八年。每窝通常产三枚卵（2-4枚），间隔一天产一枚；双方轮流孵化，但仅雌鸟夜间孵化，孵化期26-28天；在昆士兰的研究中，仅雌鸟育雏，但双方喂养幼鸟，每小时喂食1.6-12次；幼鸟对任何刺激都会发出响亮的尖叫；离巢期26-35天；离巢后幼鸟由父母喂养30天。蜥蜴（Varanus）常袭击巢穴，被成鸟攻击。","identification":"与普通仙翡翠的区别在于占据的森林层次更高，有白色的背部斑点，更长的尾羽流苏。幼鸟与成鸟的区别在于较短的尾羽流苏，棕色的喙，黄色的腿脚。","protection":"IUCN：LC（无危）","distribution":"繁殖于澳大利亚东北部和新几内亚中北部、中南部、东南部；越冬至新几内亚。","other":"在迁徙过程中，部分个体夜间飞行时可能因撞击大堡礁的灯塔或飞入窗户而死亡。"},{"name":"黑冠仙翡翠","english_name":"Black-capped Paradise Kingfisher","scientific_name":"Tanysiptera nigriceps","overview":"黑冠仙翡翠（英文名：Black-capped Paradise Kingfisher，学名：Tanysiptera nigriceps），是佛法僧目翠鸟科仙翡翠属的鸟类。色彩鲜艳的树栖翠鸟，以黑色头部、蓝白相间的长尾流苏、红嘴和锈红色下体著称。在巴布亚新几内亚的俾斯麦群岛低地和山地森林中居住。","appearance":"成年黑冠仙翡翠总长30至48厘米，体重43至74克，拥有中等体型。其特征为红嘴和极长的白蓝尾流苏（亚种间存在差异）。成鸟头部、颈背和肩羽黑色，翅膀光泽蓝色，外侧尾羽蓝色，背部和中央尾羽白色，下体橙色。幼鸟尾流苏较短，喙呈褐色，颈部羽尖蓝色，翼覆羽红褐色，背部淡黄色，下体羽毛边缘黑色。亚种nigriceps头部和肩羽黑色，尾羽灰蓝，仅中央尾羽内侧和尖端白色，腿色从暗黄到橙色。","call":"在新不列颠岛（nigriceps），发出一系列通常5至7个哀怨的'chipring'音调，以规律速率持续2至3秒。在乌姆博伊岛（leucura），发出升调和降调的啾啾声，加速至长达7秒的颤音。在日热时段极少鸣叫，但在清晨和傍晚频繁鸣叫，同时伴有尾部摇摆。","habits":"栖息于低地和山地森林，偏好有密集中层植被的林缘和次生林，常在林下层栖息。在新不列颠岛记录的高度可达1640米，但常见于低地。","breeding":"繁殖生态知之甚少。在新不列颠岛，筑巢时间可能为5月、6月和12月。已知的一个巢穴位于树上，距地面5米高。关于繁殖生态的大部分信息推测与白尾仙翡翠相似。","identification":"与其他天堂翠鸟的区别在于头部黑色、独特的长尾流苏颜色和下体颜色。亚种间的辨识主要基于尾羽颜色。","protection":"IUCN：LC（无危）。在其分布范围内局部常见，如新不列颠岛的Nakanai和Whiteman山脉。尽管因大规模森林砍伐数量有所下降，但并未受到威胁。","distribution":"分布于澳新界的新不列颠岛（俾斯麦群岛东南部）。"},{"name":"粉胸仙翡翠","english_name":"Red-breasted Paradise Kingfisher","scientific_name":"Tanysiptera nympha","overview":"粉胸仙翡翠（英文名：Red-breasted Paradise Kingfisher，学名：Tanysiptera nympha），是佛法僧目翠鸟科仙翡翠属的鸟类。分布于新几内亚，以其醒目的红胸和长尾著称，活跃于低地及山麓森林，包括红树林和河流附近的森林。","appearance":"粉胸仙翡翠拥有蓝紫前额和头顶，眼先黑色，脸颊和腮部为蓝紫色。其下体和背部呈红色，小覆羽黑色，中覆羽亮天蓝色。翅膀上方为蓝紫色，最显著的特征是尾部中央伸出的两根极长的细长绶带，外缘蓝色，末端纯白色并膨大成拍状。嘴部红色，虹膜深褐色，腿部黄褐色。","call":"其鸣唱为有力的下行颤音'brrrrrrrrrrrrrrrrrrrrrrr…!'。","habits":"粉胸仙翡翠为完全肉食性的翠鸟，擅长隐蔽于近水的树荫下捕食鱼虾。它在伫立时头部几乎不动，尾巴不时摆动。大部分时间在地面上寻找食物，通过挖掘土壤捕食昆虫、蜗牛、甲虫、蚱蜢、毛毛虫、蜈蚣、蚯蚓，偶尔也会捕食小型爬行动物如蜥蜴。","breeding":"粉胸仙翡翠在距地面约四英尺的白蚁塔上钻洞筑巢，巢穴大小约为15厘米×13厘米。雌鸟通常产5枚卵，双方共同孵化并抚育雏鸟。","identification":"与褐背仙翡翠的区别在于头部颜色，粉胸仙翡翠头部为黑色而非棕色。与Buff-breasted相比，后者具有白色的背部和尾部。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚，具体在鸟头半岛和Neck（新几内亚西北部）以及东北部的Adelbert Range、休恩半岛和Huon Gulf。"},{"name":"褐背仙翡翠","english_name":"Brown-headed Paradise Kingfisher","scientific_name":"Tanysiptera danae","overview":"褐背仙翡翠（英文名：Brown-headed Paradise Kingfisher，学名：Tanysiptera danae），是佛法僧目翠鸟科仙翡翠属的鸟类。分布于新几内亚东南部的低地森林。拥有醒目的棕色头部和背部，橙色腹部和臀部，深蓝色肩部和长长的尾羽，尾羽尖端带有细小白边。其自然栖息地为温带和热带湿润的低地森林。","appearance":"成年褐背仙翡翠长约28至30厘米，包括尾羽流苏，体重37至50克。雄鸟具赤褐色冠羽和背部，明亮的粉红色臀部，蓝色翼覆羽；粉红色的下巴和喉咙，深粉红色的胸部和腹部，较淡的侧翼和下尾覆羽；紫蓝色上尾，中央羽毛比其余羽毛长9厘米，基部有白色尖端和狭窄的内缘；红色喙；暗棕色虹膜；粉红至橙红色的腿和脚。雌鸟的下巴和喉咙为淡褐色。幼鸟的冠羽更偏棕色，橄榄棕色上部，鳞片状下部，橙色喙基部为棕色。","call":"鸣唱为上升后下降或仅下降并加速的一系列音符，以颤音结束：“weeep weep wewewewweewe……..”。","habits":"栖息于低地和山脚森林，常在树冠中层安静停留，偶尔摇动尾巴，受惊时会大幅度扇动。以昆虫为主食，包括甲虫和毛虫。相比，它在森林中的觅食高度相对较高。","breeding":"关于繁殖的信息极少，但最频繁的鸣叫发生在5月至10月间，曾记录到9月份正在挖掘巢穴的个体。","identification":"与白尾仙翡翠相似，但褐背仙翡翠的头部为棕色而非黑色和蓝色，且缺乏背部的白色条纹。","protection":"IUCN：LC（无危）。分布零散，在某些区域稀少但在其他区域常见。在Varirata国家公园定期被记录。没有人口数量数据，也没有已知的威胁信息。需要收集有关其状态和生物学的所有方面的数据。","distribution":"主要分布在新几内亚东南部，从Waria河和Aroa河向东至米尔恩湾（Milne Bay）西北岸。在较高的海拔处比普通天堂翠鸟更为常见，但在Popondetta周围，两者均在150米海拔处出现。"},{"name":"苏拉蓝耳翠鸟","english_name":"Sulawesi Lilac Kingfisher","scientific_name":"Cittura cyanotis","overview":"苏拉威西蓝耳翠鸟（英文名：Sulawesi Lilac Kingfisher，学名：Cittura cyanotis），是佛法僧目翠鸟科苏拉蓝耳翠鸟属的鸟类。拥有橄榄褐色的上体，栗色尾部，紫丁香色的眉毛、喉咙及胸部，以及引人注目的红喙。仅分布于印尼苏拉威西岛和Lembeh岛的低地雨林与山地森林。","appearance":"成年苏拉威西蓝耳翠鸟长约22厘米，雄鸟具深蓝色眼罩，雌鸟相应部位为黑色。上体橄榄褐色，尾部栗色，翅膀结合了深蓝与黑色，肩部有一条显著的白色条纹，下胸显淡红色。嘴粗直且强大，呈红色，翼尖长，尾短圆。幼鸟与成鸟相似，但羽毛色泽较暗，喙色为暗灰棕色。","call":"其鸣叫声为快速连续的“ku-ku-ku-ku”，通常在清晨较为频繁。","habits":"栖息于低地雨林和干燥的山地森林，最高可达1000米。以大型昆虫为主要食物，通过在低枝上静止观察，伺机俯冲捕食。视力适应水下环境，擅长捕捞小鱼。","breeding":"关于其繁殖行为的研究较少，但推测其可能在堤坝上挖掘巢穴或在树上筑巢，如同其他苏拉威西岛的翠鸟。","identification":"苏拉威西蓝耳翠鸟以其独特的紫丁香色面部特征和红喙区别于其他翠鸟，幼鸟的暗色羽毛和喙色有助于识别。","protection":"IUCN：LC（无危）。由于低地森林的大量砍伐，其栖息地遭受严重威胁。","distribution":"主要分布在印尼苏拉威西岛的北部、东部和中部，以及Lembeh岛。","other":"苏拉威西蓝耳翠鸟的学名源自希腊语，意为‘深蓝色的耳朵’，反映了其独特的外观特征。"},{"name":"桑岛蓝耳翠鸟","english_name":"Sangihe Lilac Kingfisher","scientific_name":"Cittura sanghirensis","overview":"桑岛蓝耳翠鸟（英文名：Sangihe Lilac Kingfisher，学名：Cittura sanghirensis），是佛法僧目翠鸟科苏拉蓝耳翠鸟属的鸟类。原生于印尼桑岛低地森林，2014年被IUCN红名单和BirdLife International认定为独立物种，此前被认为是苏拉威西蓝耳翠鸟的亚种。","appearance":"羽毛以淡褐色为主，拥有醒目的红色喙，上眼线有一显著暗色面具，边缘点缀着浅色斑点，翅膀深色，尾巴赤褐色。深色部位呈现深蓝色，但在某些光线下可能看似黑色。幼鸟颜色较暗淡，羽缘呈棕色。","call":"早晨最常听到其重复下降的叫声，音调似“wup-wup-ku-ku-ku-ku”，长度变化。","habits":"单独活动，栖息于低地和丘陵地带的森林阴凉林下层。","breeding":"繁殖信息未详述。","identification":"与苏拉威西蓝耳翠鸟的区别在于地理分布和部分外观差异。","protection":"IUCN：NT（近危）","distribution":"分布于澳新界的桑岛和印尼的锡奥岛（苏拉威西岛北部）。"},{"name":"铲嘴翠鸟","english_name":"Shovel-billed Kookaburra","scientific_name":"Dacelo rex","overview":"铲嘴翠鸟（英文名：Shovel-billed Kookaburra，学名：Dacelo rex），是佛法僧目翠鸟科笑翠鸟属的鸟类。大型树栖翠鸟，身长约33厘米，以其独特的大而短宽的喙著称。该鸟主要分布于新几内亚的低地雨林至中山区。","appearance":"铲嘴翠鸟拥有深棕色头部，眼部后方有一条橙色条纹，白色喉部，橙色颈环和下体，鲜亮的蓝色臀部。喙部粗壮且呈深棕色，虹膜深褐色，腿部黄褐色。雄鸟尾部呈深蓝色，而雌鸟尾部为棕红色。幼鸟外观类似雌鸟，但羽毛颜色较暗，颈部和胸部羽毛边缘为黑褐色。","call":"其鸣叫声为远距离传播的中音调、持续不断的‘peeep！’声。","habits":"铲嘴翠鸟栖息于新几内亚的低地雨林至海拔2400米的山地，以大蚯蚓、昆虫及其幼虫、蜗牛、小蜥蜴和小蛇为食。它们在树干上挖掘巢穴，重复使用多年。","breeding":"繁殖季节为每年10月，通常产2枚卵，雌鸟负责孵卵和育雏，每次喂养后会将尾部朝向巢外排泄。","identification":"与棕腹笑翠鸟相比，铲嘴翠鸟具有深色而非蓝色的翅膀，以及更为厚重的喙。","protection":"IUCN：LC（无危）","distribution":"铲嘴翠鸟分布于新几内亚半岛、印尼部分岛屿的东端、巴布亚和米尔恩湾，主要栖息于低地雨林至海拔2400米的山地。","other":"曾被认为是Clytoceyx属的唯一代表，后经分子系统发育研究，被归入Dacelo属。"},{"name":"笑翠鸟","english_name":"Laughing Kookaburra","scientific_name":"Dacelo novaeguineae","overview":"笑翠鸟（英文名：Laughing Kookaburra，学名：Dacelo novaeguineae），是佛法僧目翠鸟科笑翠鸟属的鸟类。身长42-46厘米，嘴长8-10厘米，重约500克，是翠鸟家族中体型最大者。以其独特的笑声命名，这种叫声常在清晨或黄昏时分响起，有‘林中居民的时钟’之称。笑翠鸟主要分布于澳大利亚东部，包括西南部地区，以及新西兰的部分地区。","appearance":"笑翠鸟拥有大而有力的喙，上身为灰褐色，腹部呈灰白相间的颜色。雄鸟翅膀上有一抹蓝色作为识别标志。尾巴较长，棕色和黑色相间。腿短且呈灰色。嘴粗直，长而坚硬，头部较大，颈部短。翼短圆，尾亦短小。嘴形长大而尖，嘴峰圆钝，脚甚短，趾细弱。第4趾与第3趾大部分并连，与第2趾仅基部并连。","call":"笑翠鸟的叫声独特，像人类的笑声，这种声音在清晨或黄昏时分尤为明显，被称为‘林中居民的时钟’。叫声由五个元素组成：‘Kooa’、‘Cackle’、‘Rolling’、‘Haha’和‘Gogo’或‘Gurgle’，具有很高的辨识度。","habits":"笑翠鸟栖息于开阔的硬叶林和林地，偏好树木空洞丰富的环境。它们全年保护自己的领域，主要食物包括蛇、蜥蜴和昆虫。它们会在树洞中筑巢，且倾向于形成家庭群体，年轻后代会协助父母照顾次年的幼鸟。","breeding":"繁殖季节在南半球的9月至12月。在树洞中筑巢，单配性，产卵2-4枚，卵白色。雏鸟在4至5周后孵化，幼鸟通常和亲鸟住在一起，并帮助喂养次年的幼鸟。","identification":"笑翠鸟与蓝翅笑翠鸟的区别在于前者具有暗色眼纹和暗色眼睛，且翅膀和臀部的蓝色较少。雄性蓝翅笑翠鸟的尾巴有蓝黑相间的条纹。","protection":"IUCN：LC（无危）","distribution":"笑翠鸟主要分布于澳大利亚东部，包括西南部地区。在新西兰，它们分布于豪拉基湾西侧的一小片区域。在澳大利亚，它们的分布从约克角半岛向南延伸至奥特威角。","other":"笑翠鸟因其捕捉蛇类的能力而闻名，曾有记录显示它们能够捕捉比自己体型大的蛇类。"},{"name":"蓝翅笑翠鸟","english_name":"Blue-winged Kookaburra","scientific_name":"Dacelo leachii","overview":"蓝翅笑翠鸟（英文名：Blue-winged Kookaburra，学名：Dacelo leachii），是佛法僧目翠鸟科笑翠鸟属的鸟类。大型翠鸟，原生于澳大利亚北部和新几内亚南部。体长约为40厘米，较笑翠鸟略小。拥有奶油色的上下体，带褐色条纹，蓝色翅膀与肩部，蓝臀。雄鸟尾部呈蓝色，雌鸟则为红褐色，带有黑色条纹。广泛分布于新几内亚南部至澳大利亚东北部。","appearance":"蓝翅笑翠鸟体长约38至41厘米，体重雄鸟250至322克，雌鸟260至370克。其头部和身体颜色淡，有蓝翼和蓝臀。雄鸟头顶有轻微暗斑，背部灰棕色，雌鸟尾部红褐色，尾羽间有黑蓝相间的条纹。幼鸟外观脏污，眼色两年内呈棕色。喙上部棕黑色，下部黄白色，虹膜白或极淡黄色，腿和脚淡肉色至灰绿。","call":"发出响亮的滚动叫声和多种大声的吠叫，与笑翠鸟的叫声截然不同，被形容为狂笑或犬吠。","habits":"栖息于多种林地环境，包括灌木林地、桉树开放林地和森林，河流沿岸高树，河口红树林和季风雨林。避免密集下层植被区。也见于牧场、农田、远离水源的种植园，以及大都市公园和花园。主要生活在低地，但在新几内亚局部可达600米高度。","breeding":"9月至翌年1月繁殖，一夫一妻制。以2至12个个体的家庭群繁殖，包括繁殖对和辅助鸟。巢建于树洞或白蚁丘，平均孵化期25至26天，幼鸟孵化后36天离巢。","identification":"与笑翠鸟相比，蓝翅笑翠鸟较小，无暗面罩，翅膀更蓝，眼色鲜明。雄鸟尾部蓝，雌鸟尾部红褐色带黑纹。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚南部和澳大利亚东北部，至昆士兰南部，横跨北端地区，最远至西澳海岸的鲨鱼湾区域。澳大利亚西北部的布鲁姆至黑德兰港之间未发现。","other":"适宜生境因农业开垦而受破坏，但在新几内亚，随着森林开垦，该物种正在扩展其范围。"},{"name":"披肩笑翠鸟","english_name":"Spangled Kookaburra","scientific_name":"Dacelo tyro","overview":"披肩笑翠鸟（英文名：Spangled Kookaburra，学名：Dacelo tyro），是佛法僧目翠鸟科笑翠鸟属的鸟类。大型棕腹笑翠鸟科笑棕腹笑翠鸟属物种。分布于印度尼西亚阿鲁群岛和新几内亚中南部，以独特的斑点头部、明亮的蓝色翅膀和尾巴以及白色胸部为显著特征。","appearance":"披肩笑翠鸟体长可达33厘米，雌鸟重约148-165克，雄鸟重约128-145克。头部、后颈和肩部呈黄褐色，边缘黑色，形成斑点状图案；背部和肩胛部黑色，臀部和尾羽覆盖物为亮丽的钴蓝色；尾羽和翅膀深蓝黑色，小翼羽和中翼羽边缘明亮蓝色；下巴和喉咙白色，其余下体淡黄色至淡橙色；上喙黑色，下喙淡角质色；虹膜深棕色，腿和脚灰色至灰绿色。幼鸟头部较暗，喉咙和胸部有狭窄的黑色边缘，肩部黑色更明显。","call":"通常成对鸣唱，发出有节奏的重复“gok-gok！”声，间杂着颤音。叫声与蓝翅笑翠鸟相似，但音调单调，一系列短促、干燥的咳嗽声或类似狗吠的声音，音符和整串叫声音调恒定。","habits":"栖息于茂密的干草原、季风林、河流森林和沼泽边缘的灌木丛，偏好原始生长环境，如阿鲁岛上的雨林。主要在林下层活动，但在阿鲁岛上通常在树冠层观察到。以昆虫为主食，如甲虫、蚂蚁和竹节虫，从1至4米高的栖木上耐心搜寻地面猎物，然后进行浅飞行捕捉。","breeding":"3月收集处于繁殖状态的雌鸟，3月发现带有幼鸟的巢。在半球形白蚁丘中挖掘巢穴，两个已知巢穴位于离地5米处，白蚁丘直径分别为45厘米和60厘米，一处在Alstonia scholaris树上，另一处在Acacia mangium树上。关于产卵数量、孵化和离巢期的信息未知。","identification":"与蓝翅笑翠鸟相比，披肩笑翠鸟体型较小，头部和背部颜色较深，尾羽外侧无白色尖端，头部斑点而非条纹。叫声单调，一系列相同、短促的咳嗽声，音调恒定，与蓝翅笑翠鸟的叫声有所不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在印度尼西亚的阿鲁群岛和新几内亚中南部，包括新几内亚的Trans-Fly EBA区域。","other":"在适宜的栖息地被认为常见，出现在瓦苏尔国家公园，伊里安查亚。自1988年以来，阿鲁群岛未有报告，但当时在那里普遍且广泛分布。"},{"name":"棕腹笑翠鸟","english_name":"Rufous-bellied Kookaburra","scientific_name":"Dacelo gaudichaud","overview":"棕腹笑翠鸟（英文名：Rufous-bellied Kookaburra，学名：Dacelo gaudichaud），是佛法僧目翠鸟科笑翠鸟属的鸟类。广泛分布在新几内亚低地森林中。以其独特的外观和生活方式著称，包括黑色的顶冠、蓝色调的翅膀、鲜明的肉桂色腹部和尾羽。雄鸟具有白色的颈环，与雌鸟和幼鸟的红褐色尾羽形成对比。","appearance":"成年棕腹笑翠鸟体型较大，长度约28-31厘米，雄鸟重110-161克，雌鸟重138-170克。雄鸟特征为眼后有白色条纹，黑色有光泽的顶冠与背部分隔开，由完整的白色颈圈环绕。下背、臀部和上覆尾羽呈闪亮的天蓝色；翅膀覆羽为黑色，边缘带有淡蓝色；尾羽深蓝色；下体自喉部以下为浓郁的肉桂色。喙白色或角黄色，虹膜深棕色，腿和脚灰白色。雌鸟与雄鸟相似，但尾羽为丰富的栗色。幼鸟与雌鸟相似，但喙和羽毛为灰色，有暗色边缘。","call":"拥有多种不同的叫声，包括重复的、粗糙响亮的“rek！”音节，伴随轻微摇尾；以及在抬尾时发出的空洞滚动声。","habits":"栖息于低地森林的下层，以蜥蜴和昆虫为食，偶尔在地面觅食。飞行直接且迅速，能灵活穿梭于密集的树丛间。以家庭为单位生活，保卫领地平均大小为2至2.5公顷。","breeding":"繁殖期通常在5月至10月，但幼鸟直至翌年2月才会完全离巢。每对每年尝试一次繁殖，产2枚白色蛋，确切的孵化周期未知。","identification":"与铲嘴翠鸟相比，棕腹笑翠鸟具有蓝色而非棕色的翅膀，且喙更长、颜色更浅。通过尾羽颜色可以区分性别：雄鸟为蓝色，雌鸟和幼鸟为红褐色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚低地森林，包括Gebe I（北摩鹿加群岛）、西巴布亚岛屿（瓦伊盖奥、巴坦塔、萨拉瓦蒂、米索尔）、新几内亚大陆（含Kolepom I）、Geelvink湾的岛屿（Mios Num、Yapen）、Aru群岛以及米尔恩湾的Heath Island（Sariba）。","other":"已知与所有其他笑翠鸟种类形成（不育）杂交种，尽管遗传研究显示它是四个种类中最远亲的。"},{"name":"白腰翡翠","english_name":"White-rumped Kingfisher","scientific_name":"Caridonax fulgidus","overview":"白腰翡翠（英文名：White-rumped Kingfisher，学名：Caridonax fulgidus），是佛法僧目翠鸟科白腰翡翠属的鸟类。最显著的特征是全身暗紫色，仅腰部为白色，分布于印尼，栖息于低地和山脚森林，包括降级林区。","appearance":"白腰翡翠身长30厘米，雄雌相似。头部、背部呈亮深紫蓝色，胸部和腹部以及尾部顶端的珍珠光泽白色形成鲜明对比。成鸟拥有红色的喙和脚，幼鸟上体光泽较少，腹部带浅黄色或红色，胸部有灰棕色羽毛，喙为黄橙色，虹膜为浅棕色。","call":"其鸣叫声为一系列快速的‘kuff-kuff-kuff...’音符，每秒约1个音节，或连续2至36声响亮、急促、类似小狗吠叫的‘wáúh, wáúh, wáúh...’。","habits":"白腰翡翠生活在热带雨林，常单独或成对活动，以昆虫、昆虫幼虫为主食，偶尔捕食小型脊椎动物如小鱼、小蛇和蜥蜴。","breeding":"白腰翡翠在弗洛雷斯岛的繁殖期为1月至3月，在松巴哇岛为2月至3月。筑巢于土崖壁或河堤上的隧道式洞穴，雌鸟每次产1或2枚卵，卵直接产在巢穴地面上。","identification":"白腰翡翠的鉴别特征在于其独特的暗紫色上体与白色腰部对比，以及红喙和红脚。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚新几内亚界，具体包括龙目岛至弗洛勒斯岛、Besar岛（弗洛勒斯岛北部）和Adonara岛（弗洛勒斯岛东部，小巽他群岛西部，中部）。","other":"白腰翡翠能够适应降级森林和林地环境，即使失去原始森林栖息地也能生存。"},{"name":"鹳嘴翡翠","english_name":"Stork-billed Kingfisher","scientific_name":"Pelargopsis capensis","overview":"鹳嘴翡翠（英文名：Stork-billed Kingfisher，学名：Pelargopsis capensis），是佛法僧目翠鸟科鹳嘴翡翠属的鸟类。广泛分布于印度次大陆至东南亚，从印度延伸至印尼。其特征为拥有硕大的红色喙，头顶、脸侧及颈背呈灰棕色，上背有一宽阔的亮棕黄色环带融入下体，上体大都蓝绿色。在多种生境中皆可见其身影，包括湖泊、河流和海岸附近的森林地带。","appearance":"鹳嘴翡翠长度可达35至41厘米，体重在143至225克之间。成年个体拥有橄榄褐色头部，白色下巴，脖颈和下部呈淡黄色，背部深绿蓝色，翅膀和尾巴更显蓝色，臀部呈现浅蓝色，极为明显。喙鲜红色，端部颜色较深，虹膜为深棕色，腿和脚橙红色。幼鸟胸和颈后缘有暗色羽缘。不同亚种在大小、颜色上有细微差异。","call":"鹳嘴翡翠发出响亮刺耳的“kak kak kak kak...”声，逐渐减弱；尖锐下降的哨音，“tree-trew”或“kwee-kwau”；非常响亮的咯咯声“kie-iek, kie-iek, kie-iek”；悦耳的类似歌声的“peer...peer...purr”；受到干扰时发出响亮尖锐的“wiak-wiak”声；飞行时发出尖叫般的笑声“kiu-kiu, kee-kiu”，通常重复数次。","habits":"鹳嘴翡翠生活在低地水域附近的各种林缘环境中，如溪流、运河、大河、水库、湖泊和海岸，高度可达870米，但在印度、婆罗洲和弗洛雷斯岛可达1200米。它们栖息于原生雨林深处、沼泽森林、竹林和红树林，但也出现在更为开阔的区域，如椰子种植园和稻田。在马来西亚半岛，常见于东北部的红树林，而在西北部，由于白腹海雕的存在，鹳嘴翡翠似乎不出现于此。","breeding":"鹳嘴翡翠的繁殖期在印度为1月至9月，斯里兰卡为1月至5月及8月至9月，尼科巴群岛和菲律宾为4月，缅甸为2月至4月，马来西亚为3月和4月，新加坡为5月至6月，爪哇为1月至2月。它们是单配制的，会积极维护领地，对抗同种和其他大型鸟类，如白腹海雕和秃鹳。巢穴通常在河岸、腐朽树干、地面或树栖白蚁丘中挖掘，深度可达1米，直径约23厘米，高13厘米。巢穴可能在连续季节中重复使用。一窝产卵2至5枚，有时会在同一巢穴中产下第二窝或替代卵。","identification":"鹳嘴翡翠与其他翠鸟的区别在于其巨大的红色喙和独特的上背亮棕黄色环带。不同亚种间在颜色和大小上存在差异，如P. c. gigantea亚种的头部、颈部和下部为白色。需与其他相似翠鸟种类进行区分，尤其是通过喙的大小和颜色，以及头部和下部的颜色差异。","protection":"IUCN：LC（无危）；在中国属于国家二级保护动物。","distribution":"鹳嘴翡翠广泛分布于东洋界，从印度次大陆到东南亚，包括印度、斯里兰卡、马来半岛、苏门答腊、婆罗洲、爪哇、菲律宾等地。在中国，主要分布在华南地区。","other":"鹳嘴翡翠的分布范围可能正在缩小，因为在龙目岛近期没有记录，且在印度古吉拉特邦，即使在保护区，该物种的数量已接近灭绝，可能是由于生态系统退化、淤积、过度捕鱼和检查坝建设的影响。"},{"name":"大嘴翡翠","english_name":"Great-billed Kingfisher","scientific_name":"Pelargopsis melanorhyncha","overview":"大嘴翡翠（英文名：Great-billed Kingfisher，学名：Pelargopsis melanorhyncha），是佛法僧目翠鸟科鹳嘴翡翠属的鸟类。体型庞大，以奶油白色头部、颈部、翕、尾部和下体为显著特征，拥有粗长的黑色喙，喙基部带有一小红斑。分布于印尼苏拉威西岛及其周边岛屿。","appearance":"大嘴翡翠身长 35 厘米，体重介于184至203克之间。成鸟头部、颈部、翕、尾部和下体呈现奶油白色，下腹部和尾巴带有浅黄色或黄色。眼先黑色，前额、颧、脸颊的羽毛有黑色斑点。背部、肩、翅膀和尾部具暗绿色和深褐色。尾部和体侧显示树荫绿色。尾巴边缘的深棕色有白色条纹。嘴黑色，嘴基有一个小红斑。虹膜为深褐色，腿为红棕色。嘴粗长似凿，基部较宽，嘴峰直，峰脊圆，两侧无鼻沟；翼圆，第1片初级飞羽与第7片初级飞羽等长或稍短，第2、3、4片几乎等长；初级飞羽基部具白色斑；尾圆形。幼鸟的胸部和颈背羽毛边缘有暗棕色细边。","call":"发出响亮的吠声“kak-kak-kak”或重复的“ke-kak”，也会发出一系列的犬吠声。","habits":"大嘴翡翠非常依赖水生环境，常栖息于河岸近水的地方，如河流、河口、海湾、红树林、海岸峭壁和繁茂的灌木丛。一般单独或成对出现，常在高处的树枝上停留。主要食螃蟹和小龙虾，通过在枝头观察水面，然后俯冲捕捉猎物。","breeding":"在9月进入繁殖期，具体繁殖细节不详。","identification":"与其他翠鸟相比，大嘴翡翠具有更为庞大的体型和独特的色彩搭配，尤其是其巨大的喙和奶油白色的头部。不同亚种间，喙的颜色从全红到全黑不等。","protection":"IUCN：LC（无危）","distribution":"主要分布于苏拉威西岛及其周边的群岛，包括Sulawesi、Bangka、Lembeh、Manadotua、Dodepo、Muna、Butung、Labuandata和Togian Islands。在Banggai Islands、Sula Islands的Taliabu、Seho、Mangole和Sanana也有发现。","other":"在Dumoga-Bone国家公园、Lore Lindu国家公园和Tangkoko DuaSudara自然保护区有其分布记录。"},{"name":"褐翅翡翠","english_name":"Brown-winged Kingfisher","scientific_name":"Pelargopsis amauroptera","overview":"褐翅翡翠（英文名：Brown-winged Kingfisher，学名：Pelargopsis amauroptera），是佛法僧目翠鸟科鹳嘴翡翠属的鸟类。以其橙色头部和下体、深棕色翅膀和背部、以及亮蓝色臀部而著称。分布于印度东部至泰国西部海岸线，主要栖息于红树林、河口和咸水海湾。","appearance":"褐翅翡翠身长35-37厘米，头部、颈部、上翕和下体为橙色，额头中央羽毛略暗，眼先暗橙色。下翕、肩、翅膀、尾部及以上体呈深棕色，背部和尾巴显亮蓝色。鸟喙强健，暗红色，虹膜深棕色，腿大红，爪尖黑色。嘴粗长似凿，翼圆，第1片初级飞羽与第7片初级飞羽等长或稍短，第2、3、4片几乎等长；初级飞羽基部具白色斑；尾圆形。","call":"发出刺耳的、咯咯的重复叫声“chak-chak-chak-chak-chak”，也有短暂的下降音阶的哨声，如“tree, treew-treew”。","habits":"褐翅翡翠几乎完全沿沿海线生活，偏好红树林、泥滩、河口和咸水海湾环境。主要以螃蟹和鱼为食，常在低洼的泥地捕捉猎物。飞行时动作看似缓慢，实则在低空时双翼稳定有力，上升时速度加快。通常单独或成对狩猎。","breeding":"繁殖季节在印度通常为3月和4月。营巢于土崖壁或河流堤坝上的隧道式洞穴，巢深可达20至60厘米，入口高约10厘米，宽20厘米。雌鸟产3或4枚卵，孵化时间未详。","identification":"与其他大型翠鸟相比，褐翅翡翠具有独特的暗棕色翅膀，亮蓝绿色臀部在飞行中最为明显。与鹳嘴翡翠的区别在于背部、翅膀和尾巴的颜色为棕色而非蓝色。","protection":"IUCN：NT（近危）","distribution":"分布于印度东部至泰国西部海岸线，包括孟加拉国、印度（尤其是Sundarbans地区）、马来西亚、缅甸和泰国。"},{"name":"赤翡翠","english_name":"Ruddy Kingfisher","scientific_name":"Halcyon coromanda","overview":"赤翡翠（英文名：Ruddy Kingfisher，学名：Halcyon coromanda），是佛法僧目翠鸟科翡翠属的鸟类。中等体型的树栖翠鸟，广泛分布在东亚和东南亚地区。以深橙色的羽毛和鲜红的大喙著称，偏好栖息于浓密森林中的隐蔽水道。繁殖期间会发出响亮的下降颤音，而在越冬地则保持沉默。","appearance":"成年赤翡翠长约25-27厘米，体重介于60-92克。上体呈锈红色，略带淡紫色光泽，背部和臀部为鲜明的天蓝色。下体为较浅的锈红色。喙部为红色或橙红色，虹膜为深棕色，眼周皮肤红色，腿和脚为鲜红色。幼鸟颜色较暗淡，胸部有灰暗的斑点。不同亚种在大小和色彩上有差异，如major亚种体型较大，颜色较淡；bangsi亚种颜色较深，天蓝色臀部较小；minor亚种体型最小，颜色最深；linae亚种颜色更深；mizorhina亚种为深锈红色，带有明亮的紫罗兰色光泽。","call":"在繁殖地，赤翡翠会发出响亮的下降颤音，而在越冬地则保持沉默。","habits":"赤翡翠广泛分布于多种环境，从海平面到海拔1800米，包括沼泽森林、红树林、林间溪流和湖泊、湿地及平原。它们独居或成对生活，领地意识强，常因领土争端而发出吵闹的叫声。赤翡翠主要在夜间迁徙，迁徙时经过森林和近海岛屿。食物以鱼、甲壳类和大昆虫为主，但在水源较少的地区，也会捕食蛙类和其他两栖动物。","breeding":"赤翡翠在地面或河岸挖掘洞穴筑巢，也会利用离地面3米以上的树洞或白蚁丘作为巢址。巢穴入口直径约5厘米，隧道长度45-100厘米，末端为宽15厘米、高12厘米的巢室。每窝产卵4-6枚，双亲轮流孵卵，仅雌鸟在夜间孵化，双方共同喂养幼鸟。","identification":"赤翡翠与其它翠鸟相比，具有独特的天蓝色臀部和鲜红色的喙。不同亚种在颜色深浅和大小上有所区别。","protection":"IUCN：LC（无危）","distribution":"分布于远东地区和澳大利亚-新西兰生物地理区，以及亚洲东部。具体包括南韩、日本北部至菲律宾南部，向西延伸至中国和印度。迁徙路线涉及中国东部、琉球群岛、台湾，越冬地在苏拉威西岛、菲律宾、泰国南部、苏门答腊和爪哇等地。","other":"赤翡翠在某些地区被视为稀有或不常见的物种，这可能与其羞涩的生活习性有关。在一些自然保护区中被观察到，如不丹的Manas野生动物保护区、越南的Cuc Phuong国家公园、苏拉威西的Tangkoko DuaSudara自然保护区和Dumoga-Bone国家公园，以及菲律宾的Rajah Sikatuna国家公园。"},{"name":"白胸翡翠","english_name":"White-throated Kingfisher","scientific_name":"Halcyon smyrnensis","overview":"白胸翡翠（英文名：White-throated Kingfisher，学名：Halcyon smyrnensis），是佛法僧目翠鸟科翡翠属的鸟类。大型树栖翠鸟，广泛分布于亚洲南部和西部，从埃及东部至中国、印度次大陆，乃至印尼。其特征为拥有明亮的蓝色背部、翅膀和尾巴，头、肩、侧翼和下腹为栗色，喉咙和胸部为醒目的白色。这种翠鸟在平原地带和海拔高达1500米的地方都能找到它们的身影，偏好开放地带，如稻田、城市花园、鱼塘和海滩。","appearance":"成年白胸翡翠长约27至28厘米，雄鸟和雌鸟相似，具有鲜明的色彩对比：头部、肩膀、侧翼和下腹为深栗色，背部、翅膀和尾部呈鲜艳的蓝色。白色的喉咙和胸部尤为突出。嘴和腿均为鲜红色。飞行时可见蓝色和黑色翅膀上的大片白色斑块。幼鸟的色泽较暗淡，缺乏成鸟的鲜艳色彩。","call":"早晨时，白胸翡翠会发出响亮的颤音，如同猛禽般的下降式鸣叫，通常在飞行中。此外，还有尖锐的‘chake ake ake-ake ake-ake’声作为接触报警，以及在搜寻猎物时的短促‘chik’声。","habits":"白胸翡翠栖息于各种开阔环境，如平原、河流、池塘、海滩和城市花园，常在电线杆、树梢或围栏上栖息。它们以昆虫、小型脊椎动物、鱼类、两栖动物和小型鸟类为食，表现出强烈的肉食性。白胸翡翠在夜间会被灯光吸引，特别是在季风季节，这表明它们可能有部分迁徙习性。","breeding":"繁殖期在印度为1月至8月，在伊拉克为4月至5月。它们在土崖或河堤上用嘴挖掘隧道作为巢穴，直接在巢穴地面产下4至7枚纯白色的近圆形卵，直径接近30毫米。双亲共同孵化和喂养幼鸟，主要以昆虫为食。","identification":"白胸翡翠与其它翠鸟的区别在于其独特的蓝、白、栗色组合。幼鸟与成鸟相比，颜色较为暗淡，胸部带有细小的暗色鳞片状图案。与近缘物种的区别在于体型、色彩和分布区域。","protection":"IUCN：LC（无危）。在中国，被列为国家二级重点保护野生动物（2021.02.05）。","distribution":"分布于亚洲南部和西部，包括中东地区。在印度、中国、印尼等地广泛存在，从平原到海拔高达1500米的山区都有其踪迹。在埃及、以色列、伊拉克、巴基斯坦、斯里兰卡、马来西亚、泰国和苏门答腊等地也有记录。","other":"白胸翡翠能够适应多种生境，如农田和低地油棕榈种植园，这使得其分布范围得以扩大。历史上，曾因美丽的羽毛而遭受猎杀，用于装饰帽子。现在是印度西孟加拉邦的州鸟。"},{"name":"爪哇翡翠","english_name":"Javan Kingfisher","scientific_name":"Halcyon cyanoventris","overview":"爪哇翡翠（英文名：Javan Kingfisher，学名：Halcyon cyanoventris），是佛法僧目翠鸟科翡翠属的鸟类。中型翠鸟，仅分布在印尼的爪哇岛和巴厘岛。其显著特征包括大型红唇般的喙和多彩的羽毛，偏好栖息于低地和山脚地带的各种生境。","appearance":"成年爪哇翡翠体长约27厘米，重约93克，两性相似。头部呈深棕色，颈部有蓝紫色羽毛，下颌、喉部、领部和胸部为深栗色，下巴浅棕色，喉咙和颈侧带黑色条纹。翕、背、肩、尾及翅膀为蓝紫色，主飞羽、次级飞羽和翼角显现出明亮的绿松石蓝色，翼尖有白色斑点。嘴鲜红，虹膜深褐，眼周红色，腿脚暗红。幼鸟色彩较暗，喉咙白色或淡黄，喙橙棕色，缺乏成鸟的鲜艳色彩。","call":"发出响亮、穿透力强的尖叫，常连续鸣叫，音似‘tjie-rie-rie-rie-rie’。","habits":"爪哇翡翠广泛分布于低地和山脚的各种环境，包括稻田、沼泽、红树林、鱼塘、森林边缘、公园和城市花园，但不常见于纯城市环境。以昆虫为主食，也会捕食鱼类、甲壳类、幼虫和青蛙。活动范围从海平面到海拔1500米。","breeding":"繁殖季节从2月至9月，期间雌鸟在土崖壁或河堤挖掘的隧道中产卵3至5枚，卵圆形，白色。巢穴深度可达60厘米，宽度20厘米，高度10厘米。","identification":"通过其独特的大型红喙、蓝紫色身体和绿松石蓝色翅膀及翼尖的白色斑点与其它翠鸟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于爪哇岛和巴厘岛，活动范围广泛，从海平面至海拔1500米。","other":"爪哇翡翠在当地被称为‘cekakak jawa’，模仿其叫声命名。"},{"name":"栗背翡翠","english_name":"Chocolate-backed Kingfisher","scientific_name":"Halcyon badia","overview":"栗背翡翠（英文名：Chocolate-backed Kingfisher，学名：Halcyon badia），是佛法僧目翠鸟科翡翠属的鸟类。典型的森林翠鸟，最显著的特征是头部和背部的深栗色，以及腹部的纯白色。分布于非洲西部的热带雨林，自塞拉利昂至加纳，南至刚果民主共和国中部。","appearance":"栗背翡翠成鸟头部和背部呈深栗色，尾部上半部分黑色，中间部分为明亮的天蓝色，末端深色。覆翼暗色，嘴红色或棕红色，虹膜深褐色，眼周有红色环。腿红紫色。幼鸟胸部有小羚羊皮色斑纹，尾部有小黑点，蓝色面积较少。喙粗长似凿，翼圆，初级飞羽基部有白色斑，尾圆形。","call":"发出一系列10个以上的哨声，音调先升后突然下降，类似'pew pew pew PEW PEW PEW pew pew'。","habits":"栖息于海拔1400米以下的茂密热带雨林和河岸近水地带。单独或成对活动，以昆虫为主食，如草蜢、甲虫、蜻蜓、蚂蚁、蜘蛛，也会捕食小型脊椎动物。在树上静静等待，偶尔飞下捕食地面上的猎物或空中飞行的昆虫。","breeding":"在土崖壁或河流堤坝上挖掘隧道式洞穴为巢，深度可达60厘米，宽20厘米，高10厘米，椭圆形，内部不铺设衬垫。有时在树干上钻洞为巢，巢穴离地面4-5米，周围有藤蔓。","identification":"与同属翠鸟相比，栗背翡翠的血红色嘴、巧克力棕色上身、纯白下身和明亮蓝色翼斑及尾部非常独特。","protection":"IUCN状态未知。","distribution":"分布于非洲西部，从塞拉利昂向东至加纳，南尼日利亚至苏丹西部南部，乌干达和刚果民主共和国中部，也见于Bioko岛。"},{"name":"蓝翡翠","english_name":"Black-capped Kingfisher","scientific_name":"Halcyon pileata","overview":"蓝翡翠（英文名：Black-capped Kingfisher，学名：Halcyon pileata），是佛法僧目翠鸟科翡翠属的鸟类。俗名: 黑顶翠鸟、黑帽鱼狗、蓝翠毛、蓝袍鱼狗、蓝鱼狗、秦椒嘴、喜鹊翠、鱼腥，体型较大的树栖翠鸟，体长28-31.5厘米，广泛分布于热带亚洲，从印度东部至中国、韩国及东南亚。其显著特征为黑顶白喉，紫蓝背翅，红喙红足，常栖息于沿海湿地及红树林，偶尔深入内陆。","appearance":"蓝翡翠体长约28厘米，具独特的羽色：头顶墨黑，颈圈洁白，背部紫蓝，腹部橙红；喙与腿皆呈鲜红色。飞行时，可见翼下的白色斑点。幼鸟颜色较暗淡，眼前方有小块锈褐色斑点，胸部有灰暗的鳞片状纹。成年鸟性别相似。","call":"蓝翡翠发出连续的尖锐‘ki-ki-ki-ki-ki’叫声，音调略高于白胸翡翠。","habits":"蓝翡翠栖息于多种湿润环境，包括红树林、湖泊边缘和沼泽地带。在中国，常见于大河流岸、河口及红树林中，偏好在河上树枝栖息。以鱼类为主食，也捕食甲壳类和大型昆虫。飞行迅速直接，短圆的翅膀快速振动。","breeding":"繁殖季节为夏季，筑巢于土堤或河岸的隧道中，洞深50-100厘米，直径9-11厘米，末端形成直径约35厘米、高9-15厘米的巢室。一般单窝产卵4-5枚，圆而白，无孵化和育雏期的详细信息。已知最长寿命为八年。","identification":"蓝翡翠与白胸翡翠相比，生性更加胆怯且罕见，其黑顶白喉的特征明显，易于区分。幼鸟与成鸟的区别在于色彩较暗和胸部的灰暗鳞片状纹。","protection":"IUCN：VU（易危）","distribution":"繁殖于东亚，包括中国（从辽宁至甘肃东部，南至海南）、朝鲜半岛、印度东北部至缅甸和印度支那北部；冬季南迁至印度、斯里兰卡、缅甸、印度支那、马来半岛、安达曼和尼科巴群岛、大巽他群岛、苏拉威西岛及菲律宾南部。在中国，夏季分布广泛，遍布东部全境。","other":"蓝翡翠的羽毛曾因其艳丽被用于装饰品和扇子制作，尤其在中国。"},{"name":"灰头翡翠","english_name":"Grey-headed Kingfisher","scientific_name":"Halcyon leucocephala","overview":"灰头翡翠（英文名：Grey-headed Kingfisher，学名：Halcyon leucocephala），是佛法僧目翠鸟科翡翠属的鸟类。以其独特的栗色腹部、蓝宝石般的蓝色尾羽和飞行羽、灰烬色头部和胸脯、鲜红的喙著称。分布于非洲热带和亚热带地区以及阿拉伯半岛，栖息于多种生境，包括干湿林地、灌木丛和耕地区域。","appearance":"灰头翡翠体长约22厘米，翼展32-34厘米，雄鸟平均体重约42克，雌鸟约43克。其特征为红嘴红脚，头部和胸部呈灰或棕色调，臀部、尾羽及翅膀为钴蓝或亮紫，腹部和翅膀下方为红色或栗色。雌雄相似，雌鸟略重。存在五个亚种，差异在于头部蓝色及翅膀灰色的细微变化。喙粗长，翼圆，尾圆形。","call":"发出尖锐的颤音‘t-t-t-t-t-t-t’，声音快速、粗糙且连续，此外还会发出一连串急促的‘tchi-tchi-tchi-tchi-tchi’声和断续的快速鸣叫。","habits":"偏好栖息于干湿林地，尤其是河岸林，亦可见于灌木丛、草地、公园和耕地区域，海拔高度可达2400米。以昆虫为主食，如蝗虫和其他节肢动物，偶尔捕食小型脊椎动物，如鱼、蛇、蜥蜴以及小型哺乳动物。","breeding":"繁殖期因地区而异，筑巢于河岸或堤坝的土崖壁上，挖掘隧道式巢穴，深度可达1米。雌鸟产卵2-6枚，平均4枚，孵化期未见记录，幼鸟由双亲共同喂养，离巢时间约为21天。","identification":"与同属物种如褐兜翠鸟相比，具有红色而非红黑相间的喙，与林地翠鸟的区别在于后者缺乏栗色腹部，背部覆盖更多青色羽毛。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲，从塞内加尔东至埃塞俄比亚，南至南非，北至阿拉伯半岛。","other":"灰头翡翠具有复杂的迁徙模式，某些群体为留鸟，而高纬度地区的群体则表现出明确的迁徙行为。"},{"name":"褐头翡翠","english_name":"Brown-hooded Kingfisher","scientific_name":"Halcyon albiventris","overview":"褐头翡翠（英文名：Brown-hooded Kingfisher，学名：Halcyon albiventris），是佛法僧目翠鸟科翡翠属的鸟类。具有独特的棕色头部和黑色与青绿色的翅膀。广泛分布在东非、东南非和中西非的稀树草原地带，常见于各种生境，包括郊区。","appearance":"成年褐头翡翠长约22厘米，雄鸟头部至颈部具黑色条纹的褐色羽毛，雌鸟的头部条纹颜色更浅，背部偏绿色调。翕和披风黑色，喉咙、下体至尾巴白色，腹部和两侧有明显的奶油色。腰部、尾巴呈蓝色，嘴红，尖端有小黑斑。幼鸟羽毛较暗，类似雌鸟。嘴粗长似凿，尾圆形。","call":"鸣叫声为下降的‘kieu ki-ki-ki-ki’，弱颤音‘tiiiu’或‘ki-ti-ti-ti’，有时重复多达20次，还有拉长音‘pi-ee-ee, pi-ee-ee’和尖锐的‘cheerit’报警声。","habits":"栖息于森林、河岸、风景区、花园、椰子种植园和芒果树林等，适应力强，能在郊区生存。主要以昆虫为食，如蟋蟀、蜘蛛、蝎子、蜗牛，也会捕食小鱼、小蛇和蜥蜴。","breeding":"繁殖期主要在9月至12月，营巢于崖壁或河流堤坝的隧道洞穴中，卵直接产在洞穴地上，每窝产4至5枚卵，孵化期约14天。","identification":"与灰头翡翠的区别在于头部条纹和胸腹颜色的不同，褐头翡翠的胸部和腹部有明显的奶油色条纹。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东部、南部和中西部，包括东非、东南非和中西非的稀树草原地带。"},{"name":"斑翡翠","english_name":"Striped Kingfisher","scientific_name":"Halcyon chelicuti","overview":"斑翡翠（英文名：Striped Kingfisher，学名：Halcyon chelicuti），是佛法僧目翠鸟科翡翠属的鸟类。生活在非洲干燥林地的小型翠鸟，以其粉蓝色的尾羽和飞行羽毛、奶油色颈圈、深色眼纹和斑驳的棕色头冠而著称。分布广泛，常见于公园般的稀树草原和林地，偏好较为干旱的荆棘林地。体长约17厘米，雄鸟重30-41克，雌鸟重37-50克。","appearance":"斑翡翠具有精致的外观，雄鸟标本的前额上方有一条白色线，头部顶部有厚重的棕色条纹，黑色眼带，奶油色颈圈，深棕色背部，蓝色背部和臀部，翅膀上的蓝色部分，绿色的尾巴；胸部有条纹，两胁有厚重的条纹；翅膀下方有宽阔的黑色亚端带；喙呈深色，下颌基部红色；虹膜深褐色；腿和脚呈暗红色。雌鸟斑纹较少，头冠颜色更偏棕色，翅膀下方无黑色亚端带。幼鸟翼和尾仅有轻微的蓝色，两胁和腹部呈淡黄色，胸部有深色横纹。","call":"斑翡翠发出响亮的高音‘keep-kirrrrr’或‘pee-hee’叫声，持续约1.2秒，可重复多达10次，东部个体的叫声比西部或南部的叫声少双音节；长颤音警告巢中的雏鸟有危险，而在求偶喂食或巢穴交接期间则会发出较轻柔的版本；在攻击捕食者或入侵者进入领地时，会发出尖锐的嘎吱声。","habits":"斑翡翠栖息于林地、灌木丛，避免密集耕种区，不总是依赖水生环境。它们生活在从海平面到2300米的高度，偏好公园般的稀树草原和林地，尤其是较为干旱的荆棘林地。以昆虫为主食，如蚱蜢、甲虫、幼虫、蝴蝶、蛾类和毛虫、螳螂、蝉、白蚁；偶尔也会捕食小型蜥蜴、蛇和啮齿动物。通常从树梢观察猎物，然后俯冲至地面捕食，再返回栖木；小猎物直接吞食，大猎物会在栖木上敲打后再吞食。","breeding":"斑翡翠在6月至10月间繁殖，通常在旧的啄木鸟或拟啄木鸟巢穴中筑巢，巢位于树上1-10米高处；巢入口直径约5厘米，离入口约20厘米处产卵。每窝产3-5枚卵，在热带地区，平均产2-6枚卵（南非平均3.4枚）；白天由两性共同孵化，夜间仅由雌鸟孵化；没有关于孵化和离巢期的信息；在第一窝幼鸟离巢一个月后，会在同一个或不同的巢中产下第二窝。","identification":"斑翡翠与同属其他物种的区别在于其特有的粉蓝色尾羽和飞行羽毛、奶油色颈圈、深色眼纹和斑驳的棕色头冠。北部亚种H. c. eremogiton的头冠和背部呈灰棕色，下体几乎无条纹。","protection":"IUCN：LC（无危）","distribution":"斑翡翠广泛分布在非洲，除了刚果河附近的密林、非洲之角、纳米布沙漠和南非的部分地区。它偏好林地、荆棘灌木丛（荆棘林地）、干燥的灌木丛和开阔的萨瓦纳草原，但避开过度耕种的土地。"},{"name":"蓝胸翡翠","english_name":"Blue-breasted Kingfisher","scientific_name":"Halcyon malimbica","overview":"蓝胸翡翠（英文名：Blue-breasted Kingfisher，学名：Halcyon malimbica），是佛法僧目翠鸟科翡翠属的鸟类。广泛分布于赤道非洲的雨林、红树林和繁茂的热带草原，高度可达1800米。该物种以蓝黑相间的羽毛、白色的喉部和独特的蓝胸带而著称，具有红色的上喙和黑色的下喙。","appearance":"蓝胸翡翠长约25厘米，雄鸟体重64-94克，雌鸟70-93克。成鸟头部为灰色，眼上有一白线，眼周有黑色三角形标记，颈部、脸颊、颈侧和背部呈蓝色，肩部和翼覆羽为黑色，背部和尾羽为亮蓝色，胸部为蓝色，腹部为白色，翅膀底部为白色，尾巴基部为黑色，上喙为红色，腿为暗红色。幼鸟颜色较为暗淡，顶冠蓝绿色，腹部为浅黄色。","call":"叫声为一连串的哨声，起始为短促而急促，随后逐渐延长和加强，先是加速上升，之后减速下降，持续时间约为3-3.5秒。","habits":"蓝胸翡翠栖息于各种森林环境，包括次生林、红树林、热带雨林和热带草原。它们主要捕食大型昆虫、无脊椎动物、鱼类、两栖动物，也会食用油棕榈果实。狩猎时，它们会在树荫下静静地寻找食物。","breeding":"繁殖期随地区而异，筑巢于树干上的白蚁丘中，高6-10米。每窝产2-4枚光滑的白色卵，大小约为28.5-31.1毫米 x 25.3-29.6毫米。","identification":"与非洲林翡翠相比，蓝胸翡翠体型更大，背部有黑色斑块，胸部蓝色，眼后有黑色线条，偏好更密集的栖息地。","protection":"IUCN：LC（无危）","distribution":"广泛分布在非洲的中部和西部地区，从海平面至海拔约1800米的森林地带。","other":"蓝胸翡翠在某些地区可能因栖息地丧失而减少，但在已砍伐的森林中似乎并不罕见。"},{"name":"非洲林翡翠","english_name":"Woodland Kingfisher","scientific_name":"Halcyon senegalensis","overview":"非洲林翡翠（英文名：Woodland Kingfisher，学名：Halcyon senegalensis），是佛法僧目翠鸟科翡翠属的鸟类。广泛分布在非洲的中型翠鸟。以电光蓝背部和双色喙（上红下黑）著称，常见于干林地带和河岸森林边缘。","appearance":"非洲林翡翠长约23厘米，体重41-81克。成鸟拥有灰蓝冠，黑色眼纹，蓝色后颈、背、上体和尾羽，翅膀基部蓝色，飞羽黑色，下体灰白，喙上红下黑，腿脚灰黑。幼鸟色泽较淡，喙黑色。与蓝胸翡翠的区别在于背部蓝色，与红树林翡翠的区别在于下颌黑色。","call":"其鸣叫特征为尖锐的‘tuuui’声，随后是持续2-3秒的快速颤音‘trrrrrrrrrr’，通常重复10次，间隔5-10秒，有时连续发出‘tirrrrr-tirrrrr-tirrrrr-tirrrrr’的声音。","habits":"偏好干林、河岸森林、人类居住区附近的树木，以及开阔的草地和公园，高度从海平面到1500米，偶尔可达2000米。昆虫为主要食物，如蚱蜢、甲虫、蜻蜓、蝉、蟑螂、螳螂、蛾、蚂蚁、白蚁等，偶尔捕食小型脊椎动物。白天多在半阴处守候，捕食时从高处俯冲。","breeding":"繁殖期在3-9月，可能在10月和12月也有繁殖，在刚果、卢旺达、赞比亚等地有所不同。筑巢于树洞中，通常使用旧巢，如啄木鸟或八哥的巢，偶尔自挖巢穴。每窝产卵2-4枚，孵化期13-14天，幼鸟由双亲照料，离巢后5周内仍与父母在一起。","identification":"与非洲其他类似翠鸟的区别在于双色喙，除蓝胸翡翠外，后者体型更大，有完整的淡蓝色胸带，偏好低地雨林。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲热带区域，南至南非，北至苏丹，西至尼日利亚，东至埃塞俄比亚。在南非，特别是在河流森林中极为常见。","other":"迁徙模式随地理位置而异，赤道附近种群相对定居，而更北或更南的种群具有迁徙性。"},{"name":"红树林翡翠","english_name":"Mangrove Kingfisher","scientific_name":"Halcyon senegaloides","overview":"红树林翡翠（英文名：Mangrove Kingfisher，学名：Halcyon senegaloides），是佛法僧目翠鸟科翡翠属的鸟类。以鲜红色的大喙和淡灰色头部为显著特征，主要栖息于非洲东部沿海的红树林、海岸森林、林地和灌木丛中。分布范围从索马里南部至南非东海岸。","appearance":"红树林翡翠体长约22厘米，重57-66克。雄雌相似，具灰棕色顶冠，黑色眼先，灰棕色脸颊和颈侧，蓝上体和尾羽，黑翼带蓝基部，下体灰白而无杂色。喙全红，虹膜深棕，腿脚灰棕。幼鸟较暗淡，腹部带黄色，喙呈黑褐色。","call":"发出嘈杂的‘tchi’系列音符，加速至轻微下降的颤音，持续约6-7秒；在巢边发出‘cling-cling-cling-cling...’声。","habits":"栖息于红树林、沿海森林、河流两岸的林地和开阔地带，偶尔深入内陆。以蟹、虾、鱼、蜥蜴和昆虫为食，常静立于树上，发现猎物后迅速飞扑。在繁殖季节，会离开海岸，向内陆移动。","breeding":"繁殖期随纬度变化，从10月至翌年4月。在土崖或河堤挖掘隧道巢穴，深约60厘米，卵产于洞底，纯白色。有时在树干上筑巢。","identification":"与非洲林翡翠相似，但可通过灰头和全红喙区分。幼鸟两者非常相似，但红树林翡翠幼鸟通常有红色喙尖。","protection":"IUCN：LC（无危）","distribution":"分布于非洲东海岸，从索马里南部沿岸至南非东海岸，包括近海岛屿。内陆记录显示其分布可达150公里深处，如索马里的朱巴河和莫桑比克的赞比西河至莫佩亚。","other":"曾有记录在南非内陆克鲁格国家公园出现，最近在赞比亚东部有成鸟记录。"},{"name":"褐胸翡翠","english_name":"Brown-breasted Kingfisher","scientific_name":"Halcyon gularis","overview":"褐胸翡翠（英文名：Brown-breasted Kingfisher，学名：Halcyon gularis），是佛法僧目翠鸟科翡翠属的鸟类。为菲律宾特有种，广泛分布于该国各岛屿。此前曾被视为白胸翡翠的一个亚种，但在2014年被IUCN红名单和BirdLife International认定为独立物种，国际鸟类学大会（IOC）于2022年正式接受这一分类。","appearance":"成年褐胸翡翠体型中大，全长约26.5至28厘米，体重介于75至108克（雄鸟）和79至101克（雌鸟）。头部、面部两侧、背部、胸部、腹部及翅膀下覆羽呈深巧克力色，颜色在头部和颈部较暗；背部、尾上覆羽及次级飞羽为鲜艳的蓝绿色，以次级飞羽和背部最为亮丽。肩部有黑色斑块，翼尖亦为黑色；下巴和喉咙白色，尾巴下方黑色。喙、眼圈、腿脚橙红色，眼睛棕色。幼鸟颜色较为暗淡。与近缘种白喉翡翠的主要区别在于下体颜色为巧克力色而非橙色。","call":"主要鸣声为响亮、下降且略带口吃的哨音，连续发出类似“pe-pe-pe-pe-pe-pe-pe”的声音，持续约1秒，每间隔约2秒重复一次，通常从栖息处发出。","habits":"褐胸翡翠偏好低地和丘陵地带的开阔乡村和森林边缘环境，常在距地面或水面5至10米高的树枝或电话线上栖息，然后俯冲到地面或头朝下潜入水中捕食。其饮食习惯尚未详尽了解，但据观察，它能捕获年轻果蝠，推测其食性与白喉翡翠相似，广泛而杂食。","breeding":"具体繁殖信息未详述。","identification":"与白胸翡翠的区别在于，褐胸翡翠的下体颜色为巧克力色而非橙色，且其叫声独特。","protection":"IUCN：LC（无危）","distribution":"广泛分布于菲律宾群岛，除了巴拉望群岛和苏禄群岛。具体岛屿包括Alabat、Basilan、Biliran、Bohol、Buad、Burias、Calagna-an、Caluya、Catanduanes、Cebu、Dinagat、Guimaras、Leyte、Libagao、Lubang、Luzon、Maestre de Campo、Marinduque、Masbate、Mindanao、Mindoro、Negros、Panaon、Panay、Polillo、Samar、Semirara、Siargao、Sibay、Sibuyan、Siquijor、Tablas、Ticao和Verde。","other":"无"},{"name":"蓝黑翡翠","english_name":"Blue-black Kingfisher","scientific_name":"Todiramphus nigrocyaneus","overview":"蓝黑翡翠（英文名：Blue-black Kingfisher，学名：Todiramphus nigrocyaneus），是佛法僧目翠鸟科林翡翠属的鸟类。中等体型的翠鸟，主要栖息于红树林和低地森林中的溪流旁。其特征为黑色的脸部、蓝色的冠羽和明亮的白色喉部。分布于新几内亚及邻近的Salawati、Batanta和Yapen等岛屿。色彩斑斓，雄鸟的下体颜色因地理位置而异，有的呈现赤褐色或深色腹部，雌鸟腹部为白色。","appearance":"蓝黑翡翠身长约为23厘米，雄鸟体重51至54克，雌鸟体重55至57克。成年雄鸟的前额和头顶为蓝紫色，眼眉延长至脖子处为较浅的蓝色，脸部、颧骨、面颊、颈部和胸部两侧为黑色，肩胛和披羽为黑色带蓝紫色调，尾巴黑色。下颏和喉咙为白色，胸部有一大片蓝色区域，胸腹间有一条白色纹，腹部蓝色。两翼、大腿、肛门区域和尾巴为黑色。嘴、眼为黑色，虹膜深棕色，腿脚灰黑色。雌鸟腹部为白色，接胸部处。喙粗长似凿，基部较宽，嘴峰直，两侧无鼻沟，翼圆，第1片初级飞羽与第7片等长或稍短，第2、3、4片近等长，初级飞羽基部具白色斑，尾圆形。","call":"鸣声包括两个上升的音符和短暂的下降颤音，持续3秒；雌鸟的叫声为重复的尖锐‘cheeez’。","habits":"蓝黑翡翠通常栖息于茂密的森林和河岸近水的地方，常见于低地森林、河流、桉树林、沼泽、灌木丛及附近小溪，甚至沿海村庄的花园和林地。以肉食为主，常在树叶或泥土中寻找无脊椎动物如蟋蟀、蜘蛛、蜗牛，也捕食小鱼、小蛇和蜥蜴。","breeding":"关于其繁殖行为的记录极少，至今（2008年）其巢穴和卵尚未被描述。鸣声与林地翡翠类似，包括三声尖锐的短节奏，随后是长而有力的颤音。","identification":"与蓝翠鸟相似，但蓝黑翡翠明显更大，具有深色的胸部或胸带。","protection":"IUCN：NT（近危）。全球种群数量估计少于10,000个成熟个体，最大的亚种群不超过1,000个成熟个体。受低地湿地森林砍伐和水质下降的威胁。","distribution":"主要分布在新几内亚和西北部的卫星岛，包括Salawati、Batanta和Yapen。"},{"name":"菲律宾翡翠","english_name":"Winchell's Kingfisher","scientific_name":"Todiramphus winchelli","overview":"菲律宾翡翠（英文名：Rufous-lored Kingfisher，学名：Todiramphus winchelli），是佛法僧目翠鸟科林翡翠属的鸟类。中等体型的翠鸟科鸟类，广泛分布于菲律宾的低地森林中。其显著特征包括深蓝上体、白色下体、独特的红褐色颈圈，以及带有橙色斑点的黑色喙。雌鸟的下体呈现橙黄色调，与雄鸟的白色形成对比。","appearance":"菲律宾翡翠体长约25厘米，雄鸟体重介于60至64克，雌鸟略重，约67至80克。其头部上覆以深蓝色，边缘泛着钴蓝光泽，眼睛前方有醒目的红褐色斑点。背部与翅膀呈现深蓝至黑色，臀部则闪耀着亮丽的天蓝色。雄鸟下体为纯白色，而雌鸟则呈现淡黄橙色。幼鸟的羽毛颜色较为暗淡，胸部和颈圈带有橙色条纹。喙呈黑色，眼色深棕，腿脚灰黑色，足底黄色。","call":"其鸣声为一连串急促的金属音，起始缓慢后加速，随后逐渐减弱，持续约1.5秒，每3至4秒重复一次。亦有长达6至8秒的快速连续鸣叫，首三个音节上升，之后是长达20多个音符的下降音阶，间歇约10秒重复。此外，还有一种单音节的警报声伴随尾羽抖动。","habits":"偏好密集的低地森林，尤其偏爱未受干扰的环境，但也适应重度退化的石灰岩森林，栖息高度可达1000米。通常在树冠层较高处活动，偶尔下至地面捕食。主要以大型昆虫为食，包括蚱蜢、蝉、甲虫幼虫，以及蜘蛛，甚至记录到捕食蚯蚓。捕获较大猎物时，会先将其敲打再吞咽。","breeding":"繁殖季节在春季，雄鸟在五月时睾丸体积增大，表明进入繁殖准备期。关于筑巢、产卵等具体繁殖行为细节尚待更多研究。","identification":"与颈环翠鸟相似，但菲律宾翡翠上体更深蓝，颈部后方有橙色，雄鸟颈圈红褐色，雌鸟下体橙黄色。不同亚种间上体色彩和雌鸟下体颜色有所差异。","protection":"IUCN：VU（易危）","distribution":"分布于菲律宾群岛，从萨马岛和塔布拉斯岛南至棉兰老岛、巴西兰岛和苏禄群岛。在塔布拉斯岛的剩余森林中相对常见，在其他岛屿如锡布延岛、马斯巴特岛、比利兰岛、宿务岛、莱特岛、保和岛、锡基霍尔岛等地也有零星记录。在棉兰老岛东部、苏禄群岛的几个岛屿以及新发现的卡米金岛也有分布。","other":"面临的主要威胁是森林砍伐和非法伐木，尤其是低地森林的破坏，对其生存构成严重挑战。"},{"name":"摩鹿加翡翠","english_name":"Blue-and-white Kingfisher","scientific_name":"Todiramphus diops","overview":"摩鹿加翡翠（英文名：Blue-and-white Kingfisher，学名：Todiramphus diops），是佛法僧目翠鸟科林翡翠属的鸟类。体型娇小，以其明亮的天蓝色上部羽毛和闪耀的白色腹部而著称。分布于印尼北马鲁古群岛，包括摩罗泰岛、Ngelengele、Halmahera、Damar、Ternate、Tidore、Moti、Bacan、Obi和Obilatu等岛屿。","appearance":"成年摩鹿加翡翠身长约19厘米，雄鸟体重41-45克，雌鸟42-65克。雄鸟头部前端至顶点为黑色，其余部分为蓝紫色，前额喙基处有一白色圆形或三角形标记，颈部黑色，带有白色羽毛，拥有显著的白色领环。翕、双翼、前胸和上体蓝紫色，肩胛和背部色彩更为鲜明。尾部呈亮蓝色，下体纯白。雌鸟的颈后两侧为蓝黑色，胸部有蓝紫色宽带。嘴粗长似凿，虹膜深褐色，腿灰黑色。","call":"发出连续的颤音‘tu-tu-tu-ti-ti’和相对高音调的三音符下降哨声，反复鸣叫。","habits":"偏好次生林地和森林边缘，常出现在红树林边缘、花园、轻度森林化耕作地、果园和椰子园，活动海拔从海平面到700米。以昆虫为食，如草蜢，常在开阔地带栖息，有时停在枯木或电线上，森林边缘则多在树木下半部停留。","breeding":"关于繁殖信息尚无具体报道。","identification":"雄鸟与雌鸟的主要区别在于雌鸟缺乏白色领环，且胸部有蓝紫色宽带。与较大的白领翡翠相比，其特征为更大的白色眉纹和翼上的白色斑块。","protection":"IUCN：LC（无危）。在北马鲁古EBA（Endemic Bird Area）范围内广泛分布，尽管在Ternate较为罕见。已适应人类活动和农业环境。","distribution":"分布于印尼北马鲁古群岛，从摩罗泰岛至Obi（印尼摩鹿加群岛北部）。"},{"name":"南摩鹿加翡翠","english_name":"Lazuli Kingfisher","scientific_name":"Todiramphus lazuli","overview":"南摩鹿加翡翠（英文名：Lazuli Kingfisher，学名：Todiramphus lazuli），是佛法僧目翠鸟科林翡翠属的鸟类。以类似青金石的色彩得名。雄鸟头顶至背部呈现明亮的蓝色，而雌鸟的胸部与腹部则呈淡蓝色。广泛分布于印尼的摩鹿加群岛，包括塞拉姆、安汶和哈鲁库等岛屿。生活在低地森林、耕作区及红树林中。","appearance":"成年雄鸟身长约22厘米，头部与帽顶黑色带蓝，眼先处有白色斑点，略高于嘴。雌鸟的后颈两侧蓝紫色，胸部与腹部浅蓝色，下颏与喉咙白色。下体羽毛呈现独特的淡蓝色，与其它翠鸟形成鲜明对比。嘴粗长似凿，尾圆形。","call":"鸣叫声包括一系列快速、高音的“ke-ke-ke”音节，持续6至20秒，速度变化后以刺耳的降调结束。另一种叫声以缓慢、哀怨的‘ki-ki-ki...’开始，逐渐加速变为双音节‘kee-kik’，最后以刺耳的三音节音符结束。","habits":"栖息于低地森林、森林边缘、耕作区和红树林。常见于海拔0至640米的地区，有时高达1100米。主要以昆虫为食，如蚱蜢和甲虫，善于从树冠或开阔地带的枯木或电线上观察猎物。","breeding":"繁殖习性知之甚少，但已知在7月至12月期间，成对在树干上的白蚁巢中筑巢，以喂养幼鸟。幼鸟近期离巢后由双亲喂食。","identification":"与同属的区分，后者具有淡蓝色的冠羽和白色的腹部。此外，与白眉翡翠区别在于后者有白色的颈圈和几乎全白的下体。","protection":"IUCN：LC（无危）。曾被视为易危物种，其分布有限，部分地区数量稀少或缺失，可能受到狩猎威胁。","distribution":"主要分布在印尼的摩鹿加群岛，包括塞拉姆、安汶和哈鲁库。在塞拉姆有15个已知地点，安汶有4个，哈鲁库仅1个。","other":"尽管在某些地区常见，但在人口密集的塞拉姆地区记录很少，安汶岛上罕见，可能已经减少。"},{"name":"林翡翠","english_name":"Forest Kingfisher","scientific_name":"Todiramphus macleayii","overview":"林翡翠（英文名：Forest Kingfisher，学名：Todiramphus macleayii），是佛法僧目翠鸟科林翡翠属的鸟类。属于翠鸟科的树翠鸟亚科。主要特征为蓝白相间，分布于印尼、新几内亚及澳大利亚沿海东部和北部地区。以昆虫、小蛙、蜥蜴等为食。","appearance":"林翡翠长约21.5-25.5厘米，雄鸟重32-43克，雌鸟重29-44克。蓝翼、蓝头、蓝尾，胸腹及颈背白色，眼前方有白色斑点，翼上有明显白色斑块。雌鸟颈后为蓝色而非白色。虹膜深褐，腿脚灰黑。幼鸟色泽稍暗，覆羽羚羊皮色，胸有暗纹，侧腹淡黄，背部灰蓝或黑。","call":"发出尖锐的t-reek声，早晨常鸣，重复规律。","habits":"栖息于热带或亚热带的森林、红树林、沼泽地、桉树林等地。以昆虫、小鱼、蜥蜴、蛇为食，从高处俯冲捕食，而后返回栖木。活动范围广泛，有领地意识。","breeding":"繁殖期在澳大利亚为8月至2月，筑巢于白蚁巢中，深度约23厘米，产卵3-6枚，由双亲及助手共同孵化，孵化期18-21天，雏鸟离巢期27-31天。","identification":"与其它翠鸟相比，林翡翠有明显的白色眼斑和翼斑，雌雄差异在于颈后的颜色。","protection":"IUCN：LC（无危）","distribution":"繁殖于澳大利亚中北部和东部，新几内亚东南部；非繁殖期至印尼摩鹿加群岛东南部和新几内亚南部。","other":"迁徙模式复杂，夏季和冬季有迁徙行为，返回同一领地。"},{"name":"白背翡翠","english_name":"White-mantled Kingfisher","scientific_name":"Todiramphus albonotatus","overview":"白背翡翠（英文名：White-mantled Kingfisher，学名：Todiramphus albonotatus），是佛法僧目翠鸟科林翡翠属的鸟类。别名: 新不列颠翡翠，中等体型的蓝白相间翠鸟。其特征为淡蓝色冠羽、黑色眼罩，身体大部分呈白色，翅膀和尾巴为蓝色。分布于巴布亚新几内亚的新不列颠群岛，偏好低地热带雨林环境。","appearance":"成年白背翡翠长度约为16至18厘米，体重约32克。雄鸟具有白色眉纹，浅蓝色冠羽，黑色眼罩，翅膀和尾巴深蓝色，其余部分白色；喙全黑，下颌基部有时为角质色；虹膜深棕色；腿和脚灰黑色。雌鸟背部和臀部为深蓝色。幼鸟色泽较暗淡，白色部位略带淡褐色，上翼覆羽边缘为淡褐色。","call":"鸣声为快速下降的四音节'kee-ku-ko-ko'或轻快的咯咯颤音'ki-ki-ki-ki-ki'。","habits":"白背翡翠常栖息于茂密的森林和河岸近水处，主要单独或成对活动。它们以大型昆虫如蟋蟀和蚱蜢为食，多在树冠层活动，也会在较低位置停歇，俯冲捕食地面猎物，捕获后返回停歇处，常将昆虫敲打在树枝上后再吞食。","breeding":"白背翡翠在土崖壁或河堤上挖掘隧道式巢穴，深度可达60厘米，宽度20厘米，高度10厘米，卵直接产在巢穴地面，形状近圆形，纯白色，尺寸约29.4×26.2毫米。","identification":"与林翡翠相比，体型略小，背部和臀部颜色不同，眼前方有更明显的白色斑点。与白眉翡翠和太平洋翡翠的当地亚种相比，淡色区域更偏奶油色，整体色调更偏向绿蓝色而非纯蓝色。与白头翡翠相比，体型较小，整体颜色更深。","protection":"IUCN：NT（近危）","distribution":"分布于新不列颠岛（Bismarck Archipelago东南部），属于澳新界的范围。"},{"name":"深蓝翡翠","english_name":"Ultramarine Kingfisher","scientific_name":"Todiramphus leucopygius","overview":"深蓝翡翠（英文名：Ultramarine Kingfisher，学名：Todiramphus leucopygius），是佛法僧目翠鸟科林翡翠属的独特中型蓝色和白色相间的翠鸟。拥有醒目的暗色面具、蓝色冠羽、亮白颈胸及下体、蓝翼背及红下尾。雄鸟具白色臀部。","appearance":"体长约21厘米，雄鸟体重35-52克，雌鸟体重44-61克。雄鸟头部和上体蓝紫色，除白领圈和背部外；下臀淡紫；下体纯白，有鲜明红下尾覆羽；喙黑色；虹膜深褐色；腿足黑色。雌鸟类似雄鸟，但背部和下背为深紫蓝色。幼鸟下体淡黄色，胸和颈有黑色横纹。","call":"声音清脆响亮，快速高音‘kidek-kidek-kidek’或‘kakatakatakata’，以及下降音调‘chew-cho-tew’和安静鼻音‘kee-kowl’。","habits":"栖息于布干维尔岛至所罗门群岛的雨林和岛屿低地，高达2000米。独居或静栖于树上或电线杆上，主要在森林边缘、树木繁茂的花园、自然生长和再生的灌木丛活动。以昆虫和蜘蛛为主食。","breeding":"筑巢于白蚁侵蚀的树干洞穴中。在布干维尔岛，繁殖期为9月至10月。具体繁殖习性细节不明。","identification":"结合广泛的暗色面具和红下尾覆羽是辨识的关键特征。","protection":"IUCN状态未提供。","distribution":"分布于澳新界，自布卡岛至美国佛罗里达群岛和瓜达尔卡纳尔岛（即瓜岛，属于所罗门群岛）（北部至所罗门群岛中部）。","other":"无"},{"name":"栗腹翡翠","english_name":"Vanuatu Kingfisher","scientific_name":"Todiramphus farquhari","overview":"栗腹翡翠（英文名：Vanuatu Kingfisher，学名：Todiramphus farquhari），是佛法僧目翠鸟科林翡翠属的鸟类。仅见于瓦努阿图的Espiritu Santo、Malo和Malakula岛。其上体深蓝色，腹部橙色鲜艳，眼周有白色斑点，头部侧边有黑色宽带，喉部和颈部白色。","appearance":"栗腹翡翠长约21厘米，体重32-42克。雄鸟拥有深蓝色的冠羽、白色的颈环、深蓝色的背部、翅膀和尾巴，喉咙白色，胸部、腹部和下尾覆羽橙色鲜明。喙上部黑色，下部基部淡黄角质色，虹膜深棕色，腿和脚灰黑色。雌鸟的下腹部有白色斑块。幼鸟颜色较暗淡，头部和颈部的白色区域带有红褐色。喙粗长似凿，翼圆，初级飞羽基部有白色斑点，尾圆形。","call":"发出一系列高音调的啾啾声，重复超过一分钟，随着音调升高而速度加快；同时发出啾啾声和尖锐的‘cach-cach’报警声。","habits":"栗腹翡翠主要栖息在岛屿内部的茂密雨林中，尤其在海拔200米以上。它们通常单独或成对活动，以昆虫为主食，尤其是甲虫，也会捕食蜘蛛和小型蜥蜴。通过在枝头守候的方式捕食，发现猎物后会飞扑或俯冲至地面或树干捕捉。","breeding":"繁殖季节主要从11月持续到2月，通常在棕榈树或树蕨上凿洞筑巢，有时会在白蚁丘中挖掘巢穴。经过大约十五天的挖掘，白蚁会封住巢穴周围的区域，随后雌雄共同产下3-4枚白色卵。","identification":"与瓦努阿图的另一种翠鸟白领翡翠相比，栗腹翡翠的上体更蓝，腹部橙色更鲜明，且眼上方无浅色条纹。","protection":"IUCN：NT（近危）。由于其非常小的分布范围和对原始雨林的特定生境需求，受到伐木严重威胁。在Malo岛上，从海岸到Pic Malo山峰的徒步路线中，相隔约200米发现了8-10对鸟。在Espiritu Santo上，由于开放和大部分次生生境被白领翡翠占据，数量较少。","distribution":"分布在瓦努阿图的Espiritu Santo、Malo和Malakula岛屿。","other":"在Espiritu Santo的Loru地区，估计每平方公里约有100只鸟，但在Big Bay地区较为罕见。除了受到伐木威胁，可能还受到野猪和牛造成的栖息地退化的影响。"},{"name":"淡黑翡翠","english_name":"Sombre Kingfisher","scientific_name":"Todiramphus funebris","overview":"淡黑翡翠（英文名：Sombre Kingfisher，学名：Todiramphus funebris），是佛法僧目翠鸟科林翡翠属的鸟类。分布于印尼摩鹿加群岛的哈马黑拉岛。其显著特征包括暗色背部、白色腹部以及独特的白眼眉和白领。雌雄颜色有所差异，雄鸟上体带有绿橄榄色调，而雌鸟则呈棕色。幼鸟颜色更为暗淡。","appearance":"成年淡黑翡翠体长约30厘米，头部和前额为黑色，眼周、颧骨、脸颊和颈部带有绿色调。拥有长而细的白眼眉和广泛的白领。上体羽毛为深绿色，背部、肩部和翅膀为暗橄榄绿色，尾部橄榄绿色。下体白色略显灰暗，胸部有少许黑色标记。嘴喙粗长，黑色，虹膜深褐色，腿脚黑色。雌鸟相较于雄鸟色彩略深，上体羽毛为浅橄榄色。","call":"发出缓慢的‘ki…ki…ki…’叫声，以及三声响亮、下降、类似疯癫笑声的音符，持续约1.5秒，间隔5秒重复，另一只鸟可能以快速的鼻音二音节上滑音回应。","habits":"栖息于低地和山丘的森林底层、森林边缘、红树林，偶尔出现在花园、低地耕作区和椰子种植园。偏好沼泽森林（如莎草棕榈）、成熟的次生林地、森林边缘和红树林。主要以大型节肢动物为食，如蚱蜢、蜈蚣，也会捕食蛇和蜥蜴。在树中层阴暗的枝干上长时间停留，扫描空地，然后俯冲至地面捕食。","breeding":"关于繁殖的信息有限，已知的活跃巢穴位于2014年9月的一个树栖白蚁丘上，位于一棵大约5米高的Pandanus树上。除此之外，关于繁殖行为的信息尚不充分。","identification":"淡黑翡翠与白领翡翠和白眉翡翠的区别在于其白色的眉毛和深色的上体。雄鸟的上体带有绿色调，而雌鸟则为棕色，有助于区分性别。","protection":"IUCN：LC（无危）。由于栖息地的丧失和退化，导致小规模种群数量正在减少。自1931年起受到印尼法律名义上的保护，栖息于Aketajawe-Lolobata国家公园内，但需更多生物学信息，尤其是对原始森林的依赖程度。","distribution":"分布局限于哈马黑拉岛（北摩鹿加群岛，印尼），主要在海平面至620米的海拔范围内，通常在100米以下。","other":"该物种在1990年代初期以来面临加速的森林破坏和碎片化，商业伐木普遍且严重，剩余森林大部分处于木材特许经营权之下。由于该物种偏好低海拔环境，上述威胁尤为严重。"},{"name":"白领翡翠","english_name":"Collared Kingfisher","scientific_name":"Todiramphus chloris","overview":"白领翡翠（英文名：Collared Kingfisher，学名：Todiramphus chloris），是佛法僧目翠鸟科林翡翠属的鸟类。中等体型的翠鸟，分布广泛，从亚洲南部至马来西亚，小巽他群岛，非洲东北部和阿拉伯半岛。其特征为蓝绿色的冠羽，白色的颈环，黑色面具延伸至后颈，以及蓝绿色的上体和明亮的蓝色臀部。该物种适应力强，常见于多种栖息地。","appearance":"白领翡翠体长23至25厘米，体重51至100克，雄鸟略轻。其上体颜色可从蓝色至绿色不等，下体为白色或淡黄色，颈部有明显的白色环带。头部有绿蓝色的冠羽，眼睛上方有白色斑点，脸部有一条黑色条纹穿过眼睛。雌鸟和幼鸟颜色较暗，上体更偏绿色，下体更偏向淡黄色，颈部和胸部的羽毛边缘有暗灰色的鳞片状标记。","call":"发出响亮、刺耳且金属质感的“kee-kee-kee”叫声，通常重复3至5次，叫声在地理上有差异，如澳大利亚的叫声为两次重复的“kek kek”。","habits":"主要栖息于沿海地带，尤其是在红树林沼泽，也出现在农田、开阔的林地、草地和花园。饮食多样，包括小型甲壳类动物、鱼类、昆虫、蜘蛛、蚯蚓、蜗牛、两栖动物、蜥蜴、蛇、小鸟蛋和小型哺乳动物。捕食方式为长时间静止守候，发现猎物后俯冲捕捉，然后飞回栖木处，较大猎物会在枝干上敲打使其失去抵抗。","breeding":"繁殖期因地区而异，筑巢于树洞、朽木、土堤或鸟巢蕨基部，也会利用啄木鸟留下的洞穴。巢穴为长5至7.5厘米，深15至90厘米的隧道，巢室宽10至15厘米，高10厘米。每窝产卵2至5枚，通常孵化期至幼鸟离巢需约44天，双亲共同育雏。","identification":"与其他翠鸟相比，白领翡翠的白色颈环和黑面具是其显著特征。不同亚种在羽色上有细微差别，如头顶部颜色从深绿色到白色不等。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界和澳新界，从亚洲南部至马来西亚，小巽他群岛，非洲东北部和阿拉伯半岛。在东南亚和印尼，该物种普遍且常见，有时会深入内陆，甚至到达山地。","other":"该物种适应性强，能在多种环境中生存，但在一些小太平洋岛屿上的亚种可能受到栖息地丧失的威胁。"},{"name":"托列斯翡翠","english_name":"Torresian Kingfisher","scientific_name":"Todiramphus sordidus","overview":"托列斯翡翠（英文名：Torresian Kingfisher，学名：Todiramphus sordidus），是佛法僧目翠鸟科林翡翠属的中等体型的翠鸟。体型较大的翠鸟，羽色多变，但始终比林翡翠或白眉翡翠更显绿褐；眼前方具一不向后延伸的淡色斑点。其分布限于红树林及相邻泥滩与岩架，是澳新红树林系统的典型指示种。","appearance":"体长23–25厘米，雄鸟体重51–90克，雌鸟54–100克。成鸟头顶及上体呈绿蓝色，臀部更亮蓝；具黑色过眼纹并在后颈连成细带，白色领环明显；眼先有一小白斑但不向后延伸；翅和尾蓝色，下体纯白。喙上喙灰黑，下喙黄白而具深褐切缘及端斑；虹膜深褐；腿脚深灰色，足底淡黄。雌鸟羽色略暗。幼鸟上体更绿，下体偏棕，颈胸羽缘暗灰，翼覆羽端部淡棕。各亚种在大小及羽色深浅上略有差异，部分亚种具性二型，雄鸟下体、额或眉纹更偏棕或赤褐色。","call":"常见叫声为响亮而带金属质感的“kee-kee-kee-kee”，连续3–5声，常在飞离栖枝时发出；澳洲种群多为双音节“kek kek”；帕劳为飞行时的重复“tchup-weee”；马里亚纳群岛则有“caw-heee”及犬吠般“kip-kip-kiup”。繁殖期成鸟近距离相遇时发出上扬的“keer keer”颤音，警戒时发出粗厉金属“aank-aank-aank”或尖锐啸声。","habits":"专性利用红树林及其邻近泥滩、岩架，从不远离潮汐环境。常单独停栖1–3米高处，长时间静止后俯冲至地面、泥面或浅水捕食，捕得猎物后返回栖枝摔打再吞咽；亦可在空中掠食昆虫或浅水面悬停扎入。猎物以甲壳类（1–2厘米宽的虾蟹）和小鱼为主，亦记录跟随印度光面水獭捕食被惊扰的鱼类。","breeding":"繁殖期因地而异：澳洲为9–翌年2月，新几内亚10–3月，所罗门群岛8–11月，瓦努阿图10月，斐济12月。成对营巢，领域全年守护。求偶时低空互追，雄鸟向雌鸟递食。巢洞多凿于红树林枯桩、树缝、树根翻起处的土堤或树冠白蚁堡，亦利用啄木鸟旧洞；隧道直径5–7.5厘米，长15–90厘米，巢室10–15厘米宽。每窝2–5枚卵，通常3枚；双亲共同孵卵育雏，雏鸟29–30日龄出飞。","identification":"与同属林翡翠及白眉翡翠相比，托列斯翡翠体色更偏绿褐，眼先白斑不延伸为眉纹，且栖地严格限于红树林；林翡翠上体更青绿，白眉翡翠则具完整白色眉纹并常见于开阔林地。","protection":"IUCN: LC（无危）。全球分布广，局部常见至丰富，但红树林开发对其沿海种群构成潜在威胁；部分小岛亚种种群极小，易受栖息地丧失及极端天气影响。","distribution":"繁殖区：西澳大利亚皮尔巴拉（德格雷河至埃克斯茅斯湾）、阿鲁群岛、新几内亚西南至东南海岸、澳大利亚北部及东北部、昆士兰沿海中部至东南部。非繁殖期基本留居，偶见圣诞岛及日本南琉球群岛迷鸟记录。"},{"name":"小岛翡翠","english_name":"Islet Kingfisher","scientific_name":"Todiramphus colonus","overview":"小岛翡翠（英文名：Islet Kingfisher，学名：Todiramphus colonus），是佛法僧目翠鸟科林翡翠属的鸟类，具有暗绿色背部，蓝绿色翅膀，深色面罩，绿色冠帽，白色颈圈和眼前方的淡橙色斑点。广泛分布于岛屿，尤其是巴布亚新几内亚的路易西亚德群岛。","appearance":"小岛翡翠是一种中等体型的翠鸟，体长23-25厘米，体重介于51-100克之间。雄鸟具白色眉纹，黑色面具延伸至后颈，白色颈圈，绿蓝色头部和上身，更亮丽的蓝色臀部，蓝色翅膀和尾巴，白色下体。喙上部灰黑色，下部黄角质色带深棕色边缘和尖端；虹膜深棕色；腿和脚暗灰色，掌黄色。雌鸟略显暗淡。幼鸟色彩较暗，上部更绿，下部更淡橙色，颈部和胸部羽毛边缘有暗灰色，翼覆羽尖端淡橙色。不同亚种在颜色上有细微差异。","call":"叫声特征鲜为人知，通常为响亮的‘kee-kee-kee-kee’声，重复3-5次，有时在起飞时发出，但存在地域变异。","habits":"栖息于多种环境，主要沿海岸线，偏好红树林。分布于从苏丹到印度的西部地区，东南亚的椰子种植园、郊区花园、道路边，马来西亚的花园和河流，印尼和菲律宾的红树林、农田、花园、稻田、棕榈园、沼泽、干草地、林地边缘等。海拔高度从海平面到约1000米，Java和Sumatra可达1500米。","breeding":"繁殖期在不同地区有所不同，一般在4月至7月之间。单个记录显示五只鸟共同挖掘树桩中的巢穴，但没有合作繁殖的迹象。巢穴通常在树上的白蚁丘、腐朽的树干、土堤、倒伏树木根部周围或鸟巢蕨基部挖掘。一对鸟会在不同洞穴中连续抚养两窝幼鸟。","identification":"与太平洋和白眉翡翠非常相似，但体型较小，喙更直，不如两者弯曲。与白眉翡翠的区别在于缺乏淡橙色下体。","protection":"IUCN：LC（无危）","distribution":"主要分布在巴布亚新几内亚的路易西亚德群岛，包括Egum、Alcester、Bonvouloir等地。在澳大利亚，分布于红树林、入海口、河口和潮滩，偶尔内陆河流旁的红树林。","other":"在20世纪下半叶在马来西亚内陆殖民化。一些小太平洋岛屿上的亚种，如vicina和brachyurus，可能因自然事件加剧的生境丧失而受到威胁。"},{"name":"马里亚纳翡翠","english_name":"Mariana Kingfisher","scientific_name":"Todiramphus albicilla","overview":"马里亚纳翡翠（英文名：Mariana Kingfisher，学名：Todiramphus albicilla），是佛法僧目翠鸟科林翡翠属的中等体型的翠鸟。原是北马里亚纳群岛的特有种，栖息于亚热带或热带湿润低地森林及种植园中。","appearance":"马里亚纳翡翠身长约23至25厘米，体重雄鸟51至90克，雌鸟54至100克。头部和身体主要为洁净的白色，有时带有淡绿色的头冠和脸颊，具有一条黑色眼纹环绕至头部后方。喙部黑色，基部黄色。翅膀比背部和尾巴更蓝，后者呈现绿色。雌鸟颜色稍暗淡，幼鸟色泽较暗，上部呈绿色，下部偏黄褐色，颈部和胸部羽毛边缘带有深灰色。","call":"马里亚纳翡翠的叫声鲜为人知，报道中描述为一系列响亮的吠叫声。","habits":"广泛分布在多种生境中，偏好沿海森林。在澳大利亚，主要限于河口、红树林的入口和潮汐滩涂，偶尔出现在内陆的红树林边缘河流。在较小的太平洋岛屿上，其栖息地选择受其他翠鸟种类的影响。以甲壳类动物如虾和蟹为主要食物，也捕食小鱼、昆虫、蜘蛛、蚯蚓、蜗牛、陆蟹、青蛙、蜥蜴、蛇、小鸟的蛋和雏鸟，以及小型哺乳动物。","breeding":"繁殖期在不同地区有所差异，如菲律宾为5月至6月，北马里亚纳群岛为7月至8月。通常每年育有两窝幼鸟。巢穴挖掘在树上的白蚁巢、腐朽的树干或树桩、土堤、倒伏树木根部周围的土壤或鸟巢蕨的底部，或利用自然洞穴或啄木鸟留下的空洞。巢穴直径约5至7.5厘米，长度15至90厘米，巢室宽10至15厘米，高10厘米。每窝产卵2至5枚，孵化期至幼鸟离巢大约44天，由双亲共同喂养。","identification":"与其他翠鸟的区别在于其更浅的体色和独特的头部图案，如白色的眼上斑点和黑色眼纹。","protection":"IUCN：LC（无危）。马里亚纳翡翠分布广泛，某些地区数量丰富。然而，一些亚种如vicina和brachyurus可能因栖息地丧失而面临威胁。","distribution":"主要分布在北马里亚纳群岛（Micronesia西部）。","other":"曾被认为是白领翡翠的亚种。"},{"name":"美岛翡翠","english_name":"Melanesian Kingfisher","scientific_name":"Todiramphus tristrami","overview":"美岛翡翠（英文名：Melanesian Kingfisher，学名：Todiramphus tristrami），是佛法僧目翠鸟科林翡翠属的鸟类。分布于俾斯麦群岛和所罗门群岛西北部至中部，曾被视为林翡翠的亚种。","appearance":"美岛翡翠体型中等，长度约为23-25厘米，体重介于51-100克之间。雄性美岛翡翠具有白色眼上斑点，黑色面罩延伸至后颈形成细带，白色领圈，蓝绿色冠羽和上体，臀部更亮呈蓝色，翅膀和尾巴蓝色，下体白色。喙上半部灰黑色，下半部黄角色带暗褐色边缘和尖端；虹膜深棕色；腿脚深灰色，足底黄色。雌鸟略显暗淡。幼鸟颜色较暗，上体更绿，下体更黄，颈部和胸部羽毛边缘有暗灰色，翼覆羽末端黄色。不同亚种在大小和颜色上有细微差异。","call":"美岛翡翠的常见叫声为响亮、清脆或刺耳的‘kee-kee-kee-kee’，重复3-5次，通常在起飞时发出，但在不同地区有所变化，如澳大利亚的两声或三声‘kek kek’，帕劳的飞行中‘tchup-weee’，马里亚纳群岛的‘caw-heee’和响亮的吠叫‘kip-kip-kiup’。","habits":"美岛翡翠栖息于岛屿的各种环境，尤其是在海岸地区，但也深入内陆，特别是在没有其他翠鸟的地区。它们偏好沿海红树林，也出现在椰子种植园、郊区花园、道路旁，甚至远离海岸的花园和河流上游。在较小的太平洋岛屿上，当存在竞争者时，美岛翡翠倾向于留在海岸，但在没有竞争者的情况下，会移居到草原、森林丘陵和封闭森林。","breeding":"繁殖季节从4月到7月在埃塞俄比亚，6月在阿联酋；在印度东北部和孟加拉国主要从3月到8月，但在安达曼群岛从3月到5月，尼科巴群岛从2月到3月，缅甸在4月，泰国在3月到7月，在马来西亚半岛从12月到8月，在苏门答腊和爪哇从3月到11月，在婆罗洲和菲律宾从5月到6月，在马里亚纳群岛从7月到8月，在新几内亚从10月到3月，在所罗门群岛从8月到11月，在瓦努阿图在10月，在斐济在12月，在澳大利亚从9月到2月。通常一对每年养育两窝。巢穴在树干或树桩的白蚁巢、腐烂的树干、土堤、倒伏树木根部周围的土壤或鸟巢蕨基部挖掘，或利用自然洞穴或啄木鸟留下的空洞。每窝产卵2-5枚，孵化期至离巢约44天，幼鸟由双亲喂养，离巢前29-30天。","identification":"美岛翡翠与其他翠鸟的区别在于其上体的蓝绿色调，苍白的领圈，纤细的暗色面罩，以及双色的喙。与白眉翡翠相比，美岛翡翠平均上体颜色更深，更接近蓝色。","protection":"IUCN：LC（无危）","distribution":"美岛翡翠分布于澳新界，具体包括俾斯麦群岛和所罗门群岛的西北部和中部地区。"},{"name":"太平洋翡翠","english_name":"Pacific Kingfisher","scientific_name":"Todiramphus sacer","overview":"太平洋翡翠（英文名：Pacific Kingfisher，学名：Todiramphus sacer），是佛法僧目翠鸟科林翡翠属的鸟类。广泛分布在南太平洋岛屿上，曾被视为白领翡翠的亚种。在一些地方十分常见，甚至数量丰富。其外观多样，随岛屿而变，一般上身绿色或蓝色，下身白色或橙色。太平洋翡翠在多个生境类型中可见，海拔可达1500米。","appearance":"中等体型，长23-25厘米，体重雄鸟51-90克，雌鸟54-100克。雄鸟具白色眉纹，黑色面罩延伸至颈背，绿色或蓝绿色冠羽及上体，更鲜艳的蓝色臀部，蓝色翅膀和尾巴，白色下体。雌鸟略暗淡。幼鸟上体较暗，下体较橙色，颈部和胸部羽毛边缘呈深灰色，翼上覆羽尖端为橙色。各亚种在大小和颜色上有细微差异。","call":"最典型的叫声是一连串响亮、刺耳的“kee-kee-kee-kee”，在飞行时常发出。叫声在不同地区有所不同。","habits":"太平洋翡翠主要栖息在沿海地区，偏好红树林，但也出现在多种生境，如农田、开阔林地、草地和花园。它通常比白领翡翠分布更内陆，进入森林或山区。常在电线、岩石或裸枝上显眼地停栖。","breeding":"繁殖期在不同地区有所变化，从4月到7月在埃塞俄比亚，12月至8月（10月）在马来西亚半岛，3月至11月在苏门答腊和爪哇，5月至6月在婆罗洲和菲律宾。通常单独配对繁殖，一季中可抚养两窝幼鸟。巢穴位于白蚁丘、腐朽树干、土堤、倒伏树木根部周围的土壤或自然洞穴中。一对鸟会轮流挖掘巢穴，巢室宽10-15厘米，高10厘米。每窝产2-5枚蛋，平均孵化期至幼鸟离巢约44天。","identification":"与白领翡翠相似，但后者喙更纤细，下体总是橙色。幼年的白领翡翠胸部斑纹更多。太平洋翡翠的叫声和行为也有助于识别。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚和新西兰地区以及太平洋西南部。在澳大利亚，全年大部分时间都可见；在所罗门群岛，占据领地间距在密集的沿海区域仅250米，而在深林内陆则更为稀疏。","other":"20世纪下半叶在马来西亚内陆地区扩散。一些小岛上的亚种，如vicina和brachyurus，可能受到自然事件负面影响下的栖息地损失威胁。"},{"name":"暗色翡翠","english_name":"Talaud Kingfisher","scientific_name":"Todiramphus enigma","overview":"暗色翡翠（英文名：Talaud Kingfisher，学名：Todiramphus enigma），是佛法僧目翠鸟科林翡翠属的鸟类。拥有干净的白色下体和蓝色绿色的上体，分布局限于塔劳群岛，栖息于森林和森林边缘，常靠近河流和溪流。","appearance":"成鸟具有白色的眉纹延伸至眼睛，黑色的面罩，蓝绿色的冠羽和背部带有蓝色调，蓝绿的翅膀和尾巴，白色的颈环和下体。喙为黑色，下颚基部黄色角质，尖端和边缘黑色；虹膜深棕色；腿和脚为黑色。体型较小，比相似的白领翡翠更为矮胖，上体绿色调更浓。","call":"鸣叫声为重复的五音符‘kee kee kee kee kee’，音节等长且音高相同，可重复4至6次；还有缓慢节奏的‘kree-ow-kree-ow…’声。","habits":"常见于原始森林、混合林和次生林，偶尔在灌木区和草原活动。它们在海岸线和河流岸边捕食，以蜥蜴、爬行动物、壁虎、昆虫、小甲壳类、蠕虫、新生小鼠和蝗虫幼虫为食。捕猎时，会静立于低枝，发现猎物后垂直俯冲，同时发出尖叫声。","breeding":"成熟期为两年。繁殖季从11月至翌年8月，夫妻会强烈保卫领地。巢穴设在高于地面6英尺的枯树洞中，每窝产3枚白色卵，孵化期21天，幼鸟孵化后盲眼，由双亲共同抚养至35天后能独立飞行。","identification":"与白领翡翠相比，暗色翡翠体型更小，喙和尾更短，上体绿色调更显著，且不在白领翡翠限制的沿海地带出现。","protection":"IUCN：NT（近危）","distribution":"分布于澳大利亚新几内亚界内的塔劳群岛（东北部，印尼苏拉威西岛北侧）。","other":"暗色翡翠的自然栖息地为亚热带或热带湿润的低地森林和河流。"},{"name":"桂红翡翠","english_name":"Guam Kingfisher","scientific_name":"Todiramphus cinnamominus","overview":"桂红翡翠（英文名：Guam Kingfisher，学名：Todiramphus cinnamominus），是佛法僧目翠鸟科林翡翠属的鸟类。别名: 密克罗尼西亚翡翠，色彩斑斓的中型翠鸟，长度约20-24厘米。雄鸟头部和下部红褐色，雌鸟下颏和喉部为象牙白色。分布于关岛，曾广泛存在，但在野外已灭绝，目前仅存于圈养繁殖计划中。","appearance":"成年雄鸟具有红褐色的头、颈、外套和下部，宽广的蓝黑色过眼纹，蓝绿色的肩、背、翅和蓝色的初翼与尾。雌鸟下颏和喉部为象牙白色，胸、颈有黑色装饰羽毛。幼鸟喉咙呈淡红褐色，胸部有暗色斑点，腹部为淡黄色。腿脚黑色，喙呈深色。","call":"发出尖锐的'kshh-skshh-skshh-kroo-ee, kroo-ee, kroo-ee'声和哀怨的'kiu-kiu-kiu'声。","habits":"栖息于森林、林地、红树林沼泽、椰子树和大花园。通常为留鸟，以昆虫、蜥蜴、壁虎为食，也会捕捉小型甲壳类动物。常在低矮的枝条上守候，伺机捕捉地面上的猎物。","breeding":"繁殖期为12月至7月。在高3-8米的树洞或椰子树中筑巢，有时利用自然树洞。每窝产2枚白色蛋，双亲共同孵化和喂养幼鸟，孵化期23-25天，幼鸟31-33天离巢。","identification":"雄鸟红褐色头部和下部明显，雌鸟下部白色，与同类翠鸟相比，具有独特的颜色组合和体型。","protection":"IUCN：EW（野外绝灭）。在华盛顿公约(CITES)和中国国家重点保护野生动物名录中未列。","distribution":"原分布于关岛（南马里亚纳群岛），野外已灭绝。圈养种群分布在美国动物园。","other":"因棕色树蛇的引入导致野外灭绝，现圈养种群正在增长，计划在控制蛇害的区域重新引入关岛。"},{"name":"锈顶翡翠","english_name":"Rusty-capped Kingfisher","scientific_name":"Todiramphus pelewensis","overview":"锈顶翡翠（英文名：Rusty-capped Kingfisher，学名：Todiramphus pelewensis），是佛法僧目翠鸟科林翡翠属的鸟类。其最显著的特征是橙红色的头顶，黑色的眼纹延伸至头部后方，以及白色的腹部。广泛分布在帕劳群岛的多种生境中，包括红树林、低地森林、种植园和大型花园。","appearance":"体型小巧，长约20厘米，下部白色，翼部呈蓝绿色，背部紫色。具有绿色脸颊，黑色眼纹，橙色的头顶。幼鸟喉部浅红褐色，腹部淡黄色或白色，下巴和喉咙的羽毛有窄暗边。成鸟喙灰黑，下颌基部大面积淡角质色；虹膜深棕色，眼周皮肤黑色；腿和脚灰黑色。","call":"相对安静，但在黎明和黄昏时会发出‘che-che-che, che-kreek, kreek, kreek’的喋喋不休叫声。","habits":"生活在帕劳群岛的多样环境中，包括红树林、低地森林、种植园和大花园。在海岸地区被太平洋翡翠所取代，但不会与其混淆。主要在清晨和黄昏时鸣叫。","breeding":"成对全年占据领地，繁殖季节开始于夏末，单只幼鸟在九月离巢。巢穴主要位于树洞高处，可能多年重复使用。幼鸟与成鸟相似，但胸部侧边可能有细小的黑色条纹。幼鸟可能与父母共居长达一年，雏鸟可能定期与母亲同栖。","identification":"与已自然灭绝的桂红翡翠和波岛翡翠的区别见分类注释。幼鸟与成鸟的主要区别在于喉部颜色和腹部色调。","protection":"IUCN：NT（近危）","distribution":"仅限于帕劳群岛（西部加罗林群岛，西部密克罗尼西亚）。在大型、树木茂盛的岛屿上仍然相当常见，尽管最近有人认为该物种实际上稀少，难以发现，数量远少于T. chloris teraokai。","other":"曾被认为是密克罗尼西亚翡翠的一个亚种。"},{"name":"波岛翡翠","english_name":"Pohnpei Kingfisher","scientific_name":"Todiramphus reichenbachii","overview":"波岛翡翠（英文名：Pohnpei Kingfisher，学名：Todiramphus reichenbachii），是佛法僧目翠鸟科林翡翠属的鸟类。密克罗尼西亚中部）。拥有蓝绿色背部，雪白腹部和颈圈，以及橙色头冠。雌雄成鸟和幼鸟的羽毛颜色有所不同。","appearance":"体长约20厘米，雄鸟平均重61.8克，雌鸟略重，平均66.7克。成年波岛翡翠头部顶部呈深红褐色，有时颈部后部混有少量白色羽毛，脸部下方、腹部及颈后圈呈现闪亮的白色，背部、翅膀和尾巴则闪耀着蓝绿色光泽。雌鸟腹部为白色，与胸部的红褐色明显分界。雄鸟的腹部为白色。幼鸟特征未详尽描述。","call":"波岛翡翠发出一连串响亮的“kweep”声，声音持久且富有穿透力。","habits":"偏好开阔的森林边缘、花园和早期次生林等环境。以低矮暴露的枝头为狩猎起点，突然俯冲捕捉猎物。全年在领土内活动，包括觅食、探索及领域维护。","breeding":"两性共同挖掘位于地面约4.3米高的白蚁巢（Nasutitermes spp.）或白蚁丘作为巢穴，巢室直径约12.7厘米，连接至巢外的隧道直径5.1厘米，长10.6厘米。有时会重复使用旧巢址。常见两窝繁殖，发生在70%的研究对中。每窝产卵两枚，双方均参与喂养幼鸟。幼鸟和成鸟的平均存活率分别为37%和58%。","identification":"波岛翡翠与锈顶翡翠和桂红翡翠有明显的差异，包括体型、羽色和叫声。与桂红翡翠的区别在于更短的翼和尾，雄鸟的白色下体而非肉桂色，以及不同的叫声。","protection":"IUCN：VU（易危）。受限制范围物种，仅存于东加罗林群岛生态区。尽管数量未量化，但目前不认为正在下降。主要威胁来自可能入侵的棕色树蛇（Boiga irregularis），这是一种导致同属种桂红翡翠在关岛野外灭绝的入侵捕食者。","distribution":"仅分布于太平洋的Pohnpei岛（加罗林群岛东部，密克罗尼西亚中部）。","other":"波岛翡翠曾被认为是Micronesian Kingfisher的一个亚种，但近期遗传学研究显示它与桂红翡翠和扁嘴翡翠有密切关系。"},{"name":"白头翡翠","english_name":"Beach Kingfisher","scientific_name":"Todiramphus saurophagus","overview":"白头翡翠（英文名：Beach Kingfisher，学名：Todiramphus saurophagus），是佛法僧目翠鸟科林翡翠属的鸟类。以其醒目的白色头部、狭窄的黑色眼后纹和蓝绿色背部著称。常见于印尼摩鹿加群岛至俾斯麦群岛和所罗门群岛的海岸地区。","appearance":"身长30厘米，重90-146克，雄鸟略轻。头部、颈部和下体均为白色，具有一条细窄的黑色眼后纹，背部、翅膀和尾部呈现蓝绿色。喙部除下颚基部淡色外，其余部分深色；虹膜极深褐色；腿和脚为黑色。幼鸟色彩较暗淡，冠部和下体呈淡黄色，胸羽边缘带灰色。亚种间差异主要体现在冠部图案上。","call":"发出响亮而深沉的叫声，包括下降音调的‘choo-chew’声和快速激动的‘kip-kip-kip-kip-kip’声。","habits":"栖息于有漂木和多个栖息点的海滩、岩岸、珊瑚悬崖和池塘、突出的岬角、红树林沼泽、悬垂树木丰富的海岸以及植被丰富的地带，偶尔光顾花园池塘。偏好有足够植被覆盖的环境，通常在离岸岛屿到内陆几百米范围内活动。在白领翡翠分布区较为罕见或不存在。","breeding":"在树干上挖掘巢穴，卵呈近圆形，纯白色，尺寸约为29.4×26.2毫米。","identification":"通过洁净的白色头部和狭窄（而非宽阔）的眼后黑色条纹，可以将其与较小的白领翡翠的所有形态区分开来。","distribution":"澳新界：印尼摩鹿加群岛至俾斯麦群岛和所罗门群岛。"},{"name":"白眉翡翠","english_name":"Sacred Kingfisher","scientific_name":"Todiramphus sanctus","overview":"白眉翡翠（英文名：Sacred Kingfisher，学名：Todiramphus sanctus），是佛法僧目翠鸟科林翡翠属的鸟类。中型翠鸟，广泛分布于澳大利亚、新西兰以及太平洋西部地区。其特征为头部有明显的白色眉纹，胸前为奶油色至白色，背部和尾部呈现美丽的蓝绿色调。雄雌外观相似，但雌鸟颜色略显暗淡。","appearance":"成年白眉翡翠身长22厘米，体重介于28至61克之间。头部较大，颈部强健。背部及尾部为鲜艳的蓝绿色，胸部和腹部呈白色或奶油色，肩部和翕为树荫般的蓝绿色。脸部有一黑色面具，从眼睛延伸至颈部。嘴部粗长，形状似凿，雌雄外观类似，但雌鸟颜色略显暗淡，幼鸟上翅覆羽边缘为淡黄色，脸颊、颈圈、胸腹羽毛尖端呈暗褐色。","call":"鸣声清晰，友好呼唤时如长笛声，受到惊吓时发出嘶哑的拨浪鼓般的声音。","habits":"栖息于红树林、桉树林和湿润地区的森林地带，偏好开放的林地、公园、花园以及沿海泥滩和红树林。主要以昆虫、蜘蛛、小型无脊椎动物为食，偶尔也会捕食小鱼、小蛇、蜥蜴等小型脊椎动物。捕食时会从低枝上俯冲抓取猎物，然后返回枝头处理食物。","breeding":"繁殖期从9月至次年1月，有时会持续至3月。营巢于土崖壁或河堤上，挖掘隧道式巢穴，深约60厘米，宽约20厘米，高约10厘米。卵为近圆形，纯白色，大小约29.4×26.2毫米，孵化期17至18天，父母双方共同参与孵化和喂养雏鸟，幼鸟在巢中停留26天左右，直至能够飞行。","identification":"与森林翠鸟相比，白眉翡翠缺乏白色的翼板。雌鸟较雄鸟更暗淡，尤其是在翅膀和臀部。幼鸟上翅覆羽有淡黄色边缘，脸颊、颈圈、胸腹有暗褐色尖端。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖澳大利亚、新喀里多尼亚、诺福克岛、新西兰和东部所罗门群岛。非繁殖期向北迁徙至印度尼西亚群岛、新几内亚、俾斯麦群岛和所罗门群岛。","other":"在某些地区，白眉翡翠的种群数量可能因土地开垦而增加，但也面临着来自入侵物种的竞争威胁，如紫翅椋鸟、家八哥和麻雀。"}];
